-- Poems batch 378
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('91afcac6-d769-431c-b924-32b3d959602f','慶雲寺檜','胡宿','宋','宋诗','song-poetry','','[]','寶坊金布地，嘉木此含榮。',48,'全唐诗/poet.song.9000.json','["寶坊金布地，嘉木此含榮。", "吳帝留青蓋，湘神駐翠旌。", "月移香砌冷，風入夜琴清。", "若比東陽樹，婆娑意未平。"]'),
('6952bc7e-b961-49ee-9e6e-8d5315c944c9','送臧寺丞赴建昌','胡宿','宋','宋诗','song-poetry','','[]','新擢京司秩，初旌幕府賢。',48,'全唐诗/poet.song.9000.json','["新擢京司秩，初旌幕府賢。", "少年裁美錦，晝日撫鳴絃。", "山好當衙際，雲閒至榻前。", "庭中無一事，時問嶽僧禪。"]'),
('01efac5d-8d0e-4983-bfbd-f8968ab75331','送君爲從事東歸','胡宿','宋','宋诗','song-poetry','','[]','秋半飭歸艎，輕橈入水鄉。',48,'全唐诗/poet.song.9000.json','["秋半飭歸艎，輕橈入水鄉。", "吳歌聞子夜，陶菊見重陽。", "月浦鯢收浪，霜空鳥拂檣。", "南冠歸未得，潘鬢莫蒼浪。"]'),
('1237c49a-f947-4e98-b00d-ad22cb70ed64','送孫從事','胡宿','宋','宋诗','song-poetry','','[]','三十一仙科，同時升大羅。',48,'全唐诗/poet.song.9000.json','["三十一仙科，同時升大羅。", "軒翔幾人去，淪謫獨君何。", "淮桂牽吟數，湘蘭寄恨多。", "且欣彈頍弁，榮路未蹉跎。"]'),
('07127ee6-bd93-4351-beec-5d8d82f46232','送王從事赴漳州','胡宿','宋','宋诗','song-poetry','','[]','再奉天官集，初登郡將筵。',48,'全唐诗/poet.song.9000.json','["再奉天官集，初登郡將筵。", "檄材磨盾妙，賓履躡珠賢。", "舊洞毛生竹，新池水映蓮。", "幕中多暇日，曳彩戲親前。"]'),
('7c5504a2-1c64-4bd2-ad21-cf86e09a4f22','禁直晨興呈承旨侍郎','胡宿','宋','宋诗','song-poetry','','[]','內殿已攢點，攬衣朝未央。',48,'全唐诗/poet.song.9000.json','["內殿已攢點，攬衣朝未央。", "月低銜禁樹，雲薄護朝霜。", "欲放魚文鑰，先含雞舌香。", "大昕鵷與鷺，奏事向明光。"]'),
('28e27461-7070-40d2-a45d-ca2a245c4f07','館中候馬','胡宿','宋','宋诗','song-poetry','','[]','紫陌歸鞍後，端門午鼓餘。',48,'全唐诗/poet.song.9000.json','["紫陌歸鞍後，端門午鼓餘。", "銅池銜落景，鐵擿掩殘書。", "水遠溝聲細，花閒壁影疏。", "去騶呼已遠，自笑守應廬。"]'),
('a1ad558e-3c2f-49a0-bb29-23008be8ed11','近郊','胡宿','宋','宋诗','song-poetry','','[]','信馬斗城外，芳郊秋物多。',48,'全唐诗/poet.song.9000.json','["信馬斗城外，芳郊秋物多。", "丹楓驚歲晏，華黍喜時和。", "野老醉相話，牧童閒自歌。", "牛羊稍覺晚，一一下層坡。"]'),
('23e2207e-36a4-4ad1-85e5-9e441b9a75bb','沙鳥','胡宿','宋','宋诗','song-poetry','','[]','一啄樊籠外，蕭然烟水鄉。',48,'全唐诗/poet.song.9000.json','["一啄樊籠外，蕭然烟水鄉。", "折蘆翻夕夢，急雨亂秋行。", "南澗漁波淺，西風菰米香。", "世無摩詰手，誰與入清防。"]'),
('8e0dba64-b9a0-4bce-93ef-d8a6e5d8b509','歲除','胡宿','宋','宋诗','song-poetry','','[]','守歲薰爐永，迎年煦律回。',48,'全唐诗/poet.song.9000.json','["守歲薰爐永，迎年煦律回。", "仙人收臘去，木帝送春來。", "桂伴陰蟾隠，梅衝艷雪開。", "平明喧壽宴，柏葉奉歡杯。"]'),
('7f35173d-b079-4ab4-a454-7914e423d30b','鸚鵡杯','胡宿','宋','宋诗','song-poetry','','[]','介族生螭蚌，杯形肖隴禽。',48,'全唐诗/poet.song.9000.json','["介族生螭蚌，杯形肖隴禽。", "曾經良匠手，見愛主人心。", "置在金樽側，來從珠水潯。", "願爲仁者壽，再拜莫辭深。"]'),
('c176923a-a427-4751-a741-65cd55d52606','上苑','胡宿','宋','宋诗','song-poetry','','[]','漢籞春來早，光風近太清。',48,'全唐诗/poet.song.9000.json','["漢籞春來早，光風近太清。", "花深迷玉漏，霧遠失金莖。", "夾道青松密，周阿碧樹生。", "回瞻葱鬰氣，遥覆九重城。"]'),
('c8ec0899-8830-4ea4-9896-008737418fe6','山中','胡宿','宋','宋诗','song-poetry','','[]','乘秋尋遠壑，偶到幽人家。',48,'全唐诗/poet.song.9000.json','["乘秋尋遠壑，偶到幽人家。", "濁醪釀秫米，香飯炊胡麻。", "微徑捫蘿蔦，高峰弄雲霞。", "餐和殆忘返，落景半規斜。"]'),
('bec3a701-fd5b-4d95-8419-5b558c1e7863','東溪早步','胡宿','宋','宋诗','song-poetry','','[]','宿雨澄紛幕，高霞冠遠岑。',48,'全唐诗/poet.song.9000.json','["宿雨澄紛幕，高霞冠遠岑。", "青蓮護水色，翠竹結村陰。", "雪浪魚跳藻，風簧鳥囀林。", "峭帆天末起，撩動五湖心。"]'),
('fe70bf68-53c6-4ca1-b80b-6dcf0c4b3a2a','水館','胡宿','宋','宋诗','song-poetry','','[]','略彴橫雲島，欄干瞰玉淵。',48,'全唐诗/poet.song.9000.json','["略彴橫雲島，欄干瞰玉淵。", "雨汀翹睡鷺，風樹咽嘶蟬。", "綠髮莓苔地，紅衣菡萏天。", "夜凉三弄笛，月在釣魚船。"]'),
('57ad6056-a0fa-473c-869f-4405f9b680c0','送徐晉卿東歸','胡宿','宋','宋诗','song-poetry','','[]','夜來龍具冷，有客厭長安。',48,'全唐诗/poet.song.9000.json','["夜來龍具冷，有客厭長安。", "去國朝衣緇，還家楚葉丹。", "雪情欺酒薄，月思拂琴寒。", "只待東風起，林鶑振美翰。"]'),
('f822f777-0b26-45ee-9aef-d1939e2042ba','送旌德田宰','胡宿','宋','宋诗','song-poetry','','[]','錦邑罷鳴琴，歸塗指上林。',48,'全唐诗/poet.song.9000.json','["錦邑罷鳴琴，歸塗指上林。", "柳鞭饒醉折，山館勝遊吟。", "清譽時苗犢，離悰望帝禽。", "明庭趨覲日，優績簡宸襟。"]'),
('967f16c7-2fa8-43a5-ab54-a5c5f45476a7','招公儀小飲','胡宿','宋','宋诗','song-poetry','','[]','官舍隠非隠，仕途才不才。',48,'全唐诗/poet.song.9000.json','["官舍隠非隠，仕途才不才。", "棟閒秋燕去，籬靜晚花開。", "卓甕何妨卧，莊軒或自來。", "求羊疏我甚，三徑有青苔。"]'),
('0af33aa8-2b85-4c64-aca3-6610c33ab93f','朱鳥航','胡宿','宋','宋诗','song-poetry','','[]','浮航二十四，一一跨淮中。',48,'全唐诗/poet.song.9000.json','["浮航二十四，一一跨淮中。", "此地名朱鳥，當年踏彩虹。", "香塵迷舊路，寒水蕩遥空。", "日暮驚飛蓋，翩翩下渚鴻。"]'),
('5a9954cf-a8ba-4e35-a7e9-62b082bcb87a','余山人居','胡宿','宋','宋诗','song-poetry','','[]','一室閉春林，蕭然物外心。',48,'全唐诗/poet.song.9000.json','["一室閉春林，蕭然物外心。", "棋聲敲月重，屐齒印苔深。", "竹閣茶烟細，山園鍛樹陰。", "會當逃世網，來此締朋簪。"]'),
('cebd1236-7eb3-4706-997b-0a147b49401e','和人山居','胡宿','宋','宋诗','song-poetry','','[]','翠柏蔭山莊，巖扃四序凉。',48,'全唐诗/poet.song.9000.json','["翠柏蔭山莊，巖扃四序凉。", "歌攀牛角遠，嘯引鳳音長。", "夕膳烹葵熟，春杯切桂香。", "列侯生計在，千戶橘含霜。"]'),
('dc0c3b93-7cd3-4095-b97a-b3cc80b21978','山居','胡宿','宋','宋诗','song-poetry','','[]','松韵笙竽徑，雲容水墨天。',48,'全唐诗/poet.song.9000.json','["松韵笙竽徑，雲容水墨天。", "人行春色裏，鶑語落花邊。", "脩竹三間屋，清泉二頃田。", "了無官府事，雞犬莫登仙。"]'),
('5b7bbf8b-4844-4952-a9de-a2b864353e79','經朱氏郊居','胡宿','宋','宋诗','song-poetry','','[]','東岡接釣磯，有客偃郊扉。',48,'全唐诗/poet.song.9000.json','["東岡接釣磯，有客偃郊扉。", "繞舍喧流水，當窗識翠微。", "溪田香稌熟，霜樹晚桃稀。", "半日揮塵袂，停車不記歸。"]'),
('b4e931bd-1a06-4856-ab2b-2a1193685251','送外表王植赴官嶺外','胡宿','宋','宋诗','song-poetry','','[]','五嶺知何許，離懷豈易言。',48,'全唐诗/poet.song.9000.json','["五嶺知何許，離懷豈易言。", "傳情無去雁，驚夢有啼猿。", "溪思吳蒓老，林香越槿繁。", "渠渠持美酒，計日望歸軒。"]'),
('20642682-c937-44ed-8af6-8df63c16f774','銀臺退朝','胡宿','宋','宋诗','song-poetry','','[]','官事良爲少，人生初得閒。',48,'全唐诗/poet.song.9000.json','["官事良爲少，人生初得閒。", "長吟聊擁鼻，薄酒且酡顔。", "春物行將晏，年芳尚可攀。", "此心同木雁，材與不材間。"]'),
('ad0cdd3a-07bb-45be-bc73-3be4ecd48c78','桃葉渡','胡宿','宋','宋诗','song-poetry','','[]','悵望情人曲，空留此渡名。',48,'全唐诗/poet.song.9000.json','["悵望情人曲，空留此渡名。", "一條衣带水，千古石頭城。", "艷歇雙桃色，歌沈兩槳聲。", "不堪懷古意，山外夕陽明。"]'),
('ef57aedf-526e-466a-87fd-75195d1265b2','春寒','胡宿','宋','宋诗','song-poetry','','[]','三楚多寒地，憑山復大川。',48,'全唐诗/poet.song.9000.json','["三楚多寒地，憑山復大川。", "龍鱗橫雪隰，羊角起風天。", "酒價高平日，花期晚去年。", "白門無限柳，疏瘦未成眠。"]'),
('726835ee-d5ab-4684-9916-ee1c9159ac45','蓬萊詞','胡宿','宋','宋诗','song-poetry','','[]','瀛閬盛佳招，排雲下赤霄。',48,'全唐诗/poet.song.9000.json','["瀛閬盛佳招，排雲下赤霄。", "水犀梳插鬢，火玉佩垂腰。", "鳬影朝青舄，鸞音咽紫簫。", "鼇宮無夜色，豹髓未嘗燒。"]'),
('83684606-1b0e-40c8-aa98-d74456185711','寄合肥知己','胡宿','宋','宋诗','song-poetry','','[]','離管回香轡，行舟動翠篙。',48,'全唐诗/poet.song.9000.json','["離管回香轡，行舟動翠篙。", "夕魂惟是黯，春目旋成蒿。", "夢與楊花蕩，書憑燕子高。", "望中人不見，湖上首重搔。"]'),
('906eeba4-0f13-4c66-9ed9-ad2068a916bf','題蘭溪','胡宿','宋','宋诗','song-poetry','','[]','招提紫翠中，僧住最高峰。',48,'全唐诗/poet.song.9000.json','["招提紫翠中，僧住最高峰。", "幾劫親諸佛，三生聽此鐘。", "早香依澗樹，高臘寄庭松。", "性海無窮願，金書字字濃。"]'),
('e1aafb0e-d52e-4ddc-b5ff-7c1177aeda8a','景福殿緋桃','胡宿','宋','宋诗','song-poetry','','[]','偷約蓬山客，閒尋芳樹蹊。',48,'全唐诗/poet.song.9000.json','["偷約蓬山客，閒尋芳樹蹊。", "晨葩鮮欲語，春色醉成迷。", "艷奪朝霞段，香傳冰麝臍。", "飄然凡境外，初有乳鶑啼。"]'),
('df4bd6ad-3938-4139-93f2-6ee44d8e3ae3','暑夕水亭','胡宿','宋','宋诗','song-poetry','','[]','曲檻瞰回塘，披襟對羽觴。',48,'全唐诗/poet.song.9000.json','["曲檻瞰回塘，披襟對羽觴。", "蘋風微有韵，水月自成凉。", "嫩篠疏疏影，新荷偃偃香。", "么絃聊按撫，志不在滄浪。"]'),
('91cfabe0-6987-4835-872e-0949dc037c2f','新荷','胡宿','宋','宋诗','song-poetry','','[]','一夜抽輕蓋，平明映曲池。',48,'全唐诗/poet.song.9000.json','["一夜抽輕蓋，平明映曲池。", "水凉魚未覺，烟凈鳥先窺。", "露重心猶卷，風多柄尚危。", "東林應結社，祇待素華披。"]'),
('0b78595b-9583-46a3-b339-8b18ca06d132','惜花','胡宿','宋','宋诗','song-poetry','','[]','試步向欄干，奇花正好看。',48,'全唐诗/poet.song.9000.json','["試步向欄干，奇花正好看。", "乾坤增著力，風雨莫無端。", "彩筆題詩易，金刀下剪難。", "十分方吐半，猶喜夜來寒。"]'),
('d106c633-da16-46a5-9c27-2f7de0744a73','晴虹','胡宿','宋','宋诗','song-poetry','','[]','霽野收雲雨，長光架一條。',48,'全唐诗/poet.song.9000.json','["霽野收雲雨，長光架一條。", "媧天初補石，乾鵲早成橋。", "日馭迷黄道，仙梯接絳霄。", "誰能乘六氣，萬里信扶摇。"]'),
('5932877a-ef07-4592-bf7e-4c0eee22071a','邑宰惠花木','胡宿','宋','宋诗','song-poetry','','[]','曉圃分花品，烟耡手自携。',48,'全唐诗/poet.song.9000.json','["曉圃分花品，烟耡手自携。", "未貪桃結實，且映李成蹊。", "瞥見香蜂集，仍聞好鳥啼。", "河陽春色晚，流過短牆西。"]'),
('33505dd0-f785-4ca3-a77c-1408150878f9','行次淮上寄何毖秀才','胡宿','宋','宋诗','song-poetry','','[]','南浦傷離數，西州作惡頻。',48,'全唐诗/poet.song.9000.json','["南浦傷離數，西州作惡頻。", "吟亭蟬送柳，宿枕鳥驚晨。", "鄴會疏沈李，吳懷豫憶蒓。", "此心何用慰，前有杏園春。"]'),
('9631b9d6-b935-4a99-b83b-3ed9ff879d58','秦淮','胡宿','宋','宋诗','song-poetry','','[]','厭勝逾千載，祖龍安在哉。',48,'全唐诗/poet.song.9000.json','["厭勝逾千載，祖龍安在哉。", "寒潮平復落，幽鳥去還來。", "龍鑿功全異，牛山事可哀。", "不知終古恨，誰見劫成灰。"]'),
('abd1c110-5635-4ae7-a772-6dbb88f78045','重陽日東園','胡宿','宋','宋诗','song-poetry','','[]','沆瀣催時律，幽陰結夕霏。',48,'全唐诗/poet.song.9000.json','["沆瀣催時律，幽陰結夕霏。", "樓臺侵日上，山水送秋歸。", "海燕辭巢盡，霜鴻避弋飛。", "一杯元亮酒，聊以浣塵機。"]'),
('9bd5e6df-159f-4142-af1b-fe7b1dd46934','宿白佛寺','胡宿','宋','宋诗','song-poetry','','[]','下馬憩禪關，春苔一徑斑。',48,'全唐诗/poet.song.9000.json','["下馬憩禪關，春苔一徑斑。", "歸雲尋谷口，倦鳥泊林間。", "山客收棋罷，龕僧數息閒。", "月高人不寐，隔嶺水潺潺。"]'),
('dfeefd86-9501-4e03-90ab-25bce9f719ac','甘露寺','胡宿','宋','宋诗','song-poetry','','[]','寶勢窮吳地，寒流對楚邦。',48,'全唐诗/poet.song.9000.json','["寶勢窮吳地，寒流對楚邦。", "一峰驚佛剎，萬象入僧窗。", "落日銜遥樹，晴虹畫半江。", "海門秋色近，翠朵自成雙。"]'),
('91d3f006-6d7a-465c-b4df-1da29eb29c74','自詠  其一','胡宿','宋','宋诗','song-poetry','','[]','索米年來甚，伶俜祇自知。',48,'全唐诗/poet.song.9000.json','["索米年來甚，伶俜祇自知。", "黑貂隨日敝，葆髮豫秋衰。", "舊産思重理，先賢恥逆施。", "呂虔刀未解，骨法謾多奇。"]'),
('87a168ff-01db-4784-a8db-1f565f3c2104','自詠  其二','胡宿','宋','宋诗','song-poetry','','[]','閉戶無還往，端居廢禮容。',48,'全唐诗/poet.song.9000.json','["閉戶無還往，端居廢禮容。", "花爲貧富焰，燕是舊過從。", "持屐對人蠟，綻衣看婦縫。", "非同叔夜傲，切莫怪疏慵。"]'),
('eb0ce2a0-1934-4275-aaf9-fc939b3476f3','華陽逋客','胡宿','宋','宋诗','song-poetry','','[]','小隠華陽客，山中不記年。',48,'全唐诗/poet.song.9000.json','["小隠華陽客，山中不記年。", "酒中長有聖，棋下更無仙。", "授得廣陵散，注成秋水篇。", "吾纓今未濯，慚愧舊林泉。"]'),
('a0dd39f4-6290-47e1-ad37-26cfacf27b1b','瓦官寺','胡宿','宋','宋诗','song-poetry','','[]','紫色嘗開國，金輝此界繩。',48,'全唐诗/poet.song.9000.json','["紫色嘗開國，金輝此界繩。", "火輪經壞劫，雪頂見殘僧。", "狂薜緣秋壁，深松映晚燈。", "哀猿不可聽，一一在巖藤。"]'),
('af2f2f40-289a-4296-baff-f9212de051e5','題劉奉禮書齋','胡宿','宋','宋诗','song-poetry','','[]','人尚西齋學，家承北第榮。',48,'全唐诗/poet.song.9000.json','["人尚西齋學，家承北第榮。", "錦囊添句重，蟾滴試毫輕。", "底法成新構，開書泣舊楹。", "丹山消息斷，喜見鳳雛聲。"]'),
('dea961cf-503c-44d2-8762-3028a57e9264','和吉老學士召赴崇政殿試舉人','胡宿','宋','宋诗','song-poetry','','[]','需宴經芳巳，嚴趨奉禁宸。',48,'全唐诗/poet.song.9000.json','["需宴經芳巳，嚴趨奉禁宸。", "子亭參覆試，止輦奉周詢。", "玉取三燒粹，金求百汰真。", "自慚諸老意，多頼洛陽人。"]'),
('c0513119-64f2-47a5-87f2-31cace037702','清明日謝人送酒','胡宿','宋','宋诗','song-poetry','','[]','寂寞揚雄宅，鴟夷載酒來。',48,'全唐诗/poet.song.9000.json','["寂寞揚雄宅，鴟夷載酒來。", "鑽榆試春火，切桂暖晨杯。", "芳蕊何須菊，香梢尚有梅。", "自慚非叔夜，聊學玉山頹。"]'),
('b590c89b-7811-4da2-bf86-7039f9bea99a','金山寺','胡宿','宋','宋诗','song-poetry','','[]','寶勢中流起，香園此布金。',48,'全唐诗/poet.song.9000.json','["寶勢中流起，香園此布金。", "鴿棲金殿冷，龍伏夜潭深。", "水鳥銜生食，江神聽梵音。", "上方聊送目，天幕杳森陰。"]'),
('3a7cae12-aff2-40a3-9216-df9337952bf6','齊國大長公主輓詞','胡宿','宋','宋诗','song-poetry','','[]','舊築王姬館，新開貴主阡。',48,'全唐诗/poet.song.9000.json','["舊築王姬館，新開貴主阡。", "山林經駐蹕，烟霧隔飛軿。", "天屬尊惟孝，邦風穆以賢。", "鸞龍摛翰藻，昭德萬斯年。"]'),
('b6cf36ac-a620-4c80-a88e-cbab9a4762eb','兵部尚書贈司空侍中晏元獻公輓詞三首  其一','胡宿','宋','宋诗','song-poetry','','[]','俊老三階後，高華四紀中。',48,'全唐诗/poet.song.9000.json','["俊老三階後，高華四紀中。", "朝廷用文治，廊廟得才雄。", "雞樹前陰改，鱣庭舊跡空。", "生存華屋處，零落恨無窮。"]'),
('9dc0382f-353a-449f-9929-c04351d0822b','兵部尚書贈司空侍中晏元獻公輓詞三首  其二','胡宿','宋','宋诗','song-poetry','','[]','川嶽淪精氣，風華喪傑才。',48,'全唐诗/poet.song.9000.json','["川嶽淪精氣，風華喪傑才。", "典刑留大雅，文象坼中台。", "聚窟香難破，鈞天夢不迴。", "只應之帝所，鳴玉侍丹臺。"]'),
('b7b5dcf5-7746-43f6-a286-fd830a2f5f28','兵部尚書贈司空侍中晏元獻公輓詞三首  其三','胡宿','宋','宋诗','song-poetry','','[]','儲極元寮寵，公貂盛策班。',48,'全唐诗/poet.song.9000.json','["儲極元寮寵，公貂盛策班。", "寧神依大騩，結冢近陘山。", "鼓吹春風裏，麒麟夕照間。", "寄言川上水，何事不西還。"]'),
('80c78bbc-83ca-4aa1-bf83-76c2007c78f9','太尉文肅鄭公輓詞三首  其一','胡宿','宋','宋诗','song-poetry','','[]','西北謀元帥，東南出雋儒。',48,'全唐诗/poet.song.9000.json','["西北謀元帥，東南出雋儒。", "上前曾借筯，閫外復投壺。", "見器同安國，憂邊得亞夫。", "如何遡黄壤，不及播洪爐。"]'),
('de22e921-52a4-4631-9064-3e1750eb3648','太尉文肅鄭公輓詞三首  其二','胡宿','宋','宋诗','song-poetry','','[]','公業關東望，夷吾天下才。',48,'全唐诗/poet.song.9000.json','["公業關東望，夷吾天下才。", "辭鋒橫劍戟，詩筆走風雷。", "帥節行邊去，氐酋獻地來。", "榮華一朝盡，埋玉使人哀。"]'),
('f4de8172-5b9e-4b24-97bd-60444add8f38','太尉文肅鄭公輓詞三首  其三','胡宿','宋','宋诗','song-poetry','','[]','將鉞徽聯重，公槐賁典加。',48,'全唐诗/poet.song.9000.json','["將鉞徽聯重，公槐賁典加。", "哀榮班襚衮，虧痛軫投瓜。", "朝露沾崇旆，秋風咽迥笳。", "英靈不可問，宰樹有棲鴉。"]'),
('a4ea7761-0489-445c-8c6e-aef4158347bb','太尉侍中鄭國宋公輓詞三首  其一','胡宿','宋','宋诗','song-poetry','','[]','第一平津策，同時入洛名。',48,'全唐诗/poet.song.9000.json','["第一平津策，同時入洛名。", "配台升上相，宰漢得元精。", "國念靈龜喪，人嗟厚棟傾。", "睿篇傷俊老，殊禮極哀榮。"]'),
('49eada9a-25ae-4583-8cc1-b54d57bc9078','太尉侍中鄭國宋公輓詞三首  其二','胡宿','宋','宋诗','song-poetry','','[]','盛業元根古，高文早變風。',48,'全唐诗/poet.song.9000.json','["盛業元根古，高文早變風。", "墮鱣遺館在，浴鳳舊池空。", "卓馬辭丹陛，騎箕向碧穹。", "琴竽三月罷，鄭國愴賢公。"]'),
('c917b65a-7cde-401b-a26d-1d01068ad111','太尉侍中鄭國宋公輓詞三首  其三','胡宿','宋','宋诗','song-poetry','','[]','天上三台坼，人間一鑑亡。',48,'全唐诗/poet.song.9000.json','["天上三台坼，人間一鑑亡。", "寧神韓土內，結冢騩山傍。", "槐鼎廞儀物，貂蟬襚密章。", "高賢同委化，茲理昧蒼蒼。"]'),
('344a69d1-59a6-40a4-b316-44c98fbdaba7','座主贈司徒侍中宣獻公輓詞五首  其一','胡宿','宋','宋诗','song-poetry','','[]','天下中庸德，人倫正始風。',48,'全唐诗/poet.song.9000.json','["天下中庸德，人倫正始風。", "立朝周鼎重，當代禹門崇。", "注意深黄閣，收神杳碧崧。", "蒼生終古恨，尺璧在丘中。"]'),
('2100d905-3417-49f9-b5d5-e818992e1e82','座主贈司徒侍中宣獻公輓詞五首  其二','胡宿','宋','宋诗','song-poetry','','[]','三陟贊樞鈞，殲良昧上旻。',48,'全唐诗/poet.song.9000.json','["三陟贊樞鈞，殲良昧上旻。", "幾傳分相史，終未立家臣。", "衛武徒虛語，巫咸不可詢。", "空餘山甫德，流詠在烝民。"]'),
('e79d1c1c-108a-4342-b1b1-3d90e436555a','座主贈司徒侍中宣獻公輓詞五首  其三','胡宿','宋','宋诗','song-poetry','','[]','門盛三鱣講，書追兩馬修。',48,'全唐诗/poet.song.9000.json','["門盛三鱣講，書追兩馬修。", "朝評尊月旦，王法正春秋。", "革履聲長絕，緇衣詠獨留。", "從今非大醉，不復過西州。"]'),
('c962aa84-ede3-48bc-bccc-430bf342e29b','座主贈司徒侍中宣獻公輓詞五首  其四','胡宿','宋','宋诗','song-poetry','','[]','鳳德衰何早，蛇年讖有開。',48,'全唐诗/poet.song.9000.json','["鳳德衰何早，蛇年讖有開。", "斂衣班上衮，愍冊賁中台。", "緣鵠空存飾，騎箕不下來。", "棟隆今已折，僑壓可勝哀。"]'),
('c1406cc8-aaac-44d3-b76f-3d6ac10ebc2e','座主贈司徒侍中宣獻公輓詞五首  其五','胡宿','宋','宋诗','song-poetry','','[]','鹵簿指西州，都人助紼謳。',48,'全唐诗/poet.song.9000.json','["鹵簿指西州，都人助紼謳。", "白雞亡謝傅，黄石葬留侯。", "霧薄旌銘慘，風長騎吹愁。", "神華何處所，流恨滿山丘。"]'),
('e5678fcf-2db6-43a0-ac98-b28a132bb0fb','禮部蔣侍郎輓詞五首  其一','胡宿','宋','宋诗','song-poetry','','[]','大雅時之老，高陽世有才。',48,'全唐诗/poet.song.9000.json','["大雅時之老，高陽世有才。", "英名知四海，公議許三台。", "華皓辭歸去，蒼黔望起來。", "一朝嵩構毀，愍冊感餘哀。"]'),
('cb73d3f1-9031-43e8-ade7-abd01d7e0400','禮部蔣侍郎輓詞五首  其二','胡宿','宋','宋诗','song-poetry','','[]','香案經爲吏，甘泉預侍晨。',48,'全唐诗/poet.song.9000.json','["香案經爲吏，甘泉預侍晨。", "衣冠親雉尾，章疏動龍鱗。", "當世高人物，諸公滿搢紳。", "忽聞捐几杖，萬恨只酸辛。"]'),
('d7ff4111-fb0f-4189-b556-f4eb4188d2d7','禮部蔣侍郎輓詞五首  其三','胡宿','宋','宋诗','song-poetry','','[]','潁水重臨久，桐鄉見愛深。',48,'全唐诗/poet.song.9000.json','["潁水重臨久，桐鄉見愛深。", "峴碑偏墮淚，鄭瑟盡停音。", "蜀士知鄒學，吳兒喜洛吟。", "生前祠影在，寒霧碧山岑。"]'),
('11dee612-6da3-4683-8a56-75d611773668','禮部蔣侍郎輓詞五首  其四','胡宿','宋','宋诗','song-poetry','','[]','尺璧丘中恨，人間第一流。',48,'全唐诗/poet.song.9000.json','["尺璧丘中恨，人間第一流。", "九原迷白日，萬壑怨清秋。", "風月高情盡，煙霞麗思休。", "故時芝館在，迢遞使人愁。"]'),
('7e1d69a7-205f-4349-86c9-cfc30e1df070','禮部蔣侍郎輓詞五首  其五','胡宿','宋','宋诗','song-poetry','','[]','茂苑來書跡，藍橋別淚痕。',48,'全唐诗/poet.song.9000.json','["茂苑來書跡，藍橋別淚痕。", "如何一交臂，不覺九招魂。", "東里嗟遺愛，西州哭舊恩。", "二孤猶在丱，未免懟乾坤。"]'),
('b4b16227-6a87-4151-b89f-90de3f366fc0','翰林南陽葉公輓詞三首  其一','胡宿','宋','宋诗','song-poetry','','[]','方丈仙山地，承明帝所人。',48,'全唐诗/poet.song.9000.json','["方丈仙山地，承明帝所人。", "辭源長萬里，筆力重千鈞。", "草詔風雷暮，賡歌律呂春。", "如何巖雨望，奄忽棄生民。"]'),
('dae3c1e0-208a-447d-82fb-6db63d41ae10','翰林南陽葉公輓詞三首  其二','胡宿','宋','宋诗','song-poetry','','[]','獻替依明主，周旋奉至公。',48,'全唐诗/poet.song.9000.json','["獻替依明主，周旋奉至公。", "直尋無枉道，方寸有孤忠。", "恥在瓶罍罄，嗟深杼軸空。", "蒼生猶未泰，夫子已先窮。"]'),
('6587dff8-53fe-47a3-90cc-a38554e9d7cf','翰林南陽葉公輓詞三首  其三','胡宿','宋','宋诗','song-poetry','','[]','遠策思開濟，孤飛易中傷。',48,'全唐诗/poet.song.9000.json','["遠策思開濟，孤飛易中傷。", "中途捨騏驥，少日鎩鸞凰。", "干鏌仍雙折，臯夔遂兩亡。", "吾生知已矣，魂斷武丘傍。"]'),
('5b4c388a-609f-4599-9873-d2fea52d8660','題飲光亭','胡宿','宋','宋诗','song-poetry','','[]','居易能藏氣，探幽復治亭。',48,'全唐诗/poet.song.9000.json','["居易能藏氣，探幽復治亭。", "泉華聊自挹，澗響與誰聽。", "圓檜行依蓋，前峰坐對屏。", "一瓢吾道在，凉月此忘形。"]'),
('1a35f62c-5901-45a6-9318-c9ed1980237f','晨起馬上口占','胡宿','宋','宋诗','song-poetry','','[]','馬過津橋外，城臨金斗傍。',48,'全唐诗/poet.song.9000.json','["馬過津橋外，城臨金斗傍。", "早霜濃著瓦，落月半銜牆。", "暗水澄寒底，初霞漏曉光。", "疏鐘林下寺，煙景正蒼凉。"]'),
('a5aa13dc-a9c3-4567-8e6a-cd5b4bd5bd6e','九月十五夜北樓望太湖','胡宿','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','雲影消空闊，霜華拂杳冥。',48,'全唐诗/poet.song.9000.json','["雲影消空闊，霜華拂杳冥。", "秋光不隠雁，夜色欲迷螢。", "爽氣橫蒼卞，凉波接洞庭。", "水仙當此夕，應化白龍形。"]'),
('1f8cd637-fec3-4e36-a48a-adbef0f2e497','登潤州城','胡宿','宋','宋诗','song-poetry','','[]','城壁起山根，樓梯易黯魂。',48,'全唐诗/poet.song.9000.json','["城壁起山根，樓梯易黯魂。", "雄風摇碧浸，畫角弔黄昏。", "一带分江紀，雙峰點海門。", "東方瞻宰樹，秋色暝前村。"]'),
('55935772-2ea6-4641-8b76-add35be320b2','懷宣城會勝院二首  其一','胡宿','宋','宋诗','song-poetry','','[]','淨剎枕城隅，溪光清且虛。',48,'全唐诗/poet.song.9000.json','["淨剎枕城隅，溪光清且虛。", "僧閒對馴鴿，客至數游魚。", "巖氣浮川上，林香生雨餘。", "南雲雖可望，長與沃洲疏。"]'),
('ba9de374-21ec-4523-87df-8d818e4412cf','懷宣城會勝院二首  其二','胡宿','宋','宋诗','song-poetry','','[]','城外尋僧遠，居常信馬蹄。',48,'全唐诗/poet.song.9000.json','["城外尋僧遠，居常信馬蹄。", "移時取香飯，半日濯靈溪。", "白馬迎人下，清猿對客啼。", "亭前有封殖，試爲問紅梨。"]'),
('7a78f8d5-0632-4938-aa96-74dea32c6a6e','仲春三衢道中','胡宿','宋','宋诗','song-poetry','','[]','隔閏年芳早，天風泛暖暉。',48,'全唐诗/poet.song.9000.json','["隔閏年芳早，天風泛暖暉。", "酒香迎社重，村語向蠶稀。", "林際新鶑出，楹間故燕歸。", "湖頭春在否，人去柳花飛。"]'),
('1db2e2c0-409c-4a4a-aba5-dc48e29c9c16','贈少室王山人','胡宿','宋','宋诗','song-poetry','','[]','九籥秘仙經，巖巖玉骨靈。',48,'全唐诗/poet.song.9000.json','["九籥秘仙經，巖巖玉骨靈。", "內書天上見，仙樂帝前聽。", "壺小藏仙界，槎高拂斗星。", "華陽陪夜話，多是說金庭。"]'),
('4f6792b7-1c06-490b-af0f-122f4dfd8594','送錢比部守盛山','胡宿','宋','宋诗','song-poetry','','[]','家世楹書在，山河廟券存。',48,'全唐诗/poet.song.9000.json','["家世楹書在，山河廟券存。", "烏衣出才子，朱轂滯王孫。", "過峽朝雲舉，辭梁臘霰翻。", "遥知巴子國，愛日有餘溫。"]'),
('e8d32a64-dd04-4efd-911b-ee181ef5c5cc','聞鶑','胡宿','宋','宋诗','song-poetry','','[]','雙翎何睍睆，百囀更綿蠻。',48,'全唐诗/poet.song.9000.json','["雙翎何睍睆，百囀更綿蠻。", "獨向芳林宿，多衝細雨還。", "低迷穿柳外，調笑入花間。", "肯比青鸚鵡，雕籠受閉關。"]'),
('e64d1e23-6af6-4c2a-9b00-36d6390f13f0','送顯忠上人歸吳郡','胡宿','宋','宋诗','song-poetry','','[]','秋風隨處起，振錫不留行。',48,'全唐诗/poet.song.9000.json','["秋風隨處起，振錫不留行。", "却背嵩雲去，迎看淮月生。", "禪通少林默，詩得杼山清。", "幾夕巖窗下，忘眠聽瀑聲。"]'),
('ebb2e58a-61aa-4119-b424-450105ae9f0a','芳茂山','胡宿','宋','宋诗','song-poetry','','[]','此地橫青嶂，當年聳紫氛。',48,'全唐诗/poet.song.9000.json','["此地橫青嶂，當年聳紫氛。", "碧花巖下柰，玉葉嶺邊雲。", "寶勢三神秀，靈風百草薰。", "將軍精爽在，可解勒移文。"]'),
('aa66e183-b449-4b63-b13d-b37d37174336','浮石寺','胡宿','宋','宋诗','song-poetry','','[]','溪碧照浮航，仁祠紫界牆。',48,'全唐诗/poet.song.9000.json','["溪碧照浮航，仁祠紫界牆。", "窗扉銜遠色，樹石納餘凉。", "升講林花落，拋生水鳥翔。", "逢僧談止觀，數刻盡牛香。"]'),
('ec13a9fb-03ef-4670-8f74-cc66b9f602fe','送張著作任柘城','胡宿','宋','宋诗','song-poetry','','[]','出宰分寰邑，修書得秘丘。',48,'全唐诗/poet.song.9000.json','["出宰分寰邑，修書得秘丘。", "青雲莫厭晚，翠柏最宜秋。", "舊學緇林散，前歡醉墨留。", "弦歌聊自慰，不足論全牛。"]'),
('6295ac75-26bb-4ac2-966c-021131d1868e','別墅園池','胡宿','宋','宋诗','song-poetry','','[]','小池連曲圃，幽可滌煩襟。',48,'全唐诗/poet.song.9000.json','["小池連曲圃，幽可滌煩襟。", "露菊凝秋艷，風荷結晚陰。", "碧蘆巢鳥重，青藻宅魚深。", "自是輪蹄外，囂塵豈易侵。"]'),
('3feba80a-9942-4ee8-a93a-5b87cc6c9605','送曹生歸臨江別墅','胡宿','宋','宋诗','song-poetry','','[]','氣入商中勁，人思瀆上勞。',48,'全唐诗/poet.song.9000.json','["氣入商中勁，人思瀆上勞。", "滄江縈故國，凉月伴歸舠。", "麗賦憑烏有，清篇託畔牢。", "竹林溫緒業，天彀佇時髦。"]'),
('ef80f7a2-fa36-4be6-9dbb-c8d51e78433e','寄善慧大師禪齋','胡宿','宋','宋诗','song-poetry','','[]','金策巡方罷，齋軒俯斗城。',48,'全唐诗/poet.song.9000.json','["金策巡方罷，齋軒俯斗城。", "池閒魚聽法，臺靜鳥窺生。", "社影香蕖白，禪陰碧柰清。", "昆灰多妙辨，平日集朝纓。"]'),
('aa557de4-7bd5-4e44-96af-e6ac4f321386','小閣','胡宿','宋','宋诗','song-poetry','','[]','小閣閉春風，疏簾隔幾重。',48,'全唐诗/poet.song.9000.json','["小閣閉春風，疏簾隔幾重。", "柳綿收未住，酒病太無悰。", "带眼偏知瘦，棋圖最信慵。", "隆中一覺睡，日影過高舂。"]'),
('1d6bd2db-d3d2-4c1c-8ff0-f1a1efc848e1','悼往','胡宿','宋','宋诗','song-poetry','','[]','昨夜西樓月，團圓似去年。',48,'全唐诗/poet.song.9000.json','["昨夜西樓月，團圓似去年。", "鳳屏非復舊，虎枕未成眠。", "破恨憑湘酎，流哀寄蜀弦。", "葛華與參宿，此見恐無緣。"]'),
('9eeed3b6-5d06-43fe-9575-5d30afb725fa','江樓','胡宿','宋','宋诗','song-poetry','','[]','亭亭紫桂樓，渺渺白蘋洲。',48,'全唐诗/poet.song.9000.json','["亭亭紫桂樓，渺渺白蘋洲。", "易斷傷春目，難銷假日憂。", "雙鳬仙子貴，兩槳美人愁。", "欲寄青泥訊，雲峰隔舊遊。"]'),
('f9d9a257-3417-42cd-8ef4-eb9692efde67','初赴揚子任','胡宿','宋','宋诗','song-poetry','','[]','補吏承人乏，安貧得士常。',48,'全唐诗/poet.song.9000.json','["補吏承人乏，安貧得士常。", "半綸朝受命，數舍宿舂糧。", "楚地元三戶，騶奴亦一囊。", "空裁宣德頌，何路奏明光。"]'),
('1a9b8cbf-c1e7-482b-99af-a18f04e6adde','徐偃王廟','胡宿','宋','宋诗','song-poetry','','[]','天下慢朝周，君王瑶水流。',48,'全唐诗/poet.song.9000.json','["天下慢朝周，君王瑶水流。", "一朝規問鼎，千里御還騮。", "故國無歸日，叢祠幾換秋。", "詵詵耳孫慶，惟烈在仁柔。"]'),
('17ce43b3-8ebd-4f07-be47-f2107c5b5163','清溪泛舟','胡宿','宋','宋诗','song-poetry','','[]','家在清溪上，乘閒一棹歌。',48,'全唐诗/poet.song.9000.json','["家在清溪上，乘閒一棹歌。", "夕凉天有月，秋迥水無波。", "鷗鳥機心斷，鯪魚香味多。", "吾纓猶未濯，終是負漁蓑。"]'),
('86251084-c830-4005-8edc-cfbe49f0cbab','一年好景','胡宿','宋','宋诗','song-poetry','','[]','樽俎真無奈，風騷亦被魔。',48,'全唐诗/poet.song.9000.json','["樽俎真無奈，風騷亦被魔。", "酒龍春力健，詩將夜謀多。", "未羨封侯印，偏憐却日戈。", "寄言嵇叔夜，休惜玉嵯峨。"]'),
('7e029cad-a595-4ec0-8331-48c225ce2051','早雁','胡宿','宋','宋诗','song-poetry','','[]','關樹來時紫，江楓到日丹。',48,'全唐诗/poet.song.9000.json','["關樹來時紫，江楓到日丹。", "驚弦初月上，避弋太虛寬。", "野水涵秋色，霜雲結夜寒。", "終年南北路，未可笑離鸞。"]'),
('d94497bd-2d81-44c0-99bf-d653c5eea934','寄懷尊師','胡宿','宋','宋诗','song-poetry','','[]','多年疏法集，長夏憶齋房。',48,'全唐诗/poet.song.9000.json','["多年疏法集，長夏憶齋房。", "桐雨生苔淨，杉風坐石凉。", "真茶烹澗溜，滿飯取天香。", "何日揮冠冕，相期作道場。"]'),
('8ec2b321-67af-4050-8feb-bcffd17291a9','華陽道士朱尊師','胡宿','宋','宋诗','song-poetry','','[]','閬苑花邊醉，知君是謫仙。',48,'全唐诗/poet.song.9000.json','["閬苑花邊醉，知君是謫仙。", "姓名金簡上，官職玉臺前。", "碧海三奇藥，青梯尺五天。", "祇愁騰踏去，相望隔芝田。"]'),
('7a2be66a-9abc-49be-9bc4-dfd2cd8e66d0','紫薔薇','胡宿','宋','宋诗','song-poetry','','[]','天上星垣貴，人間花品高。',48,'全唐诗/poet.song.9000.json','["天上星垣貴，人間花品高。", "偷模煩象管，學剪費金刀。", "西母停雲輦，東卿駐節旄。", "曉軒無限思，香架近蒲桃。"]'),
('1951acbc-1018-4c2e-9fdd-cd1ce0ef5e29','晨入都省聞子奇內翰宿太常因寄口號','胡宿','宋','宋诗','song-poetry','','[]','相思禁林客，知奉太常齋。',48,'全唐诗/poet.song.9000.json','["相思禁林客，知奉太常齋。", "月落桐依井，風休絮滿階。", "歡娛疏勝集，申寫寄長懷。", "遥望牆東隠，朋簪杳未諧。"]'),
('65a0dfb5-4f16-4e3c-be83-769ebccb2a20','又陪公素舍人晨入西閣見紫薇初開','胡宿','宋','宋诗','song-poetry','','[]','疏雨休前檻，新英艷小叢。',48,'全唐诗/poet.song.9000.json','["疏雨休前檻，新英艷小叢。", "且欣當夏日，不用憶春風。", "便可携歡伯，相從作醉翁。", "回頭問階藥，何處覓蔫紅。"]'),
('41bb8abc-3046-4482-a707-e2e53fd44890','題擷芳亭','胡宿','宋','宋诗','song-poetry','','[]','有客隠東岡，珍亭號擷芳。',48,'全唐诗/poet.song.9000.json','["有客隠東岡，珍亭號擷芳。", "仙壺分氣象，木帝借風光。", "淥水穿林遠，朱橋跨岸長。", "寶鄰曾折桂，今是狀元坊。"]'),
('2da0d454-8e91-4652-b8e5-4b2f4a68b0b0','初秋','胡宿','宋','宋诗','song-poetry','','[]','九夏困煩冤，逢秋似得仙。',48,'全唐诗/poet.song.9000.json','["九夏困煩冤，逢秋似得仙。", "短牀便月下，長簟怯風前。", "露氣清羣木，雲棱澹一天。", "西江無限水，長嘯憶樓船。"]'),
('7ebb675a-904c-4915-9491-8a7296caf5a7','大慶殿元會','胡宿','宋','宋诗','song-poetry','','[]','殿裏爐香散彩雲，殿前旌仗從朝暾。',64,'全唐诗/poet.song.9000.json','["殿裏爐香散彩雲，殿前旌仗從朝暾。", "后夔六樂調時律，太皡千春入御樽。", "神化還隨蒼震始，天顔却映少陽溫。", "新年喜氣知多少，鬰鬰葱葱覆九門。"]'),
('86cebc10-f9cf-4788-bfa1-11ac28d2ea23','燕洞宮','胡宿','宋','宋诗','song-poetry','','[]','洞裏青娥赤玉簫，香童迎過百花橋。',64,'全唐诗/poet.song.9000.json','["洞裏青娥赤玉簫，香童迎過百花橋。", "身輕不待泠風馭，天隔難逢翠羽翹。", "仙醴四升誰酩酊，使烏三足自飄颻。", "座中若話金庭事，記取真人是子喬。"]'),
('54edc4fd-d272-45eb-b7a9-08632676956b','張侍讀箋注太玄經義','胡宿','宋','宋诗','song-poetry','','[]','陳書覆瓿久無憀，天幸名儒釋舊爻。',64,'全唐诗/poet.song.9000.json','["陳書覆瓿久無憀，天幸名儒釋舊爻。", "準易一時遭客難，賞心千載獲神交。", "高情要在崇孤學，餘力猶能解衆嘲。", "誰道鳳凰難得髓，續絃今日見靈膠。"]'),
('c50b53a0-4119-49cb-84da-608d69b49efe','賞花釣魚應制','胡宿','宋','宋诗','song-poetry','','[]','球檻靈芳濯露開，瑶津朱鮪復新來。',64,'全唐诗/poet.song.9000.json','["球檻靈芳濯露開，瑶津朱鮪復新來。", "三竿御水承垂釣，萬蕊晨葩奉賜杯。", "春暖僊蓂初靃靡，日斜芝蓋尚徘徊。", "柏梁聖作星躔麗，累氣蕪音愧仰陪。"]'),
('36b11fe2-51a8-4222-bee3-6d58d1adda72','詠蟬','胡宿','宋','宋诗','song-poetry','','[]','柳條高處不須吟，正是螳螂負異心。',64,'全唐诗/poet.song.9000.json','["柳條高處不須吟，正是螳螂負異心。", "已斷清腸悲玉露，更流哀響入瑶琴。", "長洲苑下風聲急，宣曲宮中暮色深。", "莫道齊姬無伴侶，海邊精衛亦冤禽。"]'),
('982708f7-ab9a-4451-a635-ff81398413cf','登雄州視遠亭','胡宿','宋','宋诗','song-poetry','','[]','誰將粉水掃天衢，萬里全開晦景圖。',64,'全唐诗/poet.song.9000.json','["誰將粉水掃天衢，萬里全開晦景圖。", "百尺凍雲飛未起，一箏寒雁遠相呼。", "由來封略非三代，大抵漁樵似五湖。", "欲望繁臺何處是，繁臺不見見平蕪。"]'),
('80ad0871-4b11-4cfc-a934-b404f6b71f98','送錢子文著作宰福陽','胡宿','宋','宋诗','song-poetry','','[]','三政平反有惠心，民歌遥望邑中黔。',64,'全唐诗/poet.song.9000.json','["三政平反有惠心，民歌遥望邑中黔。", "桃翻浪影吳艎急，芸掩書香漢閣深。", "行訪名山須著屐，坐清囂俗且橫琴。", "西州有客偏傷別，無密瑶華寄好音。"]'),
('3b00c35c-2cdb-47c5-b8da-184c623d28e7','題承詔亭','胡宿','宋','宋诗','song-poetry','','[]','開徑臨江有舊居，野亭于此狎禽魚。',64,'全唐诗/poet.song.9000.json','["開徑臨江有舊居，野亭于此狎禽魚。", "八才素擅高陽里，五返曾迂使者車。", "圯上早傳黄石略，隆中難戀武侯廬。", "主人今醉葡萄酒，籬下秋風菊自疏。"]'),
('34bfb665-3784-433d-aa95-616f85cfc120','送清漳護戎王中立','胡宿','宋','宋诗','song-poetry','','[]','賦別匆匆涕泫然，七閩封堠接蠻煙。',64,'全唐诗/poet.song.9000.json','["賦別匆匆涕泫然，七閩封堠接蠻煙。", "山長水遠知何處，花落鶑啼又幾年。", "顧我青衫隨吏牒，惜兄華髮事戎旃。", "風波世路相逢少，腸斷東歸下瀨船。"]'),
('78253654-66ec-4dd9-95fd-e5f695e63932','送呂昭鄰同年宰巫陽','胡宿','宋','宋诗','song-poetry','','[]','清蕊君宜妙一臺，當年仙桂並枝開。',64,'全唐诗/poet.song.9000.json','["清蕊君宜妙一臺，當年仙桂並枝開。", "樓逢春雪嘗爲曲，廟近朝雲轉費才。", "遠字莫教雙鯉斷，歸期偏望二鳬來。", "巴猿蜀魄多離恨，猶喜圭田助酒材。"]'),
('6727df51-f289-4960-8776-0519355c3269','送李寺丞宰攸溪','胡宿','宋','宋诗','song-poetry','','[]','短李祠堂世閥餘，少年從學馬融居。',64,'全唐诗/poet.song.9000.json','["短李祠堂世閥餘，少年從學馬融居。", "樓中質問無疑義，帳後傳藏有默書。", "茂苑却尋花氣歇，家山重上桂陰疏。", "弦歌莫嘆浮湘遠，纔是青雲舉足初。"]'),
('da73d08d-b2fa-471d-9427-ceef8cf235b6','寄題黄氏閒宴閣','胡宿','宋','宋诗','song-poetry','','[]','翬飛迢遞拂秋槎，宴坐塵清道有芽。',64,'全唐诗/poet.song.9000.json','["翬飛迢遞拂秋槎，宴坐塵清道有芽。", "五葉對僧談妙果，一槍留客試真茶。", "簷前暮景沈歸鳥，窗外晨暉泛早霞。", "衍篋文多休寄傲，月間芳桂正窅窊。"]'),
('d883777b-55aa-4d12-9a16-876e3a7e9ab4','和邃卿館中晚入','胡宿','宋','宋诗','song-poetry','','[]','銅狄嚴扉大帝家，雨回天氣湛春華。',64,'全唐诗/poet.song.9000.json','["銅狄嚴扉大帝家，雨回天氣湛春華。", "牆頭落景半規日，樓外餘暉幾疊霞。", "風近天淵聞鬭鴨，煙開宮樹見棲鴉。", "端門漏密長廓靜，時見香英墜砌花。"]'),
('b15ff250-ca9a-4028-82f2-20aedb9f1b21','朝罷','胡宿','宋','宋诗','song-poetry','','[]','朝罷通中一覺眠，右銀臺路入西垣。',64,'全唐诗/poet.song.9000.json','["朝罷通中一覺眠，右銀臺路入西垣。", "日長易覺芝泥熟，風軟頻驚藥樹翻。", "朱檻带陰難可倚，紫薇當晝不勝繁。", "何須更寄陶窗傲，自有餘凉在此軒。"]'),
('d99ab323-12d8-4fd3-b78d-b6d240657c1a','送梅監丞宰山陰','胡宿','宋','宋诗','song-poetry','','[]','春半朱航拂水輕，季珪佳邑得時英。',64,'全唐诗/poet.song.9000.json','["春半朱航拂水輕，季珪佳邑得時英。", "民淳定見蹊田默，歲稔仍占射的明。", "太史舊遊書穴邃，右軍殘跡墨池平。", "何妨公外尋僧社，琴鶴相隨雅有情。"]'),
('bd9679f0-ff04-4fbb-93a7-6db09e57f182','送集賢李學士赴荆臺','胡宿','宋','宋诗','song-poetry','','[]','蓬島迴風此再來，當年俱重輯寧才。',64,'全唐诗/poet.song.9000.json','["蓬島迴風此再來，當年俱重輯寧才。", "芝隨禁掖新泥熟，桃應仙源舊路開。", "金契旋聞臨外閫，雲屏仍是接中台。", "專城四十前賢事，期歲行歸妙一臺。"]'),
('6136b3ee-ab41-43a1-97f5-5a1263c1b8f0','子莊見求近詩以一闋爲介','胡宿','宋','宋诗','song-poetry','','[]','半綸祗役謝英遊，牒訴裝懷思若抽。',64,'全唐诗/poet.song.9000.json','["半綸祗役謝英遊，牒訴裝懷思若抽。", "銅鉢任敲何所得，鐵盂雖缺豈銷憂。", "楚囚操樂寧忘本，蜀客摛辭祇傍愁。", "强抉巴音還首鼠，知君詩戶敵千侯。"]'),
('09336fe6-d492-424a-ae66-c77666b9b373','送張從事','胡宿','宋','宋诗','song-poetry','','[]','月毫揮檄愈頭風，屈佐初賓位未充。',64,'全唐诗/poet.song.9000.json','["月毫揮檄愈頭風，屈佐初賓位未充。", "金玉擅珍須席上，蛟龍爲物起池中。", "叢雲絢彩人歌舜，綿竹摛辭客薦雄。", "一乘追鋒看賜對，虎賁千戟照瓊宮。"]'),
('17efecf9-21b7-4e64-9da0-e60b88e6773c','山居','胡宿','宋','宋诗','song-poetry','','[]','老矣求田魚稻鄉，兒孫常要在余旁。',64,'全唐诗/poet.song.9000.json','["老矣求田魚稻鄉，兒孫常要在余旁。", "提籃買菜須靈照，舉案齊眉只孟光。", "醫國有方三折臂，扣關無路九回腸。", "紫芝白髮秋風裏，悵望商山綺與黄。"]'),
('79d9d54b-481f-4d70-abc0-4bb75195d2a1','寄子高秦州從事','胡宿','宋','宋诗','song-poetry','','[]','雪裏詩筒至自秦，仲宣佳句樂從軍。',64,'全唐诗/poet.song.9000.json','["雪裏詩筒至自秦，仲宣佳句樂從軍。", "谷鶑漸喜遷高處，塞雁猶嗟失故羣。", "北闕舊遊孤似月，西州迴望遠如雲。", "一枝春色無由寄，手弄梅花却自薰。"]'),
('f289cd15-a61a-4195-a9e4-b7338685a70c','和曼卿館中夜直','胡宿','宋','宋诗','song-poetry','','[]','右銀臺路逼仙盤，有客通中此宿官。',64,'全唐诗/poet.song.9000.json','["右銀臺路逼仙盤，有客通中此宿官。", "鈞奏暗驚天上近，霞杯難制月邊寒。", "風來禁樹龍傳點，露下高梧鳳戢翰。", "更聽建章魚鑰動，水蒼朝珮響珊珊。"]'),
('5037b99d-846f-47d0-aebf-ca2687b26cbd','遠思','胡宿','宋','宋诗','song-poetry','','[]','一片平蕪百尺樓，闌干橫絕點清秋。',64,'全唐诗/poet.song.9000.json','["一片平蕪百尺樓，闌干橫絕點清秋。", "三年字與燕鴻斷，千里心隨桂水流。", "空對霜葭驚遠別，忍題雲葉寄牢愁。", "驪駒不見西曛迫，目眩天涯片席收。"]'),
('71761c4c-952d-48a0-80f8-85eacb77a65d','和邃卿寒直','胡宿','宋','宋诗','song-poetry','','[]','子門肅唱徹周廬，甲夜輕寒臘破初。',64,'全唐诗/poet.song.9000.json','["子門肅唱徹周廬，甲夜輕寒臘破初。", "樹底倦飛還類鵲，齋中酣夢欲成魚。", "三鍾賦粟才無取，五餌干時策已疏。", "天祿舊來名寂寞，更堪窗雪照殘書。"]'),
('185f278e-3552-4e89-b978-9d94ae2f19fd','九日山陽驛作','胡宿','宋','宋诗','song-poetry','','[]','飄泊年來憩下亭，雀羅秋靜掩苔扃。',64,'全唐诗/poet.song.9000.json','["飄泊年來憩下亭，雀羅秋靜掩苔扃。", "拂窗紅葉欺閒卧，倚檻黄花笑獨醒。", "盛憶林泉羞白石，欲持香火訪丹經。", "華陽小隠平生願，可分區區事挈瓶。"]'),
('f760ada4-b162-475a-b106-84d617d70100','趙宗道歸輦下','胡宿','宋','宋诗','song-poetry','','[]','沿牒相逢楚水湄，竹林文酒此攀嵇。',64,'全唐诗/poet.song.9000.json','["沿牒相逢楚水湄，竹林文酒此攀嵇。", "半氈未暖還傷別，一臂初交未解携。", "江浦嘔啞風送櫓，河橋勃窣柳垂堤。", "明年四月秦關到，洗眼揚州看馬蹄。"]'),
('841d0eac-6518-4978-92d3-f0d2f29e9fe0','送天章王待制再領陝州','胡宿','宋','宋诗','song-poetry','','[]','愛樹重攀隔十春，召南遺俗至今淳。',64,'全唐诗/poet.song.9000.json','["愛樹重攀隔十春，召南遺俗至今淳。", "車邊野鹿依明府，池上沙鷗識主人。", "太華遠峰捫日馭，洪河高派落天津。", "壺漿竹馬參歌舞，頓覺城中喜氣新。"]'),
('101dc7f9-b995-4846-9d61-49eaefdc40a5','詠鶴','胡宿','宋','宋诗','song-poetry','','[]','獨立青田刷羽儀，朱研丹頂雪裁衣。',64,'全唐诗/poet.song.9000.json','["獨立青田刷羽儀，朱研丹頂雪裁衣。", "賦來自合凌清漢，仙去何曾識令威。", "松蓋露寒應有恨，蓬山雲斷未成歸。", "舊巢寄在三珠樹，待與還丹作使飛。"]'),
('e632200e-182c-4605-845e-0e7ba1330f20','舊將','胡宿','宋','宋诗','song-poetry','','[]','曾上燕然勒漢兵，白頭麟閣見儀形。',64,'全唐诗/poet.song.9000.json','["曾上燕然勒漢兵，白頭麟閣見儀形。", "三朝自是山西將，百戰曾焚老上廷。", "已奉列侯歸北第，更籌深策破先零。", "彎弓擊劍平生事，不許兒孫授一經。"]'),
('b13eb3f0-d681-4de6-b26b-8d90f98d0efc','七夕','胡宿','宋','宋诗','song-poetry','','[]','孔雀南來燕子西，銀河消息已驚遲。',64,'全唐诗/poet.song.9000.json','["孔雀南來燕子西，銀河消息已驚遲。", "石城仙使飛三足，玉殿華燈焰九枝。", "暫掩星機同一笑，却披雲幄重相離。", "杞天長在年梭疾，若比人間是遠期。"]'),
('074a9163-76cb-4f72-8336-8d40ac052e4a','宛陵秋晚','胡宿','宋','宋诗','song-poetry','','[]','誰道江南好物華，江南今日抵天涯。',64,'全唐诗/poet.song.9000.json','["誰道江南好物華，江南今日抵天涯。", "秋風只解吹桐葉，暮雨還來打菊花。", "寒水答砧偏響亮，迥樓飄角更嘔啞。", "舉頭試作長安望，惆悵青山繞郭斜。"]'),
('396154f6-eb21-4eae-8a56-f83f323d3e16','海上','胡宿','宋','宋诗','song-poetry','','[]','天幕紛紜海水浮，日車東上惡埃收。',64,'全唐诗/poet.song.9000.json','["天幕紛紜海水浮，日車東上惡埃收。", "金鈎欲下靈鼇怖，鐵網將沈寶樹愁。", "自昔神仙嘗有藥，從來銀闕不通舟。", "燕酣餐盡蟠桃熟，會約琴高控鯉遊。"]'),
('ee598926-e01f-4a2b-b0cc-e176125f024d','夏日舟行','胡宿','宋','宋诗','song-poetry','','[]','箭激雲檣五兩輕，波光飛入射桃笙。',64,'全唐诗/poet.song.9000.json','["箭激雲檣五兩輕，波光飛入射桃笙。", "山眉遠映羣鷗過，霞綺新和落照明。", "甘醴更無消暑意，文竿徒有羨魚情。", "飄颻若得乘羊角，直待銀潢上玉清。"]'),
('8b160ccc-98df-44ea-bae2-7d8372ed1380','送呂解元江陰禮席','胡宿','宋','宋诗','song-poetry','','[]','玉人仍是紫芝眉，五世嘉占得鳳飛。',64,'全唐诗/poet.song.9000.json','["玉人仍是紫芝眉，五世嘉占得鳳飛。", "果滿車中潘令去，馬盤樓下庾郎歸。", "東牀寄傲便便腹，北路騰裝粲粲衣。", "九燭夜堂開喜宴，畫鸞交扇接香幃。"]'),
('7e7a8008-c2a0-49a6-ade3-b40d7925e7c5','送祝熙載赴金華主簿','胡宿','宋','宋诗','song-poetry','','[]','數路收才漢得人，物塗聊試半通綸。',64,'全唐诗/poet.song.9000.json','["數路收才漢得人，物塗聊試半通綸。", "宸廷唱第瑶光近，仙簡刊名玉字新。", "芳桂行吟關外月，香葩回夢苑中春。", "平時官下文移少，日涉閒園戲綵頻。"]'),
('427e8c2c-cc89-42f7-96f5-2304f7174aed','泛舟','胡宿','宋','宋诗','song-poetry','','[]','瑟瑟凉波冷接空，恍疑雲物畫屏中。',64,'全唐诗/poet.song.9000.json','["瑟瑟凉波冷接空，恍疑雲物畫屏中。", "一篙海客乘槎水，兩槳仙人取箭風。", "秋色暗欺荷蓋紫，夕陽偷射桂旗紅。", "長來此地無窮樂，珍重笭箵與釣筒。"]'),
('dc7ca4cb-638b-45ac-9207-10a2985c718a','送王龍圖碩赴荆南','胡宿','宋','宋诗','song-poetry','','[]','南部行臺駐萬兵，繡衣歸路有光榮。',64,'全唐诗/poet.song.9000.json','["南部行臺駐萬兵，繡衣歸路有光榮。", "鳴鐃虎豹林中避，吹角蛟龍水底驚。", "湘樹遠從湖外出，峽雲時向馬前生。", "主人落筆多風調，應唱新辭遍郢城。"]'),
('7d5d3f1e-6192-4d5f-92d0-9de000288f83','送陳鐸歸吳興','胡宿','宋','宋诗','song-poetry','','[]','六篇高論吐虹霓，報罷扁舟擊汰歸。',64,'全唐诗/poet.song.9000.json','["六篇高論吐虹霓，報罷扁舟擊汰歸。", "地上麒麟須遠到，天邊鷹隼且卑飛。", "秋來苕下醪醅熟，寒去江頭膾縷肥。", "莫嘆隋和猶未售，玉蟾濡翰待君揮。"]'),
('c2a6d71d-f030-4331-ba73-c4664a6383f2','寄題雄州宴射亭','胡宿','宋','宋诗','song-poetry','','[]','北壓三關氣象雄，主人仍是紫髯翁。',64,'全唐诗/poet.song.9000.json','["北壓三關氣象雄，主人仍是紫髯翁。", "樽前樂按摩訶曲，塞外威生廣莫風。", "龍向城頭吟畫角，雁從天末避雕弓。", "休論萬里封侯事，靜勝今爲第一功。"]'),
('c06eb3c6-e04f-4f3a-a6fc-4bdc7d61bdd4','送吳江知縣陳著作','胡宿','宋','宋诗','song-poetry','','[]','南望湖山畫一屏，松江江水向人清。',64,'全唐诗/poet.song.9000.json','["南望湖山畫一屏，松江江水向人清。", "何如嵔𡾊聊爲活，況是瀟湘謾得名。", "雙槳有時青翰遠，兩衙無事素琴橫。", "遥知惠政通和氣，乳雉馴鷗自不驚。"]'),
('75bce78d-71dd-42ab-8f85-559e787e2ba6','贈華陽道士朱尊師','胡宿','宋','宋诗','song-poetry','','[]','却餌英芝養道芽，赤霄曾輾絳雲車。',64,'全唐诗/poet.song.9000.json','["却餌英芝養道芽，赤霄曾輾絳雲車。", "眼看碧海成夷路，心記蟠桃結實花。", "東府靈方修白石，上清香飯給胡麻。", "兩雙條脫皆金玉，可是南山萼綠華。"]'),
('2ddcae13-d515-4d3b-8426-58a2a6f40fcb','仲夏有感','胡宿','宋','宋诗','song-poetry','','[]','誤逐時英落彀中，拙艱爲吏悄無悰。',64,'全唐诗/poet.song.9000.json','["誤逐時英落彀中，拙艱爲吏悄無悰。", "鶢鶋已享鳴鐘賜，澼絖焉知裂地封。", "西北晚雲長望闕，東南春畝久拋農。", "匆匆禹鑿當年事，猶待神雷起蟄龍。"]'),
('69029eaf-9c15-4c26-9091-385110ed2f61','上元禁樂','胡宿','宋','宋诗','song-poetry','','[]','此夜重城鳳腦寒，放遊車馬接通闤。',64,'全唐诗/poet.song.9000.json','["此夜重城鳳腦寒，放遊車馬接通闤。", "漢祠歌罷天壇冷，鈞奏聲沈帝所閒。", "紅蠟枉殘春色裏，青樓空占月明間。", "仙壺定有尋芳處，公子雕鞍兩兩還。"]'),
('04a2061f-4f8e-4964-b18d-11f2078376a7','暮冬離京師','胡宿','宋','宋诗','song-poetry','','[]','雪中愁買出關符，又著青衫事府趨。',64,'全唐诗/poet.song.9000.json','["雪中愁買出關符，又著青衫事府趨。", "燕市有金還貴馬，鄧林無樹可棲烏。", "鴟夷痛飲傾家釀，如意狂歌缺唾壺。", "朝野多歡天子聖，目瞻東闕步踟躕。"]'),
('00820265-5041-4698-af9d-3ebac1ddca18','感舊','胡宿','宋','宋诗','song-poetry','','[]','萬里青雲未致身，馬蹄空踏幾年塵。',64,'全唐诗/poet.song.9000.json','["萬里青雲未致身，馬蹄空踏幾年塵。", "曾迷玉洞花光老，却過金城柳色新。", "粉壁已沈題鳳字，酒壚猶記姓黄人。", "塢中橫吹偏多感，一涕闌干白角巾。"]'),
('ecdc1aaf-dbc2-4455-81a2-502e7ea14026','落葉','胡宿','宋','宋诗','song-poetry','','[]','霜華昨夜拂秋林，翩落紛紛不自禁。',64,'全唐诗/poet.song.9000.json','["霜華昨夜拂秋林，翩落紛紛不自禁。", "清吹無時來檻底，紫苔相伴住牆陰。", "空餘倦鵲求枝宿，更剩殘蜩抱樸吟。", "萬物歸根真趣在，却緣江月識禪心。"]'),
('fc367b94-49bf-4df8-8c86-bd282ac4009c','嘲蝶','胡宿','宋','宋诗','song-poetry','','[]','三春流寓寄花房，雌去雄飛過短牆。',64,'全唐诗/poet.song.9000.json','["三春流寓寄花房，雌去雄飛過短牆。", "雙翅薄勻何晏粉，一身偷带賈充香。", "風多苑後飛無數，日暖池邊舞更狂。", "却爲有情人愛惜，六宮皆作繡衣裳。"]'),
('e27757f0-7add-43ae-9dae-ef42646913d2','飛將','胡宿','宋','宋诗','song-poetry','','[]','曾從嫖姚立戰功，胡雛猶畏紫髯翁。',64,'全唐诗/poet.song.9000.json','["曾從嫖姚立戰功，胡雛猶畏紫髯翁。", "雕戈夜統千廬會，緹騎秋畋五柞宮。", "後殿拜恩金印重，北堂開宴玉壺空。", "從來敵國威名大，麾下多稱黑矟公。"]'),
('0de4306f-f911-4782-989d-b429ed1da126','公子','胡宿','宋','宋诗','song-poetry','','[]','北第當衢戟有衣，巾帷鮮媚僕如犀。',64,'全唐诗/poet.song.9000.json','["北第當衢戟有衣，巾帷鮮媚僕如犀。", "萬錢供箸鳴鐘沸，三組垂腰佩玉低。", "座上賦鸚窮處士，樓前盤馬小征西。", "去天尺五城南路，此去青雲別有梯。"]'),
('113ab9b3-2020-4726-9d2d-eecdfca31ba5','古別','胡宿','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','長道何年祖軷休，風帆不斷岳陽樓。',64,'全唐诗/poet.song.9000.json','["長道何年祖軷休，風帆不斷岳陽樓。", "佳人挾瑟漳河曉，壯士悲歌易水秋。", "九帳青油徒自負，百壺芳醑豈消憂。", "至今長樂坡前水，不啻秦人怨隴頭。"]'),
('635b608d-0129-4427-8339-e055f5e5eb51','函谷關','胡宿','宋','宋诗','song-poetry','','[]','天開函谷壯關中，萬古驚塵向此空。',64,'全唐诗/poet.song.9000.json','["天開函谷壯關中，萬古驚塵向此空。", "望氣竟能知老子，棄繻何不識終童。", "謾持白馬先生論，未抵鳴雞下客功。", "符命已歸如掌地，一丸曾誤隗王東。"]'),
('4059cc8d-93bf-4554-be2d-1374f635abe2','塞上','胡宿','宋','宋诗','song-poetry','','[]','漢家神箭定天山，煙火相望萬里間。',64,'全唐诗/poet.song.9000.json','["漢家神箭定天山，煙火相望萬里間。", "契利請盟金匕酒，將軍歸卧玉門關。", "雲沈老上妖氛斷，雪照回中探騎還。", "五餌已行王道勝，絕無刁斗至闐顔。"]'),
('525a2df8-a92d-45d9-92fe-002664a735f6','湘夫人祠','胡宿','宋','宋诗','song-poetry','','[]','翠華獨去蒼梧野，紅袖同沈楚水濆。',64,'全唐诗/poet.song.9000.json','["翠華獨去蒼梧野，紅袖同沈楚水濆。", "休把蘭湯招怨魄，空留竹淚憶明君。", "風前有恨啼湘瑟，天外無言擬峽雲。", "不比石城雙姊妹，帝家釐降有遺文。"]'),
('b88b912c-d2f1-49e4-a220-4059a43f37fd','隠客舊居','胡宿','宋','宋诗','song-poetry','','[]','鵠版飛書到此山，海簪重拾更彈冠。',64,'全唐诗/poet.song.9000.json','["鵠版飛書到此山，海簪重拾更彈冠。", "畹中紉佩荒蘭葉，石上移文蠹蘚瘢。", "蕙帳煙空胎化老，柏庭風起麝香寒。", "至今門外潺湲水，疑是幽人賦考槃。"]'),
('d9f1431b-c65b-47ab-a109-5b4c438d813b','寄題公儀西溪','胡宿','宋','宋诗','song-poetry','','[]','山公休愛習家池，自有清光灧一溪。',64,'全唐诗/poet.song.9000.json','["山公休愛習家池，自有清光灧一溪。", "川上好風跳鰋鯉，波中晴日浴鳬鷖。", "孤舟小嶼閒如畫，釣綫輕緡靜可携。", "更助吟毫無限思，落霞猶共夕陽低。"]'),
('f9e29d48-fda2-47bc-a592-6d53c05cf589','送莊賢良權之歸舊隠','胡宿','宋','宋诗','song-poetry','','[]','過我東還鑑水湄，儻逢親友話襟期。',64,'全唐诗/poet.song.9000.json','["過我東還鑑水湄，儻逢親友話襟期。", "書鉗紙尾丞真負，易在牀頭叔自癡。", "破廨數間將整整，踐更三載且遲遲。", "督郵少屈吾衰矣，三徑歸來未有資。"]'),
('bd97c964-0319-4074-abe3-b71674ea7c32','送向館使赴陝郊','胡宿','宋','宋诗','song-poetry','','[]','陝服由來二伯居，使君新詔擁犀渠。',64,'全唐诗/poet.song.9000.json','["陝服由來二伯居，使君新詔擁犀渠。", "門連象魏施行馬，地控崤函佩左魚。", "世德高華河裏舊，土風淳厚召南餘。", "政成期月須嚴召，行見追鋒走傳軍。"]'),
('e132f05e-e289-4acc-9d0a-1de73a96217d','送江寧監軍李舍人歸闕','胡宿','宋','宋诗','song-poetry','','[]','假節彌年去玉墀，星郵傳詔紫芝泥。',64,'全唐诗/poet.song.9000.json','["假節彌年去玉墀，星郵傳詔紫芝泥。", "帳中密印交龍虎，麾下全軍解水犀。", "仙闕歸心春槳快，石城離思晚雲低。", "宣平貴里天姻盛，競爽行看對析珪。"]'),
('d185a338-7245-49f8-8aa8-815b0ba19f1d','城東別墅寄懷天錫','胡宿','宋','宋诗','song-poetry','','[]','幾日歸心托暮雲，半氈窗下久生塵。',64,'全唐诗/poet.song.9000.json','["幾日歸心托暮雲，半氈窗下久生塵。", "水天雨氣霏霏斷，竹閣山花點點新。", "小苑鶑聲偏破夢，大堤花艷欲迷人。", "豈無躞蹀青絲騎，不敢偷看城裏春。"]'),
('2d27011a-0210-4ee8-81b8-bedd96d6abb5','送魏屯田出守山陽','胡宿','宋','宋诗','song-poetry','','[]','左臺分契領東麾，入奏清廂幾刻移。',64,'全唐诗/poet.song.9000.json','["左臺分契領東麾，入奏清廂幾刻移。", "三采綬章秦服志，兩轓朱色漢官儀。", "雌堂夕宴沈賓轄，綠野春耕駐使旗。", "盤錯寄才知不久，英輿六尺待飛綏。"]'),
('4b440413-079d-4652-8757-a8cf1dd31f99','和承旨尚書觀春物欣盛之什  其一','胡宿','宋','宋诗','song-poetry','','[]','紫陌年光天上回，東風吹雪放新梅。',64,'全唐诗/poet.song.9000.json','["紫陌年光天上回，東風吹雪放新梅。", "燕鴻却背南雲去，楚鳥還迎社日來。", "半綠萍醅浮臘脚，殘紅桃艷弄香腮。", "山公知有登高興，樽下容誰獻壽杯。"]'),
('3468953b-d483-4517-8c57-2a329803e715','和承旨尚書觀春物欣盛之什  其二','胡宿','宋','宋诗','song-poetry','','[]','書觀春歸雪意殘，三竿初日照天關。',64,'全唐诗/poet.song.9000.json','["書觀春歸雪意殘，三竿初日照天關。", "魚聲稍喣芳塘面，鵲語頻跳碧樹間。", "渠落禁中聽御水，閣凭空際數前山。", "柳黄梅白東郊近，未得携壺一日閒。"]'),
('d77b5681-1953-4349-ac1d-0cf536ad327d','江城春日','胡宿','宋','宋诗','song-poetry','','[]','暮春江色映芳菲，雨後清和滿客衣。',64,'全唐诗/poet.song.9000.json','["暮春江色映芳菲，雨後清和滿客衣。", "遊騎自穿官柳去，落霞常伴彩橈歸。", "錦鱗劈浪深深躍，翠羽迎風兩兩飛。", "因下短亭猶惜別，萬枝香雪在薔薇。"]'),
('5fc51084-3715-429b-9c36-c57929e6fe98','謝惠詩','胡宿','宋','宋诗','song-poetry','','[]','君詩來貺我難當，語带誠齋句妙香。',64,'全唐诗/poet.song.9000.json','["君詩來貺我難當，語带誠齋句妙香。", "鮫室垂垂新下泣，蚌珠顆顆爛生光。", "魂飛錦里花爭巧，夢到池塘草又芳。", "早晚交遊逢大手，急將名姓爲傳揚。"]'),
('5b5050e8-f83c-44e3-a970-af6382b4afa4','送張著作任蘄水','胡宿','宋','宋诗','song-poetry','','[]','家世南州擅席珍，斗城傾蓋底相親。',64,'全唐诗/poet.song.9000.json','["家世南州擅席珍，斗城傾蓋底相親。", "誅茅三徑原同閈，枕水雙扉重作鄰。", "翰墨初通文苑職，弦歌聊嗣武城人。", "楚詞舊學精章句，未得金門薦買臣。"]'),
('465b14c1-1d0c-4bc5-ba24-2e3c0e2e0fb4','和春卿學士登定力寺北閣兼寄絳倅富彥國監丞','胡宿','宋','宋诗','song-poetry','','[]','玉山偷暇訪禪扉，洛社諸英昔所依。',64,'全唐诗/poet.song.9000.json','["玉山偷暇訪禪扉，洛社諸英昔所依。", "三鳳同時翔仞去，二龍相繼得標歸。", "硯池終歲貪殘墨，講樹經秋長舊圍。", "更待碧紗籠美句，始驚韋布有光輝。"]'),
('2e42aa86-ea61-4ddf-a80a-d1799a821aa8','送李留後赴天平','胡宿','宋','宋诗','song-poetry','','[]','留印高提駕伏熊，鄆城襟要此臨戎。',64,'全唐诗/poet.song.9000.json','["留印高提駕伏熊，鄆城襟要此臨戎。", "四封土俗弦歌盛，九疊霜天鼓角雄。", "風月靜歸談笑內，山川遥入撫綏中。", "居多暇日溪堂勝，不廢投壺與釣筒。"]'),
('4a48a250-0640-46a8-9e7a-52b319969a04','寄浙漕晉卿李工部','胡宿','宋','宋诗','song-poetry','','[]','名臣分刺十三州，君在東南第一流。',64,'全唐诗/poet.song.9000.json','["名臣分刺十三州，君在東南第一流。", "郡國成風皆自化，朝廷安枕更無憂。", "江湖莫作多時計，山水何妨暇日遊。", "誰與二天相對飲，看看八月弄濤頭。"]'),
('19605c31-dc3a-46ed-a427-be295fdc9684','送兵部陸學士赴漕閩中','胡宿','宋','宋诗','song-poetry','','[]','宣風一面得甌閩，丹舸乘流破月痕。',64,'全唐诗/poet.song.9000.json','["宣風一面得甌閩，丹舸乘流破月痕。", "玉色暫辭當牖坐，衣香初隔止車門。", "帝臺回望相竿遠，仙嶠重過射的存。", "曾頌天禧金石刻，定應寬利賦朝恩。"]'),
('a42b92b9-f0b5-4c85-882f-7b5b213640ec','送杜偉長學士赴漕河北','胡宿','宋','宋诗','song-poetry','','[]','甘陵孤壘起纖埃，趨詔東南武庫來。',64,'全唐诗/poet.song.9000.json','["甘陵孤壘起纖埃，趨詔東南武庫來。", "天子此時知國器，生民從古寄賢才。", "神鋒立斷無留刃，籌筆先機有疾雷。", "行見司徒封露布，鄴城歌舞夾行臺。"]'),
('495130e8-d513-43c2-ac9a-a53fe2f0c89c','送陸兵部赴漕湖南','胡宿','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','甘泉司計署名高，出拜行臺帝綍褒。',64,'全唐诗/poet.song.9000.json','["甘泉司計署名高，出拜行臺帝綍褒。", "使節遠籠三壤賦，官儀清坐七兵曹。", "時平漢斧宣威力，歲稔湘帆繕貢勞。", "秋晚洞庭山水秀，定知懷古費宮毫。"]'),
('a480a724-9f4c-4f4d-a1c6-37e150bf4bdc','送御史蔣公赴漕江東','胡宿','宋','宋诗','song-poetry','','[]','簪筆天階柱下官，孤風凜凜振臺端。',64,'全唐诗/poet.song.9000.json','["簪筆天階柱下官，孤風凜凜振臺端。", "坐曹常佐甘泉計，奏事曾紆武帳冠。", "一日雕龍分使節，幾年驄馬避朝鞍。", "商功未是須賢地，荷橐行歸侍玉鑾。"]'),
('62c7d080-aa47-4df6-ad4f-c9eb175a1ede','送石舍人得告展省','胡宿','宋','宋诗','song-poetry','','[]','先賢富貴重夸鄉，況復哀榮感履霜。',64,'全唐诗/poet.song.9000.json','["先賢富貴重夸鄉，況復哀榮感履霜。", "三最詔書新予告，九原恩澤遠生光。", "老人競醉金錢少，稚子爭牽玉佩長。", "荀令池頭芳樹在，栖雞浴鳳日相望。"]'),
('7dbe9e04-499e-470f-b442-66e1c26a1a80','送石舍人入西閣見紫薇花盛開','胡宿','宋','宋诗','song-poetry','','[]','西臺重見紫薇花，天上時時好物華。',64,'全唐诗/poet.song.9000.json','["西臺重見紫薇花，天上時時好物華。", "人向藥階升禁掖，路從桃水入仙家。", "香英半落風前酒，高艷遥烘日際霞。", "却憶後齋濃睡覺，芝泥初熟午陰斜。"]'),
('766f525c-910c-4694-9194-44a91b5fbe4c','寒蟬','胡宿','宋','宋诗','song-poetry','','[]','槁葉驚秋樹幄稀，嘶蟬猶尚警寒枝。',64,'全唐诗/poet.song.9000.json','["槁葉驚秋樹幄稀，嘶蟬猶尚警寒枝。", "玉琴可要傳深恨，珠露何妨剩薦饑。", "已伴風箏流遠韵，更邀霜籟散餘悲。", "清漳病枕無悰久，月夕煩君住少時。"]'),
('12975456-90e6-45a6-b9cf-7f74b565899f','三衢道中馬上口占','胡宿','宋','宋诗','song-poetry','','["\u897f\u6e56"]','短亭疏柳映鞦韆，馬上人家穀雨前。',64,'全唐诗/poet.song.9000.json','["短亭疏柳映鞦韆，馬上人家穀雨前。", "幾樹槍旗茶靃靡，一溪鱗甲水潺湲。", "鶑期別後聞餘哢，蠶候歸來見小眠。", "可惜西湖湖上月，夜來虛過十分圓。"]'),
('7bb4d369-44a4-46a4-856f-f6c275f0f7ad','送張待詔知越州','胡宿','宋','宋诗','song-poetry','','[]','長安廄吏馭花驄，竹使遥分浙水東。',64,'全唐诗/poet.song.9000.json','["長安廄吏馭花驄，竹使遥分浙水東。", "遠勢早推賢相子，任誠真有古人風。", "稽山一鎮居封內，阿閣三休聳禁中。", "長樂鐘聲偏怨別，何時同謁建章宮。"]'),
('19b10524-da09-4467-9199-c9c41a57475e','送陳學士知常州','胡宿','宋','宋诗','song-poetry','','[]','金斗城高二浙西，使君初拜武都泥。',64,'全唐诗/poet.song.9000.json','["金斗城高二浙西，使君初拜武都泥。", "射堂五色開雲的，齊隊千兵衣水犀。", "仙閣舊香芸辟蠹，使軒新蔭李成蹊。", "下車定有中和曲，索米州民日倚輗。"]'),
('613b5a14-c468-44ee-8b2a-028d8d2aee0f','覽朱表臣卷','胡宿','宋','宋诗','song-poetry','','[]','烏巷名生卓不羣，階庭相伴玉枝薰。',64,'全唐诗/poet.song.9000.json','["烏巷名生卓不羣，階庭相伴玉枝薰。", "天邊禁樹開龍鳳，筆下清才墜鳥雲。", "三級火雷何日化，一堂金竹此時聞。", "牛心割炙探來嚼，爭得英瑶去報君。"]'),
('e8d23ae1-420e-48f4-b17a-d975bff374fb','覽孫祐甫卷','胡宿','宋','宋诗','song-poetry','','[]','君家先正隠瓌材，巖石清聲動漢臺。',64,'全唐诗/poet.song.9000.json','["君家先正隠瓌材，巖石清聲動漢臺。", "地底何年埋玉樹，蚌中今幸産珠胎。", "氈書未挂千名榜，豆詠爭傳八斗才。", "荆璧夜來煩抵鵲，寶編三復翳瞳開。"]'),
('d3ca61a2-9cd0-4695-bdc2-e902402e71e3','南至之日輦下書事呈正卿子高二同年','胡宿','宋','宋诗','song-poetry','','[]','歲暮繁雲結夕陰，長安客舍費黄金。',64,'全唐诗/poet.song.9000.json','["歲暮繁雲結夕陰，長安客舍費黄金。", "燭窗明暗翻歸夢，雪屋清寒著旅衾。", "寶騎傳呼三陌廣，銅龍飄點九門深。", "萬年壽酒無因上，陽藿空傾向日心。"]'),
('bc1c332e-6ace-4fdd-a270-b0e263967c88','芙蓉湖泛舟','胡宿','宋','宋诗','song-poetry','','[]','小湖香艷戰芙蓉，碧葉田田擁釣蓬。',64,'全唐诗/poet.song.9000.json','["小湖香艷戰芙蓉，碧葉田田擁釣蓬。", "嵐氣欲飛山隔岸，秋光不定水摇空。", "翩翻雪鳥爭投浦，撥剌霜鱗鬭擲風。", "正是滄浪濯纓日，一竿多謝紫溪翁。"]'),
('00a33d56-573f-43f4-a7d5-5593d1e7096f','過李白墳','胡宿','宋','宋诗','song-poetry','','[]','平昔馳名蜀道難，旅魂流落古苔斑。',64,'全唐诗/poet.song.9000.json','["平昔馳名蜀道難，旅魂流落古苔斑。", "土中寶樹埋何在，澤畔靈魂些不還。", "醉後烟霞仍物外，吟餘風月尚人間。", "一哀弔罷頹陽暮，江北江南盡是山。"]'),
('a3118302-878a-4885-a652-389ced3f6d0b','送致政秘丞','胡宿','宋','宋诗','song-poetry','','[]','二紀青衫拂洛塵，桂香消盡故時春。',64,'全唐诗/poet.song.9000.json','["二紀青衫拂洛塵，桂香消盡故時春。", "徑爲天上乘槎客，厭作河濱託乘人。", "老筆工詩殊覺麗，清談傾座幾相親。", "臨滄送別多瑰藻，三徑歸資莫歎貧。"]'),
('1ccfeb6f-9625-4a00-b327-cce76329b793','送致政吳賓客','胡宿','宋','宋诗','song-poetry','','[]','挂冕高辭九列榮，年如園綺尚康寧。',64,'全唐诗/poet.song.9000.json','["挂冕高辭九列榮，年如園綺尚康寧。", "水蒼乍解趨朝佩，雲母初閒隔署屏。", "商嶺紫芝歌幾曲，武夷毛竹夢頻驚。", "門前已見施行馬，更待沙堤接鯉庭。"]'),
('147855ca-6ea5-417d-b0c2-eb581b19d779','寄致政蔣侍郎','胡宿','宋','宋诗','song-poetry','','[]','八十磻谿用釣翁，丈人冰雪在顔容。',64,'全唐诗/poet.song.9000.json','["八十磻谿用釣翁，丈人冰雪在顔容。", "乞身未及調緣鵠，濟世何當起卧龍。", "先覺令名侔大蔡，後彫遐福集寒松。", "憐才好客還依舊，終日清談綠酒醲。"]'),
('1c77b7f8-83f6-4964-9cd5-0b3101d8590d','和承旨給事寄酬南京致政杜相公','胡宿','宋','宋诗','song-poetry','','[]','賢相辭榮鬢未斑，濟川舟楫一朝閒。',64,'全唐诗/poet.song.9000.json','["賢相辭榮鬢未斑，濟川舟楫一朝閒。", "蒼生猶望安車起，使者空持拱璧還。", "郢曲傳來都輦下，蕭規留在廟堂間。", "壯猷全德知難尚，後世高名重太山。"]'),
('09c9d2dd-cd2c-43ed-86a2-b91509f16067','凉思','胡宿','宋','宋诗','song-poetry','','[]','昨夜南星破暑威，月波浮動杵天垂。',64,'全唐诗/poet.song.9000.json','["昨夜南星破暑威，月波浮動杵天垂。", "露華冷向三危滴，秋色新從一葉知。", "越水舊歌迷桂楫，楚江秋思繞蘭旗。", "桃笙碧滑人無寐，欲借鮫盤寄所思。"]'),
('209ed2ed-ba8c-4700-b11f-0f08ae7655bd','凉州','胡宿','宋','宋诗','song-poetry','','[]','一從天寶陷凉州，路絕陽關數百秋。',64,'全唐诗/poet.song.9000.json','["一從天寶陷凉州，路絕陽關數百秋。", "誰念弓裘侵紫塞，空餘歌舞在紅樓。", "將兵古有龍韜略，仗節今無燕頷侯。", "五鼎元戎方肉食，腐儒何者預軍謀。"]'),
('0d0cbdb0-7637-4ee9-aea1-8d3694a0191c','送姚秘校歸霅','胡宿','宋','宋诗','song-poetry','','[]','苕溪曾是忝朱輪，鳴鹿當年預送賓。',64,'全唐诗/poet.song.9000.json','["苕溪曾是忝朱輪，鳴鹿當年預送賓。", "楚國頻嗟三獻璞，漢廷裁得半通綸。", "勞歌未免吟梁甫，作賦還應問大鈞。", "下澤乘車知道在，折腰那久滯風塵。"]'),
('da440849-eda9-43f9-87bb-2067b38c8eae','寄蕪湖吳殿丞','胡宿','宋','宋诗','song-poetry','','[]','大花灘外憶琴堂，西北山長水更長。',64,'全唐诗/poet.song.9000.json','["大花灘外憶琴堂，西北山長水更長。", "縮地何曾人有術，摩天不及鳥能翔。", "寒梅弄臉英英態，臘甕蒸醅滿滿香。", "悵望未休還悵望，夜來庭下月如霜。"]'),
('2bfd6616-8b7b-4dfd-b298-a3c43f562a93','寄臨淮蔣使君','胡宿','宋','宋诗','song-poetry','','[]','漢臺分刺輟名臣，隼旆還臨磬水濱。',64,'全唐诗/poet.song.9000.json','["漢臺分刺輟名臣，隼旆還臨磬水濱。", "殿石乍辭龍尾遠，印鞶初結獸頭新。", "貫花佛會連香剎，種杏仙陰接寶鄰。", "荆府依劉心未獲，却憐馴鹿伴行春。"]'),
('50c1e3f2-a60e-404c-86e6-1b67293b5e6c','和吳春卿早春即事','胡宿','宋','宋诗','song-poetry','','[]','臘過春雲尚带陰，故山迢遞憶青岑。',64,'全唐诗/poet.song.9000.json','["臘過春雲尚带陰，故山迢遞憶青岑。", "芸齋舊帙書籤冷，桂甕新香酒蟻深。", "複道風煙殊可眺，曲江花柳試偷尋。", "芳樽一笑真難得，永埒何曾有剩金。"]'),
('a311a160-c939-4558-9599-d6743b16f31e','寄龍圖李諫議','胡宿','宋','宋诗','song-poetry','','[]','虎符兼綰鐵林兵，安輯南方十二城。',64,'全唐诗/poet.song.9000.json','["虎符兼綰鐵林兵，安輯南方十二城。", "昏曉星文通翼軫，陰晴雲氣接巫衡。", "江飄畫角蛟龍思，風獵干旟鳥隼鳴。", "誰伴使君紅燭宴，漆堂深夜促銀箏。"]'),
('82ea37b4-e2ad-4ae7-a195-e30c2a5ec84c','送林學士赴明州','胡宿','宋','宋诗','song-poetry','','[]','綠綈膺檢出神州，又保東吳最上游。',64,'全唐诗/poet.song.9000.json','["綠綈膺檢出神州，又保東吳最上游。", "腰下金符分半虎，手中庖刃欠全牛。", "金尊酌月吳歈席，錦纜牽風越鄂舟。", "正是金華隆舊業，羣仙相望在瀛州。"]'),
('b6c9dbb0-0440-4281-b785-6287973bfc2f','送施屯田守姑熟','胡宿','宋','宋诗','song-poetry','','[]','臺城南畔擁油韜，四十名郎此夢刀。',64,'全唐诗/poet.song.9000.json','["臺城南畔擁油韜，四十名郎此夢刀。", "文陛入辭交戟密，太微回望積星高。", "醉羅定費齋中酎，吟管應催石上毫。", "莫戀江東佳麗地，歸來開院接金鼇。"]'),
('7b985178-9f61-4e7f-a761-2e10b849c2f3','寄江淮太守表臣職方','胡宿','宋','宋诗','song-poetry','','[]','畫省高才滯兩轓，秋來依舊對淮山。',64,'全唐诗/poet.song.9000.json','["畫省高才滯兩轓，秋來依舊對淮山。", "一函星斗龍淵在，萬里風雲驥足閒。", "賦詠且裁紅燭下，卷懷聊寄綠樽間。", "次公治行聞當牖，二節如今即召還。"]'),
('2aadc01e-c558-4150-b1ac-e223bd9a5b33','送宗兄郎中守三衢','胡宿','宋','宋诗','song-poetry','','[]','新舊鞶囊兩獸頭，東南鄉郡得龍丘。',64,'全唐诗/poet.song.9000.json','["新舊鞶囊兩獸頭，東南鄉郡得龍丘。", "朱丹侯轂聊行縣，紫翠家山更滿樓。", "高第郎官猶應宿，中材裨將輒封侯。", "浩然能養浮雲志，風月樽前且獻酬。"]'),
('3fdb863f-3ac1-4141-8781-d4f196442794','送譚寺丞守鬰平','胡宿','宋','宋诗','song-poetry','','[]','金契爲州復侍親，却從湖際訪仙村。',64,'全唐诗/poet.song.9000.json','["金契爲州復侍親，却從湖際訪仙村。", "花垂晚席傾家釀，柳拂春車過里門。", "關內已誇新組去，浦中仍見舊珠存。", "名園日涉庭無訟，絲管時時薦壽樽。"]'),
('d6554736-1396-409d-b3ab-b1916a99d467','集賢石學士出守符離','胡宿','宋','宋诗','song-poetry','','[]','日邊新擁兩朱轓，亦以斜飛試羽翰。',64,'全唐诗/poet.song.9000.json','["日邊新擁兩朱轓，亦以斜飛試羽翰。", "巴郡詞人才藻壯，漢家循吏教條寬。", "明光奏事衣香在，麗正修書硯滴殘。", "歲晚政成丹詔下，歸來天上作仙官。"]'),
('60083816-b6e9-4cc1-8d28-a315f390752e','殘花','胡宿','宋','宋诗','song-poetry','','[]','雨壓殘紅一夜凋，曉來簾外正飄颻。',64,'全唐诗/poet.song.9000.json','["雨壓殘紅一夜凋，曉來簾外正飄颻。", "數枝翠葉空相對，萬片香魂不可招。", "長樂夢回春寂寂，武陵人去水迢迢。", "忍將玉笛傳遺恨，苦被芳風透綺寮。"]'),
('294d0362-34a4-4293-a391-9b05546b05ee','和承旨宋尚書告中之作','胡宿','宋','宋诗','song-poetry','','[]','鵲聲頻繞大槐枝，鼇禁歡聞舊老歸。',64,'全唐诗/poet.song.9000.json','["鵲聲頻繞大槐枝，鼇禁歡聞舊老歸。", "哆舌人間無翕訿，奎鈎天上有晶暉。", "西山五色分靈藥，南極三光接太微。", "只待延英朝隻日，便應調鼎向黄扉。"]'),
('b9b32d18-60b1-4353-892d-eedf2e105379','橘','胡宿','宋','宋诗','song-poetry','','[]','龍陽洲上密于星，紅實纍纍照日明。',64,'全唐诗/poet.song.9000.json','["龍陽洲上密于星，紅實纍纍照日明。", "露濯曉枝金色重，霜封秋蒂粉衣輕。", "楚江未分萍如蜜，漢殿何曾蔗析酲。", "誰道相如能作賦，詔園先熟是虛名。"]'),
('54f297ed-7c9b-47b4-a9b8-01a476e821f6','送次道學士倅洛中','胡宿','宋','宋诗','song-poetry','','[]','留籥初均相府勞，辟書先下得虔刀。',64,'全唐诗/poet.song.9000.json','["留籥初均相府勞，辟書先下得虔刀。", "黄圖氣象占龍闕，丹穴精神識鳳毛。", "一代策書承世學，三川風月屬詩豪。", "山公更有通家舊，應許論文醉醁醪。"]'),
('b6801479-ff26-41bc-8399-45e1dc59a4bc','送周屯田倅南徐','胡宿','宋','宋诗','song-poetry','','[]','浙河分鎮壓東西，鐵甕由來重會稽。',64,'全唐诗/poet.song.9000.json','["浙河分鎮壓東西，鐵甕由來重會稽。", "地勢頓驚江海近，天文全覺斗牛低。", "鳴秋鼓角翻朱鷺，映日樓臺拂彩霓。", "綠髮名郎才韵秀，政成看奉紫芝泥。"]'),
('2d6368cc-1084-46c6-a3e8-4a5775367041','送子思學士倅河內','胡宿','宋','宋诗','song-poetry','','[]','左符通掌日邊城，幾蔭華榱奉刺經。',64,'全唐诗/poet.song.9000.json','["左符通掌日邊城，幾蔭華榱奉刺經。", "直舍十年苔已紫，吟鞭一路柳初青。", "禁中夜閣拋行月，郊外春車駕屏星。", "河裏舊遊從古盛，好尋煙幌弔遺靈。"]'),
('fa499589-2878-44c9-9077-7d55d859cf66','送薛監丞倅絳臺','胡宿','宋','宋诗','song-poetry','','[]','故絳山川宰樹存，屏星分守出宸恩。',64,'全唐诗/poet.song.9000.json','["故絳山川宰樹存，屏星分守出宸恩。", "官榮此去夸鄉組，家法從來式里門。", "別斝正憐黄菊綻，征鞍猶怯黑貂溫。", "守居舊號園池美，應伴山翁把翠樽。"]'),
('c670114a-ffe8-4575-bbba-5515c38cfc1a','贈梅聖俞試館職得賜進士出身','胡宿','宋','宋诗','song-poetry','','[]','賦就甘泉客薦雄，獨攀仙桂向秋風。',64,'全唐诗/poet.song.9000.json','["賦就甘泉客薦雄，獨攀仙桂向秋風。", "抽毫同列三英座，換骨纔爭第一功。", "瞥看靈鼇居水下，恍聞仙犬吠雲中。", "嫦娥應有憐才意，惟許詩人到月宮。"]'),
('b6747166-7b0f-43a8-a003-b3fed3a9792b','卜居','胡宿','宋','宋诗','song-poetry','','[]','自致青雲有壯圖，且尋詹尹卜幽居。',64,'全唐诗/poet.song.9000.json','["自致青雲有壯圖，且尋詹尹卜幽居。", "一杯誰置元王醴，三尺休彈上客魚。", "足下已穿東郭履，胸中猶鬰茂陵書。", "漢皇夜御金鑾殿，豈便無人薦子虛。"]'),
('a2aa3c35-cb3a-47b7-9aec-8b889e363ed0','淮南王','胡宿','宋','宋诗','song-poetry','','[]','貪鑄金錢盜寫符，何曾七國戒前車。',64,'全唐诗/poet.song.9000.json','["貪鑄金錢盜寫符，何曾七國戒前車。", "長生不待爐中藥，鴻寶誰收篋裏書。", "碧井牀空天影在，小山人去桂叢疏。", "雲中雞犬無消息，秀麥漸漸遍故墟。"]'),
('8a65c8d6-3966-4143-be0e-895688e641c5','送劉觀察赴襄陽','胡宿','宋','宋诗','song-poetry','','[]','甲隊霜秋瑩武蜂，萬兵都府去臨戎。',64,'全唐诗/poet.song.9000.json','["甲隊霜秋瑩武蜂，萬兵都府去臨戎。", "習池峴首風流遠，漢水方城氣象雄。", "宴榭鳴鼉飄畫鼓，射堂棲鵲試雕弓。", "平時公子推能政，愛日遥知遍境中。"]'),
('28a77794-d5df-48d4-82b0-b8f513a49562','寄題徐都官吳下園亭','胡宿','宋','宋诗','song-poetry','','[]','吳下新居樹石中，綠巖香葉一重重。',64,'全唐诗/poet.song.9000.json','["吳下新居樹石中，綠巖香葉一重重。", "潺湲枕上聞流水，縹緲簷間見好峰。", "山客對棋閒覓劫，野僧留話幾侵鐘。", "由來止足前賢事，他日何慚邴曼容。"]'),
('9e17e2f7-7253-4d38-94d1-59178a1ce8ec','長卿','胡宿','宋','宋诗','song-poetry','','[]','買賦金錢出後宮，長卿文采冠諸公。',64,'全唐诗/poet.song.9000.json','["買賦金錢出後宮，長卿文采冠諸公。", "梁園末至時名大，蜀道前驅使節雄。", "已託焦桐傳密意，更因殘札寄遺忠。", "如何一諷神仙事，却得飄雲起賦中。"]'),
('4feafce9-d32c-4a0d-982c-dded74b5c480','洞靈觀納凉','胡宿','宋','宋诗','song-poetry','','[]','秋波不動簟紋融，松月愔愔透綺櫳。',64,'全唐诗/poet.song.9000.json','["秋波不動簟紋融，松月愔愔透綺櫳。", "霜重井梧翻瘦碧，雨回階藥墮嫣紅。", "彩鴛靜占銀塘水，乳燕凉飛玉宇風。", "秫酒易銷殘夢斷，却疑身在廣寒宮。"]'),
('b2ac2968-b5e8-488b-825d-c4f8a6cedd7a','天街曉望','胡宿','宋','宋诗','song-poetry','','[]','長樂纔聞一叩鐘，百官初謁未央宮。',64,'全唐诗/poet.song.9000.json','["長樂纔聞一叩鐘，百官初謁未央宮。", "金波穆穆沙堤月，玉樹琤琤上苑風。", "香重椒蘭橫結霧，氣寒龍虎遠浮空。", "嗟余索米無人問，行避霜臺御史驄。"]'),
('6af40be2-9a33-4e35-a27f-c2b002b070a4','寄昭潭王中立','胡宿','宋','宋诗','song-poetry','','[]','高弦一弄武陵深，六幕天空萬里心。',64,'全唐诗/poet.song.9000.json','["高弦一弄武陵深，六幕天空萬里心。", "吳苑歌驪成久別，楚峰回雁好歸音。", "十千美酒花期隔，三百枯棋弈思沈。", "莫上孤城頻送目，浮雲西北是家林。"]'),
('441d1741-1264-45db-991c-11d143d93e14','次韵徐爽見寄','胡宿','宋','宋诗','song-poetry','','[]','五兩青絲帝渥深，平時可敢嘆英沈。',64,'全唐诗/poet.song.9000.json','["五兩青絲帝渥深，平時可敢嘆英沈。", "侏儒自是長三尺，澼絖都來直數金。", "寂寞死灰人喪偶，婆娑生意樹交陰。", "年來想見瓊枝色，久夢蘧蘧到竹林。"]'),
('fbc82c26-47af-4400-a15e-2d492df3e0ed','雪','胡宿','宋','宋诗','song-poetry','','[]','屏翳驅雲結夜陰，素花飄墜惡氛沈。',64,'全唐诗/poet.song.9000.json','["屏翳驅雲結夜陰，素花飄墜惡氛沈。", "色欺曹國麻衣淺，寒入荆王翠被深。", "天上明河銀作水，海中仙樹玉爲林。", "日高獨擁鸘裘卧，誰乞長安取酒金。"]'),
('9bea31a9-5d19-4242-bee5-dfa5d9766d55','城南','胡宿','宋','宋诗','song-poetry','','[]','昨夜輕陰結夕霏，城南十里有香泥。',64,'全唐诗/poet.song.9000.json','["昨夜輕陰結夕霏，城南十里有香泥。", "初聞山鳥驚新哢，遥見林花識舊蹊。", "蕩槳遠從芳草渡，墊巾還傍緣楊堤。", "羅敷正苦桑蠶事，惆悵南來五馬蹄。"]'),
('35c58ecd-828e-4fcb-bdb4-567f1b7e8d10','早夏','胡宿','宋','宋诗','song-poetry','','[]','井轄投多思不禁，密垂珠箔晝沈沈。',64,'全唐诗/poet.song.9000.json','["井轄投多思不禁，密垂珠箔晝沈沈。", "睡驚燕語頻移枕，病起蛛絲半在琴。", "雨徑亂花埋宿艷，月軒脩竹轉凉陰。", "一春酒費知多少，探盡囊中換賦金。"]'),
('023383ae-8808-443e-95aa-b6d696b639ba','宿秀峰寺','胡宿','宋','宋诗','song-poetry','','[]','夕鐘初斷海鯨音，投宿香園半翠岑。',64,'全唐诗/poet.song.9000.json','["夕鐘初斷海鯨音，投宿香園半翠岑。", "冰簟浸牀消客夢，水簾澄月伴僧吟。", "雄風拂衽清凉極，珍樹交柯翠翳深。", "一夜漢陰機事息，草堂虛論破煩襟。"]'),
('b09ab62e-fcd9-4098-b415-e59bcd57f409','太湖石','胡宿','宋','宋诗','song-poetry','','["\u592a\u6e56", "\u6d1e\u5ead\u6e56"]','海岱鉛松妄得名，洞庭山脚失寒瓊。',64,'全唐诗/poet.song.9000.json','["海岱鉛松妄得名，洞庭山脚失寒瓊。", "漱成一朵孤雲勢，費盡千年白浪聲。", "誰向機邊逢織女，直疑巖下見初平。", "年來賞物多成病，日繞蒼苔幾遍行。"]'),
('9aa0d9d0-48c7-4654-87f2-bdfcde4f58dc','過桐廬','胡宿','宋','宋诗','song-poetry','','[]','兩岸山花中有溪，山花紅白遍高低。',64,'全唐诗/poet.song.9000.json','["兩岸山花中有溪，山花紅白遍高低。", "靈源忽若乘槎到，仙洞還同採藥迷。", "二月辛夷猶未落，五更鴉臼最先啼。", "茶煙漁火遥堪畫，一片人家在水西。"]'),
('4d6d1bc9-f467-477d-8d0f-dacfe93c7063','憶薦福寺牡丹','胡宿','宋','宋诗','song-poetry','','[]','十日春風隔翠岑，祇應繁朵自成陰。',64,'全唐诗/poet.song.9000.json','["十日春風隔翠岑，祇應繁朵自成陰。", "樽前可要人頹玉，樹底遥知地側金。", "花界三千春渺渺，銅槃十二夜沈沈。", "雕盤分篸何由得，空作西州擁鼻吟。"]'),
('3d70ef9d-ad25-45b3-80e9-1d5042f68ecc','次韵和朱況雨中之什','胡宿','宋','宋诗','song-poetry','','[]','蒼野迷雲黯不歸，遠風吹雨入巖扉。',64,'全唐诗/poet.song.9000.json','["蒼野迷雲黯不歸，遠風吹雨入巖扉。", "石牀潤極琴絲緩，水閣寒多酒力微。", "夕夢將成還滴滴，春心欲斷正霏霏。", "憂花惜月長如此，爭得東陽病骨肥。"]'),
('8ae6b70d-882a-46bc-9457-8c6995e08913','十六夜月二首  其一','李綱','宋','宋诗','song-poetry','','[]','清光殊未减，碧落絕纖塵。',48,'全唐诗/poet.song.90000.json','["清光殊未减，碧落絕纖塵。", "綘闕飛金鏡，銀潢渡玉輪。", "霏霏煙靄滅，湛湛露華新。", "倚幌人千里，遥知翠黛顰。"]'),
('29315ba0-d218-445e-b28a-1cff481e6790','十六夜月二首  其二','李綱','宋','宋诗','song-poetry','','[]','嫦娥長不老，宫殿復新秋。',48,'全唐诗/poet.song.90000.json','["嫦娥長不老，宫殿復新秋。", "丹桂欲飄子，素蟾相對愁。", "林寒枝繞鵲，江迥水明樓。", "逐客幾弦望，又看成玉鉤。"]'),
('01c45053-87da-4802-bed8-90979b02f6ea','讀諸葛武侯傳','李綱','宋','宋诗','song-poetry','','[]','天下兵戈正雲沸，伏龍鳳鶵那可致。',160,'全唐诗/poet.song.90000.json','["天下兵戈正雲沸，伏龍鳳鶵那可致。", "掉頭自作梁甫吟，壠上躬耕方得意。", "將軍漢裔真英雄，惠然三顧草廬中。", "心期脗合論世故，如魚得水雲從龍。", "指麾顧眄定巴蜀，抗魏連吳分鼎足。", "受遺乃在永安宫，歎息君臣難繼躅。", "南征五月深渡瀘，上疏北伐遵遺謨。", "連年動衆擾關輔，數戰未必非良圖。", "大星夜墜驚營壘，壯志雄謀嗟已矣。", "至今魚腹淺沙中，八陣依然照江水。"]'),
('8b3d8b9b-a9a0-4aa2-9d2d-ec0a5a864857','秋夜有懷二首  其一','李綱','宋','宋诗','song-poetry','','[]','草木又搖落，關河方阻深。',48,'全唐诗/poet.song.90000.json','["草木又搖落，關河方阻深。", "龍庭空入夢，鴈足不傳音。", "黄傘遊何處，蒼生思至今。", "娟娟江漢月，空照逐臣心。"]'),
('8049027c-5a0c-4045-abc5-e8cf7d693a91','秋夜有懷二首  其二','李綱','宋','宋诗','song-poetry','','[]','坐失金湯險，搖搖翠蓋飛。',48,'全唐诗/poet.song.90000.json','["坐失金湯險，搖搖翠蓋飛。", "空聞八駿御，不見六龍歸。", "天地干戈滿，瀟湘鴻鴈稀。", "漢宫秋夜月，依舊照彤闈。"]'),
('486e3aa6-03cb-4921-aecc-37767b58ec24','崇陽道中作四首  其一','李綱','宋','宋诗','song-poetry','','[]','我行江南春，初見農事作。',48,'全唐诗/poet.song.90000.json','["我行江南春，初見農事作。", "及兹旅湖外，秋稻半已穫。", "隔林聞晚舂，藁秸積籬落。", "童稚亦熙熙，田家有餘樂。"]'),
('c0260e9e-0f55-4e0d-9122-50829c0fe674','崇陽道中作四首  其二','李綱','宋','宋诗','song-poetry','','[]','溪清石齒齒，山遠木蒼蒼。',48,'全唐诗/poet.song.90000.json','["溪清石齒齒，山遠木蒼蒼。", "落日煙景暮，西風粳稻香。", "茂林歸鳥雀，平隰下牛羊。", "月露浩如洗，淒然欲結霜。"]'),
('d09d6ec9-971b-4359-a19f-2e53924cc4c8','崇陽道中作四首  其三','李綱','宋','宋诗','song-poetry','','[]','承平無事久，萬里盡農桑。',48,'全唐诗/poet.song.90000.json','["承平無事久，萬里盡農桑。", "誰使干戈起，坐令民物瘡。", "關河成阻絕，京洛亦淒涼。", "尚喜江湖外，斯民遊樂康。"]'),
('08988c5e-8237-4589-acc2-c077b6b7ad73','崇陽道中作四首  其四','李綱','宋','宋诗','song-poetry','','[]','連年兵甲興，猶幸東南稔。',48,'全唐诗/poet.song.90000.json','["連年兵甲興，猶幸東南稔。", "食足無叛民，閭里得安枕。", "傳聞江淮間，蝗旱今猶甚。", "努力事燮調，未寒心已凛。"]'),
('0fe8bb85-1555-4a75-b5b4-1c510618fc34','宿巖頭寺','李綱','宋','宋诗','song-poetry','','[]','天氣沉陰迫季秋，通城早發宿巖頭。',64,'全唐诗/poet.song.90000.json','["天氣沉陰迫季秋，通城早發宿巖頭。", "催寒小雨松桂濕，出岫孤雲嵌洞幽。", "瓶錫真還行脚債，鉗鎚罕遇點胸儔。", "夜深雲散千峰月，注目寒空獨倚樓。"]'),
('16d84dfd-ac82-4863-8eb1-7d1b41d82b79','寓崇陽西山定林院有感二首  其一','李綱','宋','宋诗','song-poetry','','[]','踰年去天闕，長是寓僧廬。',48,'全唐诗/poet.song.90000.json','["踰年去天闕，長是寓僧廬。", "雲水志方適，軒裳情已疏。", "午風吹茗椀，夜月照牀書。", "忘我兼忘世，此生真有餘。"]'),
('f255d9bb-86fd-4216-982b-3a6b22a5ce43','寓崇陽西山定林院有感二首  其二','李綱','宋','宋诗','song-poetry','','[]','清霜初入候，落葉半辭柯。',36,'全唐诗/poet.song.90000.json','["清霜初入候，落葉半辭柯。", "歲晏遽如許，時艱將若何。", "關山空歲月，江漢自風波。"]'),
('0e32a9ea-29c8-4e6b-8828-8dc85e48196f','巖桂二首  其一','李綱','宋','宋诗','song-poetry','','[]','汲水養巖桂，最憐風露香。',48,'全唐诗/poet.song.90000.json','["汲水養巖桂，最憐風露香。", "黄花金瑣碎，碧葉玉光鋩。", "却憶七閩路，有懷中隱堂。", "相看久不厭，氣味自難忘。"]'),
('58c5e856-c3d5-4e0e-8f12-ee88cbf76db5','巖桂二首  其二','李綱','宋','宋诗','song-poetry','','[]','遠地見佳木，依然如故人。',48,'全唐诗/poet.song.90000.json','["遠地見佳木，依然如故人。", "難當襌客意，爲折數枝新。", "自耐風霜早，不慚蘭蕙春。", "慇懃置瓶水，寂寞伴閑身。"]'),
('86562740-2d14-4236-b931-31a90d561659','次韻鄭教授見寄','李綱','宋','宋诗','song-poetry','','[]','泛梗飄萍逐水流，故人書到正霜秋。',48,'全唐诗/poet.song.90000.json','["泛梗飄萍逐水流，故人書到正霜秋。", "扶顛拯溺多迂論，問舍求田更拙謀。", "輦道淒涼沙磧外，鉤陳寂寞楚江頭。"]'),
('da9c2c69-b750-48f7-9dcc-a10e8420c4c9','灌溪三詠 灌溪','李綱','宋','宋诗','song-poetry','','[]','道人卓錫使泉飛，一派清甘滿石陂。',32,'全唐诗/poet.song.90000.json','["道人卓錫使泉飛，一派清甘滿石陂。", "誰識灌溪真境界，也知只見漚麻池。"]'),
('2efc69a8-3ef7-4beb-870c-3aafdd8d0c40','灌溪三詠 妙峰菴','李綱','宋','宋诗','song-poetry','','[]','結菴雄踞妙髙峰，孤秀巉然萬境通。',32,'全唐诗/poet.song.90000.json','["結菴雄踞妙髙峰，孤秀巉然萬境通。", "不見德雲空住處，却須相遇别峰中。"]'),
('ff5ce06e-66e1-47bd-96ff-167c2d7d971b','灌溪三詠 清涼境界','李綱','宋','宋诗','song-poetry','','[]','松蘿蔭翳色蒼蒼，盛夏南風草木香。',32,'全唐诗/poet.song.90000.json','["松蘿蔭翳色蒼蒼，盛夏南風草木香。", "普願衆生無熱惱，不應身獨占清涼。"]'),
('d19b0a85-4a9b-4541-977a-f67d0cfb1c7c','題青龍興化禪院方丈','李綱','宋','宋诗','song-poetry','','[]','廓然丈室湛虚明，地僻山空萬象清。',64,'全唐诗/poet.song.90000.json','["廓然丈室湛虚明，地僻山空萬象清。", "滴翠老杉清凈色，鏘金流水妙圓聲。", "慇懃禪客邀迎厚，寂寞宰官身世輕。", "野鶴孤雲無不可，會須還作二龍行。"]'),
('bcecf015-c0f3-4c1e-a182-918c78a92d95','聞山東盜所謂丁一箭者擁數萬衆臨江破黄州官吏皆保武昌江湖間騷然未知備禦之策感而賦詩','李綱','宋','宋诗','song-poetry','','[]','時危貴權謀，盜賊本王臣。',216,'全唐诗/poet.song.90000.json','["時危貴權謀，盜賊本王臣。", "招徠駕馭之，自足張吾軍。", "蠭蠆固有毒，犀象亦可馴。", "恩威儻得所，摩拊還其淳。", "光武制銅馬，曹公用黄巾。", "資其戰大敵，且以蘇良民。", "去年議招撫，乃以此義陳。", "置司未閲月，來者如屯雲。", "奈何力沮罷，坐使復紛紛。", "傳聞中原寇，鐵馬動成羣。", "虎兕出於柙，玉石同其焚。", "京輔困抄掠，遂及江湖濱。", "東南久平定，郡縣無城闉。", "天塹非不險，誰與守要津。", "古來重鎮地，控扼非其人。", "小敵已震懼，大者當何云。", "人謀自回遹，天意詎不仁。", "安得迴陽輝，一令四海春。"]'),
('5eb29466-7d0b-429f-9eba-f7180445d4f9','得諸季書報薛克寅范茂載胡仲儼皆物故感愴有作','李綱','宋','宋诗','song-poetry','','[]','新故繼凋喪，初非因荷戈。',48,'全唐诗/poet.song.90000.json','["新故繼凋喪，初非因荷戈。", "波驚川閱水，霜早葉辭柯。", "世上故人少，錄中新鬼多。", "浮生端若此，傷感意如何。"]'),
('6a4d9365-b773-4839-ba79-a61f374226a1','山居四感 鬬雀','李綱','宋','宋诗','song-poetry','','[]','翩翾啅噪繞髙簷，粒食枝棲安用貪。',32,'全唐诗/poet.song.90000.json','["翩翾啅噪繞髙簷，粒食枝棲安用貪。", "怒鬬不知緣底事，敗毛輕毳落毿毿。"]'),
('3fa63c80-0e38-4f92-b595-5494f8b3d851','山居四感 戰蟻','李綱','宋','宋诗','song-poetry','','[]','欲雨山雲四面垂，空庭蟻戰久相持。',32,'全唐诗/poet.song.90000.json','["欲雨山雲四面垂，空庭蟻戰久相持。", "只應薄伐檀蘿國，正是槐安獻捷時。"]'),
('969ab3d0-4336-4c2d-9b3f-e8f464bb12e6','山居四感 噪蟬','李綱','宋','宋诗','song-poetry','','[]','修竹茂林山寺幽，蟬聲如沸滿清秋。',32,'全唐诗/poet.song.90000.json','["修竹茂林山寺幽，蟬聲如沸滿清秋。", "吸風飲露無求世，嘒嘒何爲噪不休。"]'),
('c8d7a875-1a4c-4747-ad67-e728adc56871','山居四感 吟蛩','李綱','宋','宋诗','song-poetry','','[]','月露淒清濕草根，寒蛩偏向夜深聞。',32,'全唐诗/poet.song.90000.json','["月露淒清濕草根，寒蛩偏向夜深聞。", "隨時感氣成悲怨，不是來銷逐客魂。"]'),
('3d5fee81-8c55-44aa-b90f-eaeff7139f27','山居四景 松風','李綱','宋','宋诗','song-poetry','','[]','歲晚蒼官鬢髪青，回風披拂自悲鳴。',32,'全唐诗/poet.song.90000.json','["歲晚蒼官鬢髪青，回風披拂自悲鳴。", "不容逐客多歸夢，故作江湖波浪聲。"]'),
('c0114c2d-5137-48b2-aa2a-03631b96afc6','山居四景 竹露','李綱','宋','宋诗','song-poetry','','[]','森然繞檻翠琅玕，瘦節疏枝特地寒。',32,'全唐诗/poet.song.90000.json','["森然繞檻翠琅玕，瘦節疏枝特地寒。", "底事葉垂渾不舞，金風零露夜漙漙。"]'),
('328bb663-4393-4e3a-aabd-b81c9850c9a3','山居四景 嶺雲','李綱','宋','宋诗','song-poetry','','[]','玉潔煙輕一片深，飄然出岫本無心。',32,'全唐诗/poet.song.90000.json','["玉潔煙輕一片深，飄然出岫本無心。", "孤飛遠映碧天去，也解重來爲作霖。"]'),
('e1843deb-29cf-45e6-9a35-7880fcf655d0','山居四景 窗月','李綱','宋','宋诗','song-poetry','','[]','月出松林已半廊，故開窗牖納清光。',32,'全唐诗/poet.song.90000.json','["月出松林已半廊，故開窗牖納清光。", "嫦娥應訝年來瘦，千首新詩書滿牀。"]'),
('fec50c6f-8b14-4bfa-ac8b-e1322fc09d23','山居四適 酌酒','李綱','宋','宋诗','song-poetry','','[]','山禽喚覺不成眠，興若長鯨吸百川。',32,'全唐诗/poet.song.90000.json','["山禽喚覺不成眠，興若長鯨吸百川。", "滿酌甆甌當金盞，陶然便作酒中仙。"]'),
('23df1bbe-0831-461f-a91b-c280f014925a','山居四適 烹茶','李綱','宋','宋诗','song-poetry','','[]','安眠飽食更何求，只欠雲腴茗一甌。',32,'全唐诗/poet.song.90000.json','["安眠飽食更何求，只欠雲腴茗一甌。", "龍鳳不須誇北苑，槍旗且與試中州。"]'),
('cfa0624d-d3a0-43db-9539-ce99ea32d965','山居四適 讀書','李綱','宋','宋诗','song-poetry','','[]','平生長作蠧書蟫，老去猶資慰我心。',32,'全唐诗/poet.song.90000.json','["平生長作蠧書蟫，老去猶資慰我心。", "毎到古人名節處，慨然掩卷一沉吟。"]'),
('8a7cff28-ec3e-4de3-a7f9-343d67dc8f9e','山居四適 焚香','李綱','宋','宋诗','song-poetry','','[]','假榻禪房夜寂然，瓦爐石餅爇龍涎。',32,'全唐诗/poet.song.90000.json','["假榻禪房夜寂然，瓦爐石餅爇龍涎。", "霏微縹緲根塵際，吸引方知鼻觀圓。"]'),
('8ba37e52-64f9-47be-a669-890e4f68b2b8','山居四卉 拒霜','李綱','宋','宋诗','song-poetry','','[]','道人多種木芙蓉，曉着清霜分外紅。',32,'全唐诗/poet.song.90000.json','["道人多種木芙蓉，曉着清霜分外紅。", "萬葉千花本何有，因空成色色成空。"]'),
('4c06de75-bec0-404d-a397-675ab8536e07','山居四卉 雞冠','李綱','宋','宋诗','song-poetry','','[]','昂然璀璨繞階除，端似羣雄領衆雛。',32,'全唐诗/poet.song.90000.json','["昂然璀璨繞階除，端似羣雄領衆雛。", "只有一冠無别德，誰云魯國固多儒。"]'),
('838e139b-ca1e-412d-8581-5de1d0dd4d01','山居四卉 菊','李綱','宋','宋诗','song-poetry','','[]','重陽旋覓菊花栽，青蘂蕭疏殊未開。',32,'全唐诗/poet.song.90000.json','["重陽旋覓菊花栽，青蘂蕭疏殊未開。", "我似陶潛正無酒，休將冷艷笑空罍。"]'),
('016b5f03-48fa-498e-860d-515cfefa6b3b','山居四卉 槿','李綱','宋','宋诗','song-poetry','','[]','步屧秋風見蕣華，疏籬灼灼繞田家。',32,'全唐诗/poet.song.90000.json','["步屧秋風見蕣華，疏籬灼灼繞田家。", "朝開暮落君休笑，縱使多時終委沙。"]'),
('ce82e223-4eab-43f4-b02d-eceba73a342f','淵聖皇帝賜寶劍生鐵花感而賦詩','李綱','宋','宋诗','song-poetry','','[]','靖康虜騎窺帝闉，中原慘澹生煙塵。',248,'全唐诗/poet.song.90000.json','["靖康虜騎窺帝闉，中原慘澹生煙塵。", "帝謂細柳真將軍，總兵欲使揮浮雲。", "解賜寶劍御府珍，魚腸盤屈松檜紋。", "縷金錯翠舟瑶琨，剸截犀象如羔豚。", "驅逐狂寇出邊垠，妖腰亂領徒紛紛。", "龍吟蛟吼清夜聞，乃知此物能通神。", "邇來杜門空念恩，舊事誰復可共論。", "今晨開匣觀龍文，鐵花繡澀蒼蘚痕。", "東南卑濕相蒸熏，坐使三尺光鋩昏。", "安得礪砥來峨岷，淬鋒歛鍔硎發新。", "霜寒冰滑無皵皸，指麾尚可清妖氛。", "願提此劍平戎獯，犬羊雖衆氣可吞。", "手斬可汗羈可敦，天旋日轉還兩君。", "書銘却勒燕然勳，攄憤刷恥志乃伸。", "壯懷聊可垂乾坤，緹繡什襲傳仍昆。", "衛綰之賜何足云。"]'),
('71f6f6f5-ab18-4e8d-85de-b520f35dfaaf','讀東坡和淵明貧士詩寄諸子姪云重九俯邇樽俎蕭然今余亦有此歎因次其韻將錄寄梁谿諸弟以發數千里一笑  其一','李綱','宋','宋诗','song-poetry','','[]','迂疏得遠謫，漂泊將何依。',72,'全唐诗/poet.song.90000.json','["迂疏得遠謫，漂泊將何依。", "區區一寸心，未報三春暉。", "歲月不我與，急景驚翻飛。", "方看社鷰來，又見霜鴻歸。", "寛恩尚廩祿，未迫寒與饑。", "荒山俯佳節，九月誠可悲。"]'),
('0ff87c7a-20d7-4fbf-bd7f-ae7c8a111990','讀東坡和淵明貧士詩寄諸子姪云重九俯邇樽俎蕭然今余亦有此歎因次其韻將錄寄梁谿諸弟以發數千里一笑  其二','李綱','宋','宋诗','song-poetry','','[]','淒涼寓僧舍，寂寞坐松軒。',72,'全唐诗/poet.song.90000.json','["淒涼寓僧舍，寂寞坐松軒。", "雖辭萬鍾祿，尚未自灌園。", "仲尼猶在陳，我厨晨有煙。", "藜羮得一飽，滴露味自研。", "寒窗寫周易，更詠五千言。", "儒生真可笑，餓隱稱其賢。"]'),
('e5dac0f2-ac18-40e7-9223-1b52204a7267','讀東坡和淵明貧士詩寄諸子姪云重九俯邇樽俎蕭然今余亦有此歎因次其韻將錄寄梁谿諸弟以發數千里一笑  其三','李綱','宋','宋诗','song-poetry','','[]','何以寫我意，寄之朱絲琴。',72,'全唐诗/poet.song.90000.json','["何以寫我意，寄之朱絲琴。", "鍾期久已死，千古無知音。", "棄置不復彈，調家難繹尋。", "東籬採青蘂，濁酒聊孤斟。", "千駟所不顧，一斗誠可欽。", "陶然又復醉，誰識淵明心。"]'),
('84711e74-d616-4a6b-a61e-bed21ddb7405','讀東坡和淵明貧士詩寄諸子姪云重九俯邇樽俎蕭然今余亦有此歎因次其韻將錄寄梁谿諸弟以發數千里一笑  其四','李綱','宋','宋诗','song-poetry','','[]','骯髒老張鎬，寂寞窮黔婁。',72,'全唐诗/poet.song.90000.json','["骯髒老張鎬，寂寞窮黔婁。", "古人日已遠，此意誰復酬。", "墨翟突不黔，仲尼轍環周。", "豈爲一身計，實懷四海憂。", "沮溺但躬耕，吾豈斯人儔。", "有酒且徑醉，無酒不必求。"]'),
('c53e5d3c-209e-444d-ab7c-94d1ca82e630','讀東坡和淵明貧士詩寄諸子姪云重九俯邇樽俎蕭然今余亦有此歎因次其韻將錄寄梁谿諸弟以發數千里一笑  其五','李綱','宋','宋诗','song-poetry','','[]','佳晨迫九日，旅食寓江干。',72,'全唐诗/poet.song.90000.json','["佳晨迫九日，旅食寓江干。", "頗同謫僊人，漂泊來銅官。", "樽俎何蕭條，菊蘂漸可餐。", "回風吹青松，慘慘歲將寒。", "但有杯中物，不愧簞瓢顔。", "一觴復一詠，明月窺禪關。"]'),
('0c21e355-9b21-4884-b278-cdf2066f0a17','讀東坡和淵明貧士詩寄諸子姪云重九俯邇樽俎蕭然今余亦有此歎因次其韻將錄寄梁谿諸弟以發數千里一笑  其六','李綱','宋','宋诗','song-poetry','','[]','自我去廊廟，遠舉如飛蓬。',72,'全唐诗/poet.song.90000.json','["自我去廊廟，遠舉如飛蓬。", "徇道敢懷祿，謀身殊未工。", "空餘耿耿心，不慚楚兩龔。", "幸然諸季賢，意氣與我同。", "何當恩聽歸，兵息道路通。", "却尋惠山路，杖策得相從。"]'),
('21f3756b-a1df-466b-888d-682ad420bab8','讀東坡和淵明貧士詩寄諸子姪云重九俯邇樽俎蕭然今余亦有此歎因次其韻將錄寄梁谿諸弟以發數千里一笑  其七','李綱','宋','宋诗','song-poetry','','[]','我家梁谿上，夢墮江湖州。',72,'全唐诗/poet.song.90000.json','["我家梁谿上，夢墮江湖州。", "塊處無與語，誰復爲朋儔。", "遠懷作重陽，置酒臨清流。", "插花獨我少，感物增離憂。", "我亦事杯杓，阿宗相獻酬。", "欲寄一枝菊，川途方阻脩。"]'),
('212ed5eb-fbe9-463b-9c5a-0c9233498ee8','次韻淵明九日閑居','李綱','宋','宋诗','song-poetry','','[]','天地一逆旅，於焉寓此生。',108,'全唐诗/poet.song.90000.json','["天地一逆旅，於焉寓此生。", "羣陰慘將暮，共愛九日名。", "氣清霜露肅，天朗山川明。", "月户藹夜色，風林颯秋聲。", "東籬菊有華，可以延我齡。", "采采金瑣碎，泛此玉觴傾。", "一醉遺萬物，况復軒裳榮。", "淵明骨已朽，千載同兹情。", "時危丹砂遠，歲晏將何成。"]'),
('871b0ad7-acb9-42ef-aeda-5156b3e68e3f','初寒','李綱','宋','宋诗','song-poetry','','[]','霜早風髙寒氣萌，可堪獨傍楚江行。',64,'全唐诗/poet.song.90000.json','["霜早風髙寒氣萌，可堪獨傍楚江行。", "貂裘已敝蘇季子，葛屨更穿東郭生。", "卯酒暈紅朝玉頰，夜爐燃鼎沸松聲。", "妻孥千里應思我，悵望牛衣此日情。"]'),
('97cf4bef-aa6c-4405-ae8d-367d8ab6b6f2','蜜蜂','李綱','宋','宋诗','song-poetry','','[]','秋風淅淅桂花香，花底山蜂採掇忙。',32,'全唐诗/poet.song.90000.json','["秋風淅淅桂花香，花底山蜂採掇忙。", "但得蜜成功用足，不辭辛苦與君嘗。"]'),
('35fe6f1e-0b64-47c5-a6c2-9c53a5bc803f','病牛','李綱','宋','宋诗','song-poetry','','["\u7231\u56fd", "\u548f\u7269", "\u53e4\u8bd7\u4e09\u767e\u9996", "\u52a8\u7269", "\u5b8b\u8bd7", "\u8a00\u5fd7"]','耕犂千畝實千箱，力盡筋疲誰復傷。',32,'全唐诗/poet.song.90000.json','["耕犂千畝實千箱，力盡筋疲誰復傷。", "但願衆生皆得飽，不辭羸病臥殘陽。"]'),
('3f07da6b-2e85-4745-ae53-7785bcf140bc','胡笳十八拍 第一拍','李綱','宋','宋诗','song-poetry','','[]','四海十年不解兵，朝降夕叛幽薊城。',64,'全唐诗/poet.song.90000.json','["四海十年不解兵，朝降夕叛幽薊城。", "殺氣南行動天軸，犬戎也復臨咸京。", "鐵馬長鳴不知數，虜騎憑陵雜風雨。", "自是君王未備知，一生長恨奈何許。"]'),
('7a03db88-132b-4f1c-83ce-9da1420c5341','胡笳十八拍 第二拍','李綱','宋','宋诗','song-poetry','','[]','黑雲壓城城欲摧，赤日照耀從西來。',64,'全唐诗/poet.song.90000.json','["黑雲壓城城欲摧，赤日照耀從西來。", "虜箭如沙射金甲，甲光向日金鱗開。", "昏昏閶闔閉氛祲，六龍寒急光徘徊。", "黄昏胡騎塵滿城，百年興廢吁可哀。"]'),
('73dbeee3-81d4-4b32-b8c8-3be7aba1cf26','胡笳十八拍 第三拍','李綱','宋','宋诗','song-poetry','','[]','千乘萬騎出咸陽，百官跣足隨天王。',66,'全唐诗/poet.song.90000.json','["千乘萬騎出咸陽，百官跣足隨天王。", "翠華搖搖行復止，黄塵暗天道路長。", "金盤玉筯無消息，色難腥腐飡風香。", "晚將末契託年少，遂令再往之計墮渺茫。"]'),
('c9c2eb38-0a28-4961-ba1d-51c7d40647ee','胡笳十八拍 第四拍','李綱','宋','宋诗','song-poetry','','[]','筋簳精堅胡馬驕，猛蛟突獸紛騰逃。',65,'全唐诗/poet.song.90000.json','["筋簳精堅胡馬驕，猛蛟突獸紛騰逃。", "春寒野陰風景暮，塵埃不見咸陽橋。", "中原格鬬且未歸，隴山蕭瑟秋雲髙。", "安得壯士兮守四方，一豁明主正鬱陶。"]'),
('f7e8c6b0-348d-44e5-a639-a7ef929d3a89','胡笳十八拍 第五拍','李綱','宋','宋诗','song-poetry','','[]','漢家離宫三十六，緩歌慢舞凝絲竹。',64,'全唐诗/poet.song.90000.json','["漢家離宫三十六，緩歌慢舞凝絲竹。", "鐵騎突出刀鎗鳴，驚破霓裳羽衣曲。", "明眸皓齒今何在，細柳青蒲爲誰綠。", "桃花依舊笑春風，風動落花紅蔌蔌。"]'),
('d41da596-f2e0-4eb6-911a-5db2dadbd898','胡笳十八拍 第六拍','李綱','宋','宋诗','song-poetry','','[]','憶昔霓旌下南苑，攀條弄芳畏晼晚。',64,'全唐诗/poet.song.90000.json','["憶昔霓旌下南苑，攀條弄芳畏晼晚。", "只今飄泊干戈際，寒盡春生洛陽殿。", "梨園弟子散如煙，白馬將軍若雷電。", "城上春雲覆苑墻，回首何時復來見。"]'),
('c96d1bc8-e2f8-4f86-bd73-fe88bbbca8bf','胡笳十八拍 第七拍','李綱','宋','宋诗','song-poetry','','[]','星宫之君醉瓊漿，矯如羣帝驂龍翔。',64,'全唐诗/poet.song.90000.json','["星宫之君醉瓊漿，矯如羣帝驂龍翔。", "龍池十日飛霹靂，齊言此夕樂未央。", "玄圃滄州莽空闊，羽人稀少不在傍。", "深山窮谷不可處，託身白雲歸故郷。"]'),
('b92b7746-a26b-4a90-ab3a-4d73bcf2aa91','胡笳十八拍 第八拍','李綱','宋','宋诗','song-poetry','','[]','黄塵散漫風蕭索，殺氣森森到幽朔。',64,'全唐诗/poet.song.90000.json','["黄塵散漫風蕭索，殺氣森森到幽朔。", "五十年間似反掌，瑤池侍臣已冥寞。", "千崖無人萬壑静，旌旗無光日色薄。", "萬事反覆何所無，注目寒江倚山閣。"]'),
('c5ddcd01-e1ef-4e1a-8466-c343935ecd8f','胡笳十八拍 第九拍','李綱','宋','宋诗','song-poetry','','[]','五陵佳氣無時無，龍種自與常人殊。',64,'全唐诗/poet.song.90000.json','["五陵佳氣無時無，龍種自與常人殊。", "一去紫臺連朔漠，骨肉滿眼身羈孤。", "金鞭斷折九馬死，邂逅豈即非良圖。", "人間俯仰成今古，豈憶當殿羣臣趨。"]'),
('029ca585-6ebe-45df-8cb2-e96320a04d74','胡笳十八拍 第十拍','李綱','宋','宋诗','song-poetry','','[]','人生失意無南北，去住彼此無消息。',64,'全唐诗/poet.song.90000.json','["人生失意無南北，去住彼此無消息。", "黄蒿古城雲不開，時復看雲淚横臆。", "猛將腰間大羽箭，一箭正墜雙飛翮。", "汝休枉殺南飛鴻，道路只今多擁隔。"]'),
('aee77966-c287-4a35-b838-2a7accb1006b','胡笳十八拍 第十一拍','李綱','宋','宋诗','song-poetry','','[]','天子不在咸陽宫，翠華拂天來向東。',64,'全唐诗/poet.song.90000.json','["天子不在咸陽宫，翠華拂天來向東。", "江間波浪兼天湧，中有雲氣隨飛龍。", "干戈兵革鬬未止，無復射蛟江水中。", "江邊老人錯料事，時危慘澹來悲風。"]'),
('9953fe8b-885f-487e-8c1a-24ddd9e811d9','胡笳十八拍 第十二拍','李綱','宋','宋诗','song-poetry','','[]','漁陽突騎獵青丘，天馬跋足隨犛牛。',64,'全唐诗/poet.song.90000.json','["漁陽突騎獵青丘，天馬跋足隨犛牛。", "幕前生致九青兕，苦寒贈我青羔裘。", "萬里飛蓬映天過，歲云暮矣增離憂。", "如今正南看北斗，長安不見使人愁。"]'),
('a29a6195-c4a4-46c3-a70f-96b6800922b1','胡笳十八拍 第十三拍','李綱','宋','宋诗','song-poetry','','[]','聖朝尚飛戰鬬塵，椎鼓鳴鐘天下聞。',64,'全唐诗/poet.song.90000.json','["聖朝尚飛戰鬬塵，椎鼓鳴鐘天下聞。", "岸上荒村盡豺虎，衣冠南渡多崩犇。", "何時鑄戟作農器，欲傾東海洗乾坤。", "干戈未定失壯士，舊事無人可共論。"]'),
('a8db8276-860d-4ecb-9f8a-0b37e3116c54','胡笳十八拍 第十四拍','李綱','宋','宋诗','song-poetry','','[]','大麥乾枯小麥黄，問誰腰鐮胡與羌。',64,'全唐诗/poet.song.90000.json','["大麥乾枯小麥黄，問誰腰鐮胡與羌。", "漢家戰士三十萬，此豈有意仍騰驤。", "安得突騎只五千，長驅東胡胡走藏。", "近静潼關掃螻蟻，爲留猛士守未央。"]'),
('916ac56b-45c1-4aa9-8044-cd95e7c528be','胡笳十八拍 第十五拍','李綱','宋','宋诗','song-poetry','','[]','我生之後漢祀衰，經濟實藉英雄姿。',64,'全唐诗/poet.song.90000.json','["我生之後漢祀衰，經濟實藉英雄姿。", "遥拱北辰纒寇盗，杳杳南國多旌旗。", "傷心不忍問耆舊，垂老惡聞戰鼓悲。", "中夜起坐萬感集，誰家搗練風凄凄。"]'),
('67b01b06-8ec0-4631-93d0-8b0c8760228a','胡笳十八拍 第十六拍','李綱','宋','宋诗','song-poetry','','[]','雨聲颼颼催早寒，歲暮窮陰耿未已。',64,'全唐诗/poet.song.90000.json','["雨聲颼颼催早寒，歲暮窮陰耿未已。", "燕山雪花大如席，寒刮肌膚北風利。", "羣胡歸來血洗箭，陣前部曲終日死。", "漫漫胡天叫不聞，日夜更望官軍至。"]'),
('b6a4ccac-52ad-4d43-b768-17ae5788b0ac','胡笳十八拍 第十七拍','李綱','宋','宋诗','song-poetry','','[]','時危始識不世材，成王功大心轉小。',66,'全唐诗/poet.song.90000.json','["時危始識不世材，成王功大心轉小。", "豺狼塞路人斷絕，一門骨肉散百草。", "江頭宫殿鎖千門，不知明月爲誰好。", "何時眼前突兀見此屋，鷄鳴問寢龍樓曉。"]'),
('fd5a9779-9254-4d40-b1f1-447c72ec24e0','胡笳十八拍 第十入拍','李綱','宋','宋诗','song-poetry','','[]','風塵澒洞昏王室，咫尺波濤永相失。',64,'全唐诗/poet.song.90000.json','["風塵澒洞昏王室，咫尺波濤永相失。", "漂然時危一老翁，灑血江漢長衰疾。", "笳一會兮琴一拍，青山落日江湖白。", "身欲奮飛病在牀，此心炯炯君應識。"]'),
('a21e4b2a-39de-4928-a62e-5f90c0af07c0','重陽日醉中戲集子美句遣興  其一','李綱','宋','宋诗','song-poetry','','[]','青山落日江湖白，飄零已是滄浪客。',96,'全唐诗/poet.song.90000.json','["青山落日江湖白，飄零已是滄浪客。", "老去悲秋强自寛，青蘂重陽不堪摘。", "東流江水西飛鷰，傳語風光共流轉。", "急觴爲緩憂心擣，休語艱難尚酣戰。", "聖朝尚飛戰鬭塵，何用浮名絆此身。", "時復看雲淚横臆，晚來幽獨恐傷神。"]'),
('207c0ffe-1fb9-4b70-ba16-4cbd0a66c147','重陽日醉中戲集子美句遣興  其二','李綱','宋','宋诗','song-poetry','','[]','籬邊老却陶潛菊，開花無數黄金錢。',96,'全唐诗/poet.song.90000.json','["籬邊老却陶潛菊，開花無數黄金錢。", "且看欲盡花經眼，飲如長鯨吸百川。", "只今漂泊干戈際，方外酒徒稀醉眠。", "腐儒衰晚謬通籍，杜曲幸有桑麻田。", "故畦遺穗已蕩盡，中原君臣豺虎邊。", "安得務農息戰鬪，武陵欲問桃花源。"]'),
('8d618cba-a226-4d99-a3d7-6c5bc0a1d88a','夜寢夢遊泗上觀重建僧伽塔纔兩層塔以今春同普照王寺焚蕩殆盡豈大士有意再來此土乎覺而賦詩以紀之','李綱','宋','宋诗','song-poetry','','[]','至人於世何所求，隨緣應物初不留。',224,'全唐诗/poet.song.90000.json','["至人於世何所求，隨緣應物初不留。", "緣合則應散則休，起滅幻境如浮漚。", "僧伽塔踞淮泗流，火焚水轉歲幾周。", "國家崇奉德更優，雍熙所建無與儔。", "層層金碧巧雕鎪，鑿石作址蟠龍虬。", "簷間寶鈴韻琳璆，勢插霄漢神爲謀。", "瑞光煥發垂珠旒，青天白日爛不收。", "崔巍髙殿聳飛樓，千楹萬柱烟雲浮。", "誰知興廢相綢繆，鐵馬馳突横戈矛。", "四方羣盜起如蟊，付以一炬成荒丘。", "慈航濟物衆所庥，捨我去矣真可憂。", "昨宵夢到淮上洲，窣堵再造工方鳩。", "千章巨木回萬牛，此豈有意重來不。", "塔成大士還舊遊，更扶休運三千秋。"]'),
('c643197c-f605-4a0d-a385-e93e75ff610c','次韻淵明讀山海經','李綱','宋','宋诗','song-poetry','','[]','清霜落喬木，翠色颯以疏。',96,'全唐诗/poet.song.90000.json','["清霜落喬木，翠色颯以疏。", "而我正臥病，蕭然寓精廬。", "起坐無與歡，散帙聊觀書。", "心遊千載間，超詣非舟車。", "更酌一杯酒，薦此果與蔬。", "緬懷陶淵明，雅志與我俱。", "還看枕間屏，乃是歸來圖。", "古人不予欺，歲暮將何如。"]'),
('7b9d4eba-95b3-4c75-beb3-1bc55508eac0','余築室梁谿之上三年而後成手植花木甚衆遭值世故未嘗得安居其間歲暮羈旅慨然念之因和淵明時運詩以見意','李綱','宋','宋诗','song-poetry','','[]','卜宅梁谿，成非一朝。',160,'全唐诗/poet.song.90000.json','["卜宅梁谿，成非一朝。", "面山枕岡，遠市近郊。", "脩竹茂林，翠連烟霄。", "松桂吐香，杞菊長苗。", "旁臨清流，塵纓可濯。", "小閣崷然，九峰遠瞩。", "豈無華宇，於我自足。", "兄弟塤箎，於焉相樂。", "春服既成，如浴乎沂。", "風乎舞雩，詠嘯而歸。", "自我離羣，潛然涕揮。", "拊心念舊，電往莫追。", "今夕何夕，夢還我廬。", "稚子候門，兩髪髧如。", "携幼入室，濁酒傾壺。", "慨我寤歎，誰復如余。"]'),
('865a3684-fe8f-4f07-bc2b-4e59d2259742','梁谿八詠 中隱堂','李綱','宋','宋诗','song-poetry','','[]','不在山林不市朝，且將圖史當漁樵。',32,'全唐诗/poet.song.90000.json','["不在山林不市朝，且將圖史當漁樵。", "桂花想見秋來盛，香滿西風取次飄。"]'),
('15740390-e6e7-4b4c-aebb-88d7e0a306b9','梁谿八詠 棣華堂','李綱','宋','宋诗','song-poetry','','[]','兄弟塤箎人所推，棣華堂裏遠相思。',32,'全唐诗/poet.song.90000.json','["兄弟塤箎人所推，棣華堂裏遠相思。", "艱難世路風霜急，正是鶺鴒原上時。"]'),
('a6eef792-d7b8-4f65-9d5c-722b122caab2','梁谿八詠 文會堂','李綱','宋','宋诗','song-poetry','','[]','親賓情話款衡門，把酒揮毫氣吐雲。',32,'全唐诗/poet.song.90000.json','["親賓情話款衡門，把酒揮毫氣吐雲。", "何日寛思返三徑，一樽重與細論文。"]'),
('61a71949-4585-4054-bad1-4280b00c94da','梁谿八詠 九峰閣','李綱','宋','宋诗','song-poetry','','[]','小閣崢嶸面九峰，暮天秀出碧芙蓉。',32,'全唐诗/poet.song.90000.json','["小閣崢嶸面九峰，暮天秀出碧芙蓉。", "孔明夲有躬耕志，却合歸來看臥龍。"]'),
('da626cb1-4a13-43d4-b14e-f4cc0496d23a','梁谿八詠 舫齋','李綱','宋','宋诗','song-poetry','','[]','畫舫臨流四面通，綠窗面面有清風。',32,'全唐诗/poet.song.90000.json','["畫舫臨流四面通，綠窗面面有清風。", "年來始會虚舟意，正在江湖波浪中。"]'),
('702ca3f9-03b5-459c-9219-f975cc9750e8','梁谿八詠 怡亭','李綱','宋','宋诗','song-poetry','','[]','縹緲危亭枕曲池，紅粧翠羽自參差。',32,'全唐诗/poet.song.90000.json','["縹緲危亭枕曲池，紅粧翠羽自參差。", "晚凉小飲誰同醉，定把圓荷當屈巵。"]'),
('1b1342c9-336d-4c20-a6fa-f30e3775f8da','梁谿八詠 心遠亭','李綱','宋','宋诗','song-poetry','','[]','境寂心閑物物宜，倚欄更看嶺雲飛。',32,'全唐诗/poet.song.90000.json','["境寂心閑物物宜，倚欄更看嶺雲飛。", "曉猿夜鶴應思我，正好歸時猶未歸。"]'),
('b5bcc187-ab63-452a-b72f-474d2665c218','梁谿八詠 濯纓亭','李綱','宋','宋诗','song-poetry','','[]','畫棟飛簷俯碧流，何時歸去艤扁舟。',32,'全唐诗/poet.song.90000.json','["畫棟飛簷俯碧流，何時歸去艤扁舟。", "不須更把塵纓濯，直取冠裳裂即休。"]'),
('ca3d7d53-ef0c-48c5-9b8c-659ac1c793f3','和淵明歸田園居六首  其一','李綱','宋','宋诗','song-poetry','','[]','東吳信佳地，碧溪繞青山。',120,'全唐诗/poet.song.90000.json','["東吳信佳地，碧溪繞青山。", "我居枕溪傍，卜築亦有年。", "山空乳滿腹，迸出蒼龍淵。", "餘波滑無聲，下灌負郭田。", "秋風粳稻香，落照孤鴻間。", "黄鷄與紫蟹，日滿樽俎前。", "酌酒燕賓友，揮毫散雲烟。", "常謂享此樂，可以終華顛。", "豈知縈世故，擾擾不得閒。", "側身念吾廬，悵望情依然。"]'),
('cdfc0f8f-d1a1-42b8-b719-39858ee27cee','和淵明歸田園居六首  其二','李綱','宋','宋诗','song-poetry','','[]','一爲世網嬰，未遂稅塵鞅。',72,'全唐诗/poet.song.90000.json','["一爲世網嬰，未遂稅塵鞅。", "驅馳途路間，空積溪山想。", "我居今若何，歲月忽已往。", "三徑將荒蕪，松菊日應長。", "泛舟苕霅間，吾意誠已廣。", "時危方艱難，長恐墮渺莽。"]'),
('c5439d85-6b7a-4224-bffd-26006cbd4817','和淵明歸田園居六首  其三','李綱','宋','宋诗','song-poetry','','[]','人生不滿百，七十亦云稀。',48,'全唐诗/poet.song.90000.json','["人生不滿百，七十亦云稀。", "吾年甫知命，飄泊猶未歸。", "江湖歲將晏，霜露霑人衣。", "滄洲惠詢約，坐恐此志違。"]'),
('93e276aa-9c3a-40a5-a8e6-e020e811c488','和淵明歸田園居六首  其四','李綱','宋','宋诗','song-poetry','','[]','平生愛武林，湖山良可娛。',96,'全唐诗/poet.song.90000.json','["平生愛武林，湖山良可娛。", "連年兵火作，景物成丘墟。", "常願買一廛，築室湖上居。", "開軒蒼翠間，手植松千株。", "浮家同志和，來往得自如。", "樽中酒不空，樂死不願餘。", "那知今乃爾，此懷坐成虛。", "已矣何所道，萬法皆本無。"]'),
('e5d24545-9715-4438-bdb9-1b220244066c','和淵明歸田園居六首  其五','李綱','宋','宋诗','song-poetry','','[]','毎愛賀知章，勅賜鑑湖曲。',60,'全唐诗/poet.song.90000.json','["毎愛賀知章，勅賜鑑湖曲。", "而我不須多，數頃亦已足。", "世故俛仰間，反覆若棋局。", "良辰逝莫留，勝遊當秉燭。", "明月照芳樽，坐待東方旭。"]'),
('521460a1-3a24-4a43-ba36-baef19508e44','和淵明歸田園居六首  其六','李綱','宋','宋诗','song-poetry','','[]','我昔居梁谿，夢斷長安陌。',84,'全唐诗/poet.song.90000.json','["我昔居梁谿，夢斷長安陌。", "倒冠與落佩，志氣良自適。", "花前飲春朝，月下舞秋夕。", "自從喪亂來，光景駒過隙。", "無復舊情懷，擾擾爲物役。", "寤寐憂他人，自麻初不績。", "長嘯休去來，勞生亦何益。"]'),
('1fa39916-6320-41da-b6f0-756f895a4b2b','小雨','李綱','宋','宋诗','song-poetry','','[]','小雨廉纖作曉寒，繞簷疏竹正檀欒。',64,'全唐诗/poet.song.90000.json','["小雨廉纖作曉寒，繞簷疏竹正檀欒。", "窮愁著論墨長濕，磊塊澆胸杯未乾。", "莊舄顯時猶越語，鍾儀縶處亦南冠。", "百憂萬感無時了，更賦新詩强自寛。"]'),
('e1119d87-6fd2-4aba-8c49-5f3988147f60','客餉新橙有感','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','湖外新橙也自黄，故人相贈解包香。',64,'全唐诗/poet.song.90000.json','["湖外新橙也自黄，故人相贈解包香。", "擣虀正鱠雙魚美，薦酒聊持一瓣嘗。", "湛峴舊栽千樹橘，洞庭初落滿林霜。", "木奴供給何須道，悵望東吳雲水郷。"]'),
('3a47f94c-ba99-4327-8897-ad287c258518','偶得雙鯉付厨作鱠以薦一觴','李綱','宋','宋诗','song-poetry','','[]','雙鯉從來丙穴東，霜刀縷切膾花紅。',64,'全唐诗/poet.song.90000.json','["雙鯉從來丙穴東，霜刀縷切膾花紅。", "銀絲藿葉自争巧，玉筋金盤未覺空。", "德飽姜侯情已重，詩成杜老志應同。", "秋風笠澤鱸尤美，何日扁舟入手中。"]'),
('21303d55-e9af-4d5e-88d3-cbf0af3ed674','和淵眀擬古九首  其一','李綱','宋','宋诗','song-poetry','','[]','風霜已搖落，天氣猶清和。',60,'全唐诗/poet.song.90000.json','["風霜已搖落，天氣猶清和。", "聊持一樽酒，自飲還自歌。", "朝心愁不開，暮髪白已多。", "朱顔與綠鬂，颯若霜萎荷。", "流年不我與，不飲如老何。"]'),
('05261232-f79a-41bb-9d5c-7b800878d381','和淵眀擬古九首  其二','李綱','宋','宋诗','song-poetry','','[]','驚心如傷禽，衰質若凋柳。',84,'全唐诗/poet.song.90000.json','["驚心如傷禽，衰質若凋柳。", "百年能幾時，處世安得久。", "寤寐若有失，哀我泉下友。", "平生不識面，况復衘杯酒。", "知心乃如斯，此意豈可負。", "管鮑貧時交，於古亦云厚。", "范張久已亡，今人那復有。"]'),
('159245df-912c-40bc-b6ba-ce5e0cb46cb0','和淵眀擬古九首  其三','李綱','宋','宋诗','song-poetry','','[]','階禍初甚微，智者能要終。',72,'全唐诗/poet.song.90000.json','["階禍初甚微，智者能要終。", "被髪祭於野，辛有知其戎。", "時平足諛佞，世亂多姦雄。", "坐令夷亂華，誕謾本晉風。", "重華不再作，吾道何其窮。", "已矣可奈何，此生如夢中。"]'),
('bd9a6dfe-fc16-4a02-8672-617ea17884f0','和淵眀擬古九首  其四','李綱','宋','宋诗','song-poetry','','[]','棄置帝王宅，乃欲保一隅。',72,'全唐诗/poet.song.90000.json','["棄置帝王宅，乃欲保一隅。", "一隅豈易保，巨盜連荆舒。", "眷言浙江西，有我先人廬。", "兵火偶不到，聚族於焉居。", "羈束未得歸，田園日將蕪。", "江邊畏羣盜，歲暮當何如。"]'),
('e176468e-abd8-4b0d-a299-ca4fb3f43528','和淵眀擬古九首  其五','李綱','宋','宋诗','song-poetry','','[]','立國有常理，恩威撫要荒。',96,'全唐诗/poet.song.90000.json','["立國有常理，恩威撫要荒。", "胡爲决藩籬，坐使寇及堂。", "憑髙寓遠目，中原氣蒼茫。", "昔時冠蓋地，今日争戰塲。", "玉輦幸朔漠，金椀出北邙。", "腐儒獻奇策，碧衣坐稱昂。", "儻無濟時略，何以綏四方。", "蒼生未蘇息，慨歎情內傷。"]'),
('6d2b177f-364b-4900-81da-350e0bb5c1ec','和淵眀擬古九首  其六','李綱','宋','宋诗','song-poetry','','[]','吾憐靖節翁，食少衣不完。',96,'全唐诗/poet.song.90000.json','["吾憐靖節翁，食少衣不完。", "棄禄緣束带，貴身遂抛冠。", "簞瓢有餘樂，不慚陋巷顔。", "成趣園日涉，息交戶常關。", "返觀富與貴，一塵集毫端。", "素琴久無絃，適意自可彈。", "處心慕黔婁，抗志同伯鸞。", "斯人骨已朽，霜霰時方寒。"]'),
('c983aa11-a07c-47ec-b58e-df17b09e4158','和淵眀擬古九首  其七','李綱','宋','宋诗','song-poetry','','[]','古今紛變態，兹道長若兹。',108,'全唐诗/poet.song.90000.json','["古今紛變態，兹道長若兹。", "處世或窮達，否泰各有時。", "豈無磨與涅，貴在不磷緇。", "達人乃大觀，曲士多致疑。", "所以古聖賢，立此垂世辭。", "慇懃論出處，欲使學者思。", "周公尚居東，仲尼豈余欺。", "愈鈍久乃利，臲卼當安之。", "我亦道窮者，欲賦鴟鴞詩。"]'),
('44680883-c6af-4277-be33-0ca98d845481','和淵眀擬古九首  其八','李綱','宋','宋诗','song-poetry','','[]','結髪慕古人，絕俗期遠遊。',72,'全唐诗/poet.song.90000.json','["結髪慕古人，絕俗期遠遊。", "如登太山頂，志氣小九州。", "古今會遷變，萬壑無停流。", "向來富貴者，纍纍但荒丘。", "漢唐已磨滅，况復秦與周。", "惟餘節義士，可向編簡求。"]'),
('48697624-fe82-43f0-852c-4e981001dd8c','和淵眀擬古九首  其九','李綱','宋','宋诗','song-poetry','','[]','青松生髙岡，無意斧斤採。',60,'全唐诗/poet.song.90000.json','["青松生髙岡，無意斧斤採。", "歲寒霜霰深，未覺柯葉改。", "梁鴻既適吳，管寧亦浮海。", "二子得我心，髙舉不相待。", "士生不逢時，命矣何所悔。"]'),
('df00c785-9349-4313-b99a-27d2416e0fa8','余來湖外家問不通者累月因和淵明停雲篇以遣懷','李綱','宋','宋诗','song-poetry','','[]','上天停雲，以陰以雨。',160,'全唐诗/poet.song.90000.json','["上天停雲，以陰以雨。", "我之懷矣，川路修阻。", "田園將蕪，幼稚誰撫。", "鴈信來遲，鶴立以佇。", "凄其以風，零雨其濛。", "自去梁谿，爰止西江。", "一室蕭然，臥于北窗。", "塊獨處此，人誰我從。", "豈無軒裳，誰適爲榮。", "人之爲人，亦以有情。", "亂離瘼矣，棄家遐征。", "知我如此，不如無生。", "今夕何夕，鵲嫋庭柯。", "載植其尾，迭相鳴和。", "發書占之，遠問爲多。", "兆而未至，懷哉若何。"]'),
('f234a2c8-56b6-4411-b90b-140f10c3eb47','霜降木落獨松柏蒼然顔色愈好因和淵明榮木篇以見意','李綱','宋','宋诗','song-poetry','','[]','采采榮木，春華于兹。',160,'全唐诗/poet.song.90000.json','["采采榮木，春華于兹。", "及爾素秋，風霜瘁之。", "寒暑代謝，榮枯有時。", "改柯易葉，翩其隕而。", "蒼蒼松柏，擢榦蟠根。", "風霜雖厲，秀色長存。", "君子進德，以道爲門。", "歲寒時艱，節義彌敦。", "惟天於余，賦此拙陋。", "材不趨新，學惟求舊。", "黽勉夙夜，其何能富。", "屢冒艱危，內省不疚。", "先公有訓，豈敢失墜。", "敬慎威儀，聖言是畏。", "鉛刀雖鈍，駑馬希驥。", "一割之功，十駕而至。"]'),
('01464248-0cfa-4465-86c6-bdbdf6be91ee','和歸鳥篇','李綱','宋','宋诗','song-poetry','','[]','翼翼歸鳥，爰集于林。',160,'全唐诗/poet.song.90000.json','["翼翼歸鳥，爰集于林。", "近萃芳郊，遠依煙岑。", "眷言顧之，實獲我心。", "叢木茂止，憇此繁陰。", "翼翼歸鳥，翩然翻飛。", "風髙天闊，去將疇依。", "雲路翺翔，倦翮思歸。", "矰繳孔多，無使患遺。", "翼翼歸鳥，撫翼徘徊。", "江湖緲茫，有懷故棲。", "顧儔嘯侣，鳴聲和諧。", "願言不獲，悵然傷懷。", "翼翼歸鳥，集于舊條。", "一枝已多，豈俟髙標。", "歛翰息影，好音交交。", "願言終此，以休永勞。"]'),
('723b6ace-edf6-4b51-9857-291c57db377f','和勸農篇','李綱','宋','宋诗','song-poetry','','[]','天臨下土，是生烝民。',240,'全唐诗/poet.song.90000.json','["天臨下土，是生烝民。", "耕食鑿飲，乃含其真。", "淳澆樸散，巧僞相因。", "誰其還之，時惟聖人。", "聖人立政，爰重黍稷。", "設命官司，職是播植。", "春勤于耕，秋乃有穡。", "儲其嬴餘，荒歲足食。", "瞻彼中原，祁邳平陸。", "春日載陽，和風肅穆。", "夫耕婦饁，儔類相逐。", "少壯竭力，逸此耆宿。", "豈無他圖，惟兹永久。", "利其耒耜，十千維耦。", "带月荷鋤，侵星耘畝。", "崇本抑末，孰敢游手。", "終年厭飱，報則不貴。", "千箱萬倉，以副汝冀。", "爲酒爲醴，樂此分至。", "仰奉俯畜，夫復何愧。", "四體不勤，丈人所鄙。", "带經而耕，豈廢冠履。", "我思古人，希風往軌。", "躬耕南陽，無使專美。"]'),
('ff4d1172-3bb2-4784-a9c1-92c8f8dbaf6f','秋雨初霽天髙氣清獨遊山間意欣然樂之因和淵明遊斜川詩以紀其事','李綱','宋','宋诗','song-poetry','','[]','歲律忽晼晚，我生感行休。',120,'全唐诗/poet.song.90000.json','["歲律忽晼晚，我生感行休。", "雨餘秋氣清，策杖成獨遊。", "蒼蒼松桂合，中有清淺流。", "放懷佀樵者，忘機狎飛鷗。", "顧我疏散姿，自合在一丘。", "但恨尚羈束，塊處無朋儔。", "獨酌誰與共，獨歌誰與酬。", "此獨有至樂，當有知者不。", "盜賊紛滿眼，世故端百憂。", "置之且勿道，獨樂未易收。"]'),
('c1e48832-c0cd-4604-a643-455b5fe5c2c7','後重九半月菊始開因思東坡言菊花開日即重陽取酒爲之一醉遂和淵明已酉歲九月九日之作','李綱','宋','宋诗','song-poetry','','[]','地偏菊開晚，乃在秋冬交。',96,'全唐诗/poet.song.90000.json','["地偏菊開晚，乃在秋冬交。", "霜中色艷艷，肯逐蓬艾凋。", "感此節物殊，爲爾再登髙。", "玉觴泛金英，舉酒望層霄。", "雲氣有佳色，此豈瞪發勞。", "世態互陵滅，冰炭方凝焦。", "不如醉後眠，意味真陶陶。", "何論飲而壽，且以樂此朝。"]'),
('4681da90-87f4-4f35-b4a8-43c40de14a47','得梁谿家問足慰遠懷因和淵明答龐參軍之作','李綱','宋','宋诗','song-poetry','','[]','剝啄叩門，梁谿有書。',240,'全唐诗/poet.song.90000.json','["剝啄叩門，梁谿有書。", "發函讀之，遠懷以娛。", "長少童稚，咸安其居。", "森然滿前，如返我廬。", "一書可寶，萬金非珍。", "契闊寤歎，乃兹相親。", "鵲不吾欺，鳴以告人。", "載詢僕夫，以及其鄰。", "嗟我諸季，鷄鳴孜孜。", "左圖右書，中心好之。", "山川修阻，貽我以詩。", "三復佳句，實慰所思。", "翩翩鴻鴈，暫聚亟分。", "豈無他人，非我所欣。", "清宵步月，白日看雲。", "無遐邇心，好音數聞。", "昔我之來，鶗鴂將鳴。", "今也歲晏，霜露載零。", "言念沙漠，有懷玉京。", "終夕不寐，羣生未寧。", "悵望東吳，慨臨西風。", "願化獨鶴，烟霄可冲。", "敬慎威儀，惟以令終。", "黄髪爲期，其愛爾躬。"]'),
('d4555ded-410f-424f-a540-2281c5671c24','叔易得水晶筆格賦詩見寄因次其韻頃與叔易奕而勝得其銅獸鑪製度甚古攜行常置几案間今此格宜以贈遠與爐爲伴故卒章及之','李綱','宋','宋诗','song-poetry','','[]','武夫惡文士，每見輒不喜。',216,'全唐诗/poet.song.90000.json','["武夫惡文士，每見輒不喜。", "排紛須大劍，安用毛錐子。", "豈知管城翁，功閥著青史。", "羲之筆陣圖，善戰固其理。", "賢哉小謫仙，好古良有以。", "獨憐中書君，飄泊無定止。", "誰將素琅玕，實此錦綉篚。", "瑶山列羣峰，玉筍連厥趾。", "置君丘壑間，未覺形神滓。", "光聯玉蟾蜍，含凍共棐几。", "玲瓏小九華，一一名可指。", "作詩寄遠人，爲洗塵埃耳。", "秀句與珍玩，清絕那可擬。", "燦然珠玉間，尚許蒹葭倚。", "我生墮江湖，放浪謝簪縰。", "塵泓久寂寞，秃穎亦頽委。", "當爲千里贈，勿念一枰恥。", "配此古獸爐，縹緲孤煙起。"]'),
('d22642f2-df20-45da-8b19-6f007fc7d466','次韻叔易四絕句  其一','李綱','宋','宋诗','song-poetry','','[]','落日西風粳稻香，畦間散策月荒凉。',32,'全唐诗/poet.song.90000.json','["落日西風粳稻香，畦間散策月荒凉。", "誰知萬頃黄雲熟，行客初看插綠秧。"]'),
('05add889-b6d0-46e1-be5a-81309367af15','次韻叔易四絕句  其二','李綱','宋','宋诗','song-poetry','','[]','笑續離騷賦遠遊，霜寒雲夢杳然秋。',32,'全唐诗/poet.song.90000.json','["笑續離騷賦遠遊，霜寒雲夢杳然秋。", "何時把釣梁谿上，醉嚼蟹螯餘罷休。"]'),
('85a02b80-db3a-483a-b9da-7fc0548f63b2','次韻叔易四絕句  其三','李綱','宋','宋诗','song-poetry','','[]','身閒且作地行仙，謫墮江湖豈偶然。',32,'全唐诗/poet.song.90000.json','["身閒且作地行仙，謫墮江湖豈偶然。", "幸有惠連詩句好，不妨青紙寄新篇。"]'),
('96b1b16d-2626-4856-8854-58e9ef4e4d56','次韻叔易四絕句  其四','李綱','宋','宋诗','song-poetry','','[]','初寒一醉萬家春，尚有陶翁漉酒巾。',32,'全唐诗/poet.song.90000.json','["初寒一醉萬家春，尚有陶翁漉酒巾。", "五牧潘葑新釀熟，開樽應憶未歸人。"]'),
('cd632b2d-afa9-431c-93a6-c4c79900bcc9','山居四詠 紙帳','李綱','宋','宋诗','song-poetry','','[]','潔如白疊軟於氈，縠浪龜紋細結聯。',64,'全唐诗/poet.song.90000.json','["潔如白疊軟於氈，縠浪龜紋細結聯。", "雅稱獨欹班竹枕，最宜深炷紫沉煙。", "斜風細雨吳綾暖，萬草千花蜀錦鮮。", "何似禪房褚夫子，日髙覆幬擁衾眠。"]'),
('71a92914-9b8d-446b-8a23-8037ece6dc13','山居四詠 竹枕','李綱','宋','宋诗','song-poetry','','[]','此君勁節傲風霜，髙臥尤宜逐客牀。',64,'全唐诗/poet.song.90000.json','["此君勁節傲風霜，髙臥尤宜逐客牀。", "雅製頗同琴可薦，瑩膚端與玉爭涼。", "欲憑幻境成佳夢，故使通中貯祕方。", "富貴功名本何有，覺來猶未熟黄粱。"]'),
('b74d7c46-febd-4774-addc-4fa9dd69ada6','山居四詠 地爐','李綱','宋','宋诗','song-poetry','','[]','小寒聊試地爲爐，端爲先生病更癯。',64,'全唐诗/poet.song.90000.json','["小寒聊試地爲爐，端爲先生病更癯。", "炙背願馳金騕褭，藉床初展錦氍毹。", "聳肩傍壁詩千字，爆栗燒氈酒一壺。", "便擬慇懃事丹竈，朝晡稱火較錙銖。"]'),
('cf7c81e2-7202-4878-b26b-557540e0c05e','山居四詠 石銚','李綱','宋','宋诗','song-poetry','','[]','誰刳蒼玉事煎烹，形製深寛潔且輕。',64,'全唐诗/poet.song.90000.json','["誰刳蒼玉事煎烹，形製深寛潔且輕。", "觱沸未看浮蟹眼，颼飀先聽起松聲。", "龍頭豕腹徒謿誚，鐵澀銅腥費挈擎。", "多病文園苦消渇，煮泉瀹茗正須卿。"]'),
('7b64419f-03f9-4bb0-b164-d88f665c7c26','山居遣興四首  其一','李綱','宋','宋诗','song-poetry','','[]','偶向忙時乞得身，山居岑寂絕比鄰。',64,'全唐诗/poet.song.90000.json','["偶向忙時乞得身，山居岑寂絕比鄰。", "雀羅可設門無客，酒盞頻傾句有神。", "隱背時煩木童子，伴眠猶有竹夫人。", "蒼生未定郊多壘，敢向長沮與問津。"]'),
('7362d11f-8795-4dfc-9c7f-47af19ad6061','山居遣興四首  其二','李綱','宋','宋诗','song-poetry','','[]','三黜先生髪半華，但將筆墨作生涯。',64,'全唐诗/poet.song.90000.json','["三黜先生髪半華，但將筆墨作生涯。", "已知晏食能勝肉，更覺安行可當車。", "月好只愁無竹葉，風來自與掃巖花。", "江邊盜賊休窺伺，不是宣和宰相家。"]'),
('5d85f826-3e19-4af0-92e7-2410ec881064','山居遣興四首  其三','李綱','宋','宋诗','song-poetry','','[]','秋杪幽居分外清，傍簷鳥雀自和鳴。',64,'全唐诗/poet.song.90000.json','["秋杪幽居分外清，傍簷鳥雀自和鳴。", "過時黄菊渾無賴，入眼青山獨有情。", "酒後暈紅潮玉頰，吟餘儿杖殷金聲。", "前村野老能棋戰，時與呼來對一枰。"]'),
('18c1a4d5-97f2-414c-a54d-857dbedaea85','山居遣興四首  其四','李綱','宋','宋诗','song-poetry','','[]','沉陰天色半含情，小院重門晝掩扃。',64,'全唐诗/poet.song.90000.json','["沉陰天色半含情，小院重門晝掩扃。", "一枕睡餘香未散，三甌茶後酒初醒。", "山雲舒卷閒中看，竹雨蕭疏静處聽。", "愁寂最憐霜後菊，案頭亁死有微馨。"]'),
('5dc0d9f7-e031-4902-91c1-3b1edc3e4cc3','趙叔𩅿運判見示宣和御畫二軸其一馬舉足奮迅將起其一兔正面踞地齧草皆絕去筆墨畦徑間意態如生精妙入神伏觀歎息感慨因賦詩二篇以贊揚宸翰且叙小臣悽憤之情云 馬','李綱','宋','宋诗','song-poetry','','[]','宣和天廐多清新，肉鬃汗血皆翔麟。',128,'全唐诗/poet.song.90000.json','["宣和天廐多清新，肉鬃汗血皆翔麟。", "圉人牽來赤墀下，宸筆落紙親傳神。", "非行非立非馳逐，獨寫騰身前舉足。", "展沙奮迅欲嘶風，驤首驂驔初噴玉。", "流雲飛電五花驄，庭前榻上雙真龍。", "始知韓幹畫多肉，坐使冀北羣皆空。", "鑾輿遠狩龍荒外，八駿瑤池杳何詣。", "空留此馬落人間，感憤暗灑纍臣涕。"]'),
('eefaa349-20d7-4075-a74d-506987c270da','趙叔𩅿運判見示宣和御畫二軸其一馬舉足奮迅將起其一兔正面踞地齧草皆絕去筆墨畦徑間意態如生精妙入神伏觀歎息感慨因賦詩二篇以贊揚宸翰且叙小臣悽憤之情云 兔','李綱','宋','宋诗','song-poetry','','[]','草枯霜落秋風髙，中山之兔初長毫。',128,'全唐诗/poet.song.90000.json','["草枯霜落秋風髙，中山之兔初長毫。", "天姿狡健雅善走，韓盧宋鵲紛騰逃。", "帝居深沉九重裏，何自得此山林意。", "枯荄咀嚼如有聲，缺口長須聳雙耳。", "宣和天子儲聦明，天縱將聖尤多能。", "萬機閒暇戲染翰，作此東郭髦鬅鬙。", "胡塵漠漠暗沙磧，屬車一去無消息。", "安得壮士東擒胡，雞鳴問寢還龍德。"]'),
('8d2902b8-f96b-4fc9-a057-179ad1dd62b5','仲輔和寄送季弟詩復次韻寄之  其一','李綱','宋','宋诗','song-poetry','','[]','塊處江城無與遊，蘆花楓葉楚天秋。',64,'全唐诗/poet.song.90000.json','["塊處江城無與遊，蘆花楓葉楚天秋。", "蕭然霜鬢傷遲暮，久矣灰心任去留。", "道阻每懷千里念，時危豈爲一身憂。", "何年棣蕚還相映，醉臥元龍百尺樓。"]'),
('31d89ce6-ac15-4986-9619-730517296f2d','仲輔和寄送季弟詩復次韻寄之  其二','李綱','宋','宋诗','song-poetry','','[]','新詩寄遠慰南冠，墜露遥知飲木蘭。',64,'全唐诗/poet.song.90000.json','["新詩寄遠慰南冠，墜露遥知飲木蘭。", "素愛少游乘下澤，尚憐子美縳微官。", "遭罹貝錦如吾少，漂泊兵戈見汝難。", "華髪比年老兄弟，相思對案不能餐。"]'),
('0649e2a3-85ed-4282-b75a-3cd12cfb48df','王周士以幅素圖萬石巖見示','李綱','宋','宋诗','song-poetry','','[]','不須避世向桃源，自有巖中小洞天。',64,'全唐诗/poet.song.90000.json','["不須避世向桃源，自有巖中小洞天。", "漱石枕流塵境外，巢雲臥月玉峰前。", "髙懷肯顧三千石，福地真同十九泉。", "小隱羨君誠得計，我方憂惴老江邊。"]'),
('900f0419-b935-4ca0-aa39-55e56daa26c7','煨芋','李綱','宋','宋诗','song-poetry','','[]','禪房夜坐腹半饑，寒爐撥火煨蹲鴟。',96,'全唐诗/poet.song.90000.json','["禪房夜坐腹半饑，寒爐撥火煨蹲鴟。", "凍膚傍煖漸舒暢，展轉更覺鳴聲悲。", "毳衣脫落豐肌滑，玉軟酥香不勞齧。", "芳甘著頰自生津，多病文園正消渇。", "吾生老矣來荆蠻，得汝聊助癯儒餐。", "不學當年鬼谷子，糞土堆頭拜懶殘。"]'),
('af7db047-6202-4612-a1d1-15e39509731f','蒸栗','李綱','宋','宋诗','song-poetry','','[]','風霜開栗皺，孕此頳虬卵。',156,'全唐诗/poet.song.90000.json','["風霜開栗皺，孕此頳虬卵。", "嘉哉古所贄，飣餖入籩匴。", "纍纍紫腰菱，爛爛火蠶繭。", "甘腴能療病，炎帝所編纂。", "幽人夜讀書，坐對銅檠短。", "颼颼石鼎沸，焰焰地爐暖。", "式將瓦甑炊，剖殻黄玉軟。", "乘饑進五六，腹已果然滿。", "吾嘗位將相，日食萬錢饌。", "荒山啖芋栗，自勝太官臠。", "乃知一飽餘，萬品徒過眼。", "聊持薦杯酒，不假玻瓈盌。", "憂慨不成眠，夜寒空展轉。"]'),
('434e3eec-bc18-4a26-901c-1895aa5a6a33','摘鬢間白髪有感','李綱','宋','宋诗','song-poetry','','[]','吾生足憂患，未老頭已白。',216,'全唐诗/poet.song.90000.json','["吾生足憂患，未老頭已白。", "鬢間垂素絲，攬鏡聊一摘。", "星星去雖欣，種種鮮還慼。", "頗愁日增多，盡拔復何益。", "追思少年時，綠髪光且澤。", "森然茂雲松，豈謂少堪惜。", "自從多病後，脱落露廣額。", "蒲柳姿易衰，日與風霜迫。", "蕭蕭不勝梳，擾擾僅盈搦。", "安能上指冠，常恐吹墮幘。", "年來涉艱虞，更復非夙昔。", "奔馳動萬里，漂泊繼三謫。", "從横蹈危機，侈哆困煩嘖。", "交遊莫援手，仇怨惟下石。", "素標宜滿頭，斑鬢未爲逼。", "何年運河車，泝補泥丸宅。", "華顛復變鬒，去作煙霞客。", "憔悴楚江濱，歲晚將何獲。"]'),
('5361283a-d0f6-4904-a53d-ac29d7b4eade','初食金橘','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','江湖種橘侔洞庭，於中小者如龍睛。',192,'全唐诗/poet.song.90000.json','["江湖種橘侔洞庭，於中小者如龍睛。", "珊瑚枝幹碧玉葉，結實璀璨羅繁星。", "客持贈我意已重，貯以翠籠尤晶熒。", "氣含風露更髙潔，色著霜日微紅青。", "勻圓入手訝磊砢，甘酸流頰淒芳馨。", "金丸玉齒乍破碎，中有沆瀣凝清冰。", "厥包憶昔貢宫闕，瀟湘遠物來天扃。", "爭新效美不論直，萬顆坐覺千金輕。", "美人轉賜入懷袖，歸來分餉同瑤瓊。", "只今八駿杳安在，此物亦爾無光精。", "天涯相見兩寂寞，敢以陋質傷飄零。", "舉觴爲爾成一醉，醉中不省居蠻荆。"]'),
('2f4cc70d-52ac-478c-acb1-b57ca6bfb8f7','燈花  其一','李綱','宋','宋诗','song-poetry','','[]','獨坐對黄卷，夜寒燈自花。',48,'全唐诗/poet.song.90000.json','["獨坐對黄卷，夜寒燈自花。", "紅深誰種蒔，枝嫋忽萌芽。", "酒渌正盈爵，客愁方念家。", "慇懃報遠信，賴爾慰年華。"]'),
('50254920-29e6-448e-80cb-d7f96251eb65','燈花  其二','李綱','宋','宋诗','song-poetry','','[]','光鋩長吐焰，頃刻遽開花。',48,'全唐诗/poet.song.90000.json','["光鋩長吐焰，頃刻遽開花。", "玉粒乍排粟，金英初擢芽。", "謫官那有喜，旅食未還家。", "對爾翻惆悵，飄蕭雙鬢華。"]'),
('19efef48-1507-4cf1-8b40-5c4b6dbb5bc8','余來湖外臨行與叔易奕而勝得銅爐製作精古愛之常置几案間感物懷人爲賦此詩','李綱','宋','宋诗','song-poetry','','[]','古製精巧後莫擬，何年著此形模偉。',112,'全唐诗/poet.song.90000.json','["古製精巧後莫擬，何年著此形模偉。", "狀爲神獸踐脩虺，蜿蜒脊脅奠厥趾。", "犀兕一角昂其鼻，胸腹空洞口哆侈。", "關機開闔如投匭，葭灰養火焚沈水。", "霏微牙吻煙雲起，提攜愛玩置燕几。", "慱山篆鼎詎可比，一枰何日刷前恥。", "滿軒風月人千里，清香一炷愁如洗。"]'),
('f36c6cdb-1472-49e1-995e-761ba6258685','客有饋玉面狸者戲賦此詩','李綱','宋','宋诗','song-poetry','','[]','山林冬煖草未衰，深巖穴處狸正肥。',128,'全唐诗/poet.song.90000.json','["山林冬煖草未衰，深巖穴處狸正肥。", "丰茸斑毳面粧玉，搖曳脩尾髦如犛。", "夜行晝伏彼何罪，失身終堕網與機。", "庖厨須爾充口腹，幾欲斷尾同犧雞。", "蒸炊包裹付糟滓，酥香玉軟豐膚肌。", "霜刀縷切膩且滑，犀筯厭飫良珎奇。", "猩脣熊白不足數，披絮黄雀空多脂。", "樽前風味乃如許，爲爾倒盡黄金巵。"]'),
('d06131ac-457e-4096-858f-903bcc0b798c','冬日閒居遣興十首  其一','李綱','宋','宋诗','song-poetry','','[]','歲暮碧山中，清霜日自濃。',48,'全唐诗/poet.song.90000.json','["歲暮碧山中，清霜日自濃。", "隱牀吟蟋蟀，拂檻老芙蓉。", "風月成三友，家山夢九龍。", "道人知睡美，將曉小鳴鐘。"]'),
('391bd978-33d0-412c-a4ec-ad8a2c3d9172','冬日閒居遣興十首  其二','李綱','宋','宋诗','song-poetry','','[]','飄泊向江城，山居境過清。',48,'全唐诗/poet.song.90000.json','["飄泊向江城，山居境過清。", "霜深猶竹色，風勁更松聲。", "且盡杯中物，何須身後名。", "擁爐孤笑處，寒夜又三更。"]'),
('f7efd467-68ad-4dbd-9f11-4303df9af544','冬日閒居遣興十首  其三','李綱','宋','宋诗','song-poetry','','[]','蘭若富雲松，吾生寄此中。',48,'全唐诗/poet.song.90000.json','["蘭若富雲松，吾生寄此中。", "無心復彈劍，有恨但書空。", "白菊因霜紫，青楓向日紅。", "晚來幽獨甚，臥聼竹間風。"]'),
('557b01a8-cdf1-4785-b397-6b5ad9c21175','冬日閒居遣興十首  其四','李綱','宋','宋诗','song-poetry','','[]','蕭颯鬢絲垂，此懷誰與知。',48,'全唐诗/poet.song.90000.json','["蕭颯鬢絲垂，此懷誰與知。", "驚心傷網繳，老眼厭旌旗。", "未遂龐公隱，空餘宋玉悲。", "故園何處是，搔首望天涯。"]'),
('f2d57015-0c18-44fe-a2f6-b6f58229f800','冬日閒居遣興十首  其五','李綱','宋','宋诗','song-poetry','','[]','宿雨乍晴天，初寒氣暫暄。',48,'全唐诗/poet.song.90000.json','["宿雨乍晴天，初寒氣暫暄。", "梳頭風滿櫛，曝背日臨軒。", "小酌無新釀，閒眠只舊氈。", "忘心亦忘法，作箇是安禪。"]'),
('74d4119a-a59f-4be7-922a-14841182a9e3','冬日閒居遣興十首  其六','李綱','宋','宋诗','song-poetry','','[]','深炷一爐香，孤吟夜正長。',48,'全唐诗/poet.song.90000.json','["深炷一爐香，孤吟夜正長。", "山虚風落木，雲破月窺房。", "老驥志千里，越禽思故郷。", "羈栖兩寂寞，坐歎鬂毛霜。"]'),
('34806877-dfc6-425b-b758-1dfb55f1d28c','冬日閒居遣興十首  其七','李綱','宋','宋诗','song-poetry','','[]','投老見多難，干戈日正深。',48,'全唐诗/poet.song.90000.json','["投老見多難，干戈日正深。", "飲河胡馬健，破壘漢疆侵。", "大將未燕首，小臣空越吟。", "龍荒兩宫遠，感憤淚盈襟。"]'),
('eb445c41-e855-48f3-a9f1-176fad4d4bb2','冬日閒居遣興十首  其八','李綱','宋','宋诗','song-poetry','','[]','澤國杳何許，鴈書初報安。',48,'全唐诗/poet.song.90000.json','["澤國杳何許，鴈書初報安。", "枝間鳥鵲喜，原上鶺鴒難。", "松菊荒三徑，軒裳厭一官。", "黄粱何日熟，客夢正邯鄲。"]'),
('51839a56-4073-4c64-9957-619833df3ce2','冬日閒居遣興十首  其九','李綱','宋','宋诗','song-poetry','','[]','衰病寓僧房，閒中氣味長。',48,'全唐诗/poet.song.90000.json','["衰病寓僧房，閒中氣味長。", "盤深饒芋栗，地僻懶冠裳。", "坐隱烏皮几，行攜古錦囊。", "接籬顛倒著，不是醉髙陽。"]'),
('f015da2d-aa2c-44a5-8f2e-fa911c2371e5','冬日閒居遣興十首  其一○','李綱','宋','宋诗','song-poetry','','[]','僻處掩松門，知非更念恩。',48,'全唐诗/poet.song.90000.json','["僻處掩松門，知非更念恩。", "庭空從雀啅，山暖覺蜂喧。", "木葉静如掃，茶花開正繁。", "蕭條歲云暮，倚杖自忘言。"]'),
('ec6d56f0-5f30-4ed3-a5ae-763a73d7e27a','食蟹','李綱','宋','宋诗','song-poetry','','[]','平生最愛梁谿居，溪頭紫蟹幾尺餘。',192,'全唐诗/poet.song.90000.json','["平生最愛梁谿居，溪頭紫蟹幾尺餘。", "持矛被甲意頗横，霜後直欲陵於菟。", "端然秉炬可攻取，束縳健者歸庖厨。", "雙螯如臂自可飽，滿腹膏液凝紅酥。", "每傾新釀爲一醉，風味竊疑他所無。", "那知謪墮荒山裏，乃有此物供臞儒。", "客云來自九江郡，分以餉我良勤渠。", "輪囷初喜入盤饌，郭索想見行泥塗。", "西風江岸蘆葦枯，下田粳稻香且腴。", "朝魁把穟屢蛻殻，宜爾怪偉胸中都。", "內黄疏封何足道，左手相持真可娛。", "流膏斫雪快一嚼，不復悵望思東吳。"]'),
('92ea92ee-1072-4bc4-bc87-d5cd5eb56adc','食橘','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','洞庭一夜天雨霜，橘林綠苞朝已黄。',195,'全唐诗/poet.song.90000.json','["洞庭一夜天雨霜，橘林綠苞朝已黄。", "遠題書後三百顆，入手便覺秋風香。", "黄金爲膚白玉瓤，沆瀣深貯甘且芳。", "雕盤初擘噀清霧，冰齒乍嚼流瓊漿。", "色香氣味紛可喜，下視衆果皆茫茫。", "嗟余平生愛種此，木奴千樹梁谿傍。", "只今蒿艾已埋没，豈敢向日爭熒煌。", "蓬萊雲氣久寂寞，漢殿無復羅瀟湘。", "厥包縱有盡酸澀，剖之蠧朽安足嘗。", "乃知汝病是天意，坐使玉食無輝光。", "荒山乃爾飫佳品，安得騕褭置錦堂。", "君不見杜陵野老歌病橘，蕭蕭半死誠可傷。"]'),
('e598c008-cc4f-4f02-9f79-028b56c11bc9','秀容菊','李綱','宋','宋诗','song-poetry','','[]','黄菊已槁餘微馥，白菊初開疊羅縠。',64,'全唐诗/poet.song.90000.json','["黄菊已槁餘微馥，白菊初開疊羅縠。", "秀容丰淡却嫣然，故伴幽人慰愁獨。", "吾聞此種南陽多，千花萬蘂爭駢羅。", "鬱葱佳氣久蕭瑟，悵望菊潭今若何。"]'),
('fd69a30e-62bd-4cbb-bd58-fff57a468a07','許崧老見和月林堂夜坐詩復次前韻寄之','李綱','宋','宋诗','song-poetry','','[]','宇宙一逆旅，安用歸我廬。',144,'全唐诗/poet.song.90000.json','["宇宙一逆旅，安用歸我廬。", "解裝寓僧房，袤丈即有餘。", "三年走萬里，華髪照川途。", "頗思少壯樂，談笑輕簪裾。", "醉揮鐵如意，擊碎紅珊瑚。", "垂老見兵革，濟時愧才疏。", "及兹再飄零，歛若霜中梧。", "幸從山林遊，時與釋子俱。", "超然意有會，不必窺其書。", "臞仙静退者，久要不渝初。", "和我月林篇，此作久所無。", "徴言思會面，歲晚苦離居。"]'),
('f0999ec4-ef6f-4ef5-884c-673465e82d86','周中元賦御畫騘馬次其韻','李綱','宋','宋诗','song-poetry','','[]','蓬萊宫殿日月長，廣廷汎灑如無帚。',128,'全唐诗/poet.song.90000.json','["蓬萊宫殿日月長，廣廷汎灑如無帚。", "臨軒親貌玉花騘，天驥自出天人手。", "驚鴻欲起無羈皂，如聞朔風動秋草。", "奮身驤首舉雙蹄，意態天然始知巧。", "時危反掌同永嘉，胡騎颯沓陵中華。", "當時宸筆散煙霧，往往流落羣臣家。", "雄姿倜儻精權奇，此畫惟應識者知。", "悵望崆峒轉仙仗，忍傳耆舊把天衣。"]'),
('fc610124-3602-4f21-bbc1-01eec7927821','送周元中遊黄龍山','李綱','宋','宋诗','song-poetry','','[]','此身飄泊墮荆蠻，幸有幽人訪我閒。',64,'全唐诗/poet.song.90000.json','["此身飄泊墮荆蠻，幸有幽人訪我閒。", "得句多從丘壑裏，知音端在笑談間。", "青鞋布襪平生事，野鶴孤雲到處山。", "好去黄龍露消息，直須一箭透三關。"]'),
('8d5a8b3b-0c2c-4241-9863-47f7cc07108d','題峽江蕭氏思賢堂','李綱','宋','宋诗','song-poetry','','[]','玉笥峰邊蕭史居，拂雲松竹散扶疏。',64,'全唐诗/poet.song.90000.json','["玉笥峰邊蕭史居，拂雲松竹散扶疏。", "妙年氣節慕前軰，故老風流空結廬。", "幸有江山供一覧，自應圖史足三餘。", "何時海內干戈息，借我茅齋與著書。"]'),
('32bd50f5-bd41-4753-9d4a-62c4b1a0f677','黄雀','李綱','宋','宋诗','song-poetry','','[]','秋杪江天小雨餘，畢飛端爲網羅須。',64,'全唐诗/poet.song.90000.json','["秋杪江天小雨餘，畢飛端爲網羅須。", "秪應俛啄一粒粟，故使常行萬里途。", "愛酒情懷多骨醉，披綿風度更膚腴。", "苞苴宜入金張室，分餉何爲及老夫。"]'),
('6d0ba7a6-b809-4d16-9ce2-84082883cb04','陳幾叟以了翁所作默堂箴見示且求余言拾其遺意作四絕句  其一','李綱','宋','宋诗','song-poetry','','[]','維摩不二門中法，周廟三緘膺上銘。',32,'全唐诗/poet.song.90000.json','["維摩不二門中法，周廟三緘膺上銘。", "莫道寂然無所說，須知淵默有雷霆。"]'),
('9ade0386-2443-499d-89a6-b439714eb76d','陳幾叟以了翁所作默堂箴見示且求余言拾其遺意作四絕句  其二','李綱','宋','宋诗','song-poetry','','[]','言默當時俱是智，可言而默亦非真。',32,'全唐诗/poet.song.90000.json','["言默當時俱是智，可言而默亦非真。", "君看王導雖賢者，不語猶能殺伯仁。"]'),
('46b0efbc-b3a0-458d-8f4a-0bb8d8f8f87a','陳幾叟以了翁所作默堂箴見示且求余言拾其遺意作四絕句  其三','李綱','宋','宋诗','song-poetry','','[]','言以多窮默取容，不如體道守其中。',32,'全唐诗/poet.song.90000.json','["言以多窮默取容，不如體道守其中。", "道非言默所能載，畢竟兩端皆是空。"]'),
('c8aaa241-467b-4e91-a716-79000f90032e','陳幾叟以了翁所作默堂箴見示且求余言拾其遺意作四絕句  其四','李綱','宋','宋诗','song-poetry','','[]','鍾鳴谷響孰爲然，因擊緣聲故有言。',32,'全唐诗/poet.song.90000.json','["鍾鳴谷響孰爲然，因擊緣聲故有言。", "若會雖言本無說，從教千偈口瀾翻。"]'),
('10a2a669-a992-482b-832d-532321415974','得報以謫降官不許同處一州自鄂渚移居澧陽有感','李綱','宋','宋诗','song-poetry','','[]','萍漂梗泛又遷居，歎息謀身術已疏。',64,'全唐诗/poet.song.90000.json','["萍漂梗泛又遷居，歎息謀身術已疏。", "願訪湘妃遺珮浦，試追漢傳弔纍書。", "干戈滿眼傷羣盜，松梓連雲念故廬。", "澤畔行吟覺憔悴，前身疑是楚三閭。"]'),
('f0ff9445-f853-4be4-bcfe-871fd44036ec','翁士特見示山字韻詩兩篇復次前韻寄之  其一','李綱','宋','宋诗','song-poetry','','[]','未展垂天翼，聊尋避地山。',144,'全唐诗/poet.song.90000.json','["未展垂天翼，聊尋避地山。", "寶坊資小隱，綵服奉慈顔。", "鄉邑兵戈滿，軒窗紫翠環。", "遥知排遣處，祗在倡酬間。", "離索嗟時久，詩篇喜使還。", "故情尤覺重，佳句不容攀。", "灑落吳牋濕，韜藏古錦斑。", "開緘驚璀璨，逼耳聽綿蠻。", "陋質塵黄閤，髙材困綠綸。", "青衿同婉孌，華髪悵斒斕。", "顧我方遐棄，如公豈久閒。", "何須歎飄泊，吾道屬多艱。"]'),
('4a06cece-9069-4b14-ad65-a4e7bf9c78cb','翁士特見示山字韻詩兩篇復次前韻寄之  其二','李綱','宋','宋诗','song-poetry','','[]','踏徧江南土，來遊湖外山。',144,'全唐诗/poet.song.90000.json','["踏徧江南土，來遊湖外山。", "地卑驚鵩鳥，天遠憶龍顔。", "淮海屯貔虎，戈矛雜珮環。", "馳心萬里外，回首五雲間。", "颯沓方多故，飄零且未還。", "桃源期可問，鐵鎖悵難攀。", "霜重丹楓落，江清錦石斑。", "夢餘驚蟻垤，爭極歎蝸蠻。", "且隱重重几，深藏若若綸。", "江籬紛掩苒，湘竹暈斒斕。", "水國黿鼉横，琳宫日月閒。", "親朋未相棄，莫使鴈書艱。"]'),
('6f17e4a3-5d41-4802-ac01-f42ae66dbeab','次韻士特試谷簾泉見懷之作  其一','李綱','宋','宋诗','song-poetry','','[]','桑苧嘗來第二泉，翠松偃蓋色相鮮。',32,'全唐诗/poet.song.90000.json','["桑苧嘗來第二泉，翠松偃蓋色相鮮。", "谷簾竇乳争多少，西子南威各自妍。"]'),
('4f729296-dc92-4bea-a8db-94157cefec67','次韻士特試谷簾泉見懷之作  其二','李綱','宋','宋诗','song-poetry','','[]','片雲搖曳不勝閒，行盡江南處處山。',32,'全唐诗/poet.song.90000.json','["片雲搖曳不勝閒，行盡江南處處山。", "豈解爲霖澤枯槁，只思歸隱碧巖間。"]'),
('0555417e-08cd-40bf-b91d-d4adcd690bec','戊申冬至日有懷諸弟時赴澧陽','李綱','宋','宋诗','song-poetry','','[]','緹室初迴律管陽，貂裘還是旅殊郷。',64,'全唐诗/poet.song.90000.json','["緹室初迴律管陽，貂裘還是旅殊郷。", "可堪身向三湘遠，更覺愁隨一線長。", "棣蕚相思勞夢寐，郊禋成禮想旂裳。", "羈臣與國同休戚，老眼猶期見治康。"]'),
('eba3fe4e-fd14-4ba7-b2b8-91c87be9d099','張氏二甥寄詩可喜賦此篇以贈之','李綱','宋','宋诗','song-poetry','','[]','每見吾甥學不休，信知積善有源流。',64,'全唐诗/poet.song.90000.json','["每見吾甥學不休，信知積善有源流。", "驊騮汗血爲駒日，松柏凌霜出地秋。", "努力年華成宅相，著鞭髙躍破煙樓。", "渭陽正續離騷賦，頻寄詩來慰客愁。"]'),
('f93d6cdf-da0b-4d85-b40e-a3e9fefa0f5c','得梁谿家書報黄氏女生外孫','李綱','宋','宋诗','song-poetry','','[]','怪底朝來鵲噪門，家書遠報女生孫。',64,'全唐诗/poet.song.90000.json','["怪底朝來鵲噪門，家書遠報女生孫。", "須知鍾慶由先德，故使遺芳衍後昆。", "肌骨遥憐凝玉雪，風光自與茁蘭蓀。", "何時歸去親懷抱，華髪襃衣更覺尊。"]'),
('6cc96c5e-d9a4-4347-a9b6-c263453d31af','自蒲圻臨湘趨岳陽道中作十首  其一','李綱','宋','宋诗','song-poetry','','[]','鄂渚何嘗一日安，澧陽猶喜遠江干。',64,'全唐诗/poet.song.90000.json','["鄂渚何嘗一日安，澧陽猶喜遠江干。", "帝妃降矣空遺珮，公子思兮欲採蘭。", "水带瀟湘疑有鴈，地連嶺蜀苦無寒。", "迂疏自笑謀身拙，却荷朝廷德意寛。"]'),
('c20b78f7-cca0-47c2-9d64-b00d427afd62','自蒲圻臨湘趨岳陽道中作十首  其二','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','屈伸任道復何求，去國翻成汗漫遊。',64,'全唐诗/poet.song.90000.json','["屈伸任道復何求，去國翻成汗漫遊。", "處世久師齊物論，攄懷聊賦畔牢愁。", "霜清日薄寒光急，雲慘天髙陰氣浮。", "嫋嫋西風洞庭闊，可堪更上岳陽樓。"]'),
('5563ec4a-08f3-4fe4-8547-f5ca36f56571','自蒲圻臨湘趨岳陽道中作十首  其三','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','歲寒又復事南征，桂檝蘭舟過洞庭。',64,'全唐诗/poet.song.90000.json','["歲寒又復事南征，桂檝蘭舟過洞庭。", "水入重湖千里白，山連平楚數峰青。", "雲鴻杳杳飛何遠，汀芷微微氣自馨。", "千古靈均英爽在，固應笑我學餘醒。"]'),
('3f92eeaa-37fa-49ff-93bb-30b5461b8978','自蒲圻臨湘趨岳陽道中作十首  其四','李綱','宋','宋诗','song-poetry','','[]','三年奔走未容歸，敝盡東周季子衣。',64,'全唐诗/poet.song.90000.json','["三年奔走未容歸，敝盡東周季子衣。", "斷壠連岡平野闊，扁舟短櫂寸心違。", "凌晨白霧霑裳濕，薄暮彤雲夾日飛。", "回首梁谿杳何處，翠烟空鎖釣魚磯。"]'),
('382760ea-b7dc-4637-8bd8-9b428bb553a9','自蒲圻臨湘趨岳陽道中作十首  其五','李綱','宋','宋诗','song-poetry','','[]','還驅征騎向三湘，行盡騷人放逐鄉。',64,'全唐诗/poet.song.90000.json','["還驅征騎向三湘，行盡騷人放逐鄉。", "綠葉素榮歌橘頌，采衣姣服浴蘭湯。", "雲中帝子旍旗降，物外桃源日月長。", "便欲翛然與高蹈，故應脫屣謝軒裳。"]'),
('16560aaa-d293-498f-a30a-d6657ece9b2b','自蒲圻臨湘趨岳陽道中作十首  其六','李綱','宋','宋诗','song-poetry','','[]','不解揚波與餔醨，又還來放楚江湄。',64,'全唐诗/poet.song.90000.json','["不解揚波與餔醨，又還來放楚江湄。", "椒蘭氣味何其烈，蘅葯芬芳空爾爲。", "寧赴湘流非我事，託懷鵩鳥乃吾師。", "醉醒清濁初難共，漁父從來自不知。"]'),
('d9dfb8d9-12ea-4e3e-9ee1-28e1ffc4c0c9','自蒲圻臨湘趨岳陽道中作十首  其七','李綱','宋','宋诗','song-poetry','','[]','遠謫三湘欲卜居，試從詹尹拂占書。',64,'全唐诗/poet.song.90000.json','["遠謫三湘欲卜居，試從詹尹拂占書。", "昂昂願作雲間鶴，泛泛寧爲波底魚。", "咿喔突梯真得計，潔亷正直却成疏。", "益堅節操行吾志，龜策從來自不如。"]'),
('b0a5b201-41ca-4e81-b99d-28ac69b1c11c','自蒲圻臨湘趨岳陽道中作十首  其八','李綱','宋','宋诗','song-poetry','','[]','更欲投書弔汨羅，西風嫋嫋水增波。',64,'全唐诗/poet.song.90000.json','["更欲投書弔汨羅，西風嫋嫋水增波。", "江分夢澤於菟遠，地近芳洲杜若多。", "野鳥終年從萃止，木奴千樹正婆娑。", "卜居更作終焉計，華髪蕭蕭奈老何。"]'),
('c1a3062d-b8ab-4895-a256-a1521d1275b0','自蒲圻臨湘趨岳陽道中作十首  其九','李綱','宋','宋诗','song-poetry','','[]','俎豆其如軍旅何，誰令瀚海起干戈。',64,'全唐诗/poet.song.90000.json','["俎豆其如軍旅何，誰令瀚海起干戈。", "休將直道論三黜，且把微辭續九歌。", "山鬼含顰乘赤豹，湘靈解珮鼓雲和。", "蠻邦雖陋吾何恨，厭見旌蕤相盪摩。"]'),
('3593f035-fc27-45d3-b18b-5d7ffed40386','自蒲圻臨湘趨岳陽道中作十首  其一○','李綱','宋','宋诗','song-poetry','','[]','龍駕翩翩帝子遊，我因謫宦亦淹留。',64,'全唐诗/poet.song.90000.json','["龍駕翩翩帝子遊，我因謫宦亦淹留。", "瀟湘且傍黿鼉窟，葭菼空懷鸚鵡洲。", "專氣願師周柱史，著書更笑陸忠州。", "變心從俗吾何敢，千古騷人共此愁。"]'),
('39ea41f2-9ace-435a-a3b3-8e92a24736b4','再次韻崧老見和之作時傳春秋集傳又欲借易說故篇中及之','李綱','宋','宋诗','song-poetry','','[]','胡塵暗中原，河洛皆穹廬。',144,'全唐诗/poet.song.90000.json','["胡塵暗中原，河洛皆穹廬。", "衣冠競南渡，故國靡復餘。", "襄陵大嶽裔，亦爾困征涂。", "顛沛不忘道，呻吟曳長裾。", "如公巨川舟，豈止清廟瑚。", "愧我正羈束，未能踵漢疏。", "幸然聲氣同，鳴鳯棲必梧。", "褰裳思琢磨，道阻不得俱。", "已從借麟經，更欲窺羲書。", "庶或晚聞道，洗心復其初。", "湘沅騷人鄉，蘭芷今豈無。", "回風搖蕙草，歎息空幽居。"]'),
('b0276ed1-414e-4a0c-b356-d02134b33959','岳陽樓三首  其一','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','縹緲層樓俯洞庭，湖光霽色兩澄明。',64,'全唐诗/poet.song.90000.json','["縹緲層樓俯洞庭，湖光霽色兩澄明。", "氣蒸雲夢浮天白，水合瀟湘到底清。", "去櫂來檣雲共影，斷鴻孤鶩笛連聲。", "望中更覺君山小，一點青螺鏡面平。"]'),
('8d298295-c02e-4107-be1f-43bda96a5792','岳陽樓三首  其二','李綱','宋','宋诗','song-poetry','','["\u5cb3\u9633\u697c"]','翛然多難偶存身，又到蒼茫楚澤濱。',64,'全唐诗/poet.song.90000.json','["翛然多難偶存身，又到蒼茫楚澤濱。", "鼓舞魚龍張樂地，佩紉蘭茝獨醒人。", "涉江哀郢空回首，極目傷心欲向春。", "鼓枻寅緣傍枯葦，故應漁父尚垂綸。"]'),
('d4c83466-b44e-4855-a78a-661e9fb1f7f6','岳陽樓三首  其三','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56", "\u5cb3\u9633\u697c"]','常誦飛龍邅洞庭，登樓況復把騷經。',64,'全唐诗/poet.song.90000.json','["常誦飛龍邅洞庭，登樓況復把騷經。", "瑠璃萬頃天同碧，翠黛一螺山更青。", "白鳥風髙方倦翮，蒼鷹冬暖正舒翎。", "客愁欲作長鯨吸，却笑三閭只獨醒。"]'),
('6842018d-5c56-40d4-a779-bb259eb606f2','鼠須筆  其一','李綱','宋','宋诗','song-poetry','','[]','鼠能爲虎亦何功，用舍之間繫所逢。',32,'全唐诗/poet.song.90000.json','["鼠能爲虎亦何功，用舍之間繫所逢。", "誰謂有皮爲有禮，翦須猶得管城封。"]'),
('be3fa89c-4c7f-4c64-9de0-08c2801b9766','鼠須筆  其二','李綱','宋','宋诗','song-poetry','','[]','中山毛穎久中書，鼠輩胡爲亦可俱。',32,'全唐诗/poet.song.90000.json','["中山毛穎久中書，鼠輩胡爲亦可俱。", "寢廟穴居真得計，畏人端恐擢其須。"]'),
('c20fd7d1-4847-47d5-aafa-18e02a4660c4','渡江','李綱','宋','宋诗','song-poetry','','[]','桂枻蘭旌楚澤東，碧空如水水如空。',64,'全唐诗/poet.song.90000.json','["桂枻蘭旌楚澤東，碧空如水水如空。", "江湖落日浮秋橘，島嶼殘霞拂斷虹。", "世事茫然煙靄裏，客愁都在櫓聲中。", "沙頭鳬鴈相儔侣，笑我年年逐轉蓬。"]'),
('9c3b34ff-a55f-470e-9c16-03511e308f6b','章華臺  其一','李綱','宋','宋诗','song-poetry','','[]','斷壠連岡雲夢西，楚王宫殿尚遺基。',32,'全唐诗/poet.song.90000.json','["斷壠連岡雲夢西，楚王宫殿尚遺基。", "桂花半落垂黄橘，想見章華九月時。"]'),
('ba52c005-e660-4eee-8c0d-6d72c29df8b0','章華臺  其二','李綱','宋','宋诗','song-poetry','','[]','章華夜飲曉從糜，翠被天寒雨雪霏。',32,'全唐诗/poet.song.90000.json','["章華夜飲曉從糜，翠被天寒雨雪霏。", "馬足車塵竟何往，空令子革誦招祈。"]'),
('ebf3f20f-e828-4fc0-85b0-036323c68abd','華容西二十許里有墨山即離騷所謂玄石也山有大雲寺寺有雲母泉甘芳潔清大旱不竭唐李華有詩序之甚詳其末云華貶杭州司公恩復左補闕次于岳陽江山延望思與髙賢共飲雲母之泉躬耕墨山之下敢違朝命以詢私欲秋風露寒洞庭微波一聞猿聲不覺涕下況支離多病年甫始衰願餌藥扶壽以究無生之學事乖志負火爇余心三復其言而悲之因次其韻','李綱','宋','宋诗','song-poetry','','["\u6d1e\u5ead\u6e56"]','霜風振古林，肅肅有異聲。',228,'全唐诗/poet.song.90000.json','["霜風振古林，肅肅有異聲。", "我登玄石山，適此氛祲清。", "散策步山巔，僧廬窈而精。", "石磴盡雲母，晶熒璨瑶英。", "涓涓幽谷泉，玉色凄芳馨。", "飲者得難老，沈疴體皆平。", "乃知泉源美，本自山川靈。", "沈吟遐叔詩，此其浪得名。", "肺腑久塵埃，於焉吸清泠。", "玉池艷生肥，潄濯歸黄庭。", "却思陸子泉，厥味可弟兄。", "白首困飄泊，丹心竟何成。", "鼓枻渡瀟湘，曳裾拂荆衡。", "回頭故山遠，愴怳若爲情。", "區區金石堅，正賴日月明。", "卷舒隨用舍，未覺殊虧盈。", "風髙洞庭波，雲瞑蘭芷城。", "餌藥扶始衰，究心學無生。", "庶幾甫知命，寸田不廢耕。"]'),
('628a4e67-5cfb-400d-b085-beb47100e4e5','至澧陽寓天寧僧舍有感  其一','李綱','宋','宋诗','song-poetry','','[]','常誦離騷澧有蘭，那知謫宦憇其間。',32,'全唐诗/poet.song.90000.json','["常誦離騷澧有蘭，那知謫宦憇其間。", "片雲隻鶴風方急，只恐飄零過别山。"]'),
('b0ab016e-25db-4708-800b-18d5bf5dae2c','至澧陽寓天寧僧舍有感  其二','李綱','宋','宋诗','song-poetry','','[]','此身又復寓精廬，丈室蕭然一物無。',32,'全唐诗/poet.song.90000.json','["此身又復寓精廬，丈室蕭然一物無。", "每見招提心即喜，前生真是老浮屠。"]'),
('4cbba6d9-8e45-4d77-a166-f914adaa399e','深省軒在丈室之西余爲名之','李綱','宋','宋诗','song-poetry','','[]','軒檻虛明丈室西，叢筠佳木翠陰垂。',32,'全唐诗/poet.song.90000.json','["軒檻虛明丈室西，叢筠佳木翠陰垂。", "遊觀物物皆深省，豈在聞鐘欲覺時。"]'),
('24dbeeab-65d8-4bd5-b54b-b9a03f519a2f','見報以言者論六事其五皆靖康往故其一謂資囊士人上書以兾復用謫居海南震懼之餘斐然有作  其一','李綱','宋','宋诗','song-poetry','','[]','力小安能勝萬鈞，退藏深渺欲全身。',32,'全唐诗/poet.song.90000.json','["力小安能勝萬鈞，退藏深渺欲全身。", "大恩不報有餘責，何必煩言浪指陳。"]'),
('58e5287b-f637-42c5-ab8b-66c4cd94e6b2','見報以言者論六事其五皆靖康往故其一謂資囊士人上書以兾復用謫居海南震懼之餘斐然有作  其二','李綱','宋','宋诗','song-poetry','','[]','非才自丏罷鈞衡，百念灰寒豈復萌。',32,'全唐诗/poet.song.90000.json','["非才自丏罷鈞衡，百念灰寒豈復萌。", "剛道資嚢上書者，不知誰繼潁川生。"]'),
('ab2f9458-b287-4a80-b23b-d1c0ed78bb49','見報以言者論六事其五皆靖康往故其一謂資囊士人上書以兾復用謫居海南震懼之餘斐然有作  其三','李綱','宋','宋诗','song-poetry','','[]','尼父乘桴居九夷，管寧浮海亦多時。',32,'全唐诗/poet.song.90000.json','["尼父乘桴居九夷，管寧浮海亦多時。", "古來聖賢猶如此，我泛鯨波豈足悲。"]'),
('87e6e5df-0d46-4304-82b9-360b27b1f831','見報以言者論六事其五皆靖康往故其一謂資囊士人上書以兾復用謫居海南震懼之餘斐然有作  其四','李綱','宋','宋诗','song-poetry','','[]','功似贊皇猶遠涉，智如鶴相亦來遊。',32,'全唐诗/poet.song.90000.json','["功似贊皇猶遠涉，智如鶴相亦來遊。", "世間萬事非人力，只有安心百不憂。"]'),
('15a9b3db-9975-4df3-b0ff-800eb118b577','見報以言者論六事其五皆靖康往故其一謂資囊士人上書以兾復用謫居海南震懼之餘斐然有作  其五','李綱','宋','宋诗','song-poetry','','[]','蘇子曾爲海上仙，羣龍三復絕韋編。',32,'全唐诗/poet.song.90000.json','["蘇子曾爲海上仙，羣龍三復絕韋編。", "我今日對羲文語，却恨公書取次傳。"]'),
('82a5c17c-d660-41e4-b58a-07063d15f3f7','别夾山能老','李綱','宋','宋诗','song-poetry','','[]','相逢千偈口瀾翻，已是親曾到夾山。',32,'全唐诗/poet.song.90000.json','["相逢千偈口瀾翻，已是親曾到夾山。", "猿鳥可能知祖意，飛騰青嶂碧巖間。"]'),
('431998be-e439-4bc9-acb9-b35427e821db','藥山三詠 問道室','李綱','宋','宋诗','song-poetry','','[]','骨相嶄巖心已安，松林談道不勝寒。',32,'全唐诗/poet.song.90000.json','["骨相嶄巖心已安，松林談道不勝寒。", "習之不會髙人意，便作天雲瓶水看。"]'),
('52a64c4a-c964-4c9f-a287-e2436cc965f0','藥山三詠 伏牛菴','李綱','宋','宋诗','song-poetry','','[]','侍者何須召二空，一元調伏自知風。',32,'全唐诗/poet.song.90000.json','["侍者何須召二空，一元調伏自知風。", "軒然棟宇翬飛處，何似當年茅竹中。"]'),
('7367c4e4-0be3-4983-b970-f74a797cad06','藥山三詠 雷滿池','李綱','宋','宋诗','song-poetry','','[]','英雄割據老漁師，習氣難忘鑿此池。',32,'全唐诗/poet.song.90000.json','["英雄割據老漁師，習氣難忘鑿此池。", "尚想興酣髙會處，投身下取酒杯時。"]'),
('9fad71f9-a649-4f66-bd66-977bfe055f50','梁山觀音寺','李綱','宋','宋诗','song-poetry','','[]','大士當年白鹿馴，寶坊千古閟松筠。',32,'全唐诗/poet.song.90000.json','["大士當年白鹿馴，寶坊千古閟松筠。", "風流帝壻膏粱客，也解來爲護法神。"]'),
('781a1e56-bad9-421e-b79e-35880b009bfc','自武陵舟行至德山','李綱','宋','宋诗','song-poetry','','[]','捨車泛蘭舟，搖蕩武陵水。',228,'全唐诗/poet.song.90000.json','["捨車泛蘭舟，搖蕩武陵水。", "憇裝古叢林，幽勝冠南紀。", "當時霹靂手，掣電機在捶。", "鈐鎚今得人，宗旨振頽委。", "何須大雄殿，突兀踞巍址。", "龍蛇相混雜，衲子聚千指。", "齊竽一一吹，真贗見鑪錘。", "青葱松竹陰，積翠紛可喜。", "春風一動搖，蕭瑟鳴不已。", "却遊德峴亭，枉渚抱中沚。", "襄陽今何如，風物略如此。", "空懷墮淚碑，愧嘆羊叔子。", "坐令鄒湛輩，名字隨驥尾。", "胡雛窺漢疆，戰哭多新鬼。", "王室如綴旒，寇盜結蜂蟻。", "而我荷寛恩，抱釁適萬里。", "回頭望中原，灑涕濕巾几。", "海山渺安在，澒洞鯨波裏。", "飛仙時往來，當學長不死。"]'),
('f4a665f3-7089-4f5f-90cc-be4669dfb830','益陽白鹿寺','李綱','宋','宋诗','song-poetry','','[]','寺枕清江蔭碧梧，蕭然景物類東吳。',32,'全唐诗/poet.song.90000.json','["寺枕清江蔭碧梧，蕭然景物類東吳。", "登臨忽動思歸興，不待秋風可鱠鱸。"]'),
('0a268dd4-1d62-4af7-a4a1-7580f528f8ad','清修寺在益陽數十里間惠遠之弟居之世謂之小廬山二首  其一','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','盤紆石磴白雲間，風落巖花滿路斑。',32,'全唐诗/poet.song.90000.json','["盤紆石磴白雲間，風落巖花滿路斑。", "峰嶺横斜自重掩，箇中真是小廬山。"]'),
('794254fa-a4a4-47af-abb8-5c7be2791242','清修寺在益陽數十里間惠遠之弟居之世謂之小廬山二首  其二','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','傍山修竹翠檀欒，竦節疏枝碧玉寒。',32,'全唐诗/poet.song.90000.json','["傍山修竹翠檀欒，竦節疏枝碧玉寒。", "安得誅茅此君側，世間渾作夢中看。"]'),
('5012592a-5231-47e9-9793-594b1ae6efa0','自湘鄉趨邵陽以避謗不敢取道衡嶽有感五首  其一','李綱','宋','宋诗','song-poetry','','["\u8861\u5c71"]','平生性僻愛溪山，偶得經行秪爲閒。',32,'全唐诗/poet.song.90000.json','["平生性僻愛溪山，偶得經行秪爲閒。", "歎息迂程避煩嘖，坐令南嶽阻躋攀。"]'),
('c9ede289-cc8c-40c4-8f83-4fb773cfde7e','自湘鄉趨邵陽以避謗不敢取道衡嶽有感五首  其二','李綱','宋','宋诗','song-poetry','','[]','石廪巉天堆祝融，遥看山色有無中。',32,'全唐诗/poet.song.90000.json','["石廪巉天堆祝融，遥看山色有無中。", "寛恩異日容歸老，先到衡陽回鴈峰。"]'),
('cfeea60e-08b9-4af7-8337-4ece52a4a35c','自湘鄉趨邵陽以避謗不敢取道衡嶽有感五首  其三','李綱','宋','宋诗','song-poetry','','["\u8861\u5c71"]','恭聞南嶽魏夫人，絳節霓旌擁玉輪。',32,'全唐诗/poet.song.90000.json','["恭聞南嶽魏夫人，絳節霓旌擁玉輪。", "我欲他年受真訣，先從碧海滌埃塵。"]'),
('2bfd5878-fca9-4a92-9ef0-947b1fe5a0f0','自湘鄉趨邵陽以避謗不敢取道衡嶽有感五首  其四','李綱','宋','宋诗','song-poetry','','[]','鄴侯奇譎世難知，放浪衡湘亦避時。',32,'全唐诗/poet.song.90000.json','["鄴侯奇譎世難知，放浪衡湘亦避時。", "懶瓚不知今在否，無心更與覓蹲鴟。"]'),
('11b2250c-8385-453b-b4da-85b0a316ee9f','自湘鄉趨邵陽以避謗不敢取道衡嶽有感五首  其五','李綱','宋','宋诗','song-poetry','','[]','退之昔謫惡溪濱，精意能開衡嶽雲。',32,'全唐诗/poet.song.90000.json','["退之昔謫惡溪濱，精意能開衡嶽雲。", "我匪天窮坐人阨，試從山外望氛氲。"]'),
('75808b1c-077d-4fa2-8608-81ac21172ef1','邵陽道中雲巖寺','李綱','宋','宋诗','song-poetry','','[]','山空小寺依嵌竇，日暖幽禽轉好聲。',32,'全唐诗/poet.song.90000.json','["山空小寺依嵌竇，日暖幽禽轉好聲。", "萬箇琅玕一茅屋，何當此處寄浮生。"]'),
('e60e41c7-a191-4f63-b09d-095164103297','清湘西山寺無量壽塔','李綱','宋','宋诗','song-poetry','','[]','黄花翠竹真如性，大地山河清淨身。',32,'全唐诗/poet.song.90000.json','["黄花翠竹真如性，大地山河清淨身。", "欲識今時無量壽，不知瞻禮是何人。"]'),
('f516e944-7afd-42d3-9639-d529aa2fa87b','桂林道中二首  其一','李綱','宋','宋诗','song-poetry','','[]','桂林山水久聞風，身世茫然墮此中。',64,'全唐诗/poet.song.90000.json','["桂林山水久聞風，身世茫然墮此中。", "日暮碧雲濃作朵，春深稚筍翠成叢。", "仙家多住朱明洞，客夢來遊羣玉峰。", "鴈蕩武夷何足道，千巖元是小玲瓏。"]'),
('6559e536-e4a3-4787-a06a-1ed54f7bede7','桂林道中二首  其二','李綱','宋','宋诗','song-poetry','','[]','時危遠謫墮南巒，猶在乾坤覆載間。',64,'全唐诗/poet.song.90000.json','["時危遠謫墮南巒，猶在乾坤覆載間。", "瘴雨嵐煙殊氣候，玉簪羅带巧溪山。", "桄榔葉暗傷心碧，躑躅花開滿目斑。", "惟有月華依舊好，清輝應與照雲鬟。"]'),
('2483e6ad-2c64-4e91-80e0-89098fdb5834','山月驛聞子規次韻','李綱','宋','宋诗','song-poetry','','[]','春枕夢回孤館悄，世故縈心愁不了。',32,'全唐诗/poet.song.90000.json','["春枕夢回孤館悄，世故縈心愁不了。", "山深夜閑子規啼，殘月滿窗天未曉。"]'),
('e7af6750-59b0-46f6-ab20-088fd19ca942','道陽朔山水尤奇絕舊傳爲天下第一非虛語也賦二絕句  其一','李綱','宋','宋诗','song-poetry','','[]','溪山此地藹佳名，雨洗煙嵐分外青。',32,'全唐诗/poet.song.90000.json','["溪山此地藹佳名，雨洗煙嵐分外青。", "却恨征鞍太匆遽，無因一上萬雲亭。"]'),
('70da622f-ee17-4bbd-87f2-055a49d80d42','道陽朔山水尤奇絕舊傳爲天下第一非虛語也賦二絕句  其二','李綱','宋','宋诗','song-poetry','','[]','賦詩曾送謫仙人，垂老翻遊到海濱。',32,'全唐诗/poet.song.90000.json','["賦詩曾送謫仙人，垂老翻遊到海濱。", "夢幻去來何日了，且將病眼看嶙峋。"]'),
('1daedec9-69e3-461c-a29f-d8abaf33f848','獻花鋪唐相李德裕謫海南道此有山女獻花因以名之次壁間韻','李綱','宋','宋诗','song-poetry','','[]','我亦乘桴向海涯，無人復獻雨中花。',32,'全唐诗/poet.song.90000.json','["我亦乘桴向海涯，無人復獻雨中花。", "却愁春夢歸吳越，茗飲濃斟薄荷芽。"]'),
('0aa57afb-afd0-4653-94d5-b5ecb1628fb1','象州道中二首  其一','李綱','宋','宋诗','song-poetry','','[]','路入春山春日長，穿林渡水意徜徉。',64,'全唐诗/poet.song.90000.json','["路入春山春日長，穿林渡水意徜徉。", "溪環石笋横舟小，風落林花撲面香。", "山鳥不知興廢恨，嶺雲自覺去來忙。", "炎荒景物隨時好，何必深悲瘴癘鄉。"]'),
('8e37cf34-fcca-4197-9bc9-52e78623935d','象州道中二首  其二','李綱','宋','宋诗','song-poetry','','[]','竹屋茅簷三四家，土風漸覺異中華。',64,'全唐诗/poet.song.90000.json','["竹屋茅簷三四家，土風漸覺異中華。", "碧榕枝弱還生柱，紅荔春深已著花。", "社鷰不巢南候别，塞鴻無信北音賒。", "海山此去猶千里，會見安期棗似瓜。"]'),
('12c9f768-92aa-4862-a79b-589536d61be5','飲修仁茶','李綱','宋','宋诗','song-poetry','','[]','北苑龍團久不嘗，修仁茗飲亦甘芳。',64,'全唐诗/poet.song.90000.json','["北苑龍團久不嘗，修仁茗飲亦甘芳。", "誇研鬭白工夫拙，辟瘴消煩氣味長。", "江表露芽空絕品，蜀中仙掌可同行。", "從容飯罷何爲者，一椀還兼一炷香。"]'),
('7f315298-7352-4774-9051-3f55f354aa02','自去冬不雨至今道傍井竭田多不耕有感','李綱','宋','宋诗','song-poetry','','[]','匝地風雷空震蕩，終宵雲雨竟虛無。',64,'全唐诗/poet.song.90000.json','["匝地風雷空震蕩，終宵雲雨竟虛無。", "媮閒農具田皆廢，暍死行人井半枯。", "東海愆陽緣孝婦，桑林謁禱本讒夫。", "忠魂昭雪姦邪逐，坐見爲霖萬物蘇。"]'),
('3df23733-c508-492b-88f8-c0a87b2d9086','次貴州二首  其一','李綱','宋','宋诗','song-poetry','','[]','青楓夾道鷓鴣啼，古郡荒涼接島夷。',64,'全唐诗/poet.song.90000.json','["青楓夾道鷓鴣啼，古郡荒涼接島夷。", "陸績故城依石巘，葛洪遺竈俯江湄。", "光風苒苒吹香草，煙雨濛濛濕荔枝。", "欲作終焉卜居計，自應痀僂不吾欺。"]'),
('f1d7a96a-f5bf-4069-b77b-7d9728f7e832','次貴州二首  其二','李綱','宋','宋诗','song-poetry','','[]','懷澤爲邦古鬱林，江邊邑屋樹森森。',64,'全唐诗/poet.song.90000.json','["懷澤爲邦古鬱林，江邊邑屋樹森森。", "山連八桂峰巒秀，地近重溟霧雨淫。", "歲久承平消瘴癘，時危爭戰覺幽深。", "試謀十畝膏腴地，丹荔青蕉獲我心。"]'),
('79a5ac30-2a65-4f9f-80f6-6e244201c1f3','伏讀三月六日內禪詔書及傳將士牓檄慨王室之艱危憫生靈之塗炭悼前策之不從恨姦回之誤國感憤有作聊以述懷四首  其一','李綱','宋','宋诗','song-poetry','','[]','憶昔廷諍駐蹕時，孤忠欲挽六龍飛。',64,'全唐诗/poet.song.90000.json','["憶昔廷諍駐蹕時，孤忠欲挽六龍飛。", "萊公謾有親征策，亞父空求骸骨歸。", "靈武中興形勢便，江都巡幸士心違。", "纍臣獨荷三朝眷，瘴海徒將血涕揮。"]'),
('0ed870f2-5355-4345-824d-129a84419cc1','伏讀三月六日內禪詔書及傳將士牓檄慨王室之艱危憫生靈之塗炭悼前策之不從恨姦回之誤國感憤有作聊以述懷四首  其二','李綱','宋','宋诗','song-poetry','','[]','胡騎長驅擾漢疆，廟堂髙枕失提防。',64,'全唐诗/poet.song.90000.json','["胡騎長驅擾漢疆，廟堂髙枕失提防。", "關河自昔稱天府，淮海于今作戰塲。", "退避固知非得計，威靈何以鎮殊方。", "中原夷狄相衰盛，聖哲從來只自彊。"]'),
('d184cc59-4ada-4cd8-b6d8-94793f21a26c','伏讀三月六日內禪詔書及傳將士牓檄慨王室之艱危憫生靈之塗炭悼前策之不從恨姦回之誤國感憤有作聊以述懷四首  其三','李綱','宋','宋诗','song-poetry','','[]','歎息姦臣術已疏，謀身誤國竟何如。',64,'全唐诗/poet.song.90000.json','["歎息姦臣術已疏，謀身誤國竟何如。", "馬嵬不進楊釗死，關陜初臨元振除。", "王室威靈嗟索寞，蒼生環堵未安居。", "荒陬不見中原事，望斷東吳一紙書。"]'),
('ccff016c-40c9-4411-a95a-e45b5058ae15','伏讀三月六日內禪詔書及傳將士牓檄慨王室之艱危憫生靈之塗炭悼前策之不從恨姦回之誤國感憤有作聊以述懷四首  其四','李綱','宋','宋诗','song-poetry','','[]','建炎虛席待經綸，恩賜宸章寶墨新。',64,'全唐诗/poet.song.90000.json','["建炎虛席待經綸，恩賜宸章寶墨新。", "學際天人何敢爾，忠開金石庶當仁。", "孔明得主規模壯，陸贄離朝謗讟頻。", "今日追思慚至意，御書重執淚盈巾。"]'),
('d97d5a60-34ab-41b9-9c7b-dc43209ab12a','暮春雨中有感二首  其一','李綱','宋','宋诗','song-poetry','','[]','雨細梅黄荔子丹，殊方風物異江山。',32,'全唐诗/poet.song.90000.json','["雨細梅黄荔子丹，殊方風物異江山。", "客愁望極傷心處，更聽鉤輈雲木間。"]'),
('6590da6a-aec0-4fa5-a951-dbb0fc980059','暮春雨中有感二首  其二','李綱','宋','宋诗','song-poetry','','[]','萬物焦枯誰作霖，片雲成雨慰民心。',32,'全唐诗/poet.song.90000.json','["萬物焦枯誰作霖，片雲成雨慰民心。", "姦邪逐去精忠雪，天意方知感格深。"]'),
('ef6bdd4b-adba-4443-a96d-a7d674fe5cae','含笑花五首  其一','李綱','宋','宋诗','song-poetry','','[]','一去閩山遠玉顔，故人相遇有餘歡。',32,'全唐诗/poet.song.90000.json','["一去閩山遠玉顔，故人相遇有餘歡。", "臨風莞爾緣何事，應笑先生又失官。"]'),
('95216ade-2ab9-4e03-96a2-150856f4ff61','含笑花五首  其二','李綱','宋','宋诗','song-poetry','','[]','玉質猶披翡翠裳，温泉浴罷藹天香。',32,'全唐诗/poet.song.90000.json','["玉質猶披翡翠裳，温泉浴罷藹天香。", "回眸百媚嫣然處，羞死三千紅粉粧。"]'),
('09086f6d-6d59-4008-942b-611467e69fcb','含笑花五首  其三','李綱','宋','宋诗','song-poetry','','[]','竄逐流離老病身，天涯相見意相親。',32,'全唐诗/poet.song.90000.json','["竄逐流離老病身，天涯相見意相親。", "粲然不用干金買，應記當年作賦人。"]'),
('1747e361-4113-4c73-9f57-8bb79bc8913f','含笑花五首  其四','李綱','宋','宋诗','song-poetry','','[]','素淡丰容不自持，飬成妙質亦多時。',32,'全唐诗/poet.song.90000.json','["素淡丰容不自持，飬成妙質亦多時。", "不知巧倩東風裏，含蓄清香欲待誰。"]'),
('ee2055e4-8cef-4e0b-8f75-f3e1a8125c57','含笑花五首  其五','李綱','宋','宋诗','song-poetry','','[]','謂之曾詰笑何因，只笑明時竄海濱。',32,'全唐诗/poet.song.90000.json','["謂之曾詰笑何因，只笑明時竄海濱。", "晉以志窮萊以直，定兼我拙作三人。"]'),
('268e1429-d283-46f2-96dc-bccdc050f9e8','荔枝五首  其一','李綱','宋','宋诗','song-poetry','','[]','海山僊子絳羅襦，霧縠中單白玉膚。',32,'全唐诗/poet.song.90000.json','["海山僊子絳羅襦，霧縠中單白玉膚。", "知我遠來相勞苦，故馳先使迓中途。"]'),
('b1d7c7d1-696d-4b10-8a96-95321d251de7','荔枝五首  其二','李綱','宋','宋诗','song-poetry','','[]','絳紗囊裏水晶丸，偏得楊妃带笑看。',32,'全唐诗/poet.song.90000.json','["絳紗囊裏水晶丸，偏得楊妃带笑看。", "休道馬嵬當日事，只今何處是長安。"]'),
('c27849fe-0b14-482e-87e8-f77bb9accd1a','荔枝五首  其三','李綱','宋','宋诗','song-poetry','','[]','玉人纖指擘輕紅，猶憶恩頒自漢宫。',32,'全唐诗/poet.song.90000.json','["玉人纖指擘輕紅，猶憶恩頒自漢宫。", "翠籠藤盤異當日，蠻烟瘴雨正濛濛。"]'),
('ec50e74c-3c68-4e65-b2e7-ab9b2e8e1793','荔枝五首  其四','李綱','宋','宋诗','song-poetry','','[]','荔子蠻方也自丹，不如閩嶺爲微酸。',32,'全唐诗/poet.song.90000.json','["荔子蠻方也自丹，不如閩嶺爲微酸。", "玉盤磊珂三千顆，猶憶甘芳繞齒寒。"]'),
('6fdefac5-7f01-451c-ac6f-45732454a92a','荔枝五首  其五','李綱','宋','宋诗','song-poetry','','[]','百馬崩騰耆舊悲，只今戈戟暗江湄。',32,'全唐诗/poet.song.90000.json','["百馬崩騰耆舊悲，只今戈戟暗江湄。", "自知疏拙蒙恩重，猶得南來食荔枝。"]'),
('fd1400c2-f8a5-4570-8291-199978aae520','茉莉花二首  其一','李綱','宋','宋诗','song-poetry','','[]','泠艷幽芳雪不如，佳名初見貝多書。',32,'全唐诗/poet.song.90000.json','["泠艷幽芳雪不如，佳名初見貝多書。", "南人渾作尋常看，曾侍君王白玉除。"]'),
('e9927371-3349-498a-b8f2-9a9f02ab9226','茉莉花二首  其二','李綱','宋','宋诗','song-poetry','','[]','風露扶疏蔓翠藤，玉花剪刻見層層。',32,'全唐诗/poet.song.90000.json','["風露扶疏蔓翠藤，玉花剪刻見層層。", "清香夜久偏聞處，寂寞書生對一燈。"]'),
('475fd3af-f9eb-449a-b195-d35df39e1bf8','得梁谿書寄諸弟二首  其一','李綱','宋','宋诗','song-poetry','','[]','一紙書來抵萬金，天涯慰我念家心。',32,'全唐诗/poet.song.90000.json','["一紙書來抵萬金，天涯慰我念家心。", "只今王室猶如此，回首東吳涕作霖。"]'),
('72f53f56-a1a3-4f9e-bbd9-a91c5f03af18','得梁谿書寄諸弟二首  其二','李綱','宋','宋诗','song-poetry','','[]','荔子初丹色半青，玉膚未滿已芳馨。',32,'全唐诗/poet.song.90000.json','["荔子初丹色半青，玉膚未滿已芳馨。", "欲題書後三千顆，須待煙林燦若星。"]'),
('a6d0e139-e902-49d8-b532-bdddebc3e117','即事三首  其一','李綱','宋','宋诗','song-poetry','','[]','賓江兩岸木綿飛，負郭家家熟荔枝。',32,'全唐诗/poet.song.90000.json','["賓江兩岸木綿飛，負郭家家熟荔枝。", "瘴雨蠻煙已蕭瑟，可堪梅子欲黄時。"]'),
('4be0df65-75fd-4b18-85b0-066c6f35b2d3','即事三首  其二','李綱','宋','宋诗','song-poetry','','[]','荔枝紅紫已交加，龍眼新來又著花。',32,'全唐诗/poet.song.90000.json','["荔枝紅紫已交加，龍眼新來又著花。", "便欲謀居不須去，咀冰嚼雪過年華。"]'),
('4c8ea1df-5f49-4ccc-9e4e-d223fbce5e44','即事三首  其三','李綱','宋','宋诗','song-poetry','','[]','森森榕木碧参天，夏日初聞第一蟬。',32,'全唐诗/poet.song.90000.json','["森森榕木碧参天，夏日初聞第一蟬。", "美蔭羡君誠得計，何須悽怨嘒風前。"]'),
('2b3abf8f-3e5f-4f66-b6aa-1ea855ee4cfc','移居南山寺寺有巖洞甚幽并葛稚川丹竈','李綱','宋','宋诗','song-poetry','','[]','倚山髙閣仰觚稜，洞穴嵌空屐可登。',64,'全唐诗/poet.song.90000.json','["倚山髙閣仰觚稜，洞穴嵌空屐可登。", "丹竈舊傳留袐藥，仙巖今已屬閒僧。", "數峰削玉青如髻，羣木參天翠作層。", "小駐未妨幽興發，野禽嘲弄醉瞢騰。"]'),
('dbf0745e-5d85-4f2f-b958-530343a1bb76','伏睹四月五日赦書鑾輿反正中外大慶小臣有感斐然成章二首  其一','李綱','宋','宋诗','song-poetry','','[]','天眷吾皇築舊基，未應炎德遂中微。',64,'全唐诗/poet.song.90000.json','["天眷吾皇築舊基，未應炎德遂中微。", "共欣宸極還天步，賴有羣龍夾日飛。", "霈澤及民寰海慶，孤忠許國寸心違。", "建炎首被鈞衡選，孤負明恩淚濕衣。"]'),
('bbc410ed-b62d-46a1-9853-7f0d83b62c6e','伏睹四月五日赦書鑾輿反正中外大慶小臣有感斐然成章二首  其二','李綱','宋','宋诗','song-poetry','','[]','誤國姦邪已竄誅，天扶黼座正宸居。',64,'全唐诗/poet.song.90000.json','["誤國姦邪已竄誅，天扶黼座正宸居。", "少康一旅時猶在，髙祖三章術未疏。", "必順人心收俊傑，自應天意助耘鋤。", "纍臣海上空回首，願浥滄溟洗謗書。"]'),
('235c596d-4d60-4290-9125-2c1bb86e09e0','端午日次鬱林州','李綱','宋','宋诗','song-poetry','','[]','久謫沅湘習楚風，靈均千載此心同。',64,'全唐诗/poet.song.90000.json','["久謫沅湘習楚風，靈均千載此心同。", "豈知角黍縈絲日，却墮蠻煙瘴雨中。", "榕樹間關鸚鵡語，藤盤磊珂荔枝紅。", "殊方令節多悽感，家在東吳東復東。"]'),
('74af28ea-e187-4822-b363-c09abecf868a','恭聞詔書襃悼陳少陽贈官與一子恩澤賜緡錢五十萬感涕四首  其一','李綱','宋','宋诗','song-poetry','','[]','哀痛綸言灑帝章，賜金贈秩事非常。',64,'全唐诗/poet.song.90000.json','["哀痛綸言灑帝章，賜金贈秩事非常。", "無心聖主如天地，著意姦臣極虎狼。", "忠血他年應化碧，英魂今日已生光。", "先生憤懣誠昭雪，九死南遷豈自傷。"]'),
('7d83c910-7344-4523-a50a-f9408e4ff383','恭聞詔書襃悼陳少陽贈官與一子恩澤賜緡錢五十萬感涕四首  其二','李綱','宋','宋诗','song-poetry','','[]','祖宗德澤在斯民，韋带精忠不乏人。',64,'全唐诗/poet.song.90000.json','["祖宗德澤在斯民，韋带精忠不乏人。", "魏闕獻言開帝聽，匭函争事觸龍鱗。", "血霑斧越雖因我，心在宗祊豈計身。", "宿草已深難一慟，臨風空有涕霑巾。"]'),
('be8b128e-7232-4974-ba5a-f3206adaac0b','恭聞詔書襃悼陳少陽贈官與一子恩澤賜緡錢五十萬感涕四首  其三','李綱','宋','宋诗','song-poetry','','[]','屢將骾議叩楓宸，不爲承恩始愛君。',64,'全唐诗/poet.song.90000.json','["屢將骾議叩楓宸，不爲承恩始愛君。", "誰使崔寧論盧杞，恨無慶忌救朱雲。", "死生一吷心應了，忠義千年筆有芬。", "一介草茅言世務，從今不復數劉蕡。"]'),
('acbdac0c-b1d8-4a07-b255-775724619109','恭聞詔書襃悼陳少陽贈官與一子恩澤賜緡錢五十萬感涕四首  其四','李綱','宋','宋诗','song-poetry','','[]','平昔初無半面交，危言幾辨蓋寛饒。',64,'全唐诗/poet.song.90000.json','["平昔初無半面交，危言幾辨蓋寛饒。", "幽冥我已慚良友，忠憤君應念本朝。", "故國遥看雲杳杳，新阡何處草蕭蕭。", "撫孤未遂山濤志，誰繼騷人賦大招。"]'),
('d622a28d-b906-4e38-bf9a-25312ce4f498','寓鬱林著易傳有感  其一','李綱','宋','宋诗','song-poetry','','[]','謫來海嶠遠兵戈，精義微言得切瑳。',64,'全唐诗/poet.song.90000.json','["謫來海嶠遠兵戈，精義微言得切瑳。", "地入鬱林懷陸績，桴浮滄海學東坡。", "聖經廣大随人取，衆說紛綸奈若何。", "從此梁谿作詩少，用心已向六龍多。"]'),
('4e4fb1c0-35ef-420a-acc9-8734e059eff4','寓鬱林著易傳有感  其二','李綱','宋','宋诗','song-poetry','','[]','羲文作易仲尼傳，究極陰陽本自然。',64,'全唐诗/poet.song.90000.json','["羲文作易仲尼傳，究極陰陽本自然。", "妙理欲求須得象，至言已契可忘筌。", "絕編何啻須三過，知命從今加數年。", "歎息時無邵康節，數該今古與誰研。"]'),
('d968dfb7-7b2f-4be5-be57-2fecd05d0c74','次雷州','李綱','宋','宋诗','song-poetry','','[]','華夷圖上看雷州，萬里孤城據海陬。',64,'全唐诗/poet.song.90000.json','["華夷圖上看雷州，萬里孤城據海陬。", "萍跡飄流遽如許，騷辭擬賦畔牢愁。", "滄溟浩蕩煙雲曉，鼓角凄悲風露秋。", "莫笑炎荒地遐僻，萬安更在海南頭。"]'),
('6920a8d4-6365-42a8-9baf-534065691dc2','中秋月色佳甚與宗之對酌天寧寺寶華堂','李綱','宋','宋诗','song-poetry','','[]','去年今夕寓通城，猶有新詩寄弟兄。',64,'全唐诗/poet.song.90000.json','["去年今夕寓通城，猶有新詩寄弟兄。", "一自裹囊來海上，更無繫帛付鴻征。", "禪房酌酒夜方閴，海月窺人光更清。", "起舞月中心尚壯，乘槎便欲造蓬瀛。"]'),
('0078401b-a8ce-4ce1-84b4-d38b01db7bc9','所寓天寧方丈後有闍提花數株連月盛開玉雪可愛悵然有懷成三絕句寄吳元中  其一','李綱','宋','宋诗','song-poetry','','[]','未渡鯨波寇盗深，中原回首涕成霖。',32,'全唐诗/poet.song.90000.json','["未渡鯨波寇盗深，中原回首涕成霖。", "清愁萬斛無消處，賴有幽花慰客心。"]'),
('aa7d7816-d98d-46cc-a61f-9cc66182cd34','所寓天寧方丈後有闍提花數株連月盛開玉雪可愛悵然有懷成三絕句寄吳元中  其二','李綱','宋','宋诗','song-poetry','','[]','深院無人簾幕垂，玉英翠羽燦芳枝。',32,'全唐诗/poet.song.90000.json','["深院無人簾幕垂，玉英翠羽燦芳枝。", "世間顔色難相似，晴雪初殘未墮時。"]'),
('7e08e0fb-0db2-4030-80c5-709deb1912b2','所寓天寧方丈後有闍提花數株連月盛開玉雪可愛悵然有懷成三絕句寄吳元中  其三','李綱','宋','宋诗','song-poetry','','[]','冰玉風姿照坐寒，炎荒相遇且相寛。',32,'全唐诗/poet.song.90000.json','["冰玉風姿照坐寒，炎荒相遇且相寛。", "縞衣紵带平生志，正念幽人尚素冠。"]'),
('d8155a78-b9e4-4548-b6b0-8e169ccc85c2','得家書報長子儀之房下得孫男殊慰老懷時在雷州著易傳適至震卦因名之曰震孫以詩寄儀之','李綱','宋','宋诗','song-poetry','','[]','天涯遠報茁瓊枝，共說鵷雛骨相奇。',96,'全唐诗/poet.song.90000.json','["天涯遠報茁瓊枝，共說鵷雛骨相奇。", "鼻祖從來種桃李，耳孫自合産蘭芝。", "洊雷名震因觀易，他日趨庭使學詩。", "無復區區如爾父，定須了了勝吾兒。", "書來可想開懷抱，老去何因與弄持。", "素有龐翁攜隱志，未應孤負鹿門期。"]'),
('5d7128df-10a6-4c74-9fec-99bd46cb7eec','九日與宗之對酌懷梁谿諸季時菊花猶未結蘂於藥菓中得茱萸泛酒有饋山果海鮮者多素所不識賦詩見意二首  其一','李綱','宋','宋诗','song-poetry','','[]','此身飄泊旅天涯，九日悽然客念家。',64,'全唐诗/poet.song.90000.json','["此身飄泊旅天涯，九日悽然客念家。", "且把紅醪嘗紫蟹，何須白髪對黄花。", "藥囊賴有茱萸實，茶銚頻煩薄荷芽。", "山果海鮮多不識，却須傳與北人誇。"]'),
('de08efce-4858-4dfc-9c4b-52f4c1cd90ce','九日與宗之對酌懷梁谿諸季時菊花猶未結蘂於藥菓中得茱萸泛酒有饋山果海鮮者多素所不識賦詩見意二首  其二','李綱','宋','宋诗','song-poetry','','[]','父子相随萬里餘，途窮端欲哭楊朱。',64,'全唐诗/poet.song.90000.json','["父子相随萬里餘，途窮端欲哭楊朱。", "三年客裏逢佳節，九日罇前念友于。", "海上及秋吟蟋蟀，鬢邊何日插茱萸。", "吾生老矣謀身拙，歎息乾坤一腐儒。"]'),
('c57010b4-b625-4a08-8fdc-5807342f3648','嶠南僧罕遵戒律况向上事獨琮師隱居湖巖絕不至城市超然拔俗聞余來策杖見過與語可人知爲飽參衲子也詢其所見蓋嘗從長蘆了遊了居長蘆聚徒至千五百衆道價籍甚江淮間余雖不之識然聲氣相合心期自親嘗辱貽問今見琮益知了之門風孤峻真楷老兒孫也退處天台琮將浮海訪之因賦詩贈琮且簡了公異時得歸决須相随於石橋側可以握手一笑梁谿居士云','李綱','宋','宋诗','song-poetry','','[]','萬里謫官來海嶠，眼中衲子見絕少。',160,'全唐诗/poet.song.90000.json','["萬里謫官來海嶠，眼中衲子見絕少。", "方袍圓頂動成羣，與俗不同秪其表。", "琮師乃是雷陽人，徧歷叢林參學飽。", "歸來卜築瘴海濱，十里湖光巖洞小。", "深居不復踏城市，宴坐惟知侣猿鳥。", "惠然過我意良勤，野鶴孤雲自輕矯。", "風姿已含蔬筍氣，語論更將藤葛繞。", "黄茅深處見松筠，使我囷箱欲傾倒。", "爲親聊復戀幽棲，訪舊終須乘漭渺。", "煩師飛錫過天台，爲問了公何法了。"]'),
('cb75caf0-a2e3-4a90-996a-e1cea1fd907a','冬至','李綱','宋','宋诗','song-poetry','','[]','殊方又復一陽芽，荏苒流年歎物華。',64,'全唐诗/poet.song.90000.json','["殊方又復一陽芽，荏苒流年歎物華。", "土薄葭灰難測候，氣温桃樹已開花。", "雲鴻不到音書斷，鯨海無程道里賖。", "賴有清心爲活計，不須爛醉作生涯。"]'),
('b00e725c-7426-4830-ad50-72b2eb32e20d','海南黎人作過據臨臯縣驚刼傍近因小留海康十一月望聞官軍破賊二十日戒行戲作兩絕句  其一','李綱','宋','宋诗','song-poetry','','[]','海上羣黎亦弄兵，征車數月旅山城。',32,'全唐诗/poet.song.90000.json','["海上羣黎亦弄兵，征車數月旅山城。", "稽留謫命兢惶甚，正坐緋巾懲沸羮。"]'),
('c7fe7733-24fa-483c-87b9-a35f4826de1a','海南黎人作過據臨臯縣驚刼傍近因小留海康十一月望聞官軍破賊二十日戒行戲作兩絕句  其二','李綱','宋','宋诗','song-poetry','','[]','沈沈碧海絕津涯，一葉凌波亦快哉。',32,'全唐诗/poet.song.90000.json','["沈沈碧海絕津涯，一葉凌波亦快哉。", "假使黑風漂蕩去，不妨乘興訪蓬莱。"]'),
('c2d7d698-b99b-47db-aaf7-a26122cded53','次地角場以瘡瘍不果謁伏波廟俾宗之攝祭期以二十五日渡海一卜即吉夜半乘潮解桴星月燦然風便波平詰旦已達瓊管東坡謂斯遊奇絕冠平生非虚語也作二詩紀之  其一','李綱','宋','宋诗','song-poetry','','[]','威信昭然漢兩公，舊於青史揖英風。',64,'全唐诗/poet.song.90000.json','["威信昭然漢兩公，舊於青史揖英風。", "戈船下瀨勳猷壯，馬革裹尸心膽雄。", "顧我迂疏成遠謫，賴神正直鑒孤忠。", "病軀阻造祠庭下，幽顯雖殊此意同。"]'),
('87b96714-246d-4bc5-a01d-668a82e9cdba','次地角場以瘡瘍不果謁伏波廟俾宗之攝祭期以二十五日渡海一卜即吉夜半乘潮解桴星月燦然風便波平詰旦已達瓊管東坡謂斯遊奇絕冠平生非虚語也作二詩紀之  其二','李綱','宋','宋诗','song-poetry','','[]','夜半乘潮雲海中，伏波肯借一帆風。',64,'全唐诗/poet.song.90000.json','["夜半乘潮雲海中，伏波肯借一帆風。", "滿天星月光鋩碎，匝海波濤氣象雄。", "大舶憑陵真漭渺，寸心感格在精忠。", "老坡去後何人繼，奇絕斯遊只我同。"]'),
('4f47fe81-d3ae-4347-9fcd-657fbb2845d1','次東坡韻二首  其一','李綱','宋','宋诗','song-poetry','','[]','地角潮來未五更，陰雲解駮作霜晴。',64,'全唐诗/poet.song.90000.json','["地角潮來未五更，陰雲解駮作霜晴。", "星河明潤天容睟，風浪喧豗海氣清。", "粗見鯤鵬潛化理，豈無犬馬戀軒聲。", "遠遊不作乘桴計，虚號男兒過此生。"]'),
('0c29d7ba-c820-445e-9c67-530b1ffa2708','次東坡韻二首  其二','李綱','宋','宋诗','song-poetry','','[]','海上傳呼夜報更，舟師歡喜得新晴。',64,'全唐诗/poet.song.90000.json','["海上傳呼夜報更，舟師歡喜得新晴。", "風帆擘浪去時急，海月籠雲分外清。", "天影合中觀妙色，潮波迴處悟圓聲。", "從來渤海爲全體，試問一漚何處生。"]'),
('3f46ea53-72f2-457c-8959-ca6b61d77c31','南渡次瓊管江山風物與海北不殊民居皆在檳榔木間黎人出市交易蠻衣椎髻語音兜離不可曉也因詢萬安相去猶五百里僻陋尤甚黄茅中草屋二百餘家資生之具一切無有道由生黎峒山往往剽刼行者必自文昌縣泛海得便風三日可達艱難至此不勝慨然賦詩二首紀土風志懷抱也  其一','李綱','宋','宋诗','song-poetry','','[]','巨舶浮于海，長飈送短蓬。',192,'全唐诗/poet.song.90000.json','["巨舶浮于海，長飈送短蓬。", "夜潮和月白，曉日跳波紅。", "雲影搖脩浪，瀾光接遠空。", "喜過三河流，愁遠冠頭峰。", "雷化迷天際，瓊儋入望中。", "地遥横一線，山露點羣鴻。", "偶脫鯨鯢患，尤欣氣俗同。", "川原驚老眼，稚耋看衰翁。", "蠻市蝦魚合，賓居棟宇雄。", "人煙未寥落，竹樹自葱蘢。", "碧暗檳榔葉，香移薄荷叢。", "金花翔孔翠，綵幕問黎童。", "南極冬猶暖，中原信不通。", "管寧雖跡遠，阮籍已途窮。", "澒洞滄波裏，蒼茫返照東。", "客愁渾不寢，鼓角五更風。"]'),
('5692ae56-e0e9-4d07-96d5-f5df45662085','南渡次瓊管江山風物與海北不殊民居皆在檳榔木間黎人出市交易蠻衣椎髻語音兜離不可曉也因詢萬安相去猶五百里僻陋尤甚黄茅中草屋二百餘家資生之具一切無有道由生黎峒山往往剽刼行者必自文昌縣泛海得便風三日可達艱難至此不勝慨然賦詩二首紀土風志懷抱也  其二','李綱','宋','宋诗','song-poetry','','[]','四郡環黎母，窮愁最萬安。',192,'全唐诗/poet.song.90000.json','["四郡環黎母，窮愁最萬安。", "峒氓能憫寇，瀧吏豈欺韓。", "草屋叢篁裏，孤城瘴海端。", "民居纔百數，道里尚艱難。", "徑陸憂生蜑，乘桴畏怒瀾。", "颶風能破膽，癘氣必摧肝。", "去死垂垂近，資生物物殫。", "舶來方得米，牢罄或無餐。", "樹芋充嘉饌，蠯蠃薦淺盤。", "蔞藤茶更苦，淡水酒仍酸。", "黎户花縵服，儒生椰子冠。", "檳榔資一醉，吉貝不知寒。", "何必從詹尹，無因詠考槃。", "失圖嗟罪大，得此荷恩寛。", "顧影同三友，談空不二觀。", "中州杳何在，猶共月團欒。"]'),
('020e3bd2-f61c-4f72-a6f7-ebf8d8c5c618','檳榔','李綱','宋','宋诗','song-poetry','','[]','疏林蒼海上，結實已纍纍。',96,'全唐诗/poet.song.90000.json','["疏林蒼海上，結實已纍纍。", "煙濕頳虬卵，風搖翠羽旗。", "飛翔金鸑鷟，掩映籜龍兒。", "濩落咍椰子，勻圓訝荔支。", "當茶鎖瘴速，如酒醉人遲。", "蔞葉偏相稱，蠃灰亦謾爲。", "乍餐顔愧渥，頻嚼齒愁疲。", "飲啄随風土，端憂化島夷。"]'),
('6dd0ff5d-e645-4179-a71f-378a16ec48a3','次瓊管後三日忽奉德音恩許自便感涕之餘賦詩見志  其一','李綱','宋','宋诗','song-poetry','','[]','此身飄墮到滄溟，誰謂君王念賈生。',64,'全唐诗/poet.song.90000.json','["此身飄墮到滄溟，誰謂君王念賈生。", "黄帋再蒙題姓字，丹書特爲削刑名。", "山林老去何其幸，萍梗追思却自驚。", "天地恩寛難報德，試從今日數歸程。"]'),
('25b26874-1476-45a2-bc82-3903fef05efc','次瓊管後三日忽奉德音恩許自便感涕之餘賦詩見志  其二','李綱','宋','宋诗','song-poetry','','[]','行年舊說似東坡，鯨海于今亦再過。',64,'全唐诗/poet.song.90000.json','["行年舊說似東坡，鯨海于今亦再過。", "儋耳三年時已久，瓊山十日幸尤多。", "卻收老眼來觀國，尚冀中原早戢戈。", "病廢不堪當世用，感恩惟有涕霶𩃱。"]'),
('1603d8f8-2903-4fdf-be04-acab71d6be63','郡城南曰瓊臺北曰語海余易之曰雲海登眺有感  其一','李綱','宋','宋诗','song-poetry','','[]','孤城南面敞瓊臺，千里川原指顧開。',32,'全唐诗/poet.song.90000.json','["孤城南面敞瓊臺，千里川原指顧開。", "試向綠雲深處望，海山浮動見蓬莱。"]'),
('67eebdf3-a24a-450b-b4dd-ffff127a1e30','郡城南曰瓊臺北曰語海余易之曰雲海登眺有感  其二','李綱','宋','宋诗','song-poetry','','[]','古來雲海浩茫茫，北望悽然欲斷膓。',32,'全唐诗/poet.song.90000.json','["古來雲海浩茫茫，北望悽然欲斷膓。", "不得中州近消息，六龍何處駐東皇。"]'),
('21314964-9268-4efb-9cd5-6bb7e7837615','北歸晝渡海風便波平尤覺奇絕成五絕句  其一','李綱','宋','宋诗','song-poetry','','[]','澄波不動琉璃滑，一望應須萬里餘。',32,'全唐诗/poet.song.90000.json','["澄波不動琉璃滑，一望應須萬里餘。", "舟行衝激浪花碎，如馭白雲遊碧虚。"]'),
('e75f2d9d-fe08-4b8f-a616-455cacfb17b7','北歸晝渡海風便波平尤覺奇絕成五絕句  其二','李綱','宋','宋诗','song-poetry','','[]','去得南風來北風，神靈只在指呼中。',32,'全唐诗/poet.song.90000.json','["去得南風來北風，神靈只在指呼中。", "老坡有語舊曾記，信我人阨非天窮。"]'),
('9e8aa6d4-295e-43dc-b1e3-05f2d7c1d6f4','北歸晝渡海風便波平尤覺奇絕成五絕句  其三','李綱','宋','宋诗','song-poetry','','[]','來時風浪夜喧驚，歸去潮波枕席平。',32,'全唐诗/poet.song.90000.json','["來時風浪夜喧驚，歸去潮波枕席平。", "非是波神有分别，故教清晝看寰瀛。"]'),
('8bba0dbe-b081-4cc0-a9fd-1e52b1a39a60','北歸晝渡海風便波平尤覺奇絕成五絕句  其四','李綱','宋','宋诗','song-poetry','','[]','纖雲肆卷日方中，海色天光上下同。',32,'全唐诗/poet.song.90000.json','["纖雲肆卷日方中，海色天光上下同。", "身在琉璃光合裏，碧空涵水水涵空。"]'),
('420b4e18-fd97-4022-b97f-9493842a6b60','北歸晝渡海風便波平尤覺奇絕成五絕句  其五','李綱','宋','宋诗','song-poetry','','[]','平生奔走畏江湖，暮齒來乘海上桴。',32,'全唐诗/poet.song.90000.json','["平生奔走畏江湖，暮齒來乘海上桴。", "自哂井蛙真見小，望洋向若一盧胡。"]'),
('10204567-23bd-495b-9c4d-e550ba22bf53','歸次海康登平仙亭次莱公韵','李綱','宋','宋诗','song-poetry','','[]','碧海瞰危亭，波光混大清。',24,'全唐诗/poet.song.90000.json','["碧海瞰危亭，波光混大清。", "曠懷知樂此，夷險本來平。"]'),
('3e6a0aa2-e98f-4b73-99a3-d0117234554a','歸次海康登平仙亭次莱公韵 雷廟讀丁晉公所作碑','李綱','宋','宋诗','song-poetry','','[]','巨卵曾因霹靂開，海邦從此得名雷。',32,'全唐诗/poet.song.90000.json','["巨卵曾因霹靂開，海邦從此得名雷。", "只知寇老曾遷此，作記何緣丁令來。"]'),
('d24025ba-f538-4c66-9439-532ca4524b6a','謁寇忠愍祠堂六首  其一','李綱','宋','宋诗','song-poetry','','[]','親征决策幸澶淵，南北歡盟有本原。',32,'全唐诗/poet.song.90000.json','["親征决策幸澶淵，南北歡盟有本原。", "丞相莱公功第一，猶將孤注作讒言。"]'),
('d03c7a03-cb4e-47e6-b04d-456d1ef07a91','謁寇忠愍祠堂六首  其二','李綱','宋','宋诗','song-poetry','','[]','一幸江南一蜀中，奮然廷議叱羣公。',32,'全唐诗/poet.song.90000.json','["一幸江南一蜀中，奮然廷議叱羣公。", "攙回天步雖良策，元是真皇聽納功。"]'),
('89803c00-ba64-4752-aa3c-6d885467feec','謁寇忠愍祠堂六首  其三','李綱','宋','宋诗','song-poetry','','[]','南陽廟坐致云云，賴有嘉言爲解紛。',32,'全唐诗/poet.song.90000.json','["南陽廟坐致云云，賴有嘉言爲解紛。", "歎息今人不如古，久無慶忌救朱雲。"]'),
('2960d643-285d-4b6d-a13a-10f4032a1437','謁寇忠愍祠堂六首  其四','李綱','宋','宋诗','song-poetry','','[]','平生愛看柘枝舞，賓燕多餘密炬堆。',32,'全唐诗/poet.song.90000.json','["平生愛看柘枝舞，賓燕多餘密炬堆。", "富貴在公真末事，誰云緣此故南來。"]'),
('1c35666f-1e9e-4754-8473-292283951b4b','謁寇忠愍祠堂六首  其五','李綱','宋','宋诗','song-poetry','','[]','海邦去海只十里，山路過山應萬重。',32,'全唐诗/poet.song.90000.json','["海邦去海只十里，山路過山應萬重。", "詩讖告人元已久，未應馬援坐梁松。"]'),
('cd80df70-5bd4-4a06-b48e-a9a9f5ed43d1','謁寇忠愍祠堂六首  其六','李綱','宋','宋诗','song-poetry','','[]','鑿井得泉今尚美，掛錢插竹後成林。',32,'全唐诗/poet.song.90000.json','["鑿井得泉今尚美，掛錢插竹後成林。", "精忠感動無情物，不解潛銷讒妬心。"]'),
('9334ef1b-a52c-411f-900a-6d97f72f8467','初發雷陽有感二首  其一','李綱','宋','宋诗','song-poetry','','[]','夢中曾過鬼門關，敢冀君恩聽北還。',64,'全唐诗/poet.song.90000.json','["夢中曾過鬼門關，敢冀君恩聽北還。", "父子相随幸良厚，僕奴半死涕空澘。", "風煙蕭瑟黄茅瘴，山路崎嶇赤脚蠻。", "歸去梁谿見桑梓，定抛冠佩老巖間。"]'),
('0e17705d-021a-4b40-beb2-1b26a484d767','初發雷陽有感二首  其二','李綱','宋','宋诗','song-poetry','','[]','餘生幸爾脫垂涎，雞肋安能拒老拳。',64,'全唐诗/poet.song.90000.json','["餘生幸爾脫垂涎，雞肋安能拒老拳。", "萬里得歸辭瘴海，三年奔命厭征軒。", "採薇散髪嵇中散，開竈燒丹葛稚川。", "此去山林如脫兔，這回且結好因緣。"]'),
('7f1dfb9e-ca3a-4c79-b5ca-dcdecc1dcae5','琮師送至城月驛戲成兩絕句以答其意  其一','李綱','宋','宋诗','song-poetry','','[]','衲子來參去不辭，何勞飛錫遠相追。',32,'全唐诗/poet.song.90000.json','["衲子來參去不辭，何勞飛錫遠相追。", "贈師銀布牢收取，便是金襴付囑時。"]'),
('f37b14ca-ff66-44de-8533-0133ccb338ba','琮師送至城月驛戲成兩絕句以答其意  其二','李綱','宋','宋诗','song-poetry','','[]','好住湖巖攝此心，有緣終會有知音。',32,'全唐诗/poet.song.90000.json','["好住湖巖攝此心，有緣終會有知音。", "梁谿老去孤峰頂，月白風清難更尋。"]'),
('3145b0e4-5067-422b-88c0-4500b094cc87','立春日龍化道中得家問諸季已挈家渡浙江如劍川又聞江西頗有羣盗嘯聚遂决意由五羊趨循惠潮陽假道閩中以歸偶成三篇時十二月十九日  其一','李綱','宋','宋诗','song-poetry','','[]','東君又換一年春，迎我來從瘴海濱。',64,'全唐诗/poet.song.90000.json','["東君又換一年春，迎我來從瘴海濱。", "已覺山川有佳氣，更詢道路得通津。", "欲尋勾漏丹砂令，與訪羅浮紫府人。", "清夢相符緣契合，便須脫屣謝埃塵。"]'),
('1e7b1c4f-3abe-4a4b-8565-fa9ca3888c38','立春日龍化道中得家問諸季已挈家渡浙江如劍川又聞江西頗有羣盗嘯聚遂决意由五羊趨循惠潮陽假道閩中以歸偶成三篇時十二月十九日  其二','李綱','宋','宋诗','song-poetry','','[]','遠信來時嶺嶠春，浮家已在浙江濱。',64,'全唐诗/poet.song.90000.json','["遠信來時嶺嶠春，浮家已在浙江濱。", "更傳贑水方虞寇，須向閩山與問津。", "萬里歸來尋樂土，千巖好去作閒人。", "干戈未息中原暗，悵望關河胡馬塵。"]'),
('325e04ad-38d8-4caf-9954-ffef31507b72','立春日龍化道中得家問諸季已挈家渡浙江如劍川又聞江西頗有羣盗嘯聚遂决意由五羊趨循惠潮陽假道閩中以歸偶成三篇時十二月十九日  其三','李綱','宋','宋诗','song-poetry','','[]','川途奔走四回春，海上經年與死濱。',64,'全唐诗/poet.song.90000.json','["川途奔走四回春，海上經年與死濱。", "子美自憐常作客，長沮應笑是知津。", "艱危至死無千古，憂患如吾豈兩人。", "往返循環真磨蟻，已將大地等微塵。"]'),
('cf3aefb5-c353-49b6-aff1-84ad13ccd016','久不飲酒春日得家問喜甚與宗之對酌調馬驛中速飲數觥徑醉醉中和東坡醉題四首  其一','李綱','宋','宋诗','song-poetry','','[]','海嶠無佳釀，經時不入唇。',48,'全唐诗/poet.song.90000.json','["海嶠無佳釀，經時不入唇。", "巨觥今一醉，遠問到初春。", "偶脫長鯨口，來尋仲子鄰。", "醉中輕萬里，始信濁醪神。"]'),
('fee764e8-1f46-48f7-b558-0336cc566d10','久不飲酒春日得家問喜甚與宗之對酌調馬驛中速飲數觥徑醉醉中和東坡醉題四首  其二','李綱','宋','宋诗','song-poetry','','[]','畏病不舉盃，延客秖烹茗。',48,'全唐诗/poet.song.90000.json','["畏病不舉盃，延客秖烹茗。", "浩然雲海間，不醉亦不醒。", "偶蒙雨露恩，漸脫瘴癘境。", "麴生粗可人，相對聊酩酊。"]'),
('2273e660-e779-4e40-a397-b7020616637b','久不飲酒春日得家問喜甚與宗之對酌調馬驛中速飲數觥徑醉醉中和東坡醉題四首  其三','李綱','宋','宋诗','song-poetry','','[]','久客殊念家，歸途渺江漢。',48,'全唐诗/poet.song.90000.json','["久客殊念家，歸途渺江漢。", "是身如浮雲，罹此無窮患。", "今夕定何夕，一酌千憂散。", "從茲日曛酣，此意君莫間。"]'),
('ab17eb07-ea96-47f4-871a-a3a05cd293dd','久不飲酒春日得家問喜甚與宗之對酌調馬驛中速飲數觥徑醉醉中和東坡醉題四首  其四','李綱','宋','宋诗','song-poetry','','[]','飲少輙大醉，醉中識其真。',48,'全唐诗/poet.song.90000.json','["飲少輙大醉，醉中識其真。", "天地一秋毫，况此渺然身。", "歸休巖穴間，坐閱萬態新。", "去去勿復道，時清爲幸民。"]'),
('da057736-2a23-4718-a0c1-d35eee2085bb','寓瓊山遠華館一夕夢遊山間小堂松竹環合有道士坐堂上誦李太白送人遊桃源序中有良田名池竹果森然三十六洞别爲一天之語覺而異之今假道容惠當遊勾漏都嶠白石羅浮皆洞天也豈神者先告將有所遇耶賦詩以紀之','李綱','宋','宋诗','song-poetry','','[]','神清遂仙遊，境寂恣遐躅。',120,'全唐诗/poet.song.90000.json','["神清遂仙遊，境寂恣遐躅。", "羽人入我夢，軒户靄松竹。", "髙吟謫仙文，逸韻響金玉。", "覺來殘燈熒，倘怳猶在目。", "歸途歷容惠，問津非素卜。", "將遊四洞天，就彼白雲宿。", "豈無葛稚川，妙論資灌沃。", "試求龍虎丹，一使鬢毛綠。", "斯言儻可珍，長揖謝浮俗。", "却笑昌黎翁，强項寧詰曲。"]'),
('cead611c-2393-4322-a675-ccfd1c080a81','海上得孔雀六鸚鵡十餘攜歸遺童稚輩戲成二絕句  其一','李綱','宋','宋诗','song-poetry','','[]','鳳友鸞朋出海邦，金花翠尾爛文章。',32,'全唐诗/poet.song.90000.json','["鳳友鸞朋出海邦，金花翠尾爛文章。", "梁谿臺紹今何似，歸伴胎僊取次翔。"]'),
('aa3ed2df-6753-4b7f-a2b6-eeb58e34950e','海上得孔雀六鸚鵡十餘攜歸遺童稚輩戲成二絕句  其二','李綱','宋','宋诗','song-poetry','','[]','綠衣紺趾已能飛，學語交交末轉時。',32,'全唐诗/poet.song.90000.json','["綠衣紺趾已能飛，學語交交末轉時。", "不是蓬莱花鳥使，攜歸聊與調羣兒。"]'),
('a4339826-2b2b-44fd-abb9-dcdb2c28b698','立春後一日風雨殊有寒色偶成','李綱','宋','宋诗','song-poetry','','[]','竟夕北風號，春回雨已膏。',48,'全唐诗/poet.song.90000.json','["竟夕北風號，春回雨已膏。", "歸程離海嶠，舊服理綈袍。", "宿瘴須寒壓，清愁欲醉逃。", "何當入江浙，雪片灑鵝毛。"]'),
('9ea5d033-cb8d-45c5-ac0f-e2354538604e','容南道中二首  其一','李綱','宋','宋诗','song-poetry','','[]','路入容南境，風煙自一方。',48,'全唐诗/poet.song.90000.json','["路入容南境，風煙自一方。", "山空雲苒苒，春動水茫茫。", "紫府丹砂秘，幽村碧樹芳。", "肅然有佳致，作箇是炎荒。"]'),
('58c0cb42-e85c-4243-9229-86cfac6b9c18','容南道中二首  其二','李綱','宋','宋诗','song-poetry','','[]','聞說容南久，安知客路經。',48,'全唐诗/poet.song.90000.json','["聞說容南久，安知客路經。", "沉沉洞天近，湛湛古湫渟。", "日落峰巒翠，春回草木青。", "丹砂如可問，當卜老巖扃。"]'),
('e5c37f72-6be3-44a9-911a-873724895c67','再賦孔雀鸚鵡二首  其一','李綱','宋','宋诗','song-poetry','','[]','孔雀來從海上村，參差脩尾燦金文。',64,'全唐诗/poet.song.90000.json','["孔雀來從海上村，參差脩尾燦金文。", "素知肅穆鸞凰侣，不是喧卑雞鶩羣。", "玄圃赤霄雖有志，碧梧翠竹正須君。", "攜持萬里歸吳越，悵望海山深處雲。"]'),
('bdf9fce5-2411-48e8-913b-c303c5c49e84','再賦孔雀鸚鵡二首  其二','李綱','宋','宋诗','song-poetry','','[]','學語鸚鶵羽漸成，掌中取食絕猜驚。',64,'全唐诗/poet.song.90000.json','["學語鸚鶵羽漸成，掌中取食絕猜驚。", "籠寛得遂朋從志，春曉初聞客到聲。", "賦就襧衡文不點，杓随李白飲如鯨。", "遠攜休歎殊方去，我亦随緣得此生。"]'),
('1c3330c0-dd1c-48fc-a26d-4b28b0ed50a9','陸川道中偶成','李綱','宋','宋诗','song-poetry','','[]','嶠南江北本來同，往返紛紛一夢中。',64,'全唐诗/poet.song.90000.json','["嶠南江北本來同，往返紛紛一夢中。", "舊事銷磨那復有，新愁繚繞亦成空。", "天邊山色浮濃翠，溪上雲光拂淡紅。", "我把浮生如夢看，雲山元是小屏風。"]'),
('c08a6742-cd28-4842-8cc4-0723d145ea60','南遷道鬱林郡守王君示古律詩一篇北歸輙成兩篇以答其意  其一','李綱','宋','宋诗','song-poetry','','[]','山圍古郡碧周遭，陸績衣冠雅自襃。',64,'全唐诗/poet.song.90000.json','["山圍古郡碧周遭，陸績衣冠雅自襃。", "海上來歸懷麈尾，鬢間空歎長霜毛。", "易書顧我耽成癖，詩筆憐君老更豪。", "此去龍城幸非遠，不須巨石壓雲濤。"]'),
('dbda0c59-1da9-4b3d-ad99-bbb20bd0f528','南遷道鬱林郡守王君示古律詩一篇北歸輙成兩篇以答其意  其二','李綱','宋','宋诗','song-poetry','','[]','垂老相逢海嶠間，盈編珠玉破愁顔。',64,'全唐诗/poet.song.90000.json','["垂老相逢海嶠間，盈編珠玉破愁顔。", "清名豈籍鬱林石，雅志常存仙奕山。", "丘壑採薇嗟我病，絃歌爲政羡君閒。", "中原杳杳旌旗暗，迴首春風涕一澘。"]'),
('888a9d6f-1aad-4119-9385-173e7a02ce77','過北流縣八里遊勾漏觀留五絕句  其一','李綱','宋','宋诗','song-poetry','','[]','百里仙山氣象雄，參差峰岫翠成叢。',32,'全唐诗/poet.song.90000.json','["百里仙山氣象雄，參差峰岫翠成叢。", "雲駢鶴馭今何處，丹竈依然洞穴中。"]'),
('495e5a8c-f632-4de0-8eee-7926ada6291d','過北流縣八里遊勾漏觀留五絕句  其二','李綱','宋','宋诗','song-poetry','','[]','葛翁求令爲丹砂，今我來從海上槎。',32,'全唐诗/poet.song.90000.json','["葛翁求令爲丹砂，今我來從海上槎。", "秪恐山靈嫌俗駕，未容歸客臥煙霞。"]'),
('846065f6-ee3a-47cc-a0f7-054c370b4f9b','過北流縣八里遊勾漏觀留五絕句  其三','李綱','宋','宋诗','song-poetry','','[]','羽人相導把霓旌，窈窕松林露氣清。',32,'全唐诗/poet.song.90000.json','["羽人相導把霓旌，窈窕松林露氣清。", "不用逢迎同貴客，暫來花院聽棋聲。"]'),
('c2c811f7-d6b6-4122-bf9b-24359223a830','過北流縣八里遊勾漏觀留五絕句  其四','李綱','宋','宋诗','song-poetry','','[]','避謗多時不到山，忽驚身在洞天間。',32,'全唐诗/poet.song.90000.json','["避謗多時不到山，忽驚身在洞天間。", "北歸更覺君恩重，得遂清遊一解顔。"]'),
('aba0cc5b-f3e2-4272-9d08-fc7cb44908d1','過北流縣八里遊勾漏觀留五絕句  其五','李綱','宋','宋诗','song-poetry','','[]','洞户沉沉别有天，玉樓珠殿鎖霏煙。',32,'全唐诗/poet.song.90000.json','["洞户沉沉别有天，玉樓珠殿鎖霏煙。", "如何祠館人間世，破屋荒凉紫府前。"]'),
('53313a18-82e1-4199-a632-e8c6ad6683f3','道勾漏山靈寶觀竊睹兩朝御書謹成古風','李綱','宋','宋诗','song-poetry','','[]','抱疴臥雲海，夙夕負深恐。',252,'全唐诗/poet.song.90000.json','["抱疴臥雲海，夙夕負深恐。", "寛恩聽旋歸，何啻丘嶽重。", "問津勾漏山，散策寶圭洞。", "羣峰羅翠屏，環合無缺空。", "遊仙契初心，幽賞恊清夢。", "却來觀宸章，寶氣騰螮蝀。", "真行雜草隸，筆勢極翔動。", "大小飛白書，飄灑縈舞鳳。", "恭惟睿智姿，多能本天縱。", "妙蹟藏名山，俾與萬世共。", "林巒增炳煥，神物勞護擁。", "惜無深巖屋，蔭覆示崇奉。", "何當鳩良材，爲葺傾壓棟。", "天弧不指狼，中原胡馬閧。", "九廟未奠居，臣子衘憤痛。", "豈知炎荒中，奎畫得瞻諷。", "至哉慱大言，粟麥因異種。", "天常及諸佛，一一資妙供。", "竊於翰藻間，窺見神心用。", "源流此中來，基本中興宋。", "稽首歸琅函，斐然成善頌。"]'),
('b7dbd347-3baf-4e4f-9d5f-6959277d49a5','元結嘗經略容管王守作次山堂以思其人爲賦此詩','李綱','宋','宋诗','song-poetry','','[]','華堂髙敞爲思元，善政相望數百年。',64,'全唐诗/poet.song.90000.json','["華堂髙敞爲思元，善政相望數百年。", "冊府聲名秀羣玉，海邦巖洞有叄天。", "漫郎去久風流在，病客來臨道里邅。", "聖主中興誰作頌，願觀老手筆如椽。"]'),
('cacfdf2d-d7f5-49e8-9f2d-fedc436f11ce','客有言長沙軍變向伯恭能彈治規畫甚偉適得伯恭書亦道其事作韻語以寄之','李綱','宋','宋诗','song-poetry','','[]','長沙舞袖僅可旋，今作巨鎮湖湘邊。',160,'全唐诗/poet.song.90000.json','["長沙舞袖僅可旋，今作巨鎮湖湘邊。", "驕兵夜探赤白丸，乘間竊發將嘯翾。", "不知向子有老拳，縛束健卒秖數言。", "翩如鳥雀擒鷹鸇，姦腰兇領汙龍泉。", "彈壓一境敢復喧，稚耋鼓舞喜欲顛。", "歸哺其飴甘晏眠，衆服壯略稱無前。", "我歸自南得之傳，頗欣祖生先着鞭。", "何不付與大將權，旍旗繽紛指雲燕。", "一鼓士氣如突煙，黠虜破膽心少悛。", "洒掃海內清戈鋋，使我衰病安廬田。"]'),
('75c7ae4c-ca0a-4c01-9dfd-b6776870d083','蕭懋德秀才自臨江遣人致書海上遇於歸途賦詩寄之二首  其一','李綱','宋','宋诗','song-poetry','','[]','三黜先生今得歸，更攜稚子訪慈幃。',64,'全唐诗/poet.song.90000.json','["三黜先生今得歸，更攜稚子訪慈幃。", "病牛臥壠心衰矣，脫兔投林天憫之。", "萬里往來環轉蟻，一生謗譽舌揚箕。", "著書欲赴當時約，須待江南事定時。"]'),
('384259ce-ef0b-4e37-9e4f-f284ff5a464a','蕭懋德秀才自臨江遣人致書海上遇於歸途賦詩寄之二首  其二','李綱','宋','宋诗','song-poetry','','[]','踰年海上久安居，多謝蕭郎遠寄書。',64,'全唐诗/poet.song.90000.json','["踰年海上久安居，多謝蕭郎遠寄書。", "不向去來生一念，已將天地作吾廬。", "中洲杳杳旌旗暗，暮景駸駸齒髪疏。", "凖擬峽江成小隱，茅齋借我定何如。"]'),
('aa5b28bf-e539-4b9b-919f-816e6f543728','罪謫海上中州親故罕通問獨虞君祖道相從湖海踰年北歸同途次容南賦詩識别','李綱','宋','宋诗','song-poetry','','[]','飽經憂患莫如吾，暮景餘生寄一桴。',64,'全唐诗/poet.song.90000.json','["飽經憂患莫如吾，暮景餘生寄一桴。", "獨子相從來瘴海，豈知還得共歸途。", "應觀天下奇男子，解笑人間淺丈夫。", "老去山林養衰疾，好音時與繫飛鳬。"]'),
('117dc9bf-bea9-44a5-8e4a-1bc152952949','除夜與宗之對酌懷家','李綱','宋','宋诗','song-poetry','','[]','四年除夕旅殊方，海上歸來路更長。',64,'全唐诗/poet.song.90000.json','["四年除夕旅殊方，海上歸來路更長。", "暮景飛騰催老病，餘生留滯且炎荒。", "傳聞寇盗紛驚擾，歎息江湖墮渺茫。", "杳杳東吳家萬里，椒盤誰與頌馨香。"]'),
('1045c4cd-bc51-4a7d-9517-a28d9ffbfe51','庚戌正月一日遊都嶠山留五絕句栖真觀中  其一','李綱','宋','宋诗','song-poetry','','[]','元日尋真到洞天，溪邊春色已嫣然。',32,'全唐诗/poet.song.90000.json','["元日尋真到洞天，溪邊春色已嫣然。", "落花流水人間去，誰道桃源不是仙。"]'),
('5f892e51-ef5a-4941-8e51-ef9cded1c311','庚戌正月一日遊都嶠山留五絕句栖真觀中  其二','李綱','宋','宋诗','song-poetry','','[]','松嶺雲峰步步佳，芒鞋竹杖極幽遐。',32,'全唐诗/poet.song.90000.json','["松嶺雲峰步步佳，芒鞋竹杖極幽遐。", "使君不得同清賞，正恐山將翠幕遮。"]'),
('5ceb3c36-edf5-460a-a803-b1abe48333bc','庚戌正月一日遊都嶠山留五絕句栖真觀中  其三','李綱','宋','宋诗','song-poetry','','[]','遠目增明都嶠山，丹梯况得遂躋攀。',32,'全唐诗/poet.song.90000.json','["遠目增明都嶠山，丹梯况得遂躋攀。", "乃知猿鶴真心在，乘服軒裳秪强顔。"]'),
('2e5e56fc-0c4c-49d3-ac7a-16b5c598c75b','庚戌正月一日遊都嶠山留五絕句栖真觀中  其四','李綱','宋','宋诗','song-poetry','','[]','疊嶪髙巖聳八峰，雲間紫翠鬱相重。',32,'全唐诗/poet.song.90000.json','["疊嶪髙巖聳八峰，雲間紫翠鬱相重。", "故應洞穴通勾漏，更愛林巒接大容。"]'),
('dfab67a8-6a51-4877-918b-32dc48d46c32','庚戌正月一日遊都嶠山留五絕句栖真觀中  其五','李綱','宋','宋诗','song-poetry','','[]','石磴盤紆木蒨葱，捫羅獨上最髙峰。',32,'全唐诗/poet.song.90000.json','["石磴盤紆木蒨葱，捫羅獨上最髙峰。", "白雲深處時回首，千里江山指顧中。"]'),
('39359215-5552-4341-bfb6-ddf2dea2cb40','宿都嶠山靈景寺','李綱','宋','宋诗','song-poetry','','[]','清晨遊栖真，薄暮宿靈景。',240,'全唐诗/poet.song.90000.json','["清晨遊栖真，薄暮宿靈景。", "山空松桂香，雲細泉石冷。", "髙崖敞飛簷，象緯逼參井。", "惜無娟娟月，散此林下影。", "夜闌風露寒，巖曲燈耿耿。", "疏鐘響嵌竇，客枕發深省。", "却随猿鳥起，再上翠微頂。", "道人山後來，眸子頗清炯。", "試詢龍虎訣，妙意默已領。", "我生憂患餘，半世泛萍梗。", "脫身鯨海中，掃跡方自屏。", "願從稚川遊，薪水事丹鼎。", "庶資刀圭力，少使桑榆永。", "胡塵暗中原，静謐惟五嶺。", "渺然炎荒地，自絕羽書警。", "結茅定前緣，幽夢先異境。", "上下三洞間，安得田二頃。", "攜家學龐公，捫蝨笑王猛。", "採薇與散髪，此志久已肯。", "嵇生非吾徒，幽憤醉方醒。"]'),
('75caf2aa-d360-41c7-8c05-181aec8329e7','自學校之制廢而戎馬之患興州縣長民者不復以教育爲意獨容南鼎新郡庠招徕生徒絃誦之聲不輟誠可嘉歎所建講堂爲名之曰育材輙成五言十韻','李綱','宋','宋诗','song-poetry','','[]','治世崇儒術，膠庠寓屬臨。',120,'全唐诗/poet.song.90000.json','["治世崇儒術，膠庠寓屬臨。", "自從馳羽檄，誰復念青衿。", "賢守來南紀，宏規肇泮林。", "飛翬開講廡，鼓篋拂書蟫。", "采藻繡江水，仰髙都嶠岑。", "潛消戎馬氣，初習雅歌音。", "洙泗道非遠，張姜賢至今。", "栽培成楚梓，追琢見南金。", "常衮閩風變，文翁蜀化深。", "願言遊學者，勉副育材心。"]'),
('59fc6bd3-1ae1-46fd-ba8b-a5920af63a64','潯守李侯以所蓄法書十軸相示題卷末','李綱','宋','宋诗','song-poetry','','[]','承平文物何富哉，寶章萬笈藏蓬莱。',384,'全唐诗/poet.song.90000.json','["承平文物何富哉，寶章萬笈藏蓬莱。", "餘篇散落士夫手，名筆往往牙籖排。", "連年戎馬擾河洛，錦標玉軸随飛埃。", "李侯好事不忍棄，萬里艱棘攜南來。", "炎荒相遇一笑粲，出以示我逾瓊瑰。", "歐虞顔柳邈已遠，蘭亭况復昭陵埋。", "空遺妙蹟刻琬琰，不若古楮存煙煤。", "君謨近世稱第一，筆力與古肩相挨。", "醉翁工夫不在字，名望自足尊輿臺。", "芙蓉僊人有典則，滄浪逐客氣不衰。", "胸中磊落難屈折，故使心畫奇而巍。", "東坡行書騁姿媚，山谷草聖窮縈迴。", "二公文翰照千古，俯視凡馬皆駑駘。", "米顛碌碌不足數，運筆尚有從横才。", "邇來非是無點畫，追時取好如俳諧。", "陸書楷法雖小學，古人用意何其能。", "君看篆籀寫韻語，精巧豈易容追陪。", "今人萬事不如古，矧以毫墨争雄魁。", "嗟余病廢臥都嶠，何止我馬云虺尵。", "感時撫事百憂集，對案不復能持杯。", "明窗展卷慰岑寂，坐遷舊觀雙眸開。", "梁谿書室插架處，念遠更覺增馳懷。", "世間雅好無出此，絕勝寶玩琴藏雷。", "于今此物未易得，願言什襲傳雲來。"]'),
('75d3cb16-cfbe-4172-977e-93936122eb7f','清明日得家書四首  其一','李綱','宋','宋诗','song-poetry','','[]','去國三年久，離家萬里餘。',48,'全唐诗/poet.song.90000.json','["去國三年久，離家萬里餘。", "豈知戎馬際，仍得棣華書。", "金鼓震南國，松筠懷故廬。", "寰區端若此，天意竟何如。"]'),
('20c30c6e-9519-408a-b5ee-874d6979975f','清明日得家書四首  其二','李綱','宋','宋诗','song-poetry','','[]','南荒炎瘴地，槐火又清明。',48,'全唐诗/poet.song.90000.json','["南荒炎瘴地，槐火又清明。", "海嶠無春色，江湖有戰聲。", "繋書來鴈足，歸思羡鵬程。", "欲挽天河水，滂沱洗甲兵。"]'),
('c6337157-a141-417f-b0ac-bfc785405ce2','清明日得家書四首  其三','李綱','宋','宋诗','song-poetry','','[]','欲歸歸未得，留滯綉江濱。',48,'全唐诗/poet.song.90000.json','["欲歸歸未得，留滯綉江濱。", "感慨傷春望，僑居多北人。", "蒼生未蘇息，黄屋尚蒙塵。", "王室艱危極，澘然泣老臣。"]'),
('2b888bf2-3ee8-4e2a-9fef-42828b69e6e5','清明日得家書四首  其四','李綱','宋','宋诗','song-poetry','','[]','煙嵐飛翠蓋，鯨海泛龍舟。',48,'全唐诗/poet.song.90000.json','["煙嵐飛翠蓋，鯨海泛龍舟。", "退避亦已遠，憑陵殊未休。", "包胥思慟哭，曹劌願深謀。", "歎息繞朝策，何人知故侯。"]'),
('c6e0e984-fe74-4369-8ab0-edf4acdb3a8d','容南初食荔枝二首  其一','李綱','宋','宋诗','song-poetry','','[]','海山荔子冠炎荒，頗恨遄歸不得嘗。',32,'全唐诗/poet.song.90000.json','["海山荔子冠炎荒，頗恨遄歸不得嘗。", "猶喜容南三月裏，輕紅初擘一枝香。"]'),
('3802ad94-81a5-4430-a30d-b43c0405a1ca','容南初食荔枝二首  其二','李綱','宋','宋诗','song-poetry','','[]','買地城南種荔枝，毎留核付守園兒。',32,'全唐诗/poet.song.90000.json','["買地城南種荔枝，毎留核付守園兒。", "但祈四海兵戈息，會見開花著子時。"]'),
('2efa34ed-4faf-4971-82fc-520a62205c1b','三月二十三日德音至容南恭聞駐蹕浙東王師屢捷虜騎遠遁是日得諸季書挈家寓饒之德興幸免驚擾忻忭之餘輙成口號','李綱','宋','宋诗','song-poetry','','[]','紫泥黄耳到同時，家國無虞慰所思。',64,'全唐诗/poet.song.90000.json','["紫泥黄耳到同時，家國無虞慰所思。", "飲馬天驕歸朔漠，安巢越鳥返南枝。", "休祥允恊靈棋卜，喜事何因乾鵲知。", "便可理装尋去路，攜家深赴鹿門期。"]'),
('8c9ac1eb-773d-4a06-93b3-4f0ce07af200','四月六日離容南陸行趨藤山路崎嶇然夾道皆松陰山俺田家景物類閩中殊可喜也賦古風一篇','李綱','宋','宋诗','song-poetry','','[]','孟夏草木長，清陰散扶疏。',144,'全唐诗/poet.song.90000.json','["孟夏草木長，清陰散扶疏。", "葱籠竹樹間，石磴蟠縈紆。", "嗟我事行役，彌年困征途。", "及兹理歸鞍，敢復論崎嶇。", "深谷四無景，髙巖倚天衢。", "稍從平川行，遂得田家居。", "籬落静窈窕，桑麻鬱紛敷。", "新秧綠映水，鷄犬鳴相呼。", "中原暗鋒鏑，胡馬方長驅。", "此豈桃花源，幽深了如無。", "逝將適閩嶺，買田自耕鋤。", "結廬亂山中，聊以全妻孥。"]'),
('74f3f013-19c5-4ea7-a94d-8fd83e3bd594','自容趨藤山路古松皆合抱百餘尺枝葉扶疏行人庇賴爲取松明者所刳剔因而摧傾十已六七良可惜也','李綱','宋','宋诗','song-poetry','','[]','松林繚峻嶺，百尺森葱青。',192,'全唐诗/poet.song.90000.json','["松林繚峻嶺，百尺森葱青。", "不知何年種，天矯亂龍形。", "濃陰翳修途，當暑有餘清。", "長風一披拂，時作波濤聲。", "如何錐刀徒，使爭爝火明。", "傷膚及肌骨，風雨因摧傾。", "顛倒委榛棘，氣象猶崢嶸。", "行人失庇賴，佇立空凝情。", "緬想栽培初，愛護如目睛。", "合抱始毫末，幾經霜露零。", "一日毀有餘，百年養不成。", "忍使易凋喪，此理真難評。", "憶昔陶士行，爲政有善經。", "擢禾與移柳，一一糾以刑。", "既往不及追，將來猶可懲。", "感動遂成章，庶幾知者聽。"]'),
('6ab71401-56e6-489c-9013-6cc454337170','鐔津江閣氣象清曠有閩浙之風偶成長句','李綱','宋','宋诗','song-poetry','','[]','斷雲飛雨晚蒼茫，靈閣臨流分外涼。',64,'全唐诗/poet.song.90000.json','["斷雲飛雨晚蒼茫，靈閣臨流分外涼。", "散髪披襟嘗荔子，疏簾清簟看魚航。", "三年奔走環循蟻，萬里歸來鬢滿霜。", "未到江湖先到此，風流誰道在炎荒。"]'),
('43f8cfe6-9e1f-4892-acb6-ed3b11f438a7','同曹使君登浮金堂','李綱','宋','宋诗','song-poetry','','[]','繞堂松竹散扶疏，枕带江山美有餘。',64,'全唐诗/poet.song.90000.json','["繞堂松竹散扶疏，枕带江山美有餘。", "神物化龍同劍浦，雙溪成字類桐廬。", "朝雲夜月随時好，栖鷺飛鷗迥自如。", "茗飲相從得清賞，坐令勝事踵蘇徐。"]'),
('96ea0015-8549-417e-903d-af3a568bd51d','月夜江閣次東坡韻','李綱','宋','宋诗','song-poetry','','[]','江水如練带，江石如馬肝。',120,'全唐诗/poet.song.90000.json','["江水如練带，江石如馬肝。", "雙流會合處，蹙作蛟龍蟠。", "我來暑氣初，驟雨成驚湍。", "雲收暮山出，秀色屏中看。", "缺月掛木末，光輝溢清寒。", "冷然適我心，遇境随所安。", "夜久轉寥閴，髙松露華漙。", "獨坐念平生，行路真漫漫。", "危腸易感激，不待聞哀彈。", "猶欣碧川漲，沒盡風雷灘。"]'),
('0b491937-b8f7-429f-b343-747df77592de','晚泊蒼梧有感','李綱','宋','宋诗','song-poetry','','[]','常誦蒼梧雲正愁，豈知理櫂此間遊。',64,'全唐诗/poet.song.90000.json','["常誦蒼梧雲正愁，豈知理櫂此間遊。", "火山冰井舊傳有，桂水藤江相合流。", "念遠心如嘶北馬，踰年行徧嶠南州。", "重華一去不復返，悵望九疑空白頭。"]'),
('d62b91b1-ae8e-4944-81f6-923e7c044118','封川贈李致遠郎中','李綱','宋','宋诗','song-poetry','','[]','一别都門十載餘，相逢應笑尚迂愚。',64,'全唐诗/poet.song.90000.json','["一别都門十載餘，相逢應笑尚迂愚。", "綈袍戀戀故人意，風雨瀟瀟君子儒。", "顧我憂危宜白髪，如公暇豫亦清癯。", "年來頗得羲書旨，試讀一篇還是無。"]'),
('b52f5ba8-c937-476f-96c9-31cbc4972c64','泊晉康横翠亭愛其山水秀麗斐然有作二首  其一','李綱','宋','宋诗','song-poetry','','[]','上主疏封地，中興啟帝圖。',48,'全唐诗/poet.song.90000.json','["上主疏封地，中興啟帝圖。", "江山連肇慶，雲物接蒼梧。", "秀氣蟠南極，神功本禹謨。", "邦人榮望意，開府映番禺。"]'),
('603a8f12-2719-48c0-9206-cf0a509fab8d','泊晉康横翠亭愛其山水秀麗斐然有作二首  其二','李綱','宋','宋诗','song-poetry','','[]','環抱大江流，層巒翠靄浮。',48,'全唐诗/poet.song.90000.json','["環抱大江流，層巒翠靄浮。", "神明扶王氣，文物冠南州。", "來值炎蒸日，去翻風雨秋。", "登髙望不極，暮角起城樓。"]'),
('6b416f7f-2c53-424b-a0aa-4a144161467a','同陳使君登香山寺豁亭','李綱','宋','宋诗','song-poetry','','[]','渺渺煙波疊疊山，玉簪羅带自迴還。',64,'全唐诗/poet.song.90000.json','["渺渺煙波疊疊山，玉簪羅带自迴還。", "雨餘嵐翠濃如滴，地險江流巧轉灣。", "蟠磴迥臨飛鳥上，岸巾聊與白雲閒。", "嶠南有此佳山水，盡在賢侯几案間。"]'),
('d259a372-94d0-476f-9655-9708e710fa55','客有出示御製登中和堂詩小臣斐然仰次宸韻二首  其一','李綱','宋','宋诗','song-poetry','','[]','黄屋狩吳越，勾陳俯江津。',96,'全唐诗/poet.song.90000.json','["黄屋狩吳越，勾陳俯江津。", "迢遥八駿御，時邁慰斯民。", "漢祚歘再興，周邦命惟新。", "誰令玁狁熾，坐使宵旰勤。", "宅洛既得卜，去豳亦惟仁。", "宸章蹟禹功，道繼胼胝身。", "期運有泰否，鈍蟠利則伸。", "君王自神武，安得熊羆臣。"]'),
('52644717-47bc-445f-b17d-411b19b39037','客有出示御製登中和堂詩小臣斐然仰次宸韻二首  其二','李綱','宋','宋诗','song-poetry','','[]','賤子志丘壑，敢懷要路津。',96,'全唐诗/poet.song.90000.json','["賤子志丘壑，敢懷要路津。", "偶乘風雲會，冀拯凋瘵民。", "誤被聖主知，坐期功業新。", "飄零繼三黜，奔走亦已勤。", "生還鯨海中，仰荷皇天仁。", "不然鑠金口，何有鴻毛身。", "當從玄豹隱，無復尺蠖伸。", "感歎魏公言，願使爲良臣。"]'),
('545ecbb2-ee96-4fb4-a9a6-7cab2b8ff44e','江行即事八首  其一','李綱','宋','宋诗','song-poetry','','[]','千里江山圖畫中，嶠南浙右豈殊風。',64,'全唐诗/poet.song.90000.json','["千里江山圖畫中，嶠南浙右豈殊風。", "煙浮嵐彩重重碧，日染波光灑灑紅。", "蟻釀蟹螯情不淺，筆牀茶竈興相同。", "扁舟入手吾何事，歸去梁谿作釣翁。"]'),
('a975c87f-8cf9-4925-aa31-4cd29420202c','江行即事八首  其二','李綱','宋','宋诗','song-poetry','','[]','五月炎方氣鬱蒸，安流鼓櫂水風清。',64,'全唐诗/poet.song.90000.json','["五月炎方氣鬱蒸，安流鼓櫂水風清。", "江魚入饌有餘美，山果滿盤難强名。", "醉裏謳吟聊自適，夢中來往本無驚。", "廟堂早定安邊策，遂我山林幽遯情。"]'),
('4677d628-81f5-42de-a41e-618cfcd52554','江行即事八首  其三','李綱','宋','宋诗','song-poetry','','[]','置散徒懷報國心，還家欣得故園音。',64,'全唐诗/poet.song.90000.json','["置散徒懷報國心，還家欣得故園音。", "鈎輈曉岸雲林密，款乃暮江煙水深。", "壯志已同灰灺冷，班毛從使雪霜侵。", "臥龍只合耕南畝，抱膝空爲梁甫吟。"]'),
('ff06822d-9f8e-479b-84ae-01d157f99cc0','江行即事八首  其四','李綱','宋','宋诗','song-poetry','','[]','蒼梧雲物曉凄凉，錦石江山一带長。',64,'全唐诗/poet.song.90000.json','["蒼梧雲物曉凄凉，錦石江山一带長。", "雨浥峰巒添黛翠，風吹草木送天香。", "魚樵閒話無千古，金鼓喧聲震萬方。", "我欲誅茅寄幽僻，却愁煙水日茫茫。"]'),
('1654b8f4-70a3-4ad2-aa21-cf3904c761c5','江行即事八首  其五','李綱','宋','宋诗','song-poetry','','[]','數郡崎嶇山海間，只今多事覺寛閒。',64,'全唐诗/poet.song.90000.json','["數郡崎嶇山海間，只今多事覺寛閒。", "衣冠避地成僑寓，風月留人長往還。", "蘸水藤花方爛熳，生雲錦石自斕斒。", "平生有意五湖去，誰謂扁舟行百蠻。"]'),
('d7b04e46-62b9-4fa6-bebb-0c8cefaf8b1f','江行即事八首  其六','李綱','宋','宋诗','song-poetry','','[]','合踏青山轉碧川，雨餘風月更嬋娟。',64,'全唐诗/poet.song.90000.json','["合踏青山轉碧川，雨餘風月更嬋娟。", "光鋩影渡星河碎，片段氣蒸雲物鮮。", "心繫鴒原千里外，夢回鼓角五更前。", "翠華杳杳今何處，悵望東吳空惘然。"]'),
('ea86d92e-bde3-458a-8ea0-81afe4083dd9','江行即事八首  其七','李綱','宋','宋诗','song-poetry','','[]','峽束滄江暮靄昏，孤猿吟嘯不堪聞。',64,'全唐诗/poet.song.90000.json','["峽束滄江暮靄昏，孤猿吟嘯不堪聞。", "寥寥夜閴波沉月，漠漠曉晴山出雲。", "釣艇得魚猶撥刺，綸巾漉酒任酣醺。", "年來與物忘機甚，自覺沙鷗不亂羣。"]'),
('706f3953-d526-441a-806d-8e5dc6daa130','江行即事八首  其八','李綱','宋','宋诗','song-poetry','','[]','一重一掩翠參差，路入桃源客意迷。',64,'全唐诗/poet.song.90000.json','["一重一掩翠參差，路入桃源客意迷。", "江霧曉分山遠近，浦鷗閑送櫂東西。", "頗欣嶺表佳泉石，聞道江南多鼓鼙。", "稚子候門應念我，提攜來共此幽棲。"]'),
('84d8d154-5ef9-42fe-ad3f-1c82d18fb6c8','自晉康順流六十里有山巉然臨江下有巖洞可容千人軒豁平坦景幽邃石罅間滴泉厥味甘冽因目之曰玉乳巖賦詩以紀其事','李綱','宋','宋诗','song-poetry','','[]','鼓柁下端溪，停橈登嶻嶭。',216,'全唐诗/poet.song.90000.json','["鼓柁下端溪，停橈登嶻嶭。", "呀然巖洞開，儼若棟宇設。", "千夫可還揖，放步靡凹凸。", "玲瓏四壁間，一一幢旆列。", "誰令胚渾初，凝結有罅缺。", "當年補天手，不顧山石裂。", "鐫鑱餘舊痕，瑣碎委環玦。", "五峰近龍淵，無乃通貝闕。", "試求玉函書，何異探禹穴。", "涓涓乳泉滴，燦燦冰玉潔。", "清聲落嵌竇，自中琴筑節。", "嘗之味甘芳，滌我肺腑熱。", "瓊漿笑裴航，石髄謝王烈。", "嶠南瘴癘鄉，有此雲腴冽。", "青葱松桂陰，景物助幽絕。", "豈無會心人，來遊共旌别。", "題詩製佳名，聊以紀歲月。", "碧落遥相望，千里未磨滅。"]'),
('a0e8ec3b-648a-4443-a91b-bf1089edff0e','端康之間地名越城五山秀峙有蜿蜒飛躍之狀山有五龍廟當秦時神媪臨江五龍從之遊沒葬山上廟祀至今靈響甚著鄉人以風雨候龍之歸因作送迎辭五絕句以遺之  其一','李綱','宋','宋诗','song-poetry','','[]','風雨瀟瀟雲氣浮，五龍歸覲到靈湫。',32,'全唐诗/poet.song.90000.json','["風雨瀟瀟雲氣浮，五龍歸覲到靈湫。", "星霜換易江山在，尚憶當年水際遊。"]'),
('11766c03-0273-416e-8292-fdc82af4b5dd','端康之間地名越城五山秀峙有蜿蜒飛躍之狀山有五龍廟當秦時神媪臨江五龍從之遊沒葬山上廟祀至今靈響甚著鄉人以風雨候龍之歸因作送迎辭五絕句以遺之  其二','李綱','宋','宋诗','song-poetry','','[]','五山秀峙若飛騰，下有澄潭百丈清。',32,'全唐诗/poet.song.90000.json','["五山秀峙若飛騰，下有澄潭百丈清。", "不用燃犀窺秘怪，從來神理惡分明。"]'),
('c51f5b88-53c5-4746-8aa7-26ee7b6160ba','端康之間地名越城五山秀峙有蜿蜒飛躍之狀山有五龍廟當秦時神媪臨江五龍從之遊沒葬山上廟祀至今靈響甚著鄉人以風雨候龍之歸因作送迎辭五絕句以遺之  其三','李綱','宋','宋诗','song-poetry','','[]','萬霰干霆霹靂飛，潛藏神用濟烝黎。',32,'全唐诗/poet.song.90000.json','["萬霰干霆霹靂飛，潛藏神用濟烝黎。", "何須簫鼓祈膏澤，肯爲鄉人有所私。"]'),
('8cd1566f-d8d1-4da4-a9c2-e99ffed94d87','端康之間地名越城五山秀峙有蜿蜒飛躍之狀山有五龍廟當秦時神媪臨江五龍從之遊沒葬山上廟祀至今靈響甚著鄉人以風雨候龍之歸因作送迎辭五絕句以遺之  其四','李綱','宋','宋诗','song-poetry','','[]','貝闕珠宫不可尋，時因風雨聽清吟。',32,'全唐诗/poet.song.90000.json','["貝闕珠宫不可尋，時因風雨聽清吟。", "葉公好畫真龍出，却恨今無好畫心。"]'),
('e6a7af46-e8b9-4776-be3d-3853d43dcf3f','端康之間地名越城五山秀峙有蜿蜒飛躍之狀山有五龍廟當秦時神媪臨江五龍從之遊沒葬山上廟祀至今靈響甚著鄉人以風雨候龍之歸因作送迎辭五絕句以遺之  其五','李綱','宋','宋诗','song-poetry','','[]','日染波光紅灑灑，風搖影裏碧鱗鱗。',32,'全唐诗/poet.song.90000.json','["日染波光紅灑灑，風搖影裏碧鱗鱗。", "神靈來去初無跡，多少江頭求福人。"]'),
('c055ebd7-f4b5-4e4b-b186-f108a37e1b2e','江上晚景二首  其一','李綱','宋','宋诗','song-poetry','','[]','清江一曲深，翠岫千峰峙。',48,'全唐诗/poet.song.90000.json','["清江一曲深，翠岫千峰峙。", "江村八九家，茅舍修竹裏。", "沙頭漁網懸，林表煙素起。", "焉得惠崇師，寫此真山水。"]'),
('61c4ebc9-c07d-4172-ae38-31448142a197','江上晚景二首  其二','李綱','宋','宋诗','song-poetry','','[]','風雨逐雲急，斷霓明飲川。',48,'全唐诗/poet.song.90000.json','["風雨逐雲急，斷霓明飲川。", "江頭日欲暮，返照青林顛。", "鷗鷺自儔侣，蒹葭相接連。", "平生江海志，對此却茫然。"]'),
('6e262887-406a-4211-9aab-9953897f1aa5','遣興二首  其一','李綱','宋','宋诗','song-poetry','','[]','繚絡奔馳不記年，脫身瘴海豈徒然。',64,'全唐诗/poet.song.90000.json','["繚絡奔馳不記年，脫身瘴海豈徒然。", "昂藏鶴髪老道士，爛熳醉吟狂謫仙。", "剩把詩篇收景物，何須鑪鼎煮山川。", "平生出處吾無愧，禍福死生皆付天。"]'),
('d46de207-0dab-4264-b611-1806078ca59a','遣興二首  其二','李綱','宋','宋诗','song-poetry','','[]','海上歸來心緒多，鬢邊無那白標何。',64,'全唐诗/poet.song.90000.json','["海上歸來心緒多，鬢邊無那白標何。", "詩情粗得江山助，酒量自因風月多。", "黄卷中間籠聖哲，白雲深處避干戈。", "弟兄念我心應切，故向梅花嶺上過。"]'),
('62405d8f-c25b-437a-9c87-b715f295fdfc','次肇慶府有感','李綱','宋','宋诗','song-poetry','','[]','仁德如天覆萬方，誰知變故起非常。',96,'全唐诗/poet.song.90000.json','["仁德如天覆萬方，誰知變故起非常。", "秪因燕地開邊隙，故使中原作戰塲。", "侯景南侵幽武帝，禄山西犯走明皇。", "運遭九六人徒爾，險失山河事巨量。", "一自鑾輿遊朔漠，空餘藩邸在炎荒。", "微臣弭擢增悲感，雪涕無因問彼蒼。"]'),
('b09b2e53-eb25-4212-bce5-f6f52fa099f1','端石硯','李綱','宋','宋诗','song-poetry','','[]','端溪出硯材，最貴下巖石。',120,'全唐诗/poet.song.90000.json','["端溪出硯材，最貴下巖石。", "珍物乃卵生，孕此馬肝色。", "世傳鴝鵒眼，通透蓋其脉。", "頗同阮步兵，見客作青白。", "我來巖中遊，幽探偶有獲。", "温然一片玉，秀潤滿書宅。", "斷成蛟龍池，澀滑宜筆墨。", "當觀管城翁，沐髮散簡策。", "嗟余好陶泓，收拾積珪璧。", "得此餘可忘，一生能幾屐。"]'),
('ae9739db-2e32-42e7-a760-7ba560c81b31','蚊','李綱','宋','宋诗','song-poetry','','[]','江風蕭蕭江水清，飛蚊撲撲何處生。',128,'全唐诗/poet.song.90000.json','["江風蕭蕭江水清，飛蚊撲撲何處生。", "駝肩豹脚嘴如鐵，天使咂食同蠅蝱。", "先生暑困汗翻雨，僮僕搖扇疲屢更。", "乘虚投隙肆毒吻，鼓翅舞足何其輕。", "須臾含桃變柳絮，坐使饑腹成膨脝。", "捨身施汝豈吾惜，逼耳最惡聲嬌獰。", "有時緣拊于吾指，罪雖應爾心則矜。", "露華清泚自可飲，戒汝慎勿貪芳腥。"]'),
('a92150e1-c280-484d-a719-b132f47b66d8','出峽','李綱','宋','宋诗','song-poetry','','[]','出峽日將暮，綺霞連水明。',48,'全唐诗/poet.song.90000.json','["出峽日將暮，綺霞連水明。", "山遥欣野闊，海近覺江平。", "稍稍洲渚轉，霏霏煙靄生。", "舟人喜風便，時發櫂謳聲。"]'),
('f370a819-7d32-4807-9ffc-36e21fa5ece1','靈洲寺次東坡韻','李綱','宋','宋诗','song-poetry','','[]','迴廊小殿枕崔嵬，接武東坡我復來。',32,'全唐诗/poet.song.90000.json','["迴廊小殿枕崔嵬，接武東坡我復來。", "江色蒼茫山聳秀，蔚藍天影抱瓊臺。"]'),
('9dc570a2-2ffd-405a-85cd-a1bd3dae05fe','次韻鑿空閣','李綱','宋','宋诗','song-poetry','','[]','東坡謫仙人，遊此江海境。',120,'全唐诗/poet.song.90000.json','["東坡謫仙人，遊此江海境。", "賦詩鑿空閣，如以鏡寫影。", "我來遥相望，荏苒歲月永。", "讀翁閣上詩，宛若相像鏡。", "平生憂患餘，胸次徒耿耿。", "脫身鯨波間，遠跡方自屏。", "泊舟值炎蒸，風雨變清冷。", "佳哉幽深地，自絕鋒鏑警。", "願爲劍藏神，不作錐露穎。", "携家隱山林，屬意在閩嶺。"]'),
('2dfc975e-b550-426c-8a9b-499d2e78de8c','謁南海神廟','李綱','宋','宋诗','song-poetry','','[]','黄木灣頭潮欲平，叢林深處款祠庭。',64,'全唐诗/poet.song.90000.json','["黄木灣頭潮欲平，叢林深處款祠庭。", "豈知休咎能傳戒，但愛昌黎解勒銘。", "海上波濤呈秘怪，壁間圖畫雜紅青。", "應憐歸客稽留久，風破寒江集百靈。"]'),
('12f0f621-52d8-4fb1-b990-4aa7954cc746','艤舟泊頭鎮風雨中乘小舟行十餘里遵陸遊羅浮山寶積延祥寺','李綱','宋','宋诗','song-poetry','','[]','神山失憑依，漂泊西南州。',192,'全唐诗/poet.song.90000.json','["神山失憑依，漂泊西南州。", "連峰蟠秀氣，作鎮蒼溟陬。", "世傳朱明洞，深秘未易求。", "夜半見赤日，光若金鼇浮。", "我來夏正中，川漲通行舟。", "弭櫂泊頭渚，遂作羅浮遊。", "山靈憫病暑，風雨爲變秋。", "雲開遠岫出，黛色散不收。", "籃輿陟翠微，頗得精廬幽。", "雅志惬丘壑，斯行豈人謀。", "愧煩五色雀，顧我鳴啁啾。", "寓目天水永，微茫見瀛洲。", "中原正雲擾，盗賊屯蠭蟊。", "而我臥雲海，歸途亦淹留。", "逝將憇真境，祕訣追前修。", "稚川不可見，得見野人不。"]'),
('38eda51e-1242-42dd-9e60-9c8b2f23aeda','自延祥寺行五里至冲虚觀月出林巒之表景物幽勝坐遺履軒望麻姑峰秉燭觀稚川丹竈','李綱','宋','宋诗','song-poetry','','[]','葛翁令勾漏，晚入羅浮山。',192,'全唐诗/poet.song.90000.json','["葛翁令勾漏，晚入羅浮山。", "丹成尸解去，遺跡猶班班。", "當年薪水人，亦得刀圭殘。", "至今有遇者，綠髪長童顔。", "嗟我慕遐躅，冒暑窮躋攀。", "叩門日已落，月出青雲間。", "深院人寂寂，飛泉澗潺潺。", "松風入琴軫，桂露零星壇。", "坐觀麻姑峰，聳翠凝煙鬟。", "更呼老道士，月夜談玄關。", "清景難久駐，忽忽恨言還。", "却迷桃源路，歎息空塵寰。", "兵革未休息，世故方艱難。", "脫身事幽討，此志不可刪。", "未能騎長鯨，聊復乘兩班。", "來尋巖間竈，更鍊飛霞丹。"]'),
('3a840c9f-40af-4cba-9749-c981c4e75007','乘月泛小舟歸泊頭二首  其一','李綱','宋','宋诗','song-poetry','','[]','來時風雨作新凉，歸去還乘皎月光。',32,'全唐诗/poet.song.90000.json','["來時風雨作新凉，歸去還乘皎月光。", "多謝山靈巧留意，未窮仙賞意茫茫。"]'),
('2712d9d3-4d10-49aa-8a86-d4b8aad5600f','乘月泛小舟歸泊頭二首  其二','李綱','宋','宋诗','song-poetry','','[]','纖雲四卷列星稀，重露如珠濕客衣。',32,'全唐诗/poet.song.90000.json','["纖雲四卷列星稀，重露如珠濕客衣。", "竟日羅浮何所得，滿船空載月明歸。"]'),
('e7ad11a4-3164-4809-bb00-b09271735095','家問自閩中轉來走筆寄諸弟','李綱','宋','宋诗','song-poetry','','[]','江海相望萬里餘，干戈阻絕久離居。',64,'全唐诗/poet.song.90000.json','["江海相望萬里餘，干戈阻絕久離居。", "沉魚斷鴈杳何所，一紙千金初得書。", "身脫鯨波真偶爾，家鄰兵火幸恬如。", "弟兄老矣何爲者，相約羅浮同結廬。"]'),
('bf6de3cb-8a16-4293-97ae-ddd312937578','次韻士特見懷古風','李綱','宋','宋诗','song-poetry','','[]','遭遇登黄閤，平生志寢丘。',288,'全唐诗/poet.song.90000.json','["遭遇登黄閤，平生志寢丘。", "燋頭無寸效，失脚落遐陬。", "一去蒼龍闕，三驚白露秋。", "賈生時欲慟，平子不勝愁。", "鄂渚何曾到，蘭江未許留。", "孤城踰地角，絕島在鼇頭。", "父子同雙影，簞瓢付一舟。", "飄零已知幸，奇絕敢言遊。", "望斷歸來鶴，情孚不下鷗。", "波濤從洶湧，鼓角助清幽。", "忽奉日邊令，容還嶠北州。", "天恩方肉骨，厲鬼漫持矛。", "力拯中興業，深防不戴讐。", "當車雖怒臂，見險莫扶輈。", "往事追何及，來功勉或收。", "舍垣宜葺補，風雨正颼飀。", "離索何其久，吟哦誰與酬。", "管寧終著帽，王粲且登樓。", "阻絕江南信，淹留海上洲。", "歸心良耿耿，去路尚悠悠。", "見說鯨奔網，仍傳盗聚蟊。", "不知供羽衛，今有幾貔貅。", "甌越亦遠矣，江淮已定不。", "視天真懵懵，知命罷休休。"]'),
('5671d5ad-8744-47d0-beba-3b6cde70d49f','再賦一章寄諸季約同隱羅浮','李綱','宋','宋诗','song-poetry','','[]','枕海仙山舞翠蛟，葛洪丹竈尚餘凹。',64,'全唐诗/poet.song.90000.json','["枕海仙山舞翠蛟，葛洪丹竈尚餘凹。", "兵戈滿眼歸何地，雲木連天思結巢。", "豈有聲名同八士，當令蹤跡繼三茅。", "携家早作來遊計，玉户金關幸可敲。"]'),
('49c0c62d-a301-4394-9966-1b8e6a941f8c','惠州訪東坡舊隱','李綱','宋','宋诗','song-poetry','','[]','海上歸來訪老坡，依然遺跡未銷磨。',64,'全唐诗/poet.song.90000.json','["海上歸來訪老坡，依然遺跡未銷磨。", "松風亭下梅花老，鶴觀峰頭喬木多。", "垂世文章燦星斗，平生憂患足風波。", "華堂滿龕題詩筆，人事其如天定何。"]'),
('aeacb4dd-f6db-4fbe-85e7-f772c6b35950','白水山佛跡巖行速不果到次東坡韻','李綱','宋','宋诗','song-poetry','','[]','羅山與浮山，對峙蹲兩股。',240,'全唐诗/poet.song.90000.json','["羅山與浮山，對峙蹲兩股。", "有如垂天鵬，决起初振羽。", "茲山乃東麓，秀若芙蓉吐。", "谽谺巖洞開，地裂媧不補。", "何人履石上，修趾映玄乳。", "當時巨靈氏，擘華不用斧。", "蹈躟意未已，遺拇到南土。", "連山乃浮來，海若助掀舞。", "强稱金僊人，誰見來接武。", "坳窪踰鐫鎞，縷脉分踵拇。", "何嘗藉青蓮，長此濯白雨。", "頗疑秦漢間，方士恣飄鼓。", "鑿成巨人跡，聊示神仙府。", "祖龍茂林翁，雄毅猶猛虎。", "一爲異端惑，種種受欺侮。", "我爲江海行，風雨齊萬弩。", "餘生屢涉險，何異孤注賭。", "已從羅浮遊，勝境敢多取。", "天公本無私，尤物随意主。", "闊視天壤中，滄洲乃吾圃。"]'),
('867fd136-384d-4e57-bbdc-7be587b53dcb','次東坡月夜理髪','李綱','宋','宋诗','song-poetry','','[]','月明星稀烏鵲翻，先生夜起臨幽軒。',64,'全唐诗/poet.song.90000.json','["月明星稀烏鵲翻，先生夜起臨幽軒。", "呼童具櫛不停手，一氣泝流天地根。", "自經憂患髪如葆，欲論此心無與言。", "不如緘默度餘日，悵望吳越空銷魂。"]'),
('479e9606-b5d3-4d56-95f5-6ed2583213f3','望白水山次合江樓韻','李綱','宋','宋诗','song-poetry','','[]','羅浮之麓何壯哉，山靈爲我煙雲開。',96,'全唐诗/poet.song.90000.json','["羅浮之麓何壯哉，山靈爲我煙雲開。", "怱怱行役不一到，翠光百里随人來。", "嶠南鍾此山川美，中有幽人呼不起。", "月圓月缺豈人爲，潮落潮生自江水。", "非人流水水流人，世故人情日月新。", "撥置千憂幷百慮，且醉一斛松醪春。"]'),
('83d8142b-8a3b-4ecc-b4e7-82f12451886f','六如亭','李綱','宋','宋诗','song-poetry','','[]','松林葬玉近禪扃，便把伽陀當勒銘。',64,'全唐诗/poet.song.90000.json','["松林葬玉近禪扃，便把伽陀當勒銘。", "居士已亡三昧手，侍人空有六如亭。", "玉環約指無消息，巫峽行雲更杳冥。", "萬法本來皆夢幻，春風又見草青青。"]'),
('22469aac-d543-420b-9e21-d87c8a08cdac','北歸將自英韶趨江表因遊清遠峽碧落洞謁六祖于曹溪望韶石渡庾嶺皆嶠南絕景也適江西道梗遵海而歸此志不遂賦五絕見意 清遠峽','李綱','宋','宋诗','song-poetry','','[]','凝碧灣頭碧玉山，林松古寺寄孱顔。',32,'全唐诗/poet.song.90000.json','["凝碧灣頭碧玉山，林松古寺寄孱顔。", "佳人得侣已長嘯，空使山僧藏白環。"]'),
('b1aeb448-d1d5-409d-acac-17891ddc264f','北歸將自英韶趨江表因遊清遠峽碧落洞謁六祖于曹溪望韶石渡庾嶺皆嶠南絕景也適江西道梗遵海而歸此志不遂賦五絕見意 碧落洞','李綱','宋','宋诗','song-poetry','','[]','碧落嵌空羣玉峰，烟霞深鎖翠微重。',32,'全唐诗/poet.song.90000.json','["碧落嵌空羣玉峰，烟霞深鎖翠微重。", "乳羊不作黄羊色，放筯能迴冰雪容。"]'),
('ea0d5027-ede7-497e-8496-f8ed185db1c5','北歸將自英韶趨江表因遊清遠峽碧落洞謁六祖于曹溪望韶石渡庾嶺皆嶠南絕景也適江西道梗遵海而歸此志不遂賦五絕見意 南華寺','李綱','宋','宋诗','song-poetry','','[]','久矣曹溪法雨流，秪傳一滴滿中州。',32,'全唐诗/poet.song.90000.json','["久矣曹溪法雨流，秪傳一滴滿中州。", "南來不見祖師面，長與祖師同此遊。"]'),
('76d1b1ab-059b-42cb-a4b6-d88331a86a70','北歸將自英韶趨江表因遊清遠峽碧落洞謁六祖于曹溪望韶石渡庾嶺皆嶠南絕景也適江西道梗遵海而歸此志不遂賦五絕見意 韶石','李綱','宋','宋诗','song-poetry','','[]','重華南狩到炎荒，髙會羣神廣樂張。',32,'全唐诗/poet.song.90000.json','["重華南狩到炎荒，髙會羣神廣樂張。", "豈獨有情能率舞，至今峰石亦低昂。"]'),
('5063c582-559e-4079-b28d-be555c8aea46','北歸將自英韶趨江表因遊清遠峽碧落洞謁六祖于曹溪望韶石渡庾嶺皆嶠南絕景也適江西道梗遵海而歸此志不遂賦五絕見意 庾嶺','李綱','宋','宋诗','song-poetry','','[]','誰言庾嶺極荒遐，夾道青松釋梵家。',32,'全唐诗/poet.song.90000.json','["誰言庾嶺極荒遐，夾道青松釋梵家。", "暍暑北歸遵海上，無因一爲折梅花。"]'),
('f390e1fc-2459-4820-93a4-fb455e963329','泛舟循惠間山水清絕口號四首  其一','李綱','宋','宋诗','song-poetry','','[]','雨過溪流沒舊灘，舟行竟日畫圖間。',32,'全唐诗/poet.song.90000.json','["雨過溪流沒舊灘，舟行竟日畫圖間。", "重重翠綠相環揖，臥看王維著色山。"]'),
('d4dffff6-3d1e-4448-bbda-4ff9344b8bb2','泛舟循惠間山水清絕口號四首  其二','李綱','宋','宋诗','song-poetry','','[]','煙雨霏霏溪上村，白沙翠竹對柴門。',32,'全唐诗/poet.song.90000.json','["煙雨霏霏溪上村，白沙翠竹對柴門。", "江湖戰鬭波成血，耕鑿樵漁如不聞。"]'),
('5717eeb2-5da5-46f9-bf34-a30ffefb2ee8','泛舟循惠間山水清絕口號四首  其三','李綱','宋','宋诗','song-poetry','','[]','青山碧水白鷗飛，野岸臨流有釣磯。',32,'全唐诗/poet.song.90000.json','["青山碧水白鷗飛，野岸臨流有釣磯。", "便欲誅茅老滄海，于今江浙可忘歸。"]'),
('2b53a598-e5ff-498c-b5ea-5ec27dcd9984','泛舟循惠間山水清絕口號四首  其四','李綱','宋','宋诗','song-poetry','','[]','山下清江匹練横，山頭紅日半輪明。',32,'全唐诗/poet.song.90000.json','["山下清江匹練横，山頭紅日半輪明。", "漁人晚集知多少，静聽鳴榔撒網聲。"]'),
('c38b16f6-e869-44b9-b107-e1bd0da111b3','東坡謫英州以書語所善衲子曰戒和尚又疏脫矣讀之有感','李綱','宋','宋诗','song-poetry','','[]','東坡夙世乃戒老，次律前身爲永師。',64,'全唐诗/poet.song.90000.json','["東坡夙世乃戒老，次律前身爲永師。", "一念參差成此錯，百憂鍾萃使知非。", "我生已約渡南海，今日豈知還北歸。", "從今莫打這鼓笛，必竟是事終由誰。"]'),
('d6d63f9d-ae4b-46bd-92bb-7fe7833750c7','自鵝城乘舟至河源風雨日作江流湍激以寸步進感歎有作','李綱','宋','宋诗','song-poetry','','[]','榜舟泝迴溪，夏潦適川漲。',144,'全唐诗/poet.song.90000.json','["榜舟泝迴溪，夏潦適川漲。", "驚湍激怒瀾，怪石立異狀。", "篙師巧爲計，巨細施石上。", "譟呼集衆力，進寸退尋丈。", "峥嶸三數峰，竟日不離望。", "乃知勢不便，智力未足仗。", "我行極江海，幸免魚腹葬。", "書生妙言辭，過謂神所相。", "及茲困溝瀆，更覺水石壯。", "翻思泛滄溟，千里纔一餉。", "豈惟小中州，端欲簉崑閬。", "斯遊不可忘，臨風默惆悵。"]'),
('6dca9cdb-4eac-442b-ae87-f34fc9ffaaa3','五月晦寓河源館舍雨凉新沐偶成一絕','李綱','宋','宋诗','song-poetry','','[]','風雨蕭蕭作晚凉，山城松桂發天香。',32,'全唐诗/poet.song.90000.json','["風雨蕭蕭作晚凉，山城松桂發天香。", "蘭湯沐罷尤清快，一枕江南歸夢長。"]'),
('a6c445cd-c599-4fef-96e8-1f56b6ac7a0d','夜霽天象明潤仰觀有感成一百韻時歲在斗熒惑在氐微甚辰鎮陵犯於翼軫間夜半斗杓轉占帝座未明台星尚拆云','李綱','宋','宋诗','song-poetry','','[]','昊穹運宸極，示人文燦然。',288,'全唐诗/poet.song.90000.json','["昊穹運宸極，示人文燦然。", "萬象森布列，七曜紛迴還。", "體物具六擾，面朝别三垣。", "德隆乃循軌，政錯因失躔。", "日月有薄蝕，星辰或相挻。", "暈適與佩玦，精祲光屬聮。", "災祥本人致，銷弭術在焉。", "譬猶五藏病，察色推其原。", "詎有使之者，一氣兆所先。", "應病投藥石，厥疾尚可痊。", "恬不加料理，瞑眩知何緣。", "愈病當以藥，弭災當以言。", "苦言逆人耳，龜筴窮根源。", "甘言悅人意，無乃有後艱。", "虚心行正說，天道咫尺間。", "太戊正厥事，桑穀反爲妍。", "宋景知愛民，法星退亦遄。", "精誠所感格，應效猶衡權。", "堯舜曰欽若，七政齊璣璿。", "周公戒成王，敬德享歷年。", "奈何後世士，導使不畏天。", "爲子傲厥考，獲罪安禱旃。", "論議肈熙豐，猷爲終政宣。", "皇天豈無意，儆戒良拳拳。"]'),
('903eb08b-62a4-4d81-9a75-ef71957f73d8','自河源陸行如循梅雨齊天氣頗佳偶成古風','李綱','宋','宋诗','song-poetry','','[]','宿雨乍開霽，新暘倐飛升。',96,'全唐诗/poet.song.90000.json','["宿雨乍開霽，新暘倐飛升。", "嶠南瘴毒地，乃爾氣候清。", "束裝遵陸途，夾道松林青。", "我家大江南，及此歸有程。", "山禽亦爲喜，林間囀新聲。", "况復抵衡宇，童稚歡相迎。", "入室酒盈樽，聊以慰平生。", "已矣勿復道，晚節師淵明。"]'),
('410eb03d-3237-498b-92b5-6af74db042db','循州道中作','李綱','宋','宋诗','song-poetry','','[]','嶺海經行涉兩年，籃輿觸熱道龍川。',64,'全唐诗/poet.song.90000.json','["嶺海經行涉兩年，籃輿觸熱道龍川。", "只愁青草黄茅瘴，敢意好風佳月天。", "山頂濛濛遮薄霧，江心跕跕墮飛鳶。", "勞生往返何爲者，歸去躬耕負郭田。"]'),
('7d86069d-9fa9-43fd-867e-b86a17f38835','絕句二首  其一','李綱','宋','宋诗','song-poetry','','[]','深入循梅瘴癘鄉，煙雲浮動日蒼凉。',32,'全唐诗/poet.song.90000.json','["深入循梅瘴癘鄉，煙雲浮動日蒼凉。", "踰年踏徧嶠南土，賴有仙翁肘後方。"]'),
('398a2c96-240e-4739-af75-1616f2aa5d10','絕句二首  其二','李綱','宋','宋诗','song-poetry','','[]','邪氣豈能干正氣，妄心自不勝真心。',32,'全唐诗/poet.song.90000.json','["邪氣豈能干正氣，妄心自不勝真心。", "治心養氣無多術，一點能銷瘴毒深。"]'),
('488de82d-717b-46e2-9f3d-bfc60f6a2bf9','過黄石驛十許里嚴石間懸瀑潨射聲隱然真小三峽也命僕夫剪剔翳薈爲行者清心駭目之觀戲成兩絕  其一','李綱','宋','宋诗','song-poetry','','[]','玉濺珠跳雷雹聲，巖端飛瀑蔽林芿。',32,'全唐诗/poet.song.90000.json','["玉濺珠跳雷雹聲，巖端飛瀑蔽林芿。", "呼童取斧開蒙密，一使行人心目清。"]'),
('21c7e401-bf6e-4686-9c7f-bb9796196e6c','過黄石驛十許里嚴石間懸瀑潨射聲隱然真小三峽也命僕夫剪剔翳薈爲行者清心駭目之觀戲成兩絕  其二','李綱','宋','宋诗','song-poetry','','[]','終日崎嶇山谷間，雨餘林下水潺潺。',32,'全唐诗/poet.song.90000.json','["終日崎嶇山谷間，雨餘林下水潺潺。", "炎方六月不知暑，端爲先生從此還。"]'),
('4900285e-0b45-4ee1-9aff-f372a036808e','聞蟬','李綱','宋','宋诗','song-poetry','','[]','喬林蔽日沸蟬聲，美蔭超然風露清。',32,'全唐诗/poet.song.90000.json','["喬林蔽日沸蟬聲，美蔭超然風露清。", "嘒嘒不休聊自樂，豈因人故乃長鳴。"]'),
('61b33cb9-ac45-434c-a3a5-6027da3e89d7','新月二首  其一','李綱','宋','宋诗','song-poetry','','[]','碧落銀蟾吐，知從何處來。',48,'全唐诗/poet.song.90000.json','["碧落銀蟾吐，知從何處來。", "雕弓絃未上，寶鏡匣初開。", "照水鈎沉影，窺人光滿懷。", "微升已西沒，露坐興悠哉。"]'),
('b271da4a-8489-46e4-87ef-23def7115e21','新月二首  其二','李綱','宋','宋诗','song-poetry','','[]','初月明生小，衆星寒吐鋩。',48,'全唐诗/poet.song.90000.json','["初月明生小，衆星寒吐鋩。", "穿林未驚鵲，傍户已窺床。", "漸喜山川曉，自令風露凉。", "僊人貼片玉，爲我賜清光。"]'),
('bb08a478-0e4a-4de7-a125-9b44426fbb3e','早行二首  其一','李綱','宋','宋诗','song-poetry','','[]','夙起戒徒御，小村扉未開。',48,'全唐诗/poet.song.90000.json','["夙起戒徒御，小村扉未開。", "霧分山遠近，溪繞路縈回。", "排遣憑詩句，銷除賴酒杯。", "大恩何以報，海上得歸來。"]'),
('fd40ef4e-b92f-47ad-a537-8bc09ef15ff4','早行二首  其二','李綱','宋','宋诗','song-poetry','','[]','宿雨破袢暑，趣裝期早還。',48,'全唐诗/poet.song.90000.json','["宿雨破袢暑，趣裝期早還。", "斷塍泥滑滑，幽谷水潺潺。", "半世走長道，暮年歸故山。", "蒙頭有衲被，送老白頭間。"]'),
('6b7f8ac5-5bf9-4c68-9d17-47532a1f3a6d','通衢驛夜坐有感二首  其一','李綱','宋','宋诗','song-poetry','','[]','永夜發孤笑，起看河漢流。',48,'全唐诗/poet.song.90000.json','["永夜發孤笑，起看河漢流。", "羣山湧翠浪，纖月掛瓊鈎。", "豈謂艱難日，翻成汗漫遊。", "虚舟全不繫，暮景付滄洲。"]'),
('c4b1113e-730c-4758-8409-18911fb387ac','通衢驛夜坐有感二首  其二','李綱','宋','宋诗','song-poetry','','[]','酷暑事行役，瘴雲天一方。',48,'全唐诗/poet.song.90000.json','["酷暑事行役，瘴雲天一方。", "曉登丞相嶺，夜宿翰林堂。", "月落星河耿，軒開風露香。", "微凉生枕簟，歸夢到江鄉。"]'),
('b32617ae-3875-492e-bcd2-0c0a5b07a49e','循梅道中遣人如江南走筆寄諸季十首  其一','李綱','宋','宋诗','song-poetry','','[]','弟有青雲志，兄今白髪翁。',48,'全唐诗/poet.song.90000.json','["弟有青雲志，兄今白髪翁。", "斷鴻飛嶠北，歸鶴自遼東。", "鯨海扁舟過，煙嵐一笑空。", "衰顔雖已老，尚有渥丹紅。"]'),
('2e3b7eef-3771-47d4-867f-54839f241688','循梅道中遣人如江南走筆寄諸季十首  其二','李綱','宋','宋诗','song-poetry','','[]','海外歸來客，天涯老病身。',48,'全唐诗/poet.song.90000.json','["海外歸來客，天涯老病身。", "卷開愁細字，冠側倩傍人。", "久矣鴛鸞絕，優哉麋鹿親。", "尤堪澆美酒，醉裏發天真。"]'),
('5cf5bdd2-04c0-4ea0-9fcf-7e3ead42891a','循梅道中遣人如江南走筆寄諸季十首  其三','李綱','宋','宋诗','song-poetry','','[]','人傳吳會破，虜向福山歸。',48,'全唐诗/poet.song.90000.json','["人傳吳會破，虜向福山歸。", "松梓定安穩，池臺今是非。", "傷心懷故老，流淚落征衣。", "目斷滄波上，龍舟翠蓋飛。"]'),
('ecaa0e35-92ab-4d3a-9d47-9af1214c054b','循梅道中遣人如江南走筆寄諸季十首  其四','李綱','宋','宋诗','song-poetry','','[]','契闊三年久，驚憂一夢新。',48,'全唐诗/poet.song.90000.json','["契闊三年久，驚憂一夢新。", "江鄉漂寓客，海嶠得歸人。", "風雨對床夜，詩書開帳晨。", "速宜尋舊約，一醉萬家春。"]'),
('6af84b6f-dcc9-4fd9-9915-f10a5130305f','循梅道中遣人如江南走筆寄諸季十首  其五','李綱','宋','宋诗','song-poetry','','[]','寂默維摩病，誰參不二門。',48,'全唐诗/poet.song.90000.json','["寂默維摩病，誰參不二門。", "應緣聊遣化，問疾欲忘言。", "斷取妙喜國，同遊祗樹園。", "甚深須獨悟，勿爲衆人論。"]'),
('569f3b1a-42a2-4d98-ae07-086c1e3e9adf','循梅道中遣人如江南走筆寄諸季十首  其六','李綱','宋','宋诗','song-poetry','','[]','虜騎滋南牧，于今大將誰。',48,'全唐诗/poet.song.90000.json','["虜騎滋南牧，于今大將誰。", "樓船泛溟渤，哀詔問瘡痍。", "沙漠深鑾輅，江湖震鼓鼙。", "遠方惟嶺嶠，耕鑿自熙熙。"]'),
('d6e3bc2d-ed23-4696-9292-0d4debdbc6d4','循梅道中遣人如江南走筆寄諸季十首  其七','李綱','宋','宋诗','song-poetry','','[]','常笑晉南渡，區區營一隅。',48,'全唐诗/poet.song.90000.json','["常笑晉南渡，區區營一隅。", "近傳胡騎擾，未覺古人迂。", "談笑北支勒，指麾西破苻。", "凄凉王謝後，繼踵豈真無。"]'),
('f33a6767-2b59-4f9c-bb71-2f0564345293','循梅道中遣人如江南走筆寄諸季十首  其八','李綱','宋','宋诗','song-poetry','','[]','毎訝杜陵老，賦詩多旅愁。',48,'全唐诗/poet.song.90000.json','["毎訝杜陵老，賦詩多旅愁。", "只今萍梗跡，自乏稻梁謀。", "火氣已徂暑，金風將動秋。", "相從攻苦淡，一解萬端憂。"]'),
('ba2ae819-b5aa-43f5-a346-ee6cf0c70e48','循梅道中遣人如江南走筆寄諸季十首  其九','李綱','宋','宋诗','song-poetry','','[]','觸熱冒氛癘，懷家思弟昆。',48,'全唐诗/poet.song.90000.json','["觸熱冒氛癘，懷家思弟昆。", "早行青嶂月，夜泊綠林村。", "且喜江南近，休將塞北論。", "憑髙望吳越，黯黯更銷魂。"]'),
('3432bc07-d8ce-48be-b0b9-115e3d3ddab5','循梅道中遣人如江南走筆寄諸季十首  其一○','李綱','宋','宋诗','song-poetry','','[]','江表難久客，沙陽可暫安。',48,'全唐诗/poet.song.90000.json','["江表難久客，沙陽可暫安。", "舊諳魚稻美，頗得士民歡。", "騏驥已衰病，鶺鴒方急難。", "爲携雛稚輩，早下建溪灘。"]'),
('a2c87561-3598-44b3-a967-ee2ef9f38106','古意四首  其一','李綱','宋','宋诗','song-poetry','','[]','鸞鳳招不來，鴟鳶麾不去。',48,'全唐诗/poet.song.90000.json','["鸞鳳招不來，鴟鳶麾不去。", "君看酒肉敗，坐使醯雞聚。", "小人爲身謀，無復及遠慮。", "國敝身亦危，何殊木中蠧。"]'),
('9c0884ae-0b3c-4bad-b31f-f91ad96dd9ea','古意四首  其二','李綱','宋','宋诗','song-poetry','','[]','薰蕕不同器，梟鸞不接翼。',48,'全唐诗/poet.song.90000.json','["薰蕕不同器，梟鸞不接翼。", "君看冰炭姿，燥濕更相息。", "消長本天行，否泰非人力。", "須知坦蕩蕩，自勝長戚戚。"]'),
('58703cfe-d327-4755-94d6-42ffb3056097','古意四首  其三','李綱','宋','宋诗','song-poetry','','[]','嘉木難封植，惡木費剪除。',48,'全唐诗/poet.song.90000.json','["嘉木難封植，惡木費剪除。", "君看種榆柳，横直皆扶疏。", "裊裊不自畏，更欲陵天衢。", "不知歲寒後，松柏誰彫枯。"]'),
('39503a23-63cd-42c0-9b68-a15d83eafd99','古意四首  其四','李綱','宋','宋诗','song-poetry','','[]','松柏寒更青，蕙蘭幽自芳。',48,'全唐诗/poet.song.90000.json','["松柏寒更青，蕙蘭幽自芳。", "君看繞指柔，何似百鍊剛。", "逐物成俯仰，随時變炎凉。", "悲哉小人態，所得真毫鋩。"]'),
('330150e8-aaf6-4767-bded-864e0a7f56a4','宿興寧縣驛二首  其一','李綱','宋','宋诗','song-poetry','','[]','清夜風露冷，月華窗半侵。',48,'全唐诗/poet.song.90000.json','["清夜風露冷，月華窗半侵。", "懷家千里夢，許國一生心。", "倦鳥投林急，潛魚泳澤深。", "無人知此意，抱膝自長吟。"]'),
('4a4d0c54-ba2a-4a4f-ab6b-c505a1197838','宿興寧縣驛二首  其二','李綱','宋','宋诗','song-poetry','','[]','六月欲徂暑，又催流火輝。',48,'全唐诗/poet.song.90000.json','["六月欲徂暑，又催流火輝。", "竹間螢已亂，簷側鷰將歸。", "豈念棄紈扇，永懷勞鐵衣。", "兵戈猶未息，老盡故山薇。"]'),
('8e23abb3-b841-4715-828b-d9d58610dd1a','午暑憇夜明館道傍清流激湍可愛所乏者茂林修竹耳二首  其一','李綱','宋','宋诗','song-poetry','','[]','火雲千丈映溪山，正是人間行路難。',32,'全唐诗/poet.song.90000.json','["火雲千丈映溪山，正是人間行路難。", "賴有道傍飛瀑在，噴霜翻雪作清寒。"]'),
('878f15a8-3e89-4473-a869-10748708c118','午暑憇夜明館道傍清流激湍可愛所乏者茂林修竹耳二首  其二','李綱','宋','宋诗','song-poetry','','[]','寶氣何年夜發明，至今郵舍得佳名。',32,'全唐诗/poet.song.90000.json','["寶氣何年夜發明，至今郵舍得佳名。", "我來不暇尋光景，但愛鏘金漱玉聲。"]'),
('49ca17db-c86e-4465-af5e-497c8bb13ea2','自梅趣汀行小路墝確危甚六月十一日宿金沙寺','李綱','宋','宋诗','song-poetry','','[]','觸熱過梅川，墝嶅鳥道邊。',120,'全唐诗/poet.song.90000.json','["觸熱過梅川，墝嶅鳥道邊。", "林深晴有霧，土曠晝稀煙。", "略彴横溪小，籃輿礙石偏。", "亂蟬鳴翳薈，疊澗瀉潺湲。", "閩嶺雖近止，江鄉猶渺然。", "何曾愁瘴癘，秪是怯危顛。", "借問勞行役，何如穏晏眠。", "遭時正艱棘，賦分自迴邅。", "已幸生還里，寧辭險著鞭。", "夜凉棲野寺，相對月嬋娟。"]'),
('f87a5c58-ffd5-4e7d-a8c7-2af1ad980f89','客有饋鮮鯽月夜與宗之溪上放之','李綱','宋','宋诗','song-poetry','','[]','步月溪頭放小鮮，銀梭擲水勢飛翻。',32,'全唐诗/poet.song.90000.json','["步月溪頭放小鮮，銀梭擲水勢飛翻。", "清波真是悠然去，不似洋洋秪聽言。"]'),
('95b0c489-995a-46c6-814a-236cd2baaa9c','自金沙至梅口宿農家','李綱','宋','宋诗','song-poetry','','[]','夏夜宿山莊，風吹禾稼香。',48,'全唐诗/poet.song.90000.json','["夏夜宿山莊，風吹禾稼香。", "兒童窺户牖，雞犬訝冠裳。", "戞戞竹搖翠，輝輝螢弄光。", "濁醪澆渴肺，夢覺月侵牀。"]'),
('72a8d053-f184-447e-bb3c-e6c92ff2ea9f','南安巖恭謁定光圓應禪師二首  其一','李綱','宋','宋诗','song-poetry','','[]','白衣隱去碧巖空，塔廟巋然海嶠東。',64,'全唐诗/poet.song.90000.json','["白衣隱去碧巖空，塔廟巋然海嶠東。", "分化何殊遽如許，贈詩多寫以之中。", "青山綠水年年好，明月清風處處同。", "好住一方爲庇蔭，不須追逐泗濱翁。"]'),
('8555bd32-52b9-4015-91db-ecc1b0d0fbf7','南安巖恭謁定光圓應禪師二首  其二','李綱','宋','宋诗','song-poetry','','[]','嶺嶠經行萬屈盤，北歸今始到南安。',64,'全唐诗/poet.song.90000.json','["嶺嶠經行萬屈盤，北歸今始到南安。", "滿山泉石有古意，十里松筠生晝寒。", "頗厭病身遊夢境，欲將餘日付巖端。", "定光古佛今猶在，請問此光何處觀。"]'),
('67b78135-62e4-40f6-a5eb-73106e24de7f','錢申伯自海陵避地臨汀聞余北歸相迓於武平賦詩見意二首  其一','李綱','宋','宋诗','song-poetry','','[]','海嶠經行徧，還爲閩嶺遊。',48,'全唐诗/poet.song.90000.json','["海嶠經行徧，還爲閩嶺遊。", "清泉滌餘瘴，小雨報新秋。", "多謝故人意，來銷羈客愁。", "慇懃問淮楚，兵革已寧不。"]'),
('b4648dda-0b67-40c1-99cc-1b6ce40ab971','錢申伯自海陵避地臨汀聞余北歸相迓於武平賦詩見意二首  其二','李綱','宋','宋诗','song-poetry','','[]','我脫鯨波險，君罹寇盗驚。',48,'全唐诗/poet.song.90000.json','["我脫鯨波險，君罹寇盗驚。", "暌離四寒暑，會遇兩蓬萍。", "訪舊半爲鬼，問津多阻兵。", "衣冠漂蕩極，風雨自雞鳴。"]'),
('e95704cf-319c-4275-8a75-8ed3c99c6956','次韻申伯見贈','李綱','宋','宋诗','song-poetry','','[]','連年奔走厭艱難，痛憤胡雛入漢關。',64,'全唐诗/poet.song.90000.json','["連年奔走厭艱難，痛憤胡雛入漢關。", "萬里自忘鯨海遠，一身今伴嶺雲閒。", "孤忠耿耿空餘志，華髪蕭蕭已映顔。", "慚愧故人相勞苦，去時明月却同還。"]'),
('89fb24d7-273b-4862-99b3-00f19c6b5fdb','次韻申伯上杭道中見示二首  其一','李綱','宋','宋诗','song-poetry','','[]','川途荏苒度年華，命與時謀敢自嗟。',64,'全唐诗/poet.song.90000.json','["川途荏苒度年華，命與時謀敢自嗟。", "但使直方能養浩，豈知權勢解悲夸。", "淮舟昔共茱萸酒，閩館今同薄荷茶。", "往復紛紛成底事，龐公只合訪丹霞。"]'),
('41f53ea1-e549-4aa2-96c7-2795876261e2','次韻申伯上杭道中見示二首  其二','李綱','宋','宋诗','song-poetry','','[]','相逢閩嶺得同行，秋早凄然風露清。',64,'全唐诗/poet.song.90000.json','["相逢閩嶺得同行，秋早凄然風露清。", "蟬曳殘聲吟翳薈，泉飛小瀑落峥嶸。", "濃雲林表千峰立，細路山腰一線横。", "坎止川流任天運，未應萍梗歎勞生。"]'),
('a75ee93a-8cf9-4e35-9a8d-d004dc2457c3','宿道傍僧舍次蔣穎叔壁間韻','李綱','宋','宋诗','song-poetry','','[]','竟日碧山中，清宵憇寶宫。',24,'全唐诗/poet.song.90000.json','["竟日碧山中，清宵憇寶宫。", "客愁無那處，一葉已秋風。"]'),
('a0776a04-cd27-45c3-838e-77e5a18b8f20','寄沙陽鄧季明二首  其一','李綱','宋','宋诗','song-poetry','','[]','海上歸來近七峰，故人猶冀一樽同。',64,'全唐诗/poet.song.90000.json','["海上歸來近七峰，故人猶冀一樽同。", "心憂世故存當日，身履時危到此中。", "玉带金魚非素志，碧齋翠閣自清風。", "十年擾擾成何事，依舊梁谿一拙翁。"]'),
('d0a7ba3f-e272-4882-ad60-7a36903d8a4c','寄沙陽鄧季明二首  其二','李綱','宋','宋诗','song-poetry','','[]','當年曾到碧雲峰，惟有溪山與昔同。',64,'全唐诗/poet.song.90000.json','["當年曾到碧雲峰，惟有溪山與昔同。", "最愛幽人三徑裏，盡收春色一壺中。", "千年阨運非人力，四海横流本士風。", "爛額燋頭何所補，却輸花圃樂全翁。"]'),
('c3134eef-916c-4c8d-a83d-220ebf22e3ed','錢申伯追送至寧化栖隱寺賦詩識别','李綱','宋','宋诗','song-poetry','','[]','連年淮海悵離居，十日相從樂有餘。',64,'全唐诗/poet.song.90000.json','["連年淮海悵離居，十日相從樂有餘。", "心向功名已灰冷，老於詩酒未情疏。", "頗矜有客乃如許，共話無生正是渠。", "惜别不須追路遠，定期林下論羲書。"]'),
('9fe6fee5-5311-4ddf-8ac9-49e3a007da51','申伯見和佛跡巖詩再次前韻','李綱','宋','宋诗','song-poetry','','[]','平生嗜讀書，毎傚錐刺股。',240,'全唐诗/poet.song.90000.json','["平生嗜讀書，毎傚錐刺股。", "晚窺羲文心，射石遂飲羽。", "子雲方草玄，白鳳夢中吐。", "區區不自量，造化欲筆補。", "當其得意時，如渇味湩乳。", "誰爲摩天手，願借修月斧。", "故人適我願，邂逅遇南土。", "試將一隅授，笑喜屢作舞。", "嗟予值時危，孱懦愧不武。", "援世多掣肘，放足已折拇。", "片雲空往來，豈解作霖雨。", "逝將歸碧山，不復打這鼓。", "一氣中夜存，天光發靈府。", "參同有真契，神鼎轉龍虎。", "丹成赫朝霞，魔事敢余侮。", "世間成壞法，張弛猶弓弩。", "乾坤如許大，方以一枰賭。", "肉食謀自深，莧腹何足取。", "既非公家用，且作猿鶴主。", "相期巖穴中，蓻此方寸圃。"]'),
('b676930a-0dbd-4ac4-8fc1-c51c6da23af9','次韻翁士特相招居武夷','李綱','宋','宋诗','song-poetry','','[]','武夷山色翠崔嵬，應笑梁谿又到來。',64,'全唐诗/poet.song.90000.json','["武夷山色翠崔嵬，應笑梁谿又到來。", "脫網弱鱗初縱逸，傷弓倦翮尚驚猜。", "閒中陶寫資詩句，愁裏銷除賴酒杯。", "誰道川途廢光景，無根樹子不妨栽。"]'),
('bddbb944-f073-4365-a77a-3f2d29cb8357','靈峰寺','李綱','宋','宋诗','song-poetry','','[]','古寺宿靈峰，層巒倚碧空。',48,'全唐诗/poet.song.90000.json','["古寺宿靈峰，層巒倚碧空。", "巖花開宿雨，桂子落秋風。", "地僻溪山險，時危戰伐同。", "秪應輸衲子，蒙被白雲中。"]'),
('01dc9bbb-b527-4330-91e2-f45ba0177043','入江西境先寄諸季二首  其一','李綱','宋','宋诗','song-poetry','','[]','閩山行盡碧巉巖，稍見川原雲木參。',64,'全唐诗/poet.song.90000.json','["閩山行盡碧巉巖，稍見川原雲木參。", "萬里瘴嵐來海外，一溪煙水到江南。", "故人邂逅端如夢，世事紛紜未易談。", "鑄印墩頭家漸近，秋風歸騎亦驂驔。"]'),
('6abaf1cc-f0ad-47f2-b75f-ddae3cff5fc0','入江西境先寄諸季二首  其二','李綱','宋','宋诗','song-poetry','','[]','征途詰屈避兵戈，歎息勞生可若何。',64,'全唐诗/poet.song.90000.json','["征途詰屈避兵戈，歎息勞生可若何。", "却把蘧廬作安宅，毎聞鐃鼓輙悲歌。", "候門稚子鶴立久，浮海先生霜鬢多。", "可惜光陰四寒暑，只於來往與銷磨。"]'),
('c3521efb-2a2c-4932-b256-53978b2b5aaf','遊麻姑山二首  其一','李綱','宋','宋诗','song-poetry','','[]','魯公辭翰勒山巔，骾峭風姿亦喜僊。',64,'全唐诗/poet.song.90000.json','["魯公辭翰勒山巔，骾峭風姿亦喜僊。", "假道來遊非偶爾，追尋遺跡更茫然。", "野花幽草堪成夢，老鶴喬松不記年。", "誰謂瑶臺無路到，月明風露正涓涓。"]'),
('bc177d83-bcf6-4454-8361-b5337c719a57','遊麻姑山二首  其二','李綱','宋','宋诗','song-poetry','','[]','寶髻雲鬟衣彩霞，飈輪曾過蔡君家。',64,'全唐诗/poet.song.90000.json','["寶髻雲鬟衣彩霞，飈輪曾過蔡君家。", "河濱織女不停織，海上花姑長似花。", "幾見桑田變滄海，猶將菽粟化丹砂。", "此身漂泊干戈際，妙指煩於痒處爬。"]'),
('ef8d639f-7659-4258-8439-f7446f36b3dd','北歸次盰江疏山宗瑞長老來迓且言山巔有亭俯視羣山猶培塿也求佳名大書以榜之取少陵句爲目之曰一覽亭成兩絕句  其一','李綱','宋','宋诗','song-poetry','','[]','居士新從海上迴，勞煩竹杖與芒鞋。',32,'全唐诗/poet.song.90000.json','["居士新從海上迴，勞煩竹杖與芒鞋。", "故人何用將迎遠，明月清風常往來。"]'),
('bc2f085e-64f6-4103-9bda-3373ebc9af7e','北歸次盰江疏山宗瑞長老來迓且言山巔有亭俯視羣山猶培塿也求佳名大書以榜之取少陵句爲目之曰一覽亭成兩絕句  其二','李綱','宋','宋诗','song-poetry','','[]','千里林巒紫翠環，孤亭縹緲白雲端。',32,'全唐诗/poet.song.90000.json','["千里林巒紫翠環，孤亭縹緲白雲端。", "登臨一覽衆峰小，始見疏山境界寛。"]'),
('e85da0ff-bf0d-4dae-bc2e-145fa2be94d0','往返踰萬里首尾涉五年幸無驚憂歸次貴溪仙巖新罹寇盜焚蕩孑然始見兵火之跡感愴有作二首  其一','李綱','宋','宋诗','song-poetry','','[]','夢裏幽人獨往來，僊巖依舊碧崔嵬。',32,'全唐诗/poet.song.90000.json','["夢裏幽人獨往來，僊巖依舊碧崔嵬。", "傷心二百載涵養，極望皆成瓦礫堆。"]'),
('20fd665f-775f-4738-a4ae-44fdd54d0545','往返踰萬里首尾涉五年幸無驚憂歸次貴溪仙巖新罹寇盜焚蕩孑然始見兵火之跡感愴有作二首  其二','李綱','宋','宋诗','song-poetry','','[]','遼海歸來丁令威，山川雖是事多非。',32,'全唐诗/poet.song.90000.json','["遼海歸來丁令威，山川雖是事多非。", "衣冠南渡奔崩極，始信六朝猶足依。"]'),
('bd42a46c-309d-4da5-8cea-ee9050d8fb9c','靖康丙午冬道江南宿龜峰寺建炎庚戌秋北歸再過行遽不果到長老智光見訪成三絕句以遺之  其一','李綱','宋','宋诗','song-poetry','','[]','散策曾遊瑞相峰，煙霞深處翠成叢。',32,'全唐诗/poet.song.90000.json','["散策曾遊瑞相峰，煙霞深處翠成叢。", "清江使者今安否，五換星霜一夢中。"]'),
('ed569694-45c7-4945-9bfe-a210f679c626','靖康丙午冬道江南宿龜峰寺建炎庚戌秋北歸再過行遽不果到長老智光見訪成三絕句以遺之  其二','李綱','宋','宋诗','song-poetry','','[]','去國翻成汗漫遊，迢迢雲海六鼇愁。',32,'全唐诗/poet.song.90000.json','["去國翻成汗漫遊，迢迢雲海六鼇愁。", "歸來又踏江南土，都在當年拄杖頭。"]'),
('b79a21f4-1060-4560-8194-ae1abc7d3862','靖康丙午冬道江南宿龜峰寺建炎庚戌秋北歸再過行遽不果到長老智光見訪成三絕句以遺之  其三','李綱','宋','宋诗','song-poetry','','[]','蘭若松林物外居，羡師一住十年餘。',32,'全唐诗/poet.song.90000.json','["蘭若松林物外居，羡師一住十年餘。", "奔馳萬里心灰冷，借我峰前使結廬。"]'),
('0f7fde3f-7f67-4750-bcb7-2f7f5b3b6fdd','自海外歸間關萬里經涉五載初抵家與諸季會飲成長句兼簡鄒德久昆仲','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','楚氛未静狼烽起，翠華搖搖無定止。',224,'全唐诗/poet.song.90000.json','["楚氛未静狼烽起，翠華搖搖無定止。", "謀臣猛將如雲屯，坐視胡雛渡江水。", "我歸自南時正艱，繚絡間關萬餘里。", "問津處處皆戰塲，訪舊往往成新鬼。", "傷心不忍顧浙河，故園已在荆棘底。", "幸然家寓大江東，窈窕精廬山谷裏。", "當時百口還滿前，况復添丁長童稚。", "衣冠南渡多流離，骨肉無虞能有幾。", "生還已荷皇天慈，見汝更使清愁洗。", "夜闌秉燭疑夢中，破悲爲笑且歡喜。", "在原真赴鶺鴒難，玉樹還許蒹葭倚。", "眷言兄弟同友生，風雨雞鳴未云已。", "閩山深處是吾鄉，攜幼扶衰又將徙。", "安得廟社固根基，一使寰區盡蒙祉。"]'),
('895f5917-bedb-4416-b528-aa6d91804057','中秋與諸季及德久昆仲望月同飲','李綱','宋','宋诗','song-poetry','','[]','五年客裏過中秋，今夕安知無此愁。',64,'全唐诗/poet.song.90000.json','["五年客裏過中秋，今夕安知無此愁。", "共喜銀雲開碧落，坐看蟾魄過西樓。", "清光著物殊他夜，好景於人散百憂。", "人月皆圓那易得，莫辭大白十分浮。"]'),
('6ff0ce45-cf2b-426f-8cbf-b3f59d3806e5','送季言弟還錫山省先壠四首  其一','李綱','宋','宋诗','song-poetry','','[]','四年謫去遠桑梓，萬里歸來紛甲兵。',32,'全唐诗/poet.song.90000.json','["四年謫去遠桑梓，萬里歸來紛甲兵。", "却恨此身方抱病，掃墳不與汝同行。"]'),
('e7283c71-32f3-443a-ab31-561c7d55cd7f','送季言弟還錫山省先壠四首  其二','李綱','宋','宋诗','song-poetry','','[]','胡雛南牧浙河空，多幸依然馬鬛封。',32,'全唐诗/poet.song.90000.json','["胡雛南牧浙河空，多幸依然馬鬛封。", "勞汝遥傳一掬淚，霜前爲灑萬株松。"]'),
('93e773d4-8139-45aa-b847-65e9c4eab702','送季言弟還錫山省先壠四首  其三','李綱','宋','宋诗','song-poetry','','[]','毎憂吳會太繁雄，虜騎憑陵掌股中。',32,'全唐诗/poet.song.90000.json','["毎憂吳會太繁雄，虜騎憑陵掌股中。", "若到新經兵火地，莫將有限悼無窮。"]'),
('8caa424f-0c0c-4bd2-962b-cb5a9d8e6cc5','送季言弟還錫山省先壠四首  其四','李綱','宋','宋诗','song-poetry','','[]','連年瘴海鬢成絲，多荷君恩特放歸。',32,'全唐诗/poet.song.90000.json','["連年瘴海鬢成絲，多荷君恩特放歸。", "邂逅故人相問訊，爲言蘧瑗久知非。"]'),
('8065f9c6-de1d-4404-954e-4060544794ac','同諸季及鄒德久昆仲遊龍潭','李綱','宋','宋诗','song-poetry','','[]','避地寓江左，精廬極深幽。',264,'全唐诗/poet.song.90000.json','["避地寓江左，精廬極深幽。", "駕言窮勝賞，遂作龍潭遊。", "暑氣歛以退，輕雲藹而浮。", "疏林未搖落，山色宜清秋。", "蘿磴穿窈窕，松風散颼飀。", "鐵花秀石壁，玉韻鏘溪流。", "誰將三峽橋，斷取來巖陬。", "會心得佳趣，濁酒相獻酬。", "嫩菊青可摘，寒蔬鬱堪羞。", "樂哉山林間，乃爾遠世憂。", "豈知江淮濆，殺氣横戈矛。", "幽討未云已，散策層岡頭。", "天紳拖脩瀑，落此萬丈湫。", "空濛杳靄中，時有飛魚游。", "神物不可見，下隱長黄虬。", "百穀正焦枯，胡爲此淹留。", "會乘風雷便，一起澤九州。", "我與二三子，於世初無求。", "蕭然巖壑姿，正可擅一丘。", "願言假吾居，聊作潛珍謀。", "玉函畀思邈，貝闕歸靈脩。", "何須挾白羽，共逐青綃牛。"]'),
('d0f92292-cbd1-49e7-a05c-4a0673467cbe','九日登山亭會飲','李綱','宋','宋诗','song-poetry','','[]','淵明避世士，酷愛九日名。',144,'全唐诗/poet.song.90000.json','["淵明避世士，酷愛九日名。", "獨酌東籬下，悠然得此生。", "我輩正羈旅，佳節安可醒。", "相携陟翠巘，置酒松間亭。", "菊蘂弄新黄，橘苞破微馨。", "鬢邊插茱萸，未覺巾幘傾。", "雲山藹佳色，風林動疏聲。", "慷慨念平昔，醉舞屬羣英。", "國步方綴旒，衣冠正漂萍。", "山河舉目異，望遠若爲情。", "方期汗漫遊，天池濯吾纓。", "何必楚囚泣，牛山良可輕。"]'),
('eb2f2c4a-8113-488a-b959-f0cbf7fe470f','九日示諸季時會飲者八人','李綱','宋','宋诗','song-poetry','','[]','海外頻年懷棣蕚，江南九日共茱萸。',64,'全唐诗/poet.song.90000.json','["海外頻年懷棣蕚，江南九日共茱萸。", "莫愁羣盗驚鄰壤，且作新詩慰老夫。", "坐上豈無吹帽客，飲中况是謫僊徒。", "不將酩酊酬佳節，肯信黄花解笑無。"]'),
('4caa52df-1ebb-4aae-b282-c8848313260a','冬至後四日脩供羅漢巖因訪丹霞本老成四絕句  其一','李綱','宋','宋诗','song-poetry','','[]','道人眼静絕空花，巖壑蕭然物外家。',32,'全唐诗/poet.song.90000.json','["道人眼静絕空花，巖壑蕭然物外家。", "十載聞名今始到，龐公真是訪丹霞。"]'),
('c0c9a205-3efe-4a0e-a150-859056e63f43','冬至後四日脩供羅漢巖因訪丹霞本老成四絕句  其二','李綱','宋','宋诗','song-poetry','','[]','籃輿清曉叩禪扉，山路雲深翠濕衣。',32,'全唐诗/poet.song.90000.json','["籃輿清曉叩禪扉，山路雲深翠濕衣。", "誰家峰頭雙練瀑，空濛散作玉花飛。"]'),
('052a4421-2e6a-4335-ad23-72ae35aeebd8','冬至後四日脩供羅漢巖因訪丹霞本老成四絕句  其三','李綱','宋','宋诗','song-poetry','','[]','碧山深處敞層巖，中有幽人默自參。',32,'全唐诗/poet.song.90000.json','["碧山深處敞層巖，中有幽人默自參。", "休指天雲與瓶水，煩師試說後三三。"]'),
('7a60eebd-fc80-4a84-b19a-5213b003da14','冬至後四日脩供羅漢巖因訪丹霞本老成四絕句  其四','李綱','宋','宋诗','song-poetry','','[]','巖巒鼎足繚回廊，泉石幽奇草木香。',32,'全唐诗/poet.song.90000.json','["巖巒鼎足繚回廊，泉石幽奇草木香。", "幸有峰前方丈地，可能爲築讀書堂。"]'),
('618cf75e-2f98-4f4d-ba43-cf9b84c5802f','葉夢授龍圖同遊丹霞見和四絕句再次前韻  其一','李綱','宋','宋诗','song-poetry','','[]','巖竇嵌空南寶花，玲瓏樓閣衲僧家。',32,'全唐诗/poet.song.90000.json','["巖竇嵌空南寶花，玲瓏樓閣衲僧家。", "興來結客窮幽討，衝破晴山幾段霞。"]'),
('769819b6-a9cd-45e5-95be-d92c077a0ddc','葉夢授龍圖同遊丹霞見和四絕句再次前韻  其二','李綱','宋','宋诗','song-poetry','','[]','渡水捫蘿款石扉，杖藜同著舊緇衣。',32,'全唐诗/poet.song.90000.json','["渡水捫蘿款石扉，杖藜同著舊緇衣。", "猶嫌林下諠僮僕，欲學孤雲野鶴飛。"]'),
('ef1ad70d-eefd-43c9-8f78-0bf460301d1f','葉夢授龍圖同遊丹霞見和四絕句再次前韻  其三','李綱','宋','宋诗','song-poetry','','[]','煙霞絢彩染幽巖，紫翠葱蘢雲木參。',32,'全唐诗/poet.song.90000.json','["煙霞絢彩染幽巖，紫翠葱蘢雲木參。", "幸有幽人共清賞，豈惟風月友成三。"]'),
('01a99093-c41e-4014-8ae8-3543c228eff5','葉夢授龍圖同遊丹霞見和四絕句再次前韻  其四','李綱','宋','宋诗','song-poetry','','[]','夜寒月影照虚廊，境寂心清發妙香。',32,'全唐诗/poet.song.90000.json','["夜寒月影照虚廊，境寂心清發妙香。", "藜藿山林有餘樂，未應肉食念華堂。"]'),
('a616aec1-07d1-4200-bffa-a1091533012b','葉夢授送家園梅花且以絕句十五章見示次其韻  其一','李綱','宋','宋诗','song-poetry','','[]','天欲春光一點回，素英先識化工裁。',32,'全唐诗/poet.song.90000.json','["天欲春光一點回，素英先識化工裁。", "惱人不作鉛華態，願下當年玉鏡臺。"]'),
('c2a16b8b-95e4-41f5-a325-30f2f741e877','葉夢授送家園梅花且以絕句十五章見示次其韻  其二','李綱','宋','宋诗','song-poetry','','[]','道人宴坐得圓通，妙觀年來等色空。',32,'全唐诗/poet.song.90000.json','["道人宴坐得圓通，妙觀年來等色空。", "結習已銷花不染，何妨瓖麗伴衰翁。"]'),
('33b7afb5-ef0a-4829-bddf-29dde3e048e0','葉夢授送家園梅花且以絕句十五章見示次其韻  其三','李綱','宋','宋诗','song-poetry','','[]','枝頭數點雪初殘，折置冰壺分外寒。',32,'全唐诗/poet.song.90000.json','["枝頭數點雪初殘，折置冰壺分外寒。", "煙蘂輕盈未全拆，國香暗淡已欺蘭。"]'),
('bd69a5a8-d94b-4782-8f45-a93d8492ff83','葉夢授送家園梅花且以絕句十五章見示次其韻  其四','李綱','宋','宋诗','song-poetry','','[]','慇懃剩作送梅詩，撚斷霜髭不爲棋。',32,'全唐诗/poet.song.90000.json','["慇懃剩作送梅詩，撚斷霜髭不爲棋。", "只恐苦吟令太瘦，箇中風味有誰知。"]'),
('59db40a7-d075-4d7a-8dfc-5a254dbd2677','葉夢授送家園梅花且以絕句十五章見示次其韻  其五','李綱','宋','宋诗','song-poetry','','[]','傍雨移梅趁小寒，探春幾度獨憑欄。',32,'全唐诗/poet.song.90000.json','["傍雨移梅趁小寒，探春幾度獨憑欄。", "不知冷淡緣何事，偏得幽人带笑看。"]'),
('f9446b98-9b9f-4d89-8ed2-05c3b16d5b1b','葉夢授送家園梅花且以絕句十五章見示次其韻  其六','李綱','宋','宋诗','song-poetry','','[]','坐來寒谷變陽春，雪裏開花若有神。',32,'全唐诗/poet.song.90000.json','["坐來寒谷變陽春，雪裏開花若有神。", "多作新詩詠尤物，知君最是愛花人。"]'),
('f497b379-6740-40e3-ac2e-4e54c42ac993','葉夢授送家園梅花且以絕句十五章見示次其韻  其七','李綱','宋','宋诗','song-poetry','','[]','超然標格冠羣芳，妙質天教徹骨香。',32,'全唐诗/poet.song.90000.json','["超然標格冠羣芳，妙質天教徹骨香。", "爛熳開時何足道，最憐新蘂半塗黄。"]'),
('c3617e69-2265-4263-9b71-3469697f3f3e','葉夢授送家園梅花且以絕句十五章見示次其韻  其八','李綱','宋','宋诗','song-poetry','','[]','疏籬煙雨數枝斜，行路于今五見花。',32,'全唐诗/poet.song.90000.json','["疏籬煙雨數枝斜，行路于今五見花。", "又向閩山和月摘，坐令流寓歎年華。"]'),
('95625166-4528-41b9-935a-7cc3f91c8012','葉夢授送家園梅花且以絕句十五章見示次其韻  其九','李綱','宋','宋诗','song-poetry','','[]','山路相逢若有情，折來書幌愈輕明。',32,'全唐诗/poet.song.90000.json','["山路相逢若有情，折來書幌愈輕明。", "何須更道能調鼎，小啄微酸已解醒。"]'),
('0876fe7c-90a6-4870-9fb8-e5d335e6e946','葉夢授送家園梅花且以絕句十五章見示次其韻  其一○','李綱','宋','宋诗','song-poetry','','[]','天生麗質絕塵埃，肯把胭脂漫汙腮。',32,'全唐诗/poet.song.90000.json','["天生麗質絕塵埃，肯把胭脂漫汙腮。", "幸有清香過於雪，對人何止白皚皚。"]'),
('41df1b66-2960-4844-9cea-21bc76fc18af','葉夢授送家園梅花且以絕句十五章見示次其韻  其一一','李綱','宋','宋诗','song-poetry','','[]','蕭疏竹外裊煙梢，清淺溪流映小橋。',32,'全唐诗/poet.song.90000.json','["蕭疏竹外裊煙梢，清淺溪流映小橋。", "不似僧房静中看，月明風細夜寥寥。"]'),
('02fa9cec-bbfd-4093-8281-b8311da6b639','葉夢授送家園梅花且以絕句十五章見示次其韻  其一二','李綱','宋','宋诗','song-poetry','','[]','小軒幽檻最相宜，對酒難禁綽約姿。',32,'全唐诗/poet.song.90000.json','["小軒幽檻最相宜，對酒難禁綽約姿。", "莫訝落英飄萬點，待看青子綴疏枝。"]'),
('4a312a3a-02a9-41dd-acaf-b62b6928ecd5','葉夢授送家園梅花且以絕句十五章見示次其韻  其一三','李綱','宋','宋诗','song-poetry','','[]','雲裳縞带步搖冠，誰遣瑶姬下廣寒。',32,'全唐诗/poet.song.90000.json','["雲裳縞带步搖冠，誰遣瑶姬下廣寒。", "默侍先生渾不語，風枝時聽珮珊珊。"]'),
('a7e8f718-4091-49f7-8baa-78d756e65b46','葉夢授送家園梅花且以絕句十五章見示次其韻  其一四','李綱','宋','宋诗','song-poetry','','["\u897f\u6e56"]','廣平援筆賦梅花，冨艷清便底死誇。',32,'全唐诗/poet.song.90000.json','["廣平援筆賦梅花，冨艷清便底死誇。", "况有西湖隱君子，句中能道影横斜。"]'),
('093baf26-0af0-473d-8c12-b1c96e7ab068','葉夢授送家園梅花且以絕句十五章見示次其韻  其一五','李綱','宋','宋诗','song-poetry','','[]','草木凍死山中村，惟有梅花解返魂。',32,'全唐诗/poet.song.90000.json','["草木凍死山中村，惟有梅花解返魂。", "弱植孤根傲霜霰，玉奴終不負東昏。"]'),
('6f3cab98-2ee2-4450-bc9c-ffd145b81894','上元日同王豐甫葉夢授會飲','李綱','宋','宋诗','song-poetry','','[]','當年玉輦侍端門，豈意風塵四海奔。',64,'全唐诗/poet.song.90000.json','["當年玉輦侍端門，豈意風塵四海奔。", "正恐溪山太寥落，也将燈火照黄昏。", "月華清切人千里，曲調凄涼酒一樽。", "多謝故人相煖熱，感時撫事祗銷魂。"]'),
('337b87cc-12b1-483b-b3dd-680c72419848','聞建寇逼境攜家將由樂沙縣以如劍浦','李綱','宋','宋诗','song-poetry','','[]','我來寓杉江，客館未煖席。',264,'全唐诗/poet.song.90000.json','["我來寓杉江，客館未煖席。", "紛然羣盜起，環境暗鋒鏑。", "束装呼僕夫，又復事遠適。", "峨峨章源嶺，峻峭初未識。", "攀援僅能進，十步九傾側。", "風吹霧雨冰，草木盡矛戟。", "朝登暮始降，落日半天赤。", "兒童饑屢啼，徒御疲已極。", "薄遊玉華洞，庶可稍休息。", "東郊遽不開，蜂蟻迭吞食。", "避寇如避弩，吾敢憚行役。", "驅車適沙陽，頗喜田野闢。", "雖經兵火餘，邑屋幸如昔。", "舊遊疑夢中，一一有遺跡。", "寓軒存佛宫，脩竹自春色。", "峥嶸凝翠閣，尚對七峰碧。", "故人皆避地，誰與道胸臆。", "理舟劍浦行，稍就寛曠域。", "溪流正湍暴，惡子亦充斥。", "脫身險阻中，恊濟藉衆力。", "吟哦杜陵詩，妙語皆中的。", "喪亂古今同，臨風意如織。"]'),
('0522c2e3-9357-4a04-b980-4bde9719cf14','次沙陽留題寓軒','李綱','宋','宋诗','song-poetry','','[]','一紀重來一夢中，寓軒脩竹自春風。',64,'全唐诗/poet.song.90000.json','["一紀重來一夢中，寓軒脩竹自春風。", "故人散去因羣盜，舊意相親惟七峰。", "溪上偶存凝翠閣，圃中安往樂全翁。", "感時不用頻惆悵，萬法從來本是空。"]'),
('68302e22-b605-4f1b-9b8a-723f66532601','留題凝翠閣二絕  其一','李綱','宋','宋诗','song-poetry','','[]','重到沙陽十二春，新罹兵火爲傷神。',32,'全唐诗/poet.song.90000.json','["重到沙陽十二春，新罹兵火爲傷神。", "欲論舊事無知者，只有青山是故人。"]'),
('49812cfb-b598-4dee-bd00-aced4be06a66','留題凝翠閣二絕  其二','李綱','宋','宋诗','song-poetry','','[]','山秀波平望不窮，此身渾堕翠光中。',32,'全唐诗/poet.song.90000.json','["山秀波平望不窮，此身渾堕翠光中。", "兵戈滿眼棲何地，注目溪頭羣玉峰。"]'),
('6c91e473-7618-44bd-b97e-f8550a8fea2e','過羅疇老故居有感二首  其一','李綱','宋','宋诗','song-poetry','','[]','鳳去梁摧忽十年，空餘文翰世間傳。',64,'全唐诗/poet.song.90000.json','["鳳去梁摧忽十年，空餘文翰世間傳。", "池臺春色仍依舊，几杖遺音猶隱然。", "把酒屢陪髙閣醉，揮毫幾和白雲篇。", "追尋舊事如疇昔，淚濕幽花曲檻前。"]'),
('84cc5812-a6cc-4ca1-a88d-e5749b04a24d','過羅疇老故居有感二首  其二','李綱','宋','宋诗','song-poetry','','[]','一别那知生死分，亂離重到德公門。',64,'全唐诗/poet.song.90000.json','["一别那知生死分，亂離重到德公門。", "雷張蓮社舊同約，詢惠滄洲徒有言。", "江海凄涼人已遠，園林蕭瑟劍空存。", "我來痛恨怱怱去，宿草無因奠一樽。"]'),
('6babc6b0-71fc-490a-ad3e-3462648114b9','興國璨老浴堂新成以伽佗見示戲成三絕句  其一','李綱','宋','宋诗','song-poetry','','[]','湛然定水滿新池，試浴金毛獅子兒。',32,'全唐诗/poet.song.90000.json','["湛然定水滿新池，試浴金毛獅子兒。", "普願衆生盡無垢，此身何惜汗成泥。"]'),
('45d97524-8e98-4f2a-b120-90d764bebad9','興國璨老浴堂新成以伽佗見示戲成三絕句  其二','李綱','宋','宋诗','song-poetry','','[]','湯泉海湧氣雲蒸，垢去心安身倍輕。',32,'全唐诗/poet.song.90000.json','["湯泉海湧氣雲蒸，垢去心安身倍輕。", "誰道圓通非外護，却因妙觸得宣明。"]'),
('f93be522-e767-4928-8d86-7fe8c7be080b','興國璨老浴堂新成以伽佗見示戲成三絕句  其三','李綱','宋','宋诗','song-poetry','','[]','池中已具八功德，浴處還敷七浄華。',32,'全唐诗/poet.song.90000.json','["池中已具八功德，浴處還敷七浄華。", "妙體本來塵不染，何妨癢處與抓爬。"]'),
('64fd0a64-f038-4d5b-9ae1-e659ad5e2ea8','宿開平寺去劍浦二十里有泉石之勝曩與郡守謝德夫同遊今一紀矣溪山草木依然住持猶舊人也感嘆有作二首  其一','李綱','宋','宋诗','song-poetry','','[]','舊遊渾似夢，佳處每難忘。',48,'全唐诗/poet.song.90000.json','["舊遊渾似夢，佳處每難忘。", "地僻溪山秀，春深草木香。", "世途方梗棘，老景自凄涼。", "衲子那知此，閑中氣味長。"]'),
('5f3a6263-4a80-4e39-be13-1890e139d747','宿開平寺去劍浦二十里有泉石之勝曩與郡守謝德夫同遊今一紀矣溪山草木依然住持猶舊人也感嘆有作二首  其二','李綱','宋','宋诗','song-poetry','','[]','往年同謝老，勝賞到開平。',48,'全唐诗/poet.song.90000.json','["往年同謝老，勝賞到開平。", "步屧山雲細，回舟溪月清。", "光陰雙轉轂，身世兩浮萍。", "願卜幽棲地，翛然得此生。"]'),
('e926364f-2913-4534-a2e4-d93bb2952abd','道延平適風雨雷電大作土人謂之劍歸有感','李綱','宋','宋诗','song-poetry','','[]','干將未發埋酆城，光氣上騰干列星。',186,'全唐诗/poet.song.90000.json','["干將未發埋酆城，光氣上騰干列星。", "張雷博識各有得，神物終合歸延平。", "没人下視不可取，天矯已作虬龍形。", "至今千載有肸蠁，往往出入驅雷霆。", "我來弭櫂雙溪上，正晝雲霧忽晦暝。", "金蛇掣電起潭底，霹靂洊作聲轟轟。", "土人謂是劍歸候，連日風雨資芽萌。", "嗟嗟爾劍誠有靈，胡不奮飛輔助討不庭。", "羣兇塞路盜賊横，夷狄外侮方驕獰。", "佩之其人得所託，蠧國害民姦腰佞領邐迤皆削平。", "何爲終日但長嘯，時出光怪驚動無知氓。"]'),
('842b8a9f-cbfb-4f5d-ad1f-c11b140f96bf','題王氏志嘉堂二首  其一','李綱','宋','宋诗','song-poetry','','[]','秀嶺雲屏擁，湍流玉佩鏘。',48,'全唐诗/poet.song.90000.json','["秀嶺雲屏擁，湍流玉佩鏘。", "竹光深鎖翠，蘭氣暗騰芳。", "豈謂兵戈日，來登君子堂。", "美才方世用，嘉遯自難忘。"]'),
('c389e8e5-3479-458d-b6fe-ad5ea8b65d72','題王氏志嘉堂二首  其二','李綱','宋','宋诗','song-poetry','','[]','茗飲過溪閣，蕭然泉石幽。',48,'全唐诗/poet.song.90000.json','["茗飲過溪閣，蕭然泉石幽。", "雨餘空翠濕，春老碧鮮浮。", "行止隨時運，笑談銷客愁。", "遯亨真我事，暮景付滄洲。"]'),
('2be3376e-724f-4cb3-b091-1501a9ba4825','追次東坡和鬱林王守韻','李綱','宋','宋诗','song-poetry','','[]','蓋世文章妙語言，誰令骨相似虞翻。',64,'全唐诗/poet.song.90000.json','["蓋世文章妙語言，誰令骨相似虞翻。", "玉堂大手空遺跡，海島幽棲有斷垣。", "仙去公寧懷此土，生還我亦荷寛恩。", "龍虬滿紙疑飛動，尚想揮毫氣象軒。"]'),
('4a22f971-1732-4f3d-9a7e-68a21c9fa092','遊包道士山居','李綱','宋','宋诗','song-poetry','','[]','何日養鉛丹，幽居紫翠間。',48,'全唐诗/poet.song.90000.json','["何日養鉛丹，幽居紫翠間。", "架巖開户牖，隱几俯溪山。", "昔到渾如夢，今遊更覺閒。", "兵戈知滿地，佳處且躋攀。"]'),
('07126e59-cd70-4269-b9a9-5d44b6613782','自劍浦乘舟至水口溪流方漲備見湍激奔猛之状賦詩以紀其事','李綱','宋','宋诗','song-poetry','','[]','避地適南土，捨車登葉舟。',120,'全唐诗/poet.song.90000.json','["避地適南土，捨車登葉舟。", "春溪渾带雨，霽石出如牛。", "詰曲知操妙，飄騰覺去遒。", "烟籠嵐翠滴，灘激浪花浮。", "亷利森排戟，盤回巧轉輈。", "輕生真可戒，快意且銷憂。", "灩澦過三峽，蓬壺訪十洲。", "平生志江海，暮景侣巢由。", "易象觀嘉遯，騷經賦遠遊。", "扁舟入吾手，此外更何求。"]'),
('c8b05905-9820-440a-95b5-36fad584e88d','温泉二絕  其一','李綱','宋','宋诗','song-poetry','','[]','温冷泉源各自流，天教施浴雪峰陬。',32,'全唐诗/poet.song.90000.json','["温冷泉源各自流，天教施浴雪峰陬。", "衆生塵垢何時盡，汨汨人間幾度秋。"]'),
('2f7f55ff-83d2-4548-8f37-83573257c5a0','温泉二絕  其二','李綱','宋','宋诗','song-poetry','','[]','玉池金屋浴蘭芳，千古華清第一湯。',32,'全唐诗/poet.song.90000.json','["玉池金屋浴蘭芳，千古華清第一湯。", "何似此泉澆疾病，不妨更入荔枝郷。"]'),
('520eec64-3c5d-4da0-9db4-a2e8832238be','次韻周元仲見寄二首  其一','李綱','宋','宋诗','song-poetry','','[]','凌雲健筆有神鋒，抵掌髙談久不同。',64,'全唐诗/poet.song.90000.json','["凌雲健筆有神鋒，抵掌髙談久不同。", "江上過從猶宿昔，嶠南遊歷徧西東。", "山川多助新詩裏，花鳥愁添老眼中。", "萬里歸來好同隱，竹林今祗欠王戎。"]'),
('4c19854d-6731-41db-b056-c4efdb4adae6','次韻周元仲見寄二首  其二','李綱','宋','宋诗','song-poetry','','[]','五年奔走敝征衣，海上相親半是黎。',64,'全唐诗/poet.song.90000.json','["五年奔走敝征衣，海上相親半是黎。", "望斷故園無旅鴈，心驚中夜聽荒鷄。", "豈知南渡能還北，更笑東來又向西。", "多謝故人尋訪意，千山萬水不曾迷。"]'),
('ca8940fc-eabc-49f5-be9a-d910aea09ff7','周元仲來自湖外傳示崧老贈東林珪三友篇讀之慨然因次其韻','李綱','宋','宋诗','song-poetry','','["\u5e90\u5c71"]','粲粲襄陵翁，大嶽九世孫。',240,'全唐诗/poet.song.90000.json','["粲粲襄陵翁，大嶽九世孫。", "文章老益奇，於道見本原。", "我生植艱虞，慘澹風霾昏。", "挽翁共出力，一廓扶桑暾。", "芬馥蓺蘭芷，神姦伐蛟黿。", "此志竟蕭條，相顧聲爲吞。", "遠遊負深釁，行偏西南坤。", "憶昨遇江上，攜手廬山樊。", "林間接軟語，窮盡興衰根。", "三年隔瘴海，豈謂我尚存。", "何嘗知棗梨，頗亦聞風旛。", "讀翁三友篇，雅契久彌敦。", "江南盜雲擾，崛起巢與温。", "翁今渺安在，猶滯脩水源。", "我病寄閩嶺，栖息僧家園。", "百念悉灰冷，窺見易象渾。", "區區不自量，信筆箋微言。", "逝将從翁遊，淬礪刪其繁。", "三聖邈已遠，萬古同所尊。", "何當進此道，對坐虚明軒。"]'),
('b036258f-4f75-4e7a-a789-dab76766baab','三月二十五日邀吳民瞻鄭夢錫李似之陳巽達周元仲遊賢沙鳳池二首 賢沙','李綱','宋','宋诗','song-poetry','','[]','招提環擁碧崔嵬，攜客登臨始此回。',64,'全唐诗/poet.song.90000.json','["招提環擁碧崔嵬，攜客登臨始此回。", "寺比道林多掩抱，峰如靈隱解飛來。", "烟霞深處鐘磬響，杉桂香中殿閣開。", "莫道釣魚人已寂，至今說法尚如雷。"]'),
('b61fc64c-0d11-4547-b42a-644305eeca24','三月二十五日邀吳民瞻鄭夢錫李似之陳巽達周元仲遊賢沙鳳池二首 鳳池','李綱','宋','宋诗','song-poetry','','[]','鳳去空餘舊浴池，竹梧交蔭翠參差。',64,'全唐诗/poet.song.90000.json','["鳳去空餘舊浴池，竹梧交蔭翠參差。", "雲隨屐齒生松磴，泉合琴心瀉石陂。", "幽討平生如此少，清閑今日許誰知。", "道人爲築紬書室，杖履來遊更卜期。"]'),
('8531c820-f1cc-4ec1-9ff2-3de7036651b0','次韻奉酬鄧成材判官二首  其一','李綱','宋','宋诗','song-poetry','','[]','漂泊兵戈到越山，不妨還整切雲冠。',64,'全唐诗/poet.song.90000.json','["漂泊兵戈到越山，不妨還整切雲冠。", "乾坤策裏空真象，龍虎爐中養舊丹。", "静愛白雲歸遠岫，時邀明月下層巒。", "此生已作長閑計，秪願朝廷四海安。"]'),
('b278963d-9778-4633-b1ec-e69129eba9bc','次韻奉酬鄧成材判官二首  其二','李綱','宋','宋诗','song-poetry','','[]','文塲妙譽久推豪，筮仕猶從州縣勞。',64,'全唐诗/poet.song.90000.json','["文塲妙譽久推豪，筮仕猶從州縣勞。", "野鶴未應羣鴈鶩，幽蘭初不掩蓬蒿。", "千尋挺節無霜霰，萬里摶風有羽毛。", "好去江南吐奇策，從來勳業屬吾曹。"]'),
('c19d75fe-1144-4bc2-b03c-dc23c694adee','次韻陳中玉大卿二首  其一','李綱','宋','宋诗','song-poetry','','[]','初官託芘記當時，晚誤明恩入紫微。',64,'全唐诗/poet.song.90000.json','["初官託芘記當時，晚誤明恩入紫微。", "天邑禦戎同象弭，海邦避地各緇衣。", "能詩解飲陶元亮，去國還家丁令威。", "漂泊不須傷客寓，無何爲室更安歸。"]'),
('0629b767-1d6a-43c2-88e6-4c4e98c133fc','次韻陳中玉大卿二首  其二','李綱','宋','宋诗','song-poetry','','[]','叨塵黄閣值明時，推挽英髦愧力微。',64,'全唐诗/poet.song.90000.json','["叨塵黄閣值明時，推挽英髦愧力微。", "海上相逢顔愈渥，篋中誰謂出無衣。", "救焚拯溺非天數，脩政攘夷賴主威。", "舊國故鄉休悵望，中興恢復佇旋歸。"]'),
('6498d26f-635b-4eca-b0d5-83359cc2edf4','遊鼓山靈源洞次周元仲韻','李綱','宋','宋诗','song-poetry','','["\u957f\u6c5f"]','碧海吸長江，清波逾練浄。',240,'全唐诗/poet.song.90000.json','["碧海吸長江，清波逾練浄。", "我爲鼓山遊，潮落初放艇。", "連峰翠崔嵬，倒影涵玉鏡。", "捨舟訪招提，木末繚危磴。", "凌雲開寶閣，震谷韻幽磬。", "乃知大叢林，托棲必深夐。", "靈源更瓌奇，巖壑相隱映。", "森羅盡尤物，無乃太兼并。", "偉哉造化力，至巧於此罄。", "烟雲互卷舒，變態初不定。", "豈惟冠一方，實最東南勝。", "周行洞浹中，泉石若奔競。", "飄蕭毛髪清，滌濯肺腑瑩。", "當年喝水人，端恐溷觀聽。", "是心如虚空，動寂豈妨並。", "兵戈正聯綿，幽討亦云幸。", "相攜得佳侣，散策謝軒乘。", "媮安朝夕間，未可笑趙孟。", "淹留遂忘歸，悵望雲海暝。", "不負惠詢期，更起滄洲興。"]'),
('47a36c4e-1f29-4551-9b2c-6c87b93ce95a','六言頌六首贈安國覺老  其一','李綱','宋','宋诗','song-poetry','','[]','大虚一點真氣，都盧半掬水中。',28,'全唐诗/poet.song.90000.json','["大虚一點真氣，都盧半掬水中。", "堪笑鍾離散漢，付與安國秃翁。"]'),
('e1d99744-afe1-4898-90cd-b139bfa91330','六言頌六首贈安國覺老  其二','李綱','宋','宋诗','song-poetry','','[]','心似蓮花疏通，身如靈龜藏蟄。',28,'全唐诗/poet.song.90000.json','["心似蓮花疏通，身如靈龜藏蟄。", "三十年來住持，不曾嚼破一粒。"]'),
('adebf365-2456-4162-9417-4a08cded7742','六言頌六首贈安國覺老  其三','李綱','宋','宋诗','song-poetry','','[]','本來滴水滴凍，豈礙徹風徹顛。',28,'全唐诗/poet.song.90000.json','["本來滴水滴凍，豈礙徹風徹顛。", "欲問東西祖意，莫嫌喫飯參禪。"]'),
('c0e855ee-a8a9-4e07-b3b5-652e99263947','六言頌六首贈安國覺老  其四','李綱','宋','宋诗','song-poetry','','[]','不用讀書讀史，自能說西說東。',28,'全唐诗/poet.song.90000.json','["不用讀書讀史，自能說西說東。", "若人欲了此法，一源通處皆通。"]'),
('e22fb6a1-1677-47df-8c42-a27bf4d8a076','六言頌六首贈安國覺老  其五','李綱','宋','宋诗','song-poetry','','[]','信口長吟短詠，落筆春蚓秋蛇。',28,'全唐诗/poet.song.90000.json','["信口長吟短詠，落筆春蚓秋蛇。", "萬法無心契合，絲毫擬議即差。"]'),
('b0df967d-50b5-4007-8c18-99337d78a7ba','六言頌六首贈安國覺老  其六','李綱','宋','宋诗','song-poetry','','[]','莫問是魔是佛，休言學道學禪。',28,'全唐诗/poet.song.90000.json','["莫問是魔是佛，休言學道學禪。", "若能不作聖解，便是人間散仙。"]'),
('fe4ca66b-f548-4cf7-8b62-2fb543cd5bd7','寄吕相元直','李綱','宋','宋诗','song-poetry','','[]','許國精忠不計身，據鞭矍鑠邁前聞。',64,'全唐诗/poet.song.90000.json','["許國精忠不計身，據鞭矍鑠邁前聞。", "親提貔虎三千士，力破豺狼十萬軍。", "江表已欣迎騎氣，淮壖行慶掃妖氛。", "勞公力贊中興業，衰病安然臥白雲。"]'),
('9ad72506-4e3a-4c96-934a-6312add8fc62','留題天寧明極堂','李綱','宋','宋诗','song-poetry','','[]','久客若飛蓬，年年氣味同。',96,'全唐诗/poet.song.90000.json','["久客若飛蓬，年年氣味同。", "猶欣容榻地，更得化人宫。", "鬰勃炎蒸極，巍峨棟宇雄。", "疏林碎搖月，虚館迥含風。", "萬户軒楹外，三山指顧中。", "靈潮自朝夕，大舶各西東。", "悵望關河遠，蒼茫雲海空。", "餘生寄閑曠，任運學龐翁。"]'),
('17990e1a-8a8b-41f1-8770-1d6343c3c17a','季夏之初自安國遷南臺天寧寺依南山而面北暑氣尤盛暇日望山頂松林鬱然意必有異因穴垣鑿磴以造其上形勢坦平風日清美四顧山巒環合江潮往來景物不可模状月出林表清光更多夜久閴寂殆非塵世作古詩二十韻以紀其事奉呈巽達元仲','李綱','宋','宋诗','song-poetry','','[]','旅泊不求安，小憇南臺宫。',240,'全唐诗/poet.song.90000.json','["旅泊不求安，小憇南臺宫。", "軒楹盡北鄉，盛暑墮甑中。", "開垣追微凉，山頂羅千松。", "煩襟忽破散，濯此萬里風。", "羣山遞環遶，雲物增奇峰。", "江潮信有期，來去初不窮。", "嘯詠得所托，幽禽亦玲瓏。", "青霞蔽落日，皎月生於東。", "清光入疏林，照我鬢髪鬆。", "壮年幾何時，倐忽成衰翁。", "願餐日月華，爲駐冰雪容。", "二子皆静者，翛然此相從。", "靈丹論祕訣，妙理談真空。", "兵戈滿寰瀛，此樂豈易逢。", "猶恨邇城市，時來車馬蹤。", "逝将選幽僻，誅茅寄蒙籠。", "灌溉荔支園，可敵萬户封。", "屋前修竹合，屋後流溪通。", "風月應更好，清歡永相同。", "稚川晚聞道，尚冀刀圭功。"]'),
('e57e123e-fc51-440c-ba37-6e07fac49326','次韻劉倅寄荔支','李綱','宋','宋诗','song-poetry','','[]','色味芬芳壓衆包，誰将橘頌入離騷。',64,'全唐诗/poet.song.90000.json','["色味芬芳壓衆包，誰将橘頌入離騷。", "非緣人力栽培至，自是天資品格髙。", "璀璨萬星真偉觀，崩騰百馬亦良勞。", "南來坐享吾何幸，更把蘇禪與醉逃。"]'),
('247ab2c0-e2e5-4afd-9d11-d21c093ab545','次初訪許子大龍圖於東山大乘寺留飲觀荔支','李綱','宋','宋诗','song-poetry','','[]','物外仙家長自春，隱淪何必爲逃秦。',64,'全唐诗/poet.song.90000.json','["物外仙家長自春，隱淪何必爲逃秦。", "祗應榴洞贈花者，便是桃源種樹人。", "丹荔枝頭星燦爛，白雲峰頂玉嶙峋。", "主公留客非無意，端爲出山多世塵。"]'),
('316c278f-0a4b-4e46-81dc-22e8af136f53','王豐甫待制會宴湖亭','李綱','宋','宋诗','song-poetry','','[]','畫棟翬飛瞰曲塘，主人情重啓華觴。',64,'全唐诗/poet.song.90000.json','["畫棟翬飛瞰曲塘，主人情重啓華觴。", "月搖波影鱗鱗碧，風入荷花苒苒香。", "散策幸陪終日適，開襟還喜十分涼。", "天涯隨分同清賞，何必南園作醉郷。"]'),
('dadf40a6-0030-45eb-ac6c-5c91234ca369','秋日奉陪王豐甫許子大康平仲遊賢沙宿鳳池登昇山偶成二首  其一','李綱','宋','宋诗','song-poetry','','[]','飛來聳翠一峰孤，鳳沼幽深若畫圖。',64,'全唐诗/poet.song.90000.json','["飛來聳翠一峰孤，鳳沼幽深若畫圖。", "釣艇謝亡難復契，彈琴穎在且相娛。", "心閑自與親泉石，車穏何妨載酒壺。", "萬壑千巖爭競處，不須惆悵憶東吳。"]'),
('5f536219-ea0d-4a76-9f3d-2ad8f2ae905a','秋日奉陪王豐甫許子大康平仲遊賢沙宿鳳池登昇山偶成二首  其二','李綱','宋','宋诗','song-poetry','','[]','追陪杖屨極幽尋，共宿精廬上翠岑。',64,'全唐诗/poet.song.90000.json','["追陪杖屨極幽尋，共宿精廬上翠岑。", "鳳鳥不來空碧沼，仙人已去得黄金。", "月林散影瓊瑶碎，烟水澄光組練深。", "欲把詩篇與收拾，登臨誰會此時心。"]'),
('3a895bf5-3a93-4b36-8a98-8df82bf064ff','奉同王豐甫韻','李綱','宋','宋诗','song-poetry','','[]','年來華髪忽盈頭，欲駕雲帆訪十洲。',64,'全唐诗/poet.song.90000.json','["年來華髪忽盈頭，欲駕雲帆訪十洲。", "且向林泉窮勝賞，更欣樽俎接英遊。", "江山醉眼渾如夢，風月疏簾與上鈎。", "舊國舊都何處是，不堪回首仲宣樓。"]'),
('05635003-4272-4111-9060-ee126aff147f','次韻王豐甫同遊西禪斗車堂','李綱','宋','宋诗','song-poetry','','[]','傑閣雄樓杳靄間，佳辰良夜共躋攀。',64,'全唐诗/poet.song.90000.json','["傑閣雄樓杳靄間，佳辰良夜共躋攀。", "斗回髙柄臨華棟，月湧清光出遠山。", "急景行将悲晼晚，此身難得到寛閑。", "世間百慮何時了，且對金樽一解顔。"]'),
('3167212f-7aed-400f-917e-cdf38c4d7577','九日諸季散處長樂外邑悵然有懷二首  其一','李綱','宋','宋诗','song-poetry','','[]','去歲初從海上回，重陽相與醉髙臺。',64,'全唐诗/poet.song.90000.json','["去歲初從海上回，重陽相與醉髙臺。", "那因寇盜遷南土，阻插茱萸共一杯。", "老矣但思情話切，跫然更望足音來。", "黄花也解知人意，故向籬邊未肯開。"]'),
('fcfebecb-3950-4076-86ba-d2e30f15c5b6','九日諸季散處長樂外邑悵然有懷二首  其二','李綱','宋','宋诗','song-poetry','','[]','終朝兀坐但焚香，身世翛然已兩忘。',64,'全唐诗/poet.song.90000.json','["終朝兀坐但焚香，身世翛然已兩忘。", "收拾江山歸古錦，招邀風月入虚堂。", "鶺鴒散去波翻海，鴻鴈歸來天雨霜。", "命駕莫辭佳節後，菊花開日即重陽。"]'),
('bd147a95-3a49-4ea3-ac3e-98078d3d209b','次韻陳中玉大卿見贈  其一','李綱','宋','宋诗','song-poetry','','[]','奔走連年厭庾塵，每觀前史愧良臣。',96,'全唐诗/poet.song.90000.json','["奔走連年厭庾塵，每觀前史愧良臣。", "退藏願學靈龜蟄，進取寧希尺蠖伸。", "黄帽青鞋從素志，蒼顔華髪愧陳人。", "功名老去渾無味，麴蘖愁來覺有神。", "且把江山聊寓目，須将夢幻與觀身。", "羲書得象誰知者，更抱遺經究獲麟。"]'),
('150ae751-c4f4-4d43-ac59-a301a1dd7c51','次韻陳中玉大卿見贈  其二','李綱','宋','宋诗','song-poetry','','[]','漂泊干戈行路塵，端知奔命爲巫臣。',96,'全唐诗/poet.song.90000.json','["漂泊干戈行路塵，端知奔命爲巫臣。", "德同蘧瑗知舒卷，時在荘周有屈伸。", "皂蓋朱旛多舊愛，石渠東觀正當人。", "未将老手司文翰，且賦新詩泣鬼神。", "淮浦追尋三改甲，天涯相遇兩閑身。", "中興作頌須元結，瑞國當爲一角麟。"]'),
('6726cdf6-e6f7-4092-8538-162ccc2063df','送周元仲訪親桐廬','李綱','宋','宋诗','song-poetry','','[]','西風嫋嫋水增波，送遠其如旅况何。',64,'全唐诗/poet.song.90000.json','["西風嫋嫋水增波，送遠其如旅况何。", "身寓甌閩饒寇盗，心馳關塞阻兵戈。", "羨君有志尋華蕚，顧我無因到浙河。", "若見交遊問消息，爲言衰病鬢絲多。"]'),
('2feb45ea-8960-4b17-be21-7ebf698cb7f6','鄭夢錫教授送黄精以詩答其意','李綱','宋','宋诗','song-poetry','','[]','太陽之草名黄精，養性獨冠神農經。',164,'全唐诗/poet.song.90000.json','["太陽之草名黄精，養性獨冠神農經。", "掃除白髪有奇效，採食既久通仙靈。", "年來衰病乃如許，瘴癘憂患頻相仍。", "稍從方士學服餌，桑榆庶以延頽齡。", "鼎中九轉未遽就，聊假草木搴其英。", "閩山無雪苗可識，勞君爲我鋤青冥。", "封題寄遠意良厚，不道山寒少茯苓。", "蜜蒸日暴試新法，入口便覺身倍輕。", "只今兵革未衰息，羣盜蜂蟻猶縱横。", "何須運甓習筋力，會當一舉騰上煙雲之翠屏。"]'),
('7cd31be9-9bc0-47a1-aedf-5ce11fc4e52f','初見梅花三絕句奉呈王豐甫待制  其一','李綱','宋','宋诗','song-poetry','','[]','江梅何處不先春，海嶠初逢若故人。',32,'全唐诗/poet.song.90000.json','["江梅何處不先春，海嶠初逢若故人。", "誰謂冰姿太清淡，一回相見一回新。"]'),
('5c7883ac-2d8d-452c-a2b2-7015dfef30a5','初見梅花三絕句奉呈王豐甫待制  其二','李綱','宋','宋诗','song-poetry','','[]','開花不許衆芳知，冷艷幽芳特地奇。',32,'全唐诗/poet.song.90000.json','["開花不許衆芳知，冷艷幽芳特地奇。", "霜霰不飛閩候暖，更留綠葉伴青枝。"]'),
('988e019b-1969-4867-b544-b52a91fb452d','初見梅花三絕句奉呈王豐甫待制  其三','李綱','宋','宋诗','song-poetry','','[]','每将香劑學江梅，及嗅梅花始覺非。',32,'全唐诗/poet.song.90000.json','["每将香劑學江梅，及嗅梅花始覺非。", "月夜故園浮動處，攀條嚼蘂幾時歸。"]'),
('9af1f75f-f1aa-4065-bf00-91fa1cfbc009','奉寄吕丞相元直  其一','李綱','宋','宋诗','song-poetry','','[]','出擁彫戈入衮衣，江城重詠我公歸。',64,'全唐诗/poet.song.90000.json','["出擁彫戈入衮衣，江城重詠我公歸。", "手扶日月還黄道，足履星辰上紫微。", "已集羣英熙帝載，好施長策復邦畿。", "海濱病叟無他望，側耳天聲暢國威。"]'),
('eb349827-b89d-47d3-8bb1-59651a96816a','奉寄吕丞相元直  其二','李綱','宋','宋诗','song-poetry','','[]','年來衰病不堪論，華髪蕭蕭滿鬢根。',64,'全唐诗/poet.song.90000.json','["年來衰病不堪論，華髪蕭蕭滿鬢根。", "藥杵聲中銷晦朔，羲書畫裏見天真。", "山僧結社成初定，野老扶笻過遠村。", "休運定知興復近，剩篩麴蘖入瓶盆。"]'),
('8cb72c50-2aff-4175-b153-e1501154381e','以舊賜戰袍等贈韓少師二首  其一','李綱','宋','宋诗','song-poetry','','[]','胡騎當年犯帝閽，腐儒謬使護諸軍。',64,'全唐诗/poet.song.90000.json','["胡騎當年犯帝閽，腐儒謬使護諸軍。", "尚方寶劍頻膺賜，御府戎衣幸見分。", "丈八蛇矛金纒笴，團欒獸盾繪成文。", "山林衰病渾無用，持贈君侯立大勳。"]'),
('d28b3fde-06ee-4965-9225-a2398ac58284','以舊賜戰袍等贈韓少師二首  其二','李綱','宋','宋诗','song-poetry','','[]','舊欽忠勇冠三軍，每一相逢更絕倫。',64,'全唐诗/poet.song.90000.json','["舊欽忠勇冠三軍，每一相逢更絕倫。", "鐵馬金戈睢水上，碧油紅旆海山濱。", "氣吞勍敵唐英衛，力破羣兇漢禹恂。", "聖主中興賴良将，好陪休運上麒麟。"]'),
('a1a65692-e1a5-47ff-90fc-90b78e9d7592','奉贈宣撫孟參政二首  其一','李綱','宋','宋诗','song-poetry','','[]','赤子潢池學弄兵，柄臣仗節到閩城。',64,'全唐诗/poet.song.90000.json','["赤子潢池學弄兵，柄臣仗節到閩城。", "布宣威德雷霆奮，慰撫烝黎雨澤傾。", "鏖戰指蹤煩妙略，凱旋鐃鼓震驩聲。", "靈旗徑向江湖去，早定艱難底太平。"]'),
('ce699dec-403d-48ea-b860-c0f9ee8d2335','奉贈宣撫孟參政二首  其二','李綱','宋','宋诗','song-poetry','','[]','睢陽一别五經春，邂逅相逢瘴海濱。',64,'全唐诗/poet.song.90000.json','["睢陽一别五經春，邂逅相逢瘴海濱。", "華髪知公因國事，蒼顔顧我久埃塵。", "綈袍念舊故人意，藥裹關心多病身。", "入覲從容見知舊，爲言秪欲老垂綸。"]'),
('4e6824be-c631-48f6-b835-615037c3a9f0','題止戈堂二首奉呈安撫程待制  其一','李綱','宋','宋诗','song-poetry','','[]','會府繁雄冠列城，恩頒符節付名卿。',64,'全唐诗/poet.song.90000.json','["會府繁雄冠列城，恩頒符節付名卿。", "貔貅戰罷烽烟息，豺虎銷除氛祲清。", "齊閣已聞鈴索静，提封更絕羽書驚。", "止戈當自甌閩始，願挽天河洗甲兵。"]'),
('8025a150-3b4a-42c9-8c68-abfc6a79ea69','題止戈堂二首奉呈安撫程待制  其二','李綱','宋','宋诗','song-poetry','','[]','武備森嚴燕寝東，華堂髙敞靚相通。',64,'全唐诗/poet.song.90000.json','["武備森嚴燕寝東，華堂髙敞靚相通。", "坐令戈甲韜藏地，盡在樽罍談笑中。", "案上屈盤香篆裊，庭前磊砢荔支紅。", "偃藩樂事今多有，更詠周詩祝屢豐。"]'),
('03e4e801-301b-4920-baf9-c62059c73144','蒙恩除荆湖廣南宣撫兼知潭州具奏辭免  其一','李綱','宋','宋诗','song-poetry','','[]','得罪明時忽六年，生還新自海南邊。',64,'全唐诗/poet.song.90000.json','["得罪明時忽六年，生還新自海南邊。", "分甘伏死巉巖下，豈意猶還大将權。", "老似廉頗徒喜飯，才非祖逖敢先鞭。", "一封瀝血輸誠懇，深冀皇慈爲惻然。"]'),
('18915ff8-f6f6-4527-8791-4da162c583c0','蒙恩除荆湖廣南宣撫兼知潭州具奏辭免  其二','李綱','宋','宋诗','song-poetry','','[]','昔年宣撫兩河間，行次覃懷已召還。',64,'全唐诗/poet.song.90000.json','["昔年宣撫兩河間，行次覃懷已召還。", "壮志久拚身似葉，巧言終使罪如山。", "士風欺蔽猶前日，君命牢辭秪厚顔。", "回首追思七年事，孤危易感涕空澘。"]'),
('b480b4cb-6ca0-40f2-aa43-605758e4fd98','辭免不允蒙恩遣中使降賜趣行不獲已受命二首  其一','李綱','宋','宋诗','song-poetry','','[]','聖主隆恩雨露頒，特迂星使下天關。',64,'全唐诗/poet.song.90000.json','["聖主隆恩雨露頒，特迂星使下天關。", "自嗟犬馬雖衰疾，敢避朝廷正急難。", "龔遂有心安渤海，謝安無計戀東山。", "中原恢復吾何敢，且與君王鎮百蠻。"]'),
('97e27e53-0ec2-4c23-8955-4e7a2bacc297','辭免不允蒙恩遣中使降賜趣行不獲已受命二首  其二','李綱','宋','宋诗','song-poetry','','[]','頻年巨盜據荆湖，自是廷臣計畫迂。',64,'全唐诗/poet.song.90000.json','["頻年巨盜據荆湖，自是廷臣計畫迂。", "虎兕儻令隨指擾，瘡痍可使即時蘇。", "上流自昔多雄鎮，內静方能備外虞。", "子賤只憂還掣肘，文侯解信樂羊無。"]'),
('0a177939-b824-495d-bb43-5de51a9e145a','五月六日率師離長樂乘舟如水口二首  其一','李綱','宋','宋诗','song-poetry','','[]','力疾驅馳爲主恩，敢辭炎暑道途勤。',64,'全唐诗/poet.song.90000.json','["力疾驅馳爲主恩，敢辭炎暑道途勤。", "五更鼓角催行色，百里旌旗拂曉雲。", "閩粤乍開新幕府，灞陵初起舊将軍。", "江山滿目難留戀，試擁彫戈静楚氛。"]'),
('afd4e247-f2a1-4007-8632-a4a2b9403fef','五月六日率師離長樂乘舟如水口二首  其二','李綱','宋','宋诗','song-poetry','','[]','畫舸連檣泛碧波，瀟湘去路飽經過。',64,'全唐诗/poet.song.90000.json','["畫舸連檣泛碧波，瀟湘去路飽經過。", "山川煥發旌旜色，将士歡娛鐃鼓歌。", "舊學但曾聞俎豆，暮年何意總干戈。", "據鞍馬援平生志，豈在驪駒白玉珂。"]'),
('e87a18cb-5c4b-4cb9-829d-0a4dcb826d0f','次昭武省祖塋焚黄因會宗族二首  其一','李綱','宋','宋诗','song-poetry','','[]','不到鄉閭二十秋，幸因帝命得來遊。',64,'全唐诗/poet.song.90000.json','["不到鄉閭二十秋，幸因帝命得來遊。", "過家上塚懷先德，釃酒揮金學故侯。", "季子歸來饒印綬，魏舒起廢擁貔貅。", "自嗟慷慨據鞍客，不及當年馬少游。"]'),
('b8c58f16-42c1-4d8e-a651-4f32c06d0da6','次昭武省祖塋焚黄因會宗族二首  其二','李綱','宋','宋诗','song-poetry','','[]','兵火燒殘井邑空，谿山依舊夕陽中。',64,'全唐诗/poet.song.90000.json','["兵火燒殘井邑空，谿山依舊夕陽中。", "故鄉自昔悲遊子，壮歲來歸今老翁。", "細認里閭尋樹石，怪看旌旆走兒童。", "王師新定回源盜，猶喜田家歲事豐。"]'),
('33edc3ad-78f6-4481-99ff-29efa2fdc081','道臨川按閱兵将錢巽叔侍郎賦詩次其韻三首  其一','李綱','宋','宋诗','song-poetry','','[]','平生多難豈能賢，恩許猶持閫外權。',64,'全唐诗/poet.song.90000.json','["平生多難豈能賢，恩許猶持閫外權。", "貔虎幸蒙分壯士，桑榆愧已迫衰年。", "枕前鼓角元戎報，帳下更籌契箭傳。", "多少豪英志恢復，問誰先著祖生鞭。"]'),
('47846254-d6e8-4e2a-b1c9-aaa8bb446f4d','道臨川按閱兵将錢巽叔侍郎賦詩次其韻三首  其二','李綱','宋','宋诗','song-poetry','','[]','酷暑脩途起戴星，恨無鵬翼激鯤溟。',64,'全唐诗/poet.song.90000.json','["酷暑脩途起戴星，恨無鵬翼激鯤溟。", "折衝未論攘無敵，假道何妨小勒兵。", "試使觸鐃齊作止，敢言旗幟益精明。", "三軍酺醵皆呼舞，賴有賢侯守郡城。"]'),
('5045809f-10ad-445d-8738-c5a0630d0e5d','道臨川按閱兵将錢巽叔侍郎賦詩次其韻三首  其三','李綱','宋','宋诗','song-poetry','','[]','經綸屯難正雲雷，誤沐恩光玷上台。',64,'全唐诗/poet.song.90000.json','["經綸屯難正雲雷，誤沐恩光玷上台。", "報國有心同犬馬，和羮無補愧鹽梅。", "偶持漢節如荆楚，幸會羣英共酒盃。", "更辱佳篇與褒飾，珍藏他日詫田萊。"]'),
('f6a2ac89-8157-4fcb-a23d-eea6f01f385a','道廬陵遊青原山謁保寧宗老一首','李綱','宋','宋诗','song-poetry','','[]','老病維摩臥七閩，欲邀瓶錫伴閒身。',64,'全唐诗/poet.song.90000.json','["老病維摩臥七閩，欲邀瓶錫伴閒身。", "愧無拂石眠雲分，來作輕裘緩带人。", "小隊入山風嫋嫋，飛泉出寺石磷磷。", "煩師更舉西來意，一點陽和萬物春。"]'),
('799884fa-0921-4ce7-b0e2-1d27360b253f','八月十一日次茶陵縣入湖南界有感','李綱','宋','宋诗','song-poetry','','[]','憶昔湖南全盛日，郡邑郷村盡充實。',304,'全唐诗/poet.song.90000.json','["憶昔湖南全盛日，郡邑郷村盡充實。", "連年兵火人煙稀，田野荆榛氣蕭瑟。", "我初入境重傷懷，空有山川照旌節。", "試呼耆老細詢問，未語吞聲已先咽。", "自從虜騎犯長沙，巨寇如麻恣馳突。", "殺人不異犬與羊，至今澗谷猶流血。", "盜賊縱横尚可避，官吏貪殘不可說。", "挾威倚勢甚豺狼，刻削誅求到毫髪。", "父子妻孥不相保，何止肌膚困鞭撻。", "上户逃移下户死，人口凋零十無八。", "九重深遠那得知，使者寛容失譏察。", "今朝幸睹漢官儀，願使斯民再蘇活。", "我聞此語心如摧，平生况有陽城拙。", "行移州縣遣官僚，盡罷科須治姦猾。", "巨蠧推窮付囹圄，社鼠城狐掃巢穴。", "削平羣盜拊瘡痍，報政何須待朞月。", "祖宗德澤感人深，周漢正賴宣光哲。", "中興之運期有在，庶以涓微助溟渤。", "少陵酷愛舂陵行，千古知心有元結。"]'),
('9a23bf9e-bd1a-4476-bb4d-53b2215de195','次衡州二首  其一','李綱','宋','宋诗','song-poetry','','[]','搖落霜林一半紅，瀟湘秋色有無中。',64,'全唐诗/poet.song.90000.json','["搖落霜林一半紅，瀟湘秋色有無中。", "未尋嶽麓抱黄洞，先到衡陽回鴈峰。", "茱菊有情迎九日，旌旗無力舞西風。", "年年佳節多行路，玉帳樽罍幸不空。"]'),
('9a1ffc01-7c70-41c6-ba75-30dd6015d8de','次衡州二首  其二','李綱','宋','宋诗','song-poetry','','[]','弄兵赤子滿潢池，渤海龔生真吏師。',64,'全唐诗/poet.song.90000.json','["弄兵赤子滿潢池，渤海龔生真吏師。", "欲使循良買牛犢，會須哀痛問瘡痍。", "東南王氣雖方振，西北流民自可悲。", "七萬虎狼皆斂戢，廟堂還有阿誰知。"]'),
('3448e522-5ff8-410c-b9b8-d326ceb42df1','馬友餘黨步諒等以萬衆自江西寇湖南破醴陵攸縣屯於衡山縣界得報即自衡陽率師次衡山遣兵将夜渡江晨叩其壘賊出不意悉解以降放散驅虜老弱外得精兵七千人分隸諸将漫成口號四首  其一','李綱','宋','宋诗','song-poetry','','["\u8861\u5c71"]','貔貅一夜渡湘江，賊壘朝臨盡出降。',32,'全唐诗/poet.song.90000.json','["貔貅一夜渡湘江，賊壘朝臨盡出降。", "自古成功在機會，周郎赤壁豈難雙。"]'),
('5ad781b0-36e0-42de-a29f-2f28eaa7d01a','馬友餘黨步諒等以萬衆自江西寇湖南破醴陵攸縣屯於衡山縣界得報即自衡陽率師次衡山遣兵将夜渡江晨叩其壘賊出不意悉解以降放散驅虜老弱外得精兵七千人分隸諸将漫成口號四首  其二','李綱','宋','宋诗','song-poetry','','["\u8861\u5c71"]','王師破賊凱歌還，積甲高於熊耳山。',32,'全唐诗/poet.song.90000.json','["王師破賊凱歌還，積甲高於熊耳山。", "盡選精強付諸將，威聲已足鎮荆蠻。"]'),
('25dd01a0-d905-4509-9e21-d9f728943a73','馬友餘黨步諒等以萬衆自江西寇湖南破醴陵攸縣屯於衡山縣界得報即自衡陽率師次衡山遣兵将夜渡江晨叩其壘賊出不意悉解以降放散驅虜老弱外得精兵七千人分隸諸将漫成口號四首  其三','李綱','宋','宋诗','song-poetry','','["\u8861\u5c71"]','赤眉銅馬與黄巾，漢魏收功豈異人。',31,'全唐诗/poet.song.90000.json','["赤眉銅馬與黄巾，漢魏收功豈異人。", "駕馭撫綏要有術，從盜賊本王臣。"]'),
('e2f46501-5d89-48c7-b9a5-c836f47ade23','馬友餘黨步諒等以萬衆自江西寇湖南破醴陵攸縣屯於衡山縣界得報即自衡陽率師次衡山遣兵将夜渡江晨叩其壘賊出不意悉解以降放散驅虜老弱外得精兵七千人分隸諸将漫成口號四首  其四','李綱','宋','宋诗','song-poetry','','["\u8861\u5c71"]','祝融道士蒼生雨，萬事須知總是天。',32,'全唐诗/poet.song.90000.json','["祝融道士蒼生雨，萬事須知總是天。", "宣暢威靈聊塞責，乞身從此老林泉。"]'),
('9fc64f48-6719-4b12-8ace-4641a2a5eb0f','余兩過湖湘皆以事阻不到南嶽今自衡趨潭意謂決可一到又以新討降步諒之衆不果往爲之悵然成兩絕句  其一','李綱','宋','宋诗','song-poetry','','["\u8861\u5c71"]','衡嶽崢嶸倚太清，長時霧雨少晴明。',32,'全唐诗/poet.song.90000.json','["衡嶽崢嶸倚太清，長時霧雨少晴明。", "我來卻恨緣征討，不得祝融峰上行。"]'),
('3a9767c6-61c9-4649-a084-c4aca1ff5cc4','余兩過湖湘皆以事阻不到南嶽今自衡趨潭意謂決可一到又以新討降步諒之衆不果往爲之悵然成兩絕句  其二','李綱','宋','宋诗','song-poetry','','["\u8861\u5c71"]','七年三楚江邊，阻上衡山信鮮緣。',31,'全唐诗/poet.song.90000.json','["七年三楚江邊，阻上衡山信鮮緣。", "此去便爲歸老計，不知重到是何年。"]');
